# ─── Dual Arb Bot System ──────────────────────────────────────────────────────
# Strategy: place LIMIT BUY orders on both YES and NO sides simultaneously.
# Both orders sit in the order book as bids (market maker = no taker fees).
# As price volatility causes each side to fill, profit is locked in on settlement.
# Stop loss: if one side fills and the other side's bid drops X cents, market-sell
# the filled side to exit (market order guarantees execution despite taker fees).

active_bots = {}  # bot_id -> bot_config
trade_history = []  # completed/stopped bots log (newest first)
_opening_lines = {}  # ticker -> {'yes_price': int, 'captured_at': float} — pre-game closing line

# ─── Activity Log ─────────────────────────────────────────────────────────────
LOG_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'activity_log.jsonl')
_log_lock = threading.Lock()

def bot_log(event: str, bot_id: str = '', details: dict = None, level: str = 'INFO'):
    """Write a structured log entry. Every bot decision gets logged here.
    
    Events:
      BOT_CREATED, ORDER_PLACED, ORDER_CANCELLED, ORDER_FILLED,
      FAV_POSTED, FAV_FILLED, DOG_POSTED, FAV_REPOSTED, FAV_STALE_CANCELLED,
      SL_TRIGGERED, SL_BLOCKED_STALE, SL_FIRED, SL_FAILED,
      TP_TRIGGERED, TP_FIRED, TP_FAILED,
      REPOST, RESIZE, SETTLEMENT, MARKET_SETTLED,
      WATCH_FILLED, WATCH_SL, WATCH_TP, WATCH_SETTLED,
      REPEAT_STARTED, REPEAT_TIMEOUT,
      MONITOR_CYCLE, ERROR
    """
    entry = {
        'ts': datetime.now(timezone.utc).isoformat(),
        'epoch': time.time(),
        'event': event,
        'level': level,
        'bot_id': bot_id,
    }
    # Snapshot bot state if it exists
    if bot_id and bot_id in active_bots:
        b = active_bots[bot_id]
        entry['bot_snapshot'] = {
            'type': b.get('type', 'arb'),
            'ticker': b.get('ticker'),
            'status': b.get('status'),
            'side': b.get('side'),
            'yes_price': b.get('yes_price'),
            'no_price': b.get('no_price'),
            'entry_price': b.get('entry_price'),
            'quantity': b.get('quantity'),
            'yes_fill_qty': b.get('yes_fill_qty', 0),
            'no_fill_qty': b.get('no_fill_qty', 0),
            'fill_qty': b.get('fill_qty', 0),
            'live_bid': b.get('live_bid'),
            'stop_loss_cents': b.get('stop_loss_cents'),
            'game_phase': b.get('game_phase'),
            'fav_side': b.get('fav_side'),
            'profit_per': b.get('profit_per'),
            'repost_count': b.get('repost_count', 0),
            'fair_value_cents': b.get('fair_value_cents'),
        }
    if details:
        entry['details'] = details
    
    with _log_lock:
        try:
            with open(LOG_FILE, 'a') as f:
                f.write(json.dumps(entry, default=str) + '\n')
        except Exception as e:
            print(f'⚠ bot_log write failed: {e}')
    
    # Also print a compact summary to console
    det_str = f' | {details}' if details else ''
    print(f'📋 [{level}] {event} {bot_id}{det_str}')

# ─── State Persistence ────────────────────────────────────────────────────────
DATA_FILE   = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'data.json')
TRADES_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'trades.jsonl')

_save_lock = threading.Lock()

applied_migrations: list = []  # tracks which migrations have run

# ─── Kalshi Fee Calculation ──────────────────────────────────────────────────
# Maker fee = ceil(0.0175 * C * P * (1-P) * 100) cents per side
# Taker fee = ceil(0.07   * C * P * (1-P) * 100) cents per side
# Arb bots use resting limit orders → maker fee on both legs.
KALSHI_MAKER_RATE = 0.0175
KALSHI_TAKER_RATE = 0.07

def _kalshi_side_fee_cents(price_cents: int, qty: int) -> int:
    """Maker fee for one side in cents (rounded up)."""
    P = price_cents / 100
    raw_dollars = KALSHI_MAKER_RATE * qty * P * (1 - P)
    return _math.ceil(raw_dollars * 100)  # cents, rounded up

def _kalshi_taker_side_fee_cents(price_cents: int, qty: int) -> int:
    """Taker fee for one side in cents (rounded up)."""
    P = price_cents / 100
    raw_dollars = KALSHI_TAKER_RATE * qty * P * (1 - P)
    return _math.ceil(raw_dollars * 100)  # cents, rounded up

def kalshi_fee_cents(yes_price: int, no_price: int, qty: int) -> int:
    """Total Kalshi maker fee for both legs of an arb trade, in cents."""
    return _kalshi_side_fee_cents(yes_price, qty) + _kalshi_side_fee_cents(no_price, qty)

def _apex_snap_check(anchor_price, bid_price, qty=1, snap_ceiling=None):
    """Return True if snapping to bid is profitable. Simple cents check — no fee math.
    Snap only if combined <= snap_ceiling (default SNAP_CEILING_CENTS)."""
    combined = anchor_price + bid_price
    return combined <= (snap_ceiling if snap_ceiling is not None else SNAP_CEILING_CENTS)


def _apex_sellback_check(bot_id, bot, avg_anchor, current_fav_bid, qty):
    """Compare sell-back cost vs completion cost at ceiling. Return True if sell-back is cheaper.
    Accounts for the profit from completing — only sells back when completing is a NET loss."""
    ticker = bot['ticker']
    filled_side = bot.get('first_fill_side', 'yes')
    # For Apex: the filled side IS the anchor/dog side
    dog_side = filled_side

    # Get current dog bid from WS cache (fast, no API call)
    dog_bid = bot.get(f'live_{dog_side}_bid', 0)
    if not dog_bid or dog_bid < 3:
        return False  # dog nearly worthless, just complete the arb

    # Net cost to complete: raw loss + fees MINUS profit from the spread
    # When combined < 100, the arb is profitable (100 - combined per contract)
    combined = avg_anchor + current_fav_bid
    complete_profit_per = max(0, 100 - combined)  # per-contract profit from spread
    complete_loss_per = max(0, combined - 100)     # per-contract loss if over 100
    complete_fees = _kalshi_side_fee_cents(avg_anchor, qty) + _kalshi_side_fee_cents(current_fav_bid, qty)
    complete_total = (complete_loss_per * qty) + complete_fees
    # Net: total cost minus profit earned
    net_complete_cost = complete_total - (complete_profit_per * qty)

    # Cost to sell back: what we'd lose selling the dog as MAKER (post at ask, not cross bid)
    sellback_loss_per = max(0, avg_anchor - dog_bid)
    sellback_fees = _kalshi_side_fee_cents(avg_anchor, qty) + _kalshi_side_fee_cents(dog_bid, qty)
    sellback_total = (sellback_loss_per * qty) + sellback_fees

    # Only sell back if completing is a NET loss (fees exceed spread profit)
    # When arb is profitable (combined < 100 - fees), always prefer completing
    if net_complete_cost <= 0:
        # Completing is net-profitable — don't sell back
        bot_log('APEX_SELLBACK_CHECK', bot_id, {
            'avg_anchor': avg_anchor, 'fav_bid': current_fav_bid, 'dog_bid': dog_bid,
            'combined': combined, 'complete_profit_per': complete_profit_per,
            'net_complete_cost': net_complete_cost, 'sellback_loss': sellback_total,
            'qty': qty, 'decision': 'complete_profitable',
        })
        return False

    # Completing is a net loss — sell back if it's cheaper
    saves_per_contract = (net_complete_cost - sellback_total) / qty if qty > 0 else 0

    bot_log('APEX_SELLBACK_CHECK', bot_id, {
        'avg_anchor': avg_anchor, 'fav_bid': current_fav_bid, 'dog_bid': dog_bid,
        'combined': combined, 'complete_profit_per': complete_profit_per,
        'net_complete_cost': net_complete_cost, 'sellback_loss': sellback_total,
        'saves_per_contract': round(saves_per_contract, 1), 'qty': qty,
        'decision': 'sell_back' if saves_per_contract > 0 else 'complete',
    })

    return saves_per_contract > 0


def _apex_sell_back(bot_id, bot, avg_anchor, fav_bid, actions):
    """Initiate Apex sell-back: cancel hedge, post maker sell order, enter selling_back state.
    The monitor loop handles walking the sell price down and recording the trade on fill."""
    now = time.time()
    ticker = bot['ticker']
    filled_side = bot.get('first_fill_side', 'yes')
    anchor_side = filled_side
    qty = bot.get('hedge_qty', 1)

    print(f'🔙 APEX SELLBACK INIT: {bot_id} avg_anchor={avg_anchor}¢ fav_bid={fav_bid}¢ qty={qty}')
    bot_log('APEX_SELLBACK_INIT', bot_id, {
        'avg_anchor': avg_anchor, 'fav_bid': fav_bid, 'qty': qty,
        'anchor_side': anchor_side, 'ticker': ticker,
    })

    # 1. Cancel the hedge order
    hedge_oid = bot.get('hedge_order_id')
    if hedge_oid:
        try:
            api_rate_limiter.wait()
            kalshi_client.cancel_order(hedge_oid)
        except Exception as e:
            print(f'⚠ APEX SELLBACK: cancel hedge failed: {e}')

    # Cancel any remaining orders
    group_id = bot.get('_order_group_id')
    if group_id:
        try:
            api_rate_limiter.wait()
            kalshi_client.cancel_order_group(group_id)
        except Exception:
            pass

    # 2. Verify actual fill count
    for rung in bot.get('rungs', []):
        oid = rung.get(f'{anchor_side}_order_id')
        if oid:
            try:
                api_read_limiter.wait()
                resp = kalshi_client.get_order(oid)
                ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
                filled = _parse_fill_count(ord_data)
                rung[f'{anchor_side}_fill_qty'] = filled
            except Exception:
                pass

    actual_qty = sum(r.get(f'{anchor_side}_fill_qty', 0) for r in bot.get('rungs', []))
    if actual_qty <= 0:
        print(f'⚠ APEX SELLBACK: no fills found — aborting')
        bot_log('APEX_SELLBACK_NO_FILLS', bot_id, {'qty': qty, 'actual_qty': actual_qty})
        return

    hedge_filled = bot.get('_hedge_fill_count', 0)
    sell_qty = actual_qty - hedge_filled
    if sell_qty <= 0:
        print(f'⚠ APEX SELLBACK: hedge already filled {hedge_filled}/{actual_qty} — no sell-back needed')
        return

    # 3. Get current ask price for maker sell
    try:
        api_read_limiter.wait()
        ob = kalshi_client.get_market_orderbook(ticker)
        anchor_ask = _best_ask(ob, anchor_side)
        anchor_bid = _best_bid(ob, anchor_side)
    except Exception:
        anchor_ask = 0
        anchor_bid = 0

    # Post sell at ask (maker) — or ask-1 if we want to be first in queue
    if anchor_ask > 0 and anchor_bid > 0 and anchor_ask - anchor_bid >= 2:
        # Gapped market: post at ask - 1 (inside the spread, still maker)
        sell_price = anchor_ask - 1
    elif anchor_ask > 0:
        sell_price = anchor_ask
    elif anchor_bid > 0:
        # No ask data — post at bid + 1 (above bid = maker)
        sell_price = anchor_bid + 1
    else:
        sell_price = max(1, avg_anchor)  # fallback

    sell_price = max(1, min(sell_price, 99))

    # Place maker sell order
    try:
        sell_kwargs = {
            'ticker': ticker,
            'side': anchor_side,
            'action': 'sell',
            'count': sell_qty,
        }
        if anchor_side == 'yes':
            sell_kwargs['yes_price'] = sell_price
        else:
            sell_kwargs['no_price'] = sell_price
        api_rate_limiter.wait()
        resp = kalshi_client.create_order(**sell_kwargs)
        resp_ord = resp.get('order', resp) if isinstance(resp, dict) else {}
        sell_order_id = resp_ord.get('order_id')
    except Exception as e:
        print(f'⚠ APEX SELLBACK: maker sell order failed: {e} — will retry')
        bot['_apex_sellback_attempts'] = bot.get('_apex_sellback_attempts', 0) + 1
        bot_log('APEX_SELLBACK_POST_FAILED', bot_id, {'error': str(e)[:200], 'sell_price': sell_price})
        actions.append({'bot_id': bot_id, 'action': 'apex_sellback_retry'})
        return

    if not sell_order_id:
        print(f'⚠ APEX SELLBACK: no order_id returned — will retry')
        bot['_apex_sellback_attempts'] = bot.get('_apex_sellback_attempts', 0) + 1
        return

    # 4. Transition to selling_back state
    bot['_pre_sellback_status'] = bot['status']
    bot['status'] = 'apex_selling_back'
    bot['_sellback_order_id'] = sell_order_id
    bot['_sellback_price'] = sell_price
    bot['_sellback_qty'] = sell_qty
    bot['_sellback_fill_qty'] = 0
    bot['_sellback_started_at'] = now
    bot['_sellback_last_walk_at'] = now
    bot['_sellback_walk_count'] = 0
    bot['_sellback_avg_anchor'] = avg_anchor
    bot['_sellback_fav_bid'] = fav_bid
    bot['_sellback_hedge_filled'] = hedge_filled
    save_state()

    print(f'🔙 APEX SELLBACK POSTED: {bot_id} {anchor_side} sell @{sell_price}¢ ×{sell_qty} (maker)')
    bot_log('APEX_SELLBACK_POSTED', bot_id, {
        'sell_price': sell_price, 'sell_qty': sell_qty, 'order_id': sell_order_id[:12],
        'anchor_bid': anchor_bid, 'anchor_ask': anchor_ask, 'avg_anchor': avg_anchor,
    })
    _audit('APEX_SELLBACK_POSTED', bot_id, {'ticker': ticker, 'anchor_side': anchor_side, 'sell_price': sell_price, 'qty': sell_qty})
    actions.append({'bot_id': bot_id, 'action': 'apex_sellback_posted', 'sell_price': sell_price})


def _apex_sellback_complete(bot_id, bot, sell_price, actions):
    """Record the completed sell-back trade after the maker sell fills."""
    now = time.time()
    ticker = bot['ticker']
    anchor_side = bot.get('first_fill_side', 'yes')
    avg_anchor = bot.get('_sellback_avg_anchor', 0)
    fav_bid = bot.get('_sellback_fav_bid', 0)
    sell_qty = bot.get('_sellback_qty', 1)
    hedge_filled = bot.get('_sellback_hedge_filled', 0)

    loss_cents = (avg_anchor - sell_price) * sell_qty if sell_price else avg_anchor * sell_qty

    # Fees: maker on original anchor buy + maker on sell (both maker)
    buy_fee = _kalshi_side_fee_cents(avg_anchor, sell_qty)
    sell_fee = _kalshi_side_fee_cents(sell_price, sell_qty) if sell_price else 0
    total_fees = buy_fee + sell_fee
    loss_cents += total_fees

    # Partial hedge profit
    partial_profit = 0
    if hedge_filled > 0:
        hedge_price = bot.get('hedge_price', 0)
        partial_per = 100 - avg_anchor - hedge_price
        hedge_fee = _kalshi_side_fee_cents(avg_anchor, hedge_filled) + _kalshi_side_fee_cents(hedge_price, hedge_filled)
        partial_profit = max(0, partial_per * hedge_filled - hedge_fee)

    if loss_cents < 0:
        profit_cents = abs(loss_cents) + partial_profit
        loss_cents = 0
    else:
        profit_cents = partial_profit
        loss_cents = max(0, loss_cents - partial_profit)

    if profit_cents > 0:
        session_pnl['gross_profit_cents'] = session_pnl.get('gross_profit_cents', 0) + profit_cents
    if loss_cents > 0:
        session_pnl['gross_loss_cents'] += loss_cents
    bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + profit_cents - loss_cents
    bot['_trade_recorded'] = True

    _record_trade({
        'bot_id': bot_id, 'ticker': ticker,
        'yes_price': avg_anchor if anchor_side == 'yes' else fav_bid,
        'no_price': avg_anchor if anchor_side == 'no' else fav_bid,
        'quantity': sell_qty,
        'profit_cents': profit_cents,
        'loss_cents': loss_cents,
        'fee_cents': total_fees,
        'result': 'apex_sellback',
        'exit_via': f'apex_sell_back_{anchor_side}',
        'first_leg': anchor_side,
        'dog_side': anchor_side,
        'dog_price': avg_anchor,
        'sell_back_price': sell_price,
        'fav_bid_at_sellback': fav_bid,
        'hedge_filled': hedge_filled,
        'timestamp': now,
        'placed_at': bot.get('created_at', now),
        'arb_width': bot.get('avg_width', 0) or bot.get('target_width', 0),
        'game_phase': bot.get('game_phase', 'live'),
        'game_context': _get_game_context(ticker),
        'fill_source': 'apex_sellback',
        'bot_category': 'ladder_arb',
    }, bot)

    bot_log('APEX_SELLBACK_COMPLETE', bot_id, {
        'avg_anchor': avg_anchor, 'sell_price': sell_price,
        'loss_cents': loss_cents, 'profit_cents': profit_cents,
        'sell_qty': sell_qty, 'hedge_filled': hedge_filled,
    })
    print(f'🔙 APEX SELLBACK FILLED: {bot_id} sold {sell_qty}×{anchor_side}@{sell_price}¢ '
          f'(avg_anchor={avg_anchor}¢) loss={loss_cents}¢ profit={profit_cents}¢')
    _audit('APEX_SELLBACK_COMPLETE', bot_id, {'ticker': ticker, 'sell_price': sell_price, 'qty': sell_qty})
    _audit_position_check(bot_id, ticker, anchor_side, 'after_apex_sellback')

    # Repeat support: sell-back counts as a cycle, continue if repeats remain
    repeats_done_now = bot.get('repeats_done', 0) + 1
    bot['repeats_done'] = repeats_done_now
    repeat_total = bot.get('repeat_count', 0)
    if repeats_done_now <= repeat_total:
        bot['status'] = 'waiting_repeat'
        bot['waiting_repeat_since'] = now
        bot['_trade_recorded'] = False
        bot['_apex_sellback_attempted'] = False
        bot['_consolidated'] = False
        bot['_bot_completed'] = False
        bot['_ws_fill_handling'] = False
        bot['_hedge_verified'] = False
        bot['hedge_order_id'] = None
        bot['hedge_price'] = 0
        bot['hedge_qty'] = 0
        bot['_hedge_fill_count'] = 0
        bot['_sellback_order_id'] = None
        bot['hedge_history'] = []
        bot['_all_hedge_order_ids'] = []
        bot['_all_placed_order_ids'] = []
        bot['cumulative_pnl'] = 0
        bot['completed_rungs_count'] = 0
        bot['walk_count'] = 0
        bot['first_fill_at'] = None
        bot['first_fill_side'] = None
        bot['lifetime_pnl'] = bot.get('lifetime_pnl', 0) + (profit_cents - loss_cents)
        for rung in bot.get('rungs', []):
            rung['completed'] = False
            rung['_profit_recorded'] = False
            rung['yes_fill_qty'] = 0
            rung['no_fill_qty'] = 0
            rung['yes_filled_at'] = None
            rung['no_filled_at'] = None
            rung['yes_order_id'] = None
            rung['no_order_id'] = None
        print(f'🔄 APEX SELLBACK REPEAT: {bot_id} cycle {repeats_done_now}/{repeat_total} — re-entering')
        bot_log('APEX_SELLBACK_REPEAT', bot_id, {'cycle': repeats_done_now, 'total': repeat_total})
    else:
        bot['status'] = 'stopped'
        bot['stopped_at'] = now
    save_state()
    actions.append({'bot_id': bot_id, 'action': 'apex_sellback', 'loss_cents': loss_cents, 'profit_cents': profit_cents})


# ─── Width-Based Quantity Scaling ────────────────────────────────────────────
# When deploying multiple widths (ladder-arb), wider spreads are rarer but more
# profitable — scale up contract size on wider rungs automatically.
WIDTH_QTY_TIERS = [
    (13, 3.0),   # 13-16¢: 3× base
    (9,  2.0),   # 9-12¢:  2× base
    (1,  1.0),   # 5-8¢:   1× base (fallback)
]

def _width_qty_multiplier(width: int) -> float:
    for threshold, mult in WIDTH_QTY_TIERS:
        if width >= threshold:
            return mult
    return 1.0

def _scale_qty_for_width(base_qty: int, width: int) -> int:
    """Apply width tier multiplier to base quantity (floor, min 1)."""
    return max(1, int(base_qty * _width_qty_multiplier(width)))


# ─── Data Migrations ─────────────────────────────────────────────────────────
# To modify trade_history data permanently, add a migration function below.
# Each migration runs ONCE after load_state(), modifies trade_history in memory,
# then save_state() persists the changes. The migration name is recorded in
# applied_migrations so it never re-runs.
#
# HOW TO ADD A NEW MIGRATION:
#   1. Write a function: def _migrate_NNN_description():
#      - It can read/modify the global trade_history list directly
#      - Print what it did
#   2. Add an entry to the MIGRATIONS list: ('NNN_description', _migrate_NNN_description)
#   3. Restart the server — it runs automatically
#
# The server must be restarted for migrations to apply. They run in order.
# ─────────────────────────────────────────────────────────────────────────────

def _migrate_001_recalc_fees():
    """Recalculate fee_cents on all historical trades using correct Kalshi maker formula.
    Also adjusts profit_cents/loss_cents to include fees."""
    global trade_history
    updated = 0
    for t in trade_history:
        yes_p = t.get('yes_price') or t.get('yes_fill_price')
        no_p = t.get('no_price') or t.get('no_fill_price')
        qty = t.get('quantity') or t.get('contracts') or 100
        if not yes_p or not no_p:
            continue
        yes_p = int(yes_p)
        no_p = int(no_p)
        qty = int(qty)
        fee = kalshi_fee_cents(yes_p, no_p, qty)
        old_fee = t.get('fee_cents', 0) or 0
        if old_fee == fee:
            continue  # already correct
        # Undo old fee from profit/loss, apply new fee
        if 'profit_cents' in t:
            t['profit_cents'] = int(t['profit_cents']) + int(old_fee) - fee
        if 'loss_cents' in t and int(t.get('loss_cents', 0)) > 0:
            t['loss_cents'] = int(t['loss_cents']) - int(old_fee) + fee
        t['fee_cents'] = fee
        updated += 1
    print(f'📊 Migration 001: recalculated fees on {updated} trades')

def _migrate_002_remove_mar12():
    """Remove all March 12 trades — they're from the old timeout-sell system
    before the amend system was implemented. Data is inaccurate."""
    global trade_history, pnl_resets
    before = len(trade_history)
    trade_history = [t for t in trade_history
                     if datetime.fromtimestamp(t.get('timestamp', 0)).strftime('%Y-%m-%d') != '2026-03-12']
    removed = before - len(trade_history)
    pnl_resets.pop('2026-03-12', None)
    print(f'📊 Migration 002: removed {removed} Mar 12 trades (old system), cleared Mar 12 reset')

def _migrate_003_reclean_mar12():
    """Re-delete Mar 12 trades that got restored from trades.jsonl.
    Migration 002 only cleaned data.json, not trades.jsonl, so restarts re-added them."""
    global trade_history, pnl_resets
    before = len(trade_history)
    trade_history = [t for t in trade_history
                     if datetime.fromtimestamp(t.get('timestamp', 0)).strftime('%Y-%m-%d') != '2026-03-12']
    removed = before - len(trade_history)
    pnl_resets.pop('2026-03-12', None)
    print(f'📊 Migration 003: re-cleaned {removed} Mar 12 trades (were restored from trades.jsonl)')

def _migrate_004_fix_completed_labels():
    """Fix trades labeled 'completed' that actually lost money.
    A true completed arb (both legs filled < 100c) always profits.
    If profit < 0 or loss > 0, it was amended/timed out, not completed."""
    global trade_history
    fixed = 0
    for t in trade_history:
        if t.get('result') != 'completed':
            continue
        p = t.get('profit_cents', 0) or 0
        l = t.get('loss_cents', 0) or 0
        if p >= 0 and l <= 0:
            continue  # genuinely completed
        # Determine correct label based on exit_via
        exit_via = t.get('exit_via', '')
        if exit_via == 'timeout_amend' or exit_via == 'cancel_amend':
            t['result'] = 'amended'
        elif p < 0:
            # Negative profit, no exit_via — was amended but not tagged
            t['result'] = 'amended'
            # Normalize: move negative profit into loss_cents
            t['loss_cents'] = abs(p)
            t['profit_cents'] = 0
        elif l > 0:
            # Has loss_cents on a "completed" — was amended
            t['result'] = 'amended'
        fixed += 1
    print(f'📊 Migration 004: relabeled {fixed} mislabeled "completed" trades → "amended"')

def _migrate_005_fix_rebalancer_pnl():
    """Fix rebalancer_scrape and rebalancer_enhance trades with missing/incorrect P&L fields."""
    global trade_history
    fixed = 0
    for t in trade_history:
        if t.get('result') == 'rebalancer_scrape':
            loss = t.get('loss_cents', 0) or 0
            if loss < 0:
                # Was profitable but stored as negative loss
                t['profit_cents'] = abs(loss)
                t['loss_cents'] = 0
                fixed += 1
            elif 'profit_cents' not in t:
                t['profit_cents'] = 0
                fixed += 1
        elif t.get('result') == 'rebalancer_enhance':
            recovery = t.get('recovery_cents', 0) or 0
            if 'profit_cents' not in t:
                t['profit_cents'] = recovery
                t['loss_cents'] = 0
                fixed += 1
    print(f'📊 Migration 005: fixed P&L on {fixed} rebalancer trades')

# Master migration list — add new migrations at the bottom
def _migrate_006_dedup_rung_trades():
    """Remove duplicate rung completion trades caused by race condition.
    _check_apex_rung_completions was called from 3 places, recording the same
    rung twice before _profit_recorded flag was saved. Dedup by (bot_id, prices, qty, result, exit_via)."""
    global trade_history
    from collections import defaultdict
    before = len(trade_history)
    by_bot = defaultdict(list)
    for t in trade_history:
        by_bot[t.get('bot_id', 'unknown')].append(t)
    cleaned = []
    for bot_id, bt in by_bot.items():
        bt.sort(key=lambda x: x.get('timestamp', 0))
        seen = set()
        for t in bt:
            key = (t.get('yes_price'), t.get('no_price'), t.get('quantity'),
                   t.get('result'), t.get('exit_via'))
            if key in seen:
                continue
            seen.add(key)
            cleaned.append(t)
    cleaned.sort(key=lambda t: t.get('timestamp', 0), reverse=True)
    trade_history = cleaned
    removed = before - len(trade_history)
    print(f'📊 Migration 006: removed {removed} duplicate rung trades ({before} → {len(trade_history)})')

MIGRATIONS = [
    ('001_recalc_fees', _migrate_001_recalc_fees),
    ('002_remove_mar12', _migrate_002_remove_mar12),
    ('003_reclean_mar12', _migrate_003_reclean_mar12),
    ('004_fix_completed_labels', _migrate_004_fix_completed_labels),
    ('005_fix_rebalancer_pnl', _migrate_005_fix_rebalancer_pnl),
    ('006_dedup_rung_trades', _migrate_006_dedup_rung_trades),
]

def run_migrations():
    """Run any pending data migrations after load_state(). Saves once if any ran."""
    global applied_migrations
    ran = 0
    for name, func in MIGRATIONS:
        if name in applied_migrations:
            continue
        print(f'🔄 Running migration: {name}')
        try:
            func()
            applied_migrations.append(name)
            ran += 1
        except Exception as e:
            print(f'❌ Migration {name} failed: {e}')
            break  # stop on failure — don't skip
    if ran:
        save_state()
        # Also rewrite trades.jsonl so deleted trades don't come back on restart
        try:
            with open(TRADES_FILE, 'w') as _tf:
                for t in trade_history[:2000]:
                    _tf.write(json.dumps(t, default=str) + '\n')
            print(f'📝 trades.jsonl rewritten after migrations ({len(trade_history)} trades)')
        except Exception as _je:
            print(f'⚠ trades.jsonl rewrite failed: {_je}')
        print(f'✅ {ran} migration(s) applied and saved')
    else:
        print('✅ No pending migrations')


def save_state():
    """Persist active_bots and trade_history to disk so they survive restarts.
    Uses atomic write (temp → rename) so a crash mid-write never corrupts data.json."""
    with _save_lock:
        try:
            tmp = DATA_FILE + '.tmp'
            with open(tmp, 'w') as f:
                json.dump({
                    'active_bots': active_bots,
                    'trade_history': trade_history[:2000],
                    'session_pnl': session_pnl,
                    'opening_lines': _opening_lines,
                    'pnl_resets': pnl_resets,
                    'applied_migrations': applied_migrations,
                }, f, indent=2, default=str)
            os.replace(tmp, DATA_FILE)  # atomic — no partial-write corruption
        except Exception as e:
            print(f'⚠ save_state: {e}')

BACKUP_FILE = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'data_backup.json')

def load_state():
    """Load persisted bots and history from disk.
    Also merges trades.jsonl to recover any trades recorded after the last save_state()."""
    global active_bots, trade_history, session_pnl, _opening_lines, pnl_resets, applied_migrations
    try:
        if os.path.exists(DATA_FILE):
            with open(DATA_FILE, 'r') as f:
                data = json.load(f)
            active_bots = data.get('active_bots', {})
            trade_history = data.get('trade_history', [])
            _opening_lines = data.get('opening_lines', {})
            applied_migrations = data.get('applied_migrations', [])
            # Load per-day resets (or migrate from legacy single float)
            saved_resets = data.get('pnl_resets')
            if isinstance(saved_resets, dict):
                pnl_resets = saved_resets
            else:
                # Legacy: single pnl_reset_since float
                old_val = float(data.get('pnl_reset_since', 0))
                if old_val > 0:
                    from datetime import datetime as _dt
                    old_day = _dt.fromtimestamp(old_val).date().isoformat()
                    pnl_resets = {old_day: old_val}
                else:
                    pnl_resets = {}
            saved = data.get('session_pnl')
            if saved:
                for k in ('gross_profit_cents','gross_loss_cents','completed_bots','stopped_bots'):
                    if k in saved:
                        session_pnl[k] = saved[k]
            print(f'✅ Loaded: {len(active_bots)} bots, {len(trade_history)} history, {len(_opening_lines)} opening lines, resets={pnl_resets}')
            # Clear transient runtime flags that should never persist across restarts.
            # _completion_in_progress is set during the multi-phase apex completion flow
            # and cleared in a finally block — but if the server restarts mid-completion,
            # the flag stays True in data.json and permanently blocks re-entry.
            _transient_cleared = 0
            for _bid, _bot in active_bots.items():
                # Clear ALL transient thread flags — threads are dead after restart
                _any_cleared = False
                for _flag in ('_completion_in_progress', '_ws_fill_handling', '_bot_completed',
                              '_completion_repeat_processed', '_sweep_thread_running'):
                    if _bot.get(_flag):
                        _bot[_flag] = False
                        _any_cleared = True
                if _any_cleared:
                    _transient_cleared += 1
                    print(f'🔧 STARTUP FIX: {_bid[:40]} cleared stuck thread flags')
            if _transient_cleared:
                print(f'🔧 Cleared {_transient_cleared} stuck transient flags on startup')
            # Write a backup on startup so we can always recover
            if trade_history:
                try:
                    import shutil
                    shutil.copy2(DATA_FILE, BACKUP_FILE)
                    print(f'📦 Backup written: {len(trade_history)} trades')
                except Exception as be:
                    print(f'⚠ backup: {be}')
    except Exception as e:
        print(f'⚠ load_state: {e}')

    # ── Merge trades.jsonl: recover trades written after last save_state ──
    if os.path.exists(TRADES_FILE):
        try:
            existing_ids = set()
            for t in trade_history:
                tid = t.get('_trade_id') or f"{t.get('timestamp',0)}_{t.get('bot_id','')}"
                existing_ids.add(tid)
            recovered = 0
            with open(TRADES_FILE, 'r') as _tf:
                for line in _tf:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        t = json.loads(line)
                        tid = t.get('_trade_id') or f"{t.get('timestamp',0)}_{t.get('bot_id','')}"
                        if tid not in existing_ids:
                            trade_history.append(t)
                            existing_ids.add(tid)
                            recovered += 1
                    except Exception:
                        pass
            if recovered:
                trade_history.sort(key=lambda t: t.get('timestamp', 0), reverse=True)
                print(f'🔁 Recovered {recovered} trades from trades.jsonl (were missing from data.json)')
            # Rewrite trades.jsonl from the merged list to prune duplicates/old entries
            with open(TRADES_FILE, 'w') as _tf:
                for t in trade_history[:2000]:
                    _tf.write(json.dumps(t, default=str) + '\n')
        except Exception as _jle:
            print(f'⚠ trades.jsonl merge failed: {_jle}')

    # ── Deduplicate: remove duplicate trades for the same bot_id within 60s ──
    # Multiple paths (WS handler, monitor REST, monitor timeout amend) can record
    # the same arb completion. Keep the FIRST entry (earliest timestamp) per bot_id
    # within any 60-second window, remove all others.
    # Also convert legacy 'timeout_exit_*' results to 'completed' since amend
    # completes the arb — the old result type is vestigial.
    _seen_bots = {}  # bot_id → timestamp of kept entry
    _remove_idx = set()
    for i, t in enumerate(trade_history):
        bid = t.get('bot_id', '')
        ts = t.get('timestamp', 0)
        if not bid:
            continue
        # Convert legacy timeout_exit_* to completed
        if t.get('result', '').startswith('timeout_exit'):
            t['result'] = 'completed'
            if not t.get('exit_via'):
                t['exit_via'] = 'timeout_amend'
        # Rung completions are separate trades per rung — never dedup them
        if t.get('exit_via') == 'ladder_arb_rung_complete':
            continue
        if bid in _seen_bots and abs(ts - _seen_bots[bid]) < 60:
            _remove_idx.add(i)
        else:
            _seen_bots[bid] = ts
    if _remove_idx:
        trade_history = [t for i, t in enumerate(trade_history) if i not in _remove_idx]
        print(f'🧹 Deduped: removed {len(_remove_idx)} duplicate trade entries')
        save_state()  # persist cleaned data immediately

# ─── Rate Limiter (Upgrade #7: API rate limit guard) ──────────────────────────
class RateLimiter:
    """Burst rate limiter — fires up to `burst` requests instantly within a
    1-second window, then hard-blocks until the next window starts.
    No delay between requests within the burst (preserves 1ms latency).
    Reserves 2 tokens for priority hedge operations so they never queue."""
    RESERVED_HEDGE_TOKENS = 2  # always keep 2 slots free for hedges

    def __init__(self, burst: int = 10):
        self.burst = burst
        self._count = 0
        self._window_start = time.time()
        self._lock = threading.Lock()

    def wait(self, priority=False):
        while True:
            with self._lock:
                now = time.time()
                elapsed = now - self._window_start
                if elapsed >= 1.0:
                    # New window — reset counter
                    self._window_start = now
                    self._count = 1
                    return
                # Priority (hedge) calls can use the full burst including reserved tokens
                effective_burst = self.burst if priority else (self.burst - self.RESERVED_HEDGE_TOKENS)
                if self._count < effective_burst:
                    self._count += 1
                    return
                # Burst exhausted — compute sleep, release lock FIRST
                sleep_time = 1.0 - elapsed
            # Sleep OUTSIDE the lock so priority callers aren't blocked
            time.sleep(sleep_time)

api_rate_limiter = RateLimiter(burst=10)  # Kalshi basic tier: 10 writes/s burst
api_read_limiter = RateLimiter(burst=15)  # Kalshi basic tier: 20 reads/s (keep 5 headroom)

# ─── WebSocket Manager: real-time price/fill/order monitoring ─────────────────
import websocket as _ws_lib

class KalshiWSManager:
    """
    Manages a single authenticated WebSocket connection to Kalshi.
    Subscribes to orderbook_delta, ticker, fill, and user_orders channels
    for the tickers that active bots care about.

    Keeps a local price cache so the monitor loop can read prices instantly
    instead of making REST calls.
    """

    def __init__(self):
        self._ws = None
        self._thread = None
        self._connected = False
        self._cmd_id = 0
        self._lock = threading.Lock()

        # Local caches updated by WS messages
        self.ticker_cache = {}    # {market_ticker: {yes_bid, yes_ask, no_bid, no_ask, ...}}
        self.fill_events = []     # Recent fill events (capped at 200)
        self.order_events = []    # Recent user_order events (capped at 200)
        self._subscribed_tickers = set()
        self._sids = {}           # {channel: sid}

        # Balance / portfolio cache — updated by WS messages AND a background REST poll
        self.balance_cache = {
            'balance_cents': 0,
            'portfolio_value_cents': 0,
            'positions': {},   # {ticker: {'yes': qty, 'no': qty, 'value_cents': v}}
            'ts': 0,           # last update timestamp
        }
        self._balance_poll_started = False

    @property
    def connected(self):
        return self._connected and self._ws is not None

    def _next_id(self):
        self._cmd_id += 1
        return self._cmd_id

    # ── Connect ──────────────────────────────────────────────────
    def connect(self, kalshi_api):
        """Open WS connection using credentials from the KalshiAPI instance."""
        if self._connected:
            return
        self._api = kalshi_api
        url = kalshi_api.ws_url
        headers = kalshi_api.ws_auth_headers()
        # websocket-client expects header list ["Key: Value", ...]
        header_list = [f'{k}: {v}' for k, v in headers.items()]

        def on_open(ws):
            self._connected = True
            print('🔌 Kalshi WS connected')
            # Subscribe to portfolio channel for live balance/position updates
            threading.Timer(0.5, self._subscribe_portfolio).start()

        def on_message(ws, message):
            try:
                data = json.loads(message)
                self._handle_message(data)
            except Exception as e:
                print(f'⚠ WS message parse error: {e}')

        def on_error(ws, error):
            print(f'⚠ Kalshi WS error: {error}')
            # Mark disconnected so auto-reconnect can fire from on_close
            self._connected = False

        def on_close(ws, close_status_code, close_msg):
            self._connected = False
            self._sids = {}  # Clear stale subscription IDs so re-subscribe sends fresh commands
            # Save tickers before clearing so reconnect can resubscribe
            self._reconnect_tickers = set(self._subscribed_tickers)
            self._subscribed_tickers = set()  # Clear so subscribe() treats them as new
            print(f'🔌 Kalshi WS closed: {close_status_code} {close_msg}')
            # Auto-reconnect after 5 seconds
            threading.Timer(5.0, lambda: self._auto_reconnect(kalshi_api)).start()

        try:
            self._ws = _ws_lib.WebSocketApp(
                url,
                header=header_list,
                on_open=on_open,
                on_message=on_message,
                on_error=on_error,
                on_close=on_close,
            )
            self._thread = threading.Thread(
                target=self._ws.run_forever,
                kwargs={'ping_interval': 10, 'ping_timeout': 5,
                        'ping_payload': 'heartbeat'},
                daemon=True,
            )
            self._thread.start()
        except Exception as e:
            print(f'❌ WS connect failed: {e}')

    def _auto_reconnect(self, kalshi_api):
        """Try to reconnect after a disconnect."""
        if self._connected:
            return
        print('🔄 WS auto-reconnect...')
        try:
            self.connect(kalshi_api)
            # Re-subscribe after reconnect using tickers saved before close cleared them
            time.sleep(1)
            reconnect_tickers = getattr(self, '_reconnect_tickers', set())
            if reconnect_tickers:
                self.subscribe(list(reconnect_tickers))
            threading.Timer(1.0, self._subscribe_portfolio).start()
        except Exception as e:
            print(f'❌ WS reconnect failed: {e}')

    def _subscribe_portfolio(self):
        """No-op: Kalshi WS doesn't support a 'balance' channel (returns error 8).
        Balance updates are handled by start_balance_poll() via REST instead."""
        pass

    def start_balance_poll(self, kalshi_api_client):
        """Start a background thread that polls balance + positions every 15s via REST.
        This serves as fallback when the WS balance channel isn't available."""
        if self._balance_poll_started:
            return  # don't start a second poller
        self._balance_poll_started = True

        def _poller():
            while True:
                try:
                    b = kalshi_api_client.get_balance()
                    self.balance_cache['balance_cents'] = b.get('balance', 0)
                    self.balance_cache['portfolio_value_cents'] = b.get('portfolio_value', 0)
                    # Positions
                    p = kalshi_api_client.get_positions()
                    pos_list = p.get('market_positions', p.get('positions', []))
                    pos_map = {}
                    for pos in pos_list:
                        t = pos.get('ticker', '')
                        qty = _parse_position_qty(pos)
                        val = pos.get('market_exposure', pos.get('value', 0))
                        pos_map[t] = {
                            'yes': max(0, qty),
                            'no':  max(0, -qty),
                            'value_cents': val,
                        }
                    self.balance_cache['positions'] = pos_map
                    self.balance_cache['ts'] = time.time()
                except Exception as _pe:
                    pass  # silent — don't spam logs
                time.sleep(15)
        t = threading.Thread(target=_poller, daemon=True, name='balance-poll')
        t.start()

    def disconnect(self):
        """Close the WS connection."""
        if self._ws:
            try:
                self._ws.close()
            except Exception:
                pass
        self._connected = False
        self._ws = None

    # ── Subscribe / Unsubscribe ────────────────────────────────
    def subscribe(self, tickers):
        """Subscribe to ticker, fill, and user_orders channels for given market tickers."""
        if not self._connected or not self._ws:
            return
        tickers = [t for t in tickers if t]
        if not tickers:
            return
        new_tickers = [t for t in tickers if t not in self._subscribed_tickers]
        if not new_tickers and self._sids:
            return  # Already subscribed

        with self._lock:
            # Market-data channels (need market_tickers)
            for channel in ['ticker']:
                cmd = {
                    'id': self._next_id(),
                    'cmd': 'subscribe',
                    'params': {
                        'channels': [channel],
                        'market_tickers': new_tickers,
                    }
                }
                self._ws.send(json.dumps(cmd))

            # Private channels — fill and user_orders for these tickers
            for channel in ['fill', 'user_orders']:
                cmd = {
                    'id': self._next_id(),
                    'cmd': 'subscribe',
                    'params': {
                        'channels': [channel],
                        'market_tickers': new_tickers,
                    }
                }
                self._ws.send(json.dumps(cmd))

            self._subscribed_tickers.update(new_tickers)
            print(f'📡 WS subscribed to {len(new_tickers)} tickers: {new_tickers[:5]}...')

    def add_ticker(self, ticker):
        """Add a single ticker to existing subscriptions (or start fresh)."""
        if ticker in self._subscribed_tickers:
            return
        if not self._sids:
            # No existing subs — do a fresh subscribe
            self.subscribe([ticker])
            return
        # Use update_subscription to add to existing sids
        with self._lock:
            for channel, sid in self._sids.items():
                if channel in ('ticker', 'fill', 'user_orders'):
                    cmd = {
                        'id': self._next_id(),
                        'cmd': 'update_subscription',
                        'params': {
                            'sids': [sid],
                            'market_tickers': [ticker],
                            'action': 'add_markets',
                        }
                    }
                    self._ws.send(json.dumps(cmd))
            self._subscribed_tickers.add(ticker)

    # ── Message handler ──────────────────────────────────────
    def _handle_message(self, data):
        msg_type = data.get('type', '')
        msg = data.get('msg', {})

        if msg_type == 'subscribed':
            channel = msg.get('channel', '')
            sid = data.get('msg', {}).get('sid') or data.get('sid')
            if sid and channel:
                self._sids[channel] = sid
            return

        if msg_type == 'ticker':
            ticker = msg.get('market_ticker', '')
            if ticker:
                def _ws_cents(field):
                    # Handle new FP format (yes_bid_dollars="0.59") and old int cents (yes_bid=59)
                    d = msg.get(field + '_dollars')
                    if d is not None:
                        return int(round(float(d) * 100))
                    v = msg.get(field, 0)
                    return int(v) if v else 0
                yb = _ws_cents('yes_bid')
                ya = _ws_cents('yes_ask')
                nb = _ws_cents('no_bid')
                na = _ws_cents('no_ask')
                # Market identity: YES ask + NO bid = 100, YES bid + NO ask = 100.
                # Kalshi WS only sends yes_bid / yes_ask — derive the NO side (and fill
                # in any missing ask when only the opposite bid is available).
                if nb == 0 and ya > 0: nb = 100 - ya
                if ya == 0 and nb > 0: ya = 100 - nb
                if na == 0 and yb > 0: na = 100 - yb
                if yb == 0 and na > 0: yb = 100 - na
                self.ticker_cache[ticker] = {
                    'yes_bid': yb,
                    'yes_ask': ya,
                    'no_bid':  nb,
                    'no_ask':  na,
                    'price': msg.get('price', 0),
                    'volume': msg.get('volume', 0),
                    'ts': msg.get('ts', 0),
                    '_local_ts': time.time(),
                }
                # ── Real-time flip threshold check on every WS tick ──
                try:
                    yes_bid_rt = yb
                    no_bid_rt  = nb if nb > 0 else ((100 - ya) if ya > 0 else 0)
                    _ws_realtime_flip_check(ticker, yes_bid_rt, no_bid_rt)
                except Exception as flip_err:
                    print(f'⚠ WS real-time flip check error: {flip_err}')
                # ── Real-time phantom drop: if hedge is above bid, drop instantly ──
                # Run in background thread — MUST NOT block WS handler (kills hedge latency)
                try:
                    threading.Thread(target=_ws_phantom_instant_drop, args=(ticker, yb, nb, ya, na), daemon=True).start()
                except Exception as _pd_err:
                    pass  # don't spam logs on every tick
            return

        if msg_type == 'fill':
            self.fill_events.insert(0, msg)
            if len(self.fill_events) > 200:
                self.fill_events = self.fill_events[:200]
            ticker = msg.get('market_ticker', '')
            order_id = msg.get('order_id', '')
            side = msg.get('side', '')
            # Kalshi WS may send count_fp (string) or count (int)
            _c = msg.get('count_fp') or msg.get('count') or 0
            count = int(float(_c)) if _c else 0
            print(f'💰 WS FILL: {side} {count}x {ticker} (order {order_id[:8]}...)')
            # ── Real-time fill handling: update bot fill counts + trigger actions ──
            try:
                _ws_realtime_fill_handler(ticker, order_id, side, count)
            except Exception as fh_err:
                print(f'⚠ WS real-time fill handler error: {fh_err}')
            return

        if msg_type == 'user_order':
            self.order_events.insert(0, msg)
            if len(self.order_events) > 200:
                self.order_events = self.order_events[:200]
            return

        if msg_type == 'balance':
            # Kalshi WS balance update — msg contains 'balance' and optionally 'portfolio_value'
            b = msg.get('balance', msg.get('balance_cents'))
            pv = msg.get('portfolio_value', msg.get('portfolio_value_cents'))
            if b is not None:
                self.balance_cache['balance_cents'] = int(b)
            if pv is not None:
                self.balance_cache['portfolio_value_cents'] = int(pv)
            self.balance_cache['ts'] = time.time()
            return

        if msg_type == 'error':
            code = msg.get('code', '?')
            emsg = msg.get('msg', '')
            print(f'⚠ WS error [{code}]: {emsg}')
            return

    # ── Price lookups ───────────────────────────────────────────
    def get_price(self, ticker, max_age_s=60):
        """Get cached price data for a ticker. Returns None if not cached or stale (>max_age_s)."""
        entry = self.ticker_cache.get(ticker)
        if entry and max_age_s > 0:
            cache_age = time.time() - entry.get('_local_ts', 0)
            if cache_age > max_age_s:
                return None  # stale — force REST fallback
        return entry

    def get_fills_for_order(self, order_id):
        """Get all WS fill events for a given order_id."""
        return [f for f in self.fill_events if f.get('order_id') == order_id]

    def get_total_fills(self, order_id):
        """Sum up fill counts for an order_id from WS events."""
        return sum(f.get('count', 0) for f in self.fill_events if f.get('order_id') == order_id)


# Global WS manager instance
ws_manager = KalshiWSManager()

# ─── Monitor lock: prevent concurrent monitor calls from double-executing ─────
monitor_lock = threading.Lock()

# ─── WS Flip lock: prevent WS real-time flip and monitor from double-firing ───
ws_flip_lock = threading.Lock()


def _ws_realtime_flip_check(ticker, yes_bid, no_bid):
    """
    No-op stub — flip logic removed in simultaneous dual-order architecture.
    5/8-minute timeout is handled by the monitor loop instead.
    Kept for signature compatibility.
    """
    return


# Lock to prevent concurrent phantom drop amends
_phantom_drop_lock = threading.Lock()

def _ws_phantom_instant_drop(ticker, yes_bid, no_bid, yes_ask, no_ask):
    """Instant drop: if any phantom bot's hedge is above the fav bid, amend down immediately.
    Called on every WS price tick — must be fast. Only acts when price > bid (overpaying)."""
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') not in ('anchor_dog', 'anchor_ladder'):
            continue
        if bot.get('status') != 'fav_hedge_posted':
            continue
        # Match ticker (same-market or cross-market hedge)
        hedge_ticker = bot.get('hedge_ticker', bot.get('ticker', ''))
        if hedge_ticker != ticker and bot.get('ticker') != ticker:
            continue

        fav_side = bot.get('fav_side', '')
        fav_price = bot.get('fav_price') or 0
        if fav_price <= 0 or not fav_side:
            continue

        # Get current bid for fav side from this WS tick
        fav_bid = (yes_bid if fav_side == 'yes' else no_bid) if hedge_ticker == ticker else 0
        if fav_bid <= 0:
            continue

        # Only drop if hedge is ABOVE bid (overpaying)
        if fav_price <= fav_bid:
            continue

        # Calculate drop target (same logic as monitor: bid or bid+1 in gap)
        fav_ask_now = yes_ask if fav_side == 'yes' else no_ask
        fav_spread = (fav_ask_now - fav_bid) if fav_ask_now > fav_bid else 1
        if fav_spread >= 2 and fav_ask_now > fav_bid:
            drop_target = min(fav_bid + 1, fav_ask_now - 1)
        else:
            drop_target = fav_bid

        # Cap at ceiling
        dog_price = bot.get('dog_price') or bot.get('avg_fill_price') or 0
        if dog_price > 0:
            max_fav = bot.get('fav_walk_ceiling', HARD_CEILING_CENTS) - dog_price
            drop_target = min(drop_target, max_fav)

        if drop_target <= 0 or drop_target >= fav_price:
            continue

        # Acquire lock — only one amend at a time (prevents race with monitor walk)
        if not _phantom_drop_lock.acquire(blocking=False):
            return  # another drop or walk in progress

        try:
            # Re-read fav_order_id AFTER acquiring lock (monitor may have updated it)
            fav_oid = bot.get('fav_order_id')
            if not fav_oid:
                continue
            amend_kwargs = {f'{fav_side}_price': drop_target}
            api_rate_limiter.wait()
            _amend_resp = kalshi_client.amend_order(fav_oid, ticker=hedge_ticker, side=fav_side,
                                      count=bot.get('hedge_qty', bot.get('quantity', 1)),
                                      **amend_kwargs)
            # Capture new order ID if Kalshi reassigned (amend = cancel+repost internally)
            _amend_order = _amend_resp.get('order', _amend_resp) if isinstance(_amend_resp, dict) else {}
            _new_oid = _amend_order.get('order_id', '')
            if _new_oid and _new_oid != fav_oid:
                bot['fav_order_id'] = _new_oid
                if fav_side == 'yes':
                    bot['yes_order_id'] = _new_oid
                else:
                    bot['no_order_id'] = _new_oid
            bot['fav_price'] = drop_target
            if fav_side == 'yes':
                bot['yes_price'] = drop_target
            else:
                bot['no_price'] = drop_target
            bot['fav_last_walk_at'] = time.time()
            bot['fav_walk_count'] = bot.get('fav_walk_count', 0) + 1
            print(f'⚡ WS PHANTOM DROP: {bot_id} fav {fav_price}→{drop_target}¢ (bid={fav_bid}¢)')
            bot_log('PHANTOM_WS_INSTANT_DROP', bot_id, {
                'old_price': fav_price, 'new_price': drop_target,
                'fav_bid': fav_bid, 'fav_ask': fav_ask_now,
            })
            save_state()
        except Exception as e:
            if '404' not in str(e):
                print(f'⚠ WS PHANTOM DROP FAIL: {bot_id}: {e}')
        finally:
            _phantom_drop_lock.release()
        return  # one drop per tick max


def _execute_ws_flip(bot_id, filled_side, entry_price, trigger_bid, flip_thresh, filled_qty, floor=None):
    """
    No-op stub — flip logic removed in simultaneous dual-order architecture.
    5/8-minute timeout is handled by the monitor loop instead.
    Kept for signature compatibility.
    """
    pass


# ─── WS Fill Lock: prevent WS fill handler and monitor from double-acting ─────
ws_fill_lock = threading.Lock()
# ─── Late Anchor Amend Lock: serialize late anchor amend API calls ────────────
# Prevents race where multiple WS fill threads read stale hedge_qty/hedge_price
# and overwrite each other's walk_offset calculations.
_late_anchor_amend_lock = threading.Lock()

# ─── Phantom Hedge Worker: pre-spawned thread for instant hedge placement ─────
# Eliminates ~8ms thread spawn overhead. WS handler pushes jobs, worker executes
# instantly. The #1 speed priority in the entire app.
import queue as _queue_mod
_hedge_worker_queue = _queue_mod.Queue()

def _hedge_worker_loop():
    """Dedicated worker thread — always alive, waiting for hedge jobs."""
    while True:
        try:
            job = _hedge_worker_queue.get()
            if job is None:
                break
            fn, args = job
            fn(*args)
        except Exception as e:
            print(f'⚠ HEDGE WORKER ERROR: {e}')

_hedge_worker_thread = threading.Thread(target=_hedge_worker_loop, daemon=True)
_hedge_worker_thread.start()

# ─── Pending WS actions: queued by WS handler, drained by monitor into response ─
# This ensures the frontend sees 'completed' / 'timeout_exit' actions even when
# the WS handler wins the race against the REST monitor loop.
_pending_ws_actions = []
_pending_ws_actions_lock = threading.Lock()


def _ws_realtime_fill_handler(ticker, order_id, side, count):
    """
    Real-time fill handler triggered directly from the WebSocket fill event.
    Matches the fill to an active bot and:
      1. Updates fill counts immediately
      2. If fav leg just completed → posts dog leg instantly
      3. If both legs now filled → marks completed instantly

    Actions are dispatched to background threads so the WS handler doesn't block.
    """
    if not active_bots or not kalshi_client:
        return

    for bot_id, bot in list(active_bots.items()):
        if bot.get('ticker') != ticker:
            continue
        if bot.get('type') == 'watch':
            continue
        status = bot.get('status', '')
        if status in ('stopped', 'completed'):
            continue

        # Match fill to this bot's order IDs
        matched_leg = None  # 'yes' or 'no'
        if order_id == bot.get('yes_order_id') or (order_id == bot.get('fav_order_id') and bot.get('fav_side') == 'yes'):
            matched_leg = 'yes'
        elif order_id == bot.get('no_order_id') or (order_id == bot.get('fav_order_id') and bot.get('fav_side') == 'no'):
            matched_leg = 'no'

        if not matched_leg:
            continue

        qty = bot['quantity']

        # Update fill counts — accumulate (WS sends incremental fills)
        if matched_leg == 'yes':
            bot['yes_fill_qty'] = bot.get('yes_fill_qty', 0) + count
            yes_filled = bot['yes_fill_qty']
            no_filled = bot.get('no_fill_qty', 0)
        else:
            bot['no_fill_qty'] = bot.get('no_fill_qty', 0) + count
            no_filled = bot['no_fill_qty']
            yes_filled = bot.get('yes_fill_qty', 0)

        print(f'⚡ WS FILL UPDATE: {bot_id} {matched_leg.upper()} +{count} '
              f'→ YES={yes_filled}/{qty} NO={no_filled}/{qty}')

        # ── Both legs fully filled → instant completion ──
        if yes_filled >= qty and no_filled >= qty:
            if bot.get('_ws_fill_handling'):
                continue
            bot['_ws_fill_handling'] = True
            print(f'⚡ WS INSTANT COMPLETE: {bot_id} — both legs filled!')
            threading.Thread(
                target=_execute_ws_completion,
                args=(bot_id,),
                daemon=True
            ).start()
            break

        # ── Fav leg just completed → instant dog-leg posting ──
        if status == 'fav_posted':
            fav_side = bot.get('fav_side', 'yes')
            fav_filled = yes_filled if fav_side == 'yes' else no_filled
            if fav_filled >= qty:
                if bot.get('_ws_fill_handling'):
                    continue
                bot['_ws_fill_handling'] = True
                print(f'⚡ WS INSTANT FAV FILL: {bot_id} {fav_side.upper()} filled — posting dog leg NOW')
                threading.Thread(
                    target=_execute_ws_dog_post,
                    args=(bot_id,),
                    daemon=True
                ).start()
                break

        break  # Only one bot can match this order_id (arb bot)

    # ── Middle Bot WS fill matching (keyed by order_a_id / order_b_id, no ticker filter) ──
    for bot_id, bot in list(active_bots.items()):
        if bot.get('type') != 'middle':
            continue
        if bot.get('status') in ('stopped', 'completed', 'both_filled'):
            continue
        matched_leg = None
        if order_id == bot.get('order_a_id'):
            matched_leg = 'a'
        elif order_id == bot.get('order_b_id'):
            matched_leg = 'b'
        if not matched_leg:
            continue

        qty = bot.get('qty', 1)
        fill_key = f'leg_{matched_leg}_fill_qty'
        bot[fill_key] = bot.get(fill_key, 0) + count
        fill_qty = bot[fill_key]
        print(f'⚡ WS MIDDLE FILL: {bot_id} LEG {matched_leg.upper()} +{count} → {fill_qty}/{qty}')

        if fill_qty >= qty:
            fill_price = bot.get(f'target_price_{matched_leg}', bot.get('target_price', 49))
            bot[f'leg_{matched_leg}_filled'] = True
            bot[f'leg_{matched_leg}_fill_price'] = fill_price
            other_leg = 'b' if matched_leg == 'a' else 'a'
            other_filled = bot.get(f'leg_{other_leg}_filled', False)
            if other_filled:
                bot['status'] = 'both_filled'
                bot['both_filled_at'] = time.time()
                bot_log('MIDDLE_BOTH_FILLED', bot_id, {'leg': matched_leg, 'source': 'ws_realtime'})
                print(f'⚡ WS MIDDLE BOTH FILLED: {bot_id}')
            else:
                bot['status'] = 'one_filled'
                bot['filled_leg'] = matched_leg
                bot['one_filled_at'] = time.time()
                bot_log('MIDDLE_LEG_FILLED', bot_id, {'leg': matched_leg, 'source': 'ws_realtime'})
                print(f'⚡ WS MIDDLE LEG {matched_leg.upper()} FILLED: {bot_id}')
            save_state()
        break

    # ── Anchor-Dog WS fill matching ──────────────────────────────
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'anchor_dog':
            continue
        if bot.get('status') not in ('dog_anchor_posted', 'fav_hedge_posted'):
            continue
        matched = None
        if order_id == bot.get('dog_order_id') and bot['status'] == 'dog_anchor_posted':
            matched = 'dog'
        elif order_id == bot.get('fav_order_id') and bot['status'] == 'fav_hedge_posted':
            matched = 'fav'
        if not matched:
            continue

        qty_bot = bot.get('quantity', 1)
        if matched == 'dog':
            bot['dog_fill_qty'] = bot.get('dog_fill_qty', 0) + count
            if bot['dog_side'] == 'yes':
                bot['yes_fill_qty'] = bot['dog_fill_qty']
            else:
                bot['no_fill_qty'] = bot['dog_fill_qty']
            if bot['dog_fill_qty'] >= qty_bot and not bot.get('_hedge_fired'):
                # SPEED CRITICAL — hedge worker gets the job IMMEDIATELY, log after
                bot['_hedge_fired'] = True
                bot['dog_filled_at'] = time.time()
                bot['status'] = 'dog_filled'
                _hedge_worker_queue.put((_execute_phantom_hedge, (bot_id,)))
                break
            print(f'👻 WS PHANTOM FILL: {bot_id} +{count} → {bot["dog_fill_qty"]}/{qty_bot}')
        elif matched == 'fav':
            bot['fav_fill_qty'] = bot.get('fav_fill_qty', 0) + count
            if bot['fav_side'] == 'yes':
                bot['yes_fill_qty'] = bot['fav_fill_qty']
            else:
                bot['no_fill_qty'] = bot['fav_fill_qty']
            print(f'👻 WS PHANTOM FAV FILL: {bot_id} +{count} → {bot["fav_fill_qty"]}/{qty_bot}')
            # Full fav fill will be handled by monitor on next cycle
        save_state()
        break

    # ── Anchor-Ladder WS fill matching ──────────────────────────────
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'anchor_ladder':
            continue
        if bot.get('status') == 'ladder_posted':
            # Match fill against any rung's order_id
            matched_rung = None
            for idx, rung in enumerate(bot.get('rungs', [])):
                if order_id == rung.get('order_id'):
                    matched_rung = idx
                    break
            if matched_rung is None:
                continue
            rung = bot['rungs'][matched_rung]
            rung['fill_qty'] = rung.get('fill_qty', 0) + count
            if rung['fill_qty'] >= rung['qty'] and not rung.get('filled_at'):
                rung['filled_at'] = time.time()
            total_fill = sum(r.get('fill_qty', 0) for r in bot['rungs'])
            bot['total_dog_fill_qty'] = total_fill
            if bot['dog_side'] == 'yes':
                bot['yes_fill_qty'] = total_fill
            else:
                bot['no_fill_qty'] = total_fill
            # SPEED CRITICAL — hedge fires BEFORE any logging
            _hedge_spawned = False
            if total_fill >= bot['total_dog_qty'] and not bot.get('_hedge_fired'):
                bot['_hedge_fired'] = True
                bot['dog_filled_at'] = time.time()
                _hedge_worker_queue.put((_execute_phantom_ladder_hedge, (bot_id,)))
                _hedge_spawned = True
            elif not bot.get('_sweep_timer_started') and not bot.get('_hedge_fired'):
                bot['_sweep_timer_started'] = True
                bot['first_fill_at'] = time.time()
                _hedge_worker_queue.put((_ladder_sweep_then_hedge, (bot_id,)))
                _hedge_spawned = True
            # Log AFTER hedge is queued — not on hot path
            print(f'👻 WS PHANTOM RUNG FILL: {bot_id} rung[{matched_rung}] @{rung["price"]}¢ +{count} → {rung["fill_qty"]}/{rung["qty"]} (total {total_fill}/{bot["total_dog_qty"]})')
            _audit('LADDER_RUNG_FILL', bot_id, {'ticker': bot['ticker'], 'rung_price': rung.get('price'), 'fill_qty': rung.get('fill_qty'), 'total_fills': total_fill})
            if _hedge_spawned:
                # Defer save_state to background — don't block WS handler while hedge thread needs GIL
                threading.Thread(target=save_state, daemon=True).start()
            else:
                save_state()
            break
        elif bot.get('status') in ('fav_hedge_posted', 'ladder_filled_no_fav'):
            # Check rung order IDs first (late dog fills AFTER hedge posted)
            _late_rung = None
            for idx, rung in enumerate(bot.get('rungs', [])):
                if order_id == rung.get('order_id'):
                    _late_rung = idx
                    break
            if _late_rung is not None:
                rung = bot['rungs'][_late_rung]
                rung['fill_qty'] = rung.get('fill_qty', 0) + count
                if rung['fill_qty'] >= rung['qty'] and not rung.get('filled_at'):
                    rung['filled_at'] = time.time()
                total_fill = sum(r.get('fill_qty', 0) for r in bot['rungs'])
                bot['total_dog_fill_qty'] = total_fill
                if bot['dog_side'] == 'yes':
                    bot['yes_fill_qty'] = total_fill
                else:
                    bot['no_fill_qty'] = total_fill
                print(f'👻 WS LATE RUNG FILL: {bot_id} rung[{_late_rung}] @{rung["price"]}¢ +{count} (hedge already posted, total {total_fill})')
                bot_log('PHANTOM_LADDER_LATE_RUNG_FILL', bot_id, {
                    'rung_idx': _late_rung, 'rung_price': rung.get('price'),
                    'fill_qty': rung['fill_qty'], 'total_fill': total_fill,
                    'status': bot.get('status'),
                })
                save_state()
                break
            # Then check fav order ID (hedge fills)
            if order_id != bot.get('fav_order_id'):
                continue
            bot['fav_fill_qty'] = bot.get('fav_fill_qty', 0) + count
            if bot['fav_side'] == 'yes':
                bot['yes_fill_qty'] = bot['fav_fill_qty']
            else:
                bot['no_fill_qty'] = bot['fav_fill_qty']
            print(f'👻 WS PHANTOM FAV FILL: {bot_id} +{count} → {bot["fav_fill_qty"]}/{bot.get("hedge_qty", "?")}')
            save_state()
            break

    # ── Ladder-Arb WS fill matching ──────────────────────────────
    for bot_id, bot in list(active_bots.items()):
        if bot.get('bot_category') != 'ladder_arb':
            continue
        status = bot.get('status', '')
        if status not in ('ladder_arb_posted', 'ladder_arb_yes_filled', 'ladder_arb_no_filled'):
            continue

        # Check if this fill is for the consolidated hedge order (bot-level tracking)
        is_hedge_fill = False
        if order_id in bot.get('_all_hedge_order_ids', []):
            is_hedge_fill = True
            _old_hfc = bot.get('_hedge_fill_count', 0)
            bot['_hedge_fill_count'] = _old_hfc + count
            hedge_qty = bot.get('hedge_qty', 0)
            _was_capped = False
            if hedge_qty > 0 and bot['_hedge_fill_count'] > hedge_qty:
                _was_capped = True
                bot['_hedge_fill_count'] = hedge_qty
            if not bot.get('hedge_fill_at'):
                bot['hedge_fill_at'] = time.time()
            bot_log('APEX_WS_HEDGE_FILL', bot_id, {
                'order_id': order_id, 'fill_count': count,
                'old_hedge_fill_count': _old_hfc, 'new_hedge_fill_count': bot['_hedge_fill_count'],
                'hedge_qty': hedge_qty, 'was_capped': _was_capped,
                'current_hedge_order_id': bot.get('hedge_order_id'),
                'filled_yes_qty': bot.get('filled_yes_qty', 0),
                'filled_no_qty': bot.get('filled_no_qty', 0),
                '_hedge_verified': bot.get('_hedge_verified', False),
            })
            # First hedge fill → cancel all remaining anchor orders to freeze anchor qty
            # This prevents more anchors from filling while hedge is executing
            if _old_hfc == 0 and not bot.get('_anchors_cancelled_on_hedge_fill'):
                bot['_anchors_cancelled_on_hedge_fill'] = True
                _anchor_side = bot.get('first_fill_side', 'yes')
                # FAST PATH: batch cancel via order group (1 API call instead of N)
                _apex_og_id = bot.get('_order_group_id')
                if _apex_og_id:
                    def _batch_cancel_apex_anchors(_og, _bid):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order_group(_og)
                            print(f'🛑 APEX BATCH CANCEL: {_bid} order group {_og[:12]} cancelled on first hedge fill')
                            bot_log('APEX_ANCHORS_BATCH_CANCELLED', _bid, {'order_group_id': _og[:12]})
                        except Exception as _e:
                            print(f'⚠ APEX BATCH CANCEL FAIL: {_bid} {_e} — falling back to individual')
                            # Fallback: individual cancels
                            for _r in bot.get('rungs', []):
                                _aoid = _r.get(f'{_anchor_side}_order_id')
                                if _aoid:
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.cancel_order(_aoid)
                                    except Exception:
                                        pass
                    threading.Thread(target=_batch_cancel_apex_anchors, args=(_apex_og_id, bot_id), daemon=True).start()
                else:
                    # No order group — individual cancels (legacy path)
                    _cancel_oids = []
                    for _r in bot.get('rungs', []):
                        _aoid = _r.get(f'{_anchor_side}_order_id')
                        if _aoid and _r.get(f'{_anchor_side}_fill_qty', 0) < _r.get('quantity', 1):
                            _cancel_oids.append(_aoid)
                            _r[f'{_anchor_side}_order_id'] = None
                    if _cancel_oids:
                        def _cancel_anchors_on_hedge(_oids, _bid):
                            for _oid in _oids:
                                try:
                                    api_rate_limiter.wait()
                                    kalshi_client.cancel_order(_oid)
                                except Exception:
                                    pass
                            print(f'🛑 APEX ANCHORS CANCELLED: {_bid} cancelled {len(_oids)} anchor orders on first hedge fill')
                            bot_log('APEX_ANCHORS_CANCELLED_ON_HEDGE_FILL', _bid, {'cancelled_count': len(_oids)})
                        threading.Thread(target=_cancel_anchors_on_hedge, args=(_cancel_oids, bot_id), daemon=True).start()

        matched_rung = None
        matched_side = None
        for idx, rung in enumerate(bot.get('rungs', [])):
            if order_id == rung.get('yes_order_id'):
                matched_rung = idx
                matched_side = 'yes'
                break
            elif order_id == rung.get('no_order_id'):
                matched_rung = idx
                matched_side = 'no'
                break
        if matched_rung is None and not is_hedge_fill:
            continue

        if matched_rung is not None:
            rung = bot['rungs'][matched_rung]
            fill_key = f'{matched_side}_fill_qty'
            qty_per = rung.get('quantity', bot.get('quantity', 1))
            old_fill = rung.get(fill_key, 0)
            rung[fill_key] = min(old_fill + count, qty_per)
            if rung[fill_key] >= qty_per and not rung.get(f'{matched_side}_filled_at'):
                rung[f'{matched_side}_filled_at'] = time.time()

            # Late Fill Protocol: anchor fill arrived after hedge already consolidated
            if (bot.get('_consolidated') and matched_side == bot.get('first_fill_side')
                    and not is_hedge_fill):
                threading.Thread(
                    target=_handle_late_anchor_fill,
                    args=(bot_id, bot, matched_rung, count),
                    daemon=True
                ).start()

        _recompute_apex_fills(bot)

        total_yes = bot['filled_yes_qty']
        total_no = bot['filled_no_qty']
        total_expected_per_side = sum(r.get('quantity', bot.get('quantity', 1)) for r in bot['rungs'])

        hedge_info = f' (hedge fill #{bot.get("_hedge_fill_count", 0)})' if is_hedge_fill else ''
        rung_info = f'rung[{matched_rung}] {matched_side.upper()}' if matched_rung is not None else 'hedge-only'
        print(f'△ WS APEX FILL: {bot_id} {rung_info} +{count}{hedge_info} '
              f'→ YES={total_yes}/{total_expected_per_side} NO={total_no}/{total_expected_per_side}')
        _audit('APEX_RUNG_FILL', bot_id, {'ticker': bot.get('ticker', ''), 'side': matched_side, 'rung_idx': matched_rung, 'count': count, 'is_hedge': is_hedge_fill, 'total_yes': total_yes, 'total_no': total_no})
        bot_log('LADDER_ARB_WS_FILL', bot_id, {
            'rung_idx': matched_rung, 'side': matched_side, 'count': count,
            'is_hedge_fill': is_hedge_fill,
            'old_fill': old_fill if matched_rung is not None else None,
            'new_fill': rung.get(fill_key, 0) if matched_rung is not None else None,
            'rung_price': rung.get(f'{matched_side}_price', 0) if matched_rung is not None else None,
            'hedge_fill_count': bot.get('_hedge_fill_count', 0),
            'total_yes': total_yes, 'total_no': total_no,
            'total_expected': total_expected_per_side,
        })

        # Check if ALL rungs have both sides filled (reliable per-rung tracking)
        _all_rungs_filled = (total_yes >= total_expected_per_side and total_no >= total_expected_per_side)

        # Check if hedge is fully done — require API verification
        _hedge_fully_filled = (bot.get('_consolidated')
                               and bot.get('_hedge_fill_count', 0) >= bot.get('hedge_qty', 0)
                               and bot.get('hedge_qty', 0) > 0)
        _hedge_fully_done = (_hedge_fully_filled and bot.get('_hedge_verified'))
        # Note: completion handler (Phase 3) detects unhedged anchors and handles them.
        # No extra hedge generation here — that caused orphans.

        if _all_rungs_filled or _hedge_fully_done:
            # Both sides fully filled OR hedge fully done — complete!
            if not bot.get('_ws_fill_handling'):
                bot['_ws_fill_handling'] = True
                bot_log('LADDER_ARB_BOTH_FILLED', bot_id, {
                    'trigger': 'all_rungs_filled' if _all_rungs_filled else 'hedge_fully_done',
                    'total_yes': total_yes, 'total_no': total_no,
                    'total_expected_per_side': total_expected_per_side,
                    'hedge_fully_done': _hedge_fully_done,
                    '_hedge_fill_count': bot.get('_hedge_fill_count', 0),
                    'hedge_qty': bot.get('hedge_qty', 0),
                    '_hedge_verified': bot.get('_hedge_verified', False),
                    '_consolidated': bot.get('_consolidated', False),
                    'hedge_order_id': bot.get('hedge_order_id'),
                    '_all_hedge_order_ids': bot.get('_all_hedge_order_ids', []),
                    'filled_yes_qty': bot.get('filled_yes_qty', 0),
                    'filled_no_qty': bot.get('filled_no_qty', 0),
                    'first_fill_side': bot.get('first_fill_side'),
                    'first_fill_at': bot.get('first_fill_at'),
                    'time_to_complete_s': round(time.time() - bot.get('first_fill_at', time.time()), 1),
                })
                threading.Thread(target=_execute_apex_completion, args=(bot_id,), daemon=True).start()
        elif total_yes > 0 and total_no == 0:
            bot['status'] = 'ladder_arb_yes_filled'
            if not bot.get('first_fill_at'):
                bot['first_fill_at'] = time.time()
                bot['first_fill_side'] = 'yes'
                bot_log('LADDER_ARB_FIRST_FILL', bot_id, {
                    'side': 'yes', 'total_yes': total_yes,
                    'rung_idx': matched_rung, 'fill_price': rung.get('yes_price', 0) if matched_rung is not None else None,
                })
                if not bot.get('_sweep_thread_running') and not bot.get('_consolidated'):
                    bot['_sweep_thread_running'] = True
                    threading.Thread(target=_execute_ladder_arb_sweep_and_hedge, args=(bot_id,), daemon=True).start()
                    print(f'△ APEX SWEEP SPAWNED: {bot_id} YES fill detected — sweep thread launched')
        elif total_no > 0 and total_yes == 0:
            bot['status'] = 'ladder_arb_no_filled'
            if not bot.get('first_fill_at'):
                bot['first_fill_at'] = time.time()
                bot['first_fill_side'] = 'no'
                bot_log('LADDER_ARB_FIRST_FILL', bot_id, {
                    'side': 'no', 'total_no': total_no,
                    'rung_idx': matched_rung, 'fill_price': rung.get('no_price', 0) if matched_rung is not None else None,
                })
                if not bot.get('_sweep_thread_running') and not bot.get('_consolidated'):
                    bot['_sweep_thread_running'] = True
                    threading.Thread(target=_execute_ladder_arb_sweep_and_hedge, args=(bot_id,), daemon=True).start()
                    print(f'△ APEX SWEEP SPAWNED: {bot_id} NO fill detected — sweep thread launched')
        elif total_yes > 0 and total_no > 0:
            # Both sides have some fills — keep the current status or set based on which has more
            if bot['status'] == 'ladder_arb_posted':
                bot['status'] = 'ladder_arb_yes_filled' if total_yes >= total_no else 'ladder_arb_no_filled'
                if not bot.get('first_fill_at'):
                    bot['first_fill_at'] = time.time()
                    bot['first_fill_side'] = 'yes' if total_yes >= total_no else 'no'
                    if not bot.get('_sweep_thread_running') and not bot.get('_consolidated'):
                        bot['_sweep_thread_running'] = True
                        threading.Thread(target=_execute_ladder_arb_sweep_and_hedge, args=(bot_id,), daemon=True).start()
                        print(f'△ APEX SWEEP SPAWNED: {bot_id} mixed fills — sweep thread launched')

        save_state()
        break


def _precalc_phantom_hedge(dog_price, target_width, dog_side, qty):
    """Pre-calculate the hedge price so it's ready to fire instantly on dog fill.
    Returns the ceiling-capped hedge price or 0 if too low.
    This is a FALLBACK when no live bid is available — the WS path uses the actual bid."""
    # Cap at 98¢ walk ceiling only (profit target determines dog depth, not hedge cap)
    max_hedge = HARD_CEILING_CENTS - dog_price
    if max_hedge < 1:
        return 0
    return max_hedge


def _precalc_phantom_ladder_hedges(rungs, target_width, dog_side):
    """Pre-calculate hedge prices AND avg fill prices for EVERY possible fill count.
    Handles partial rung fills (important at high contract counts).
    Assumes top-down fill order (highest price fills first).
    Returns (hedge_dict, avg_dict) — both keyed by cumulative fill qty."""
    sorted_rungs = sorted(rungs, key=lambda r: r['price'], reverse=True)
    hedges = {}
    avgs = {}
    cum_qty = 0
    cum_price_x_qty = 0
    for r in sorted_rungs:
        rq = r.get('qty', 1)
        price = r['price']
        # Precalc for every partial fill within this rung
        for partial in range(1, rq + 1):
            qty_at = cum_qty + partial
            cost_at = cum_price_x_qty + price * partial
            avg = round(cost_at / qty_at)
            hedges[qty_at] = _precalc_phantom_hedge(avg, target_width, dog_side, qty_at)
            avgs[qty_at] = avg
        cum_qty += rq
        cum_price_x_qty += price * rq
    return hedges, avgs


def _execute_phantom_hedge(bot_id):
    """Post the favorite hedge immediately after the dog fills.
    Called from WS fill handler in a background thread for speed.
    Posts at fav BID (maker) from WS cache — speed gets us first in queue."""
    try:
        bot = active_bots.get(bot_id)
        if not bot or bot.get('status') in ('stopped', 'completed'):
            return

        ticker = bot['ticker']
        hedge_ticker = bot.get('hedge_ticker', ticker)
        fav_side = bot['fav_side']
        dog_side = bot['dog_side']
        qty = bot.get('quantity', 1)
        dog_price = bot['dog_price']

        # Ceiling: max we'll ever walk to
        max_hedge = HARD_CEILING_CENTS - dog_price

        # Post at fav BID — maker order, first in queue with our speed
        # ALWAYS read from ws_manager first (real-time), fall back to bot cache
        _is_cross = hedge_ticker != ticker
        fav_bid = 0
        fav_ask = 0
        _ws_ticker = hedge_ticker if _is_cross else ticker
        if ws_manager:
            _ws_data = ws_manager.get_price(_ws_ticker)
            if _ws_data:
                fav_bid = _ws_data.get(f'{fav_side}_bid', 0)
                fav_ask = _ws_data.get(f'{fav_side}_ask', 0)
                if fav_ask <= 0:
                    _opp = _ws_data.get(f'{"no" if fav_side == "yes" else "yes"}_bid', 0)
                    fav_ask = (100 - _opp) if _opp > 0 else 0
        if fav_bid <= 0:
            # WS unavailable: fall back to bot cache
            _pfx = 'live_hedge_' if _is_cross else 'live_'
            fav_bid = bot.get(f'{_pfx}{fav_side}_bid', 0)
            if fav_ask <= 0:
                opp_bid = bot.get(f'{_pfx}{"no" if fav_side == "yes" else "yes"}_bid', 0)
                fav_ask = (100 - opp_bid) if opp_bid > 0 else 0
        fav_spread = (fav_ask - fav_bid) if fav_ask > 0 and fav_bid > 0 else 0

        if fav_bid > 0:
            # Always post at bid — phantom needs ceiling margin, walk follows bid
            hedge_price = fav_bid
            hedge_price = min(hedge_price, max_hedge)  # never exceed ceiling
        else:
            # No WS bid available — fall back to precalc
            hedge_price = bot.get('_precalc_hedge_price') or 0
            if hedge_price < 1:
                hedge_price = _precalc_phantom_hedge(dog_price, bot.get('target_width', 5), dog_side, qty)

        if hedge_price < 1:
            print(f'   ⚠ Hedge price {hedge_price}¢ too low — deferring')
            bot_log('PHANTOM_HEDGE_TOO_LOW', bot_id, {'hedge_price': hedge_price, 'dog_price': dog_price, 'fav_bid': fav_bid, 'path': 'ws_fast'})
            bot['status'] = 'dog_filled'
            return

        # At ceiling — cap at max_hedge and post anyway. Fill at 98 = breakeven > sellback loss.
        if dog_price + hedge_price >= HARD_CEILING_CENTS:
            hedge_price = max(1, max_hedge)
            print(f'📌 PHANTOM HEDGE AT CEILING: {bot_id} capped to {hedge_price}¢ (combined={dog_price + hedge_price}¢) — posting and holding')
            bot_log('PHANTOM_HEDGE_AT_CEILING_POST', bot_id, {
                'dog_price': dog_price, 'hedge_price': hedge_price,
                'combined': dog_price + hedge_price, 'fav_bid': fav_bid,
                'max_hedge': max_hedge, 'path': 'ws_fast',
            })

        # Record raw hedge speed RIGHT before API call — nothing between this and HTTP send
        if not bot.get('dog_filled_at'):
            bot['dog_filled_at'] = time.time()
        _raw_fill_at = bot.get('dog_filled_at')
        _is_retry = bot.get('raw_hedge_ms') is not None
        if _raw_fill_at and not _is_retry:
            _raw_ms = (time.time() - _raw_fill_at) * 1000
            bot['raw_hedge_ms'] = round(_raw_ms, 1)
            _record_latency('raw_hedge_phantom', _raw_ms, {'bot_id': bot_id, 'type': 'phantom'})
        # SPEED CRITICAL — straight to API, no rate limiter
        fav_resp, actual_fav_price = create_order_maker(
            ticker=hedge_ticker, side=fav_side, action='buy',
            count=qty, price=hedge_price, priority=True,
            skip_rate_limit=True
        )
        # Round trip measurement
        _rt_ms = (time.time() - _raw_fill_at) * 1000 if _raw_fill_at and not _is_retry else None
        if _rt_ms is not None:
            bot['hedge_latency_ms'] = round(_rt_ms, 1)
            _record_latency('fill_to_hedge_phantom', _rt_ms, {'bot_id': bot_id, 'type': 'phantom', 'fav_price': actual_fav_price})

        fav_order_id = fav_resp['order']['order_id']
        bot['fav_order_id'] = fav_order_id
        bot['fav_price'] = actual_fav_price
        bot['status'] = 'fav_hedge_posted'
        bot['fav_posted_at'] = time.time()
        bot['fav_walk_count'] = 0
        bot['fav_last_walk_at'] = None
        if fav_side == 'yes':
            bot['yes_price'] = actual_fav_price
            bot['yes_order_id'] = fav_order_id
        else:
            bot['no_price'] = actual_fav_price
            bot['no_order_id'] = fav_order_id
        save_state()  # deferred from WS handler — save after hedge is posted

        print(f'👻 PHANTOM HEDGE: {bot_id} {fav_side.upper()} @{actual_fav_price}¢ | raw={round(_raw_ms, 1) if _raw_fill_at else "?"}ms rt={round(_rt_ms, 1) if _rt_ms else "?"}ms')
        bot_log('PHANTOM_WS_HEDGE_POSTED', bot_id, {
            'fav_side': fav_side, 'fav_price': actual_fav_price,
            'fav_bid': fav_bid, 'fav_ask': fav_ask, 'fav_spread': fav_spread,
            'fav_order_id': fav_order_id[:12], 'dog_price': dog_price,
            'combined': dog_price + actual_fav_price, 'qty': qty,
            'path': 'ws_fast',
        })
        _audit('PHANTOM_WS_HEDGE_POSTED', bot_id, {
            'ticker': ticker, 'fav_side': fav_side, 'fav_price': actual_fav_price,
            'fav_order_id': fav_order_id, 'dog_price': dog_price, 'qty': qty,
        })
        # Async: verify actual dog fill price (non-blocking, after hedge is already placed)
        def _verify_dog_price():
            try:
                vp = get_actual_fill_price(bot.get('dog_order_id'), dog_side)
                if vp and vp != dog_price:
                    bot['dog_price'] = vp
                    print(f'   📋 Dog fill price verified: {dog_price}¢ → {vp}¢')
                    save_state()
            except Exception:
                pass
        threading.Thread(target=_verify_dog_price, daemon=True).start()
    except Exception as e:
        print(f'❌ WS PHANTOM HEDGE {bot_id}: {e}')
        import traceback
        traceback.print_exc()
        bot_log('PHANTOM_WS_HEDGE_ERROR', bot_id, {'error': str(e)[:300], 'path': 'ws_fast'}, level='ERROR')
        _audit('PHANTOM_WS_HEDGE_ERROR', bot_id, {'error': str(e)[:200]})
        bot = active_bots.get(bot_id)
        if bot:
            bot['status'] = 'dog_filled'  # fallback to monitor


def _execute_phantom_ladder_hedge(bot_id):
    """Post fav hedge based on filled ladder rungs — SPEED IS EVERYTHING.
    Posts at fav BID or bid+1 in gapped markets. Falls back to precalc price only if no WS bid."""
    try:
        bot = active_bots.get(bot_id)
        if not bot or bot.get('status') in ('stopped', 'completed', 'fav_hedge_posted'):
            bot_log('PHANTOM_LADDER_WS_HEDGE_SKIP', bot_id, {
                'status': bot.get('status') if bot else 'no_bot',
            })
            return

        ticker = bot['ticker']
        hedge_ticker = bot.get('hedge_ticker', ticker)
        fav_side = bot['fav_side']
        dog_side = bot['dog_side']

        # ── Compute avg_price and hedge_qty ──
        total_fill_qty = bot.get('total_dog_fill_qty', 0)
        precalc_avgs = bot.get('_precalc_avg_prices', {})
        avg_price = precalc_avgs.get(total_fill_qty) or precalc_avgs.get(str(total_fill_qty), 0)

        if avg_price > 0 and total_fill_qty > 0:
            bot['avg_fill_price'] = avg_price
            bot['hedge_qty'] = total_fill_qty
            bot['dog_filled_at'] = bot.get('dog_filled_at') or time.time()
        else:
            # Compute from rung fills (recovery path)
            filled_rungs = [r for r in bot['rungs'] if r.get('fill_qty', 0) > 0]
            bot_log('PHANTOM_LADDER_WS_HEDGE_START', bot_id, {
                'path': 'computed', 'filled_rungs': len(filled_rungs),
                'total_fill_qty': total_fill_qty, 'dog_side': dog_side, 'fav_side': fav_side,
            })
            if not filled_rungs:
                bot_fill = bot.get('total_dog_fill_qty', 0) or bot.get(f'{dog_side}_fill_qty', 0) or 0
                if bot_fill > 0 and bot.get('avg_fill_price'):
                    bot['rungs'][0]['fill_qty'] = min(bot_fill, bot['rungs'][0]['qty'])
                    filled_rungs = [bot['rungs'][0]]
                    print(f'🔧 PHANTOM HEDGE RECOVERY: {bot_id} reconstructed rung fills from bot-level data (fill={bot_fill})')
                else:
                    try:
                        api_read_limiter.wait()
                        _pos_r = kalshi_client.get_positions(ticker=ticker)
                        _pos_list = _pos_r.get('market_positions', _pos_r.get('positions', []))
                        for _p in _pos_list:
                            if _p.get('ticker') == ticker:
                                _actual_qty = abs(_parse_position_qty(_p))
                                if _actual_qty > 0:
                                    print(f'⚠ PHANTOM HEDGE {bot_id}: 0 local fills but Kalshi has {_actual_qty} contracts — reconstructing')
                                    _remaining = _actual_qty
                                    for _r in bot['rungs']:
                                        _assign = min(_r['qty'], _remaining)
                                        _r['fill_qty'] = _assign
                                        _remaining -= _assign
                                        if _remaining <= 0:
                                            break
                                    filled_rungs = [r for r in bot['rungs'] if r.get('fill_qty', 0) > 0]
                                    break
                    except Exception as _pe:
                        print(f'⚠ PHANTOM HEDGE position check failed: {_pe}')
                    if not filled_rungs:
                        print(f'👻 PHANTOM HEDGE {bot_id}: no filled rungs confirmed — marking complete')
                        bot['status'] = 'completed'
                        bot['completed_at'] = time.time()
                        save_state()
                        return

            total_fill_qty = sum(r['fill_qty'] for r in filled_rungs)
            avg_price = round(sum(r['price'] * r['fill_qty'] for r in filled_rungs) / total_fill_qty)
            bot['avg_fill_price'] = avg_price
            bot['hedge_qty'] = total_fill_qty
            bot['dog_filled_at'] = bot.get('dog_filled_at') or time.time()

        # ── Hedge price: fav BID or bid+1 in gapped markets ──
        _max_hedge = HARD_CEILING_CENTS - (avg_price or bot.get('dog_price', 0))
        _is_cross = hedge_ticker != ticker
        _fav_bid = 0
        _fav_ask = 0
        _ws_ticker = hedge_ticker if _is_cross else ticker
        if ws_manager:
            _ws_h = ws_manager.get_price(_ws_ticker)
            if _ws_h:
                _fav_bid = _ws_h.get(f'{fav_side}_bid', 0)
                _fav_ask = _ws_h.get(f'{fav_side}_ask', 0)
                if _fav_ask <= 0:
                    _opp = _ws_h.get(f'{"no" if fav_side == "yes" else "yes"}_bid', 0)
                    _fav_ask = (100 - _opp) if _opp > 0 else 0
        if _fav_bid <= 0:
            _ppfx = 'live_hedge_' if _is_cross else 'live_'
            _fav_bid = bot.get(f'{_ppfx}{fav_side}_bid', 0)
            if _fav_ask <= 0:
                _opp_bid = bot.get(f'{_ppfx}{"no" if fav_side == "yes" else "yes"}_bid', 0)
                _fav_ask = (100 - _opp_bid) if _opp_bid > 0 else 0

        if _fav_bid > 0:
            # Always post at bid — phantom needs ceiling margin, walk follows bid
            hedge_price = _fav_bid
        else:
            # No WS bid — fall back to precalc hedge price
            precalc_hedges = bot.get('_precalc_hedge_prices', {})
            hedge_price = precalc_hedges.get(total_fill_qty) or precalc_hedges.get(str(total_fill_qty), 0)
            if hedge_price <= 0:
                hedge_price = _precalc_phantom_hedge(avg_price, bot.get('target_width', 5), dog_side, total_fill_qty)
            if hedge_price <= 0:
                hedge_price = bot.get('_precalc_hedge_price', 0)

        if hedge_price < 1:
            print(f'   ⚠ Hedge price {hedge_price}¢ too low — deferring')
            bot['status'] = 'ladder_filled_no_fav'
            bot['_hedge_thread_active'] = False
            save_state()
            return

        # At ceiling — don't hedge at breakeven, flag for monitor to sell back
        _ladder_combined = (avg_price or bot.get('dog_price', 0)) + hedge_price
        if _ladder_combined >= HARD_CEILING_CENTS:
            print(f'🚫 PHANTOM LADDER HEDGE SKIP: {bot_id} combined {avg_price}+{hedge_price}={_ladder_combined}¢ >= {HARD_CEILING_CENTS}¢ — deferring to sellback')
            bot_log('PHANTOM_LADDER_HEDGE_AT_CEILING', bot_id, {
                'avg_price': avg_price, 'hedge_price': hedge_price,
                'combined': _ladder_combined, 'fav_bid': _fav_bid,
                'max_hedge': _max_hedge, 'path': 'ws_fast',
            })
            bot['_ceiling_sellback'] = True
            bot['_hedge_thread_active'] = False
            save_state()
            return

        print(f'👻 PHANTOM HEDGE: {bot_id} | avg={avg_price}¢ qty={total_fill_qty} | bid={_fav_bid}¢ spread={_fav_spread}¢ → @{hedge_price}¢ (ceil={_max_hedge}¢)')

        # ── Record raw speed (fill → right before API call) then fire ──
        # Ensure dog_filled_at is set (WS handler sets it, but recovery/sweep paths may not)
        if not bot.get('dog_filled_at') and not bot.get('first_fill_at'):
            bot['dog_filled_at'] = time.time()
        _raw_fill_at = bot.get('dog_filled_at') or bot.get('first_fill_at')
        _is_retry = bot.get('raw_hedge_ms') is not None
        if _raw_fill_at and not _is_retry:
            _raw_ms = (time.time() - _raw_fill_at) * 1000
            bot['raw_hedge_ms'] = round(_raw_ms, 1)
            _record_latency('raw_hedge_phantom', _raw_ms, {'bot_id': bot_id, 'type': 'phantom_ladder'})
            print(f'   ⚡ Raw: {_raw_ms:.1f}ms (fill → API send)')
        elif _is_retry:
            print(f'   🔄 Hedge RETRY (original raw={bot["raw_hedge_ms"]}ms)')
        fav_resp, actual_fav_price = create_order_maker(
            ticker=hedge_ticker, side=fav_side, action='buy',
            count=total_fill_qty, price=hedge_price, priority=True,
            skip_rate_limit=True
        )
        # Round trip (fill → Kalshi confirms order queued)
        if _raw_fill_at and not _is_retry:
            _rt_ms = (time.time() - _raw_fill_at) * 1000
            bot['hedge_latency_ms'] = round(_rt_ms, 1)
            _record_latency('fill_to_hedge_phantom', _rt_ms, {'bot_id': bot_id, 'type': 'phantom_ladder', 'fav_price': actual_fav_price})
            print(f'   🏁 RT: {_rt_ms:.1f}ms (fill → Kalshi confirmed)')
        fav_order_id = fav_resp['order']['order_id']
        bot['fav_order_id'] = fav_order_id
        bot['fav_price'] = actual_fav_price
        bot['status'] = 'fav_hedge_posted'
        bot['fav_posted_at'] = time.time()
        bot['fav_walk_count'] = 0
        bot['fav_last_walk_at'] = None
        if fav_side == 'yes':
            bot['yes_price'] = actual_fav_price
            bot['yes_order_id'] = fav_order_id
        else:
            bot['no_price'] = actual_fav_price
            bot['no_order_id'] = fav_order_id
        print(f'   ✅ FAV POSTED: {fav_side.upper()} @ {actual_fav_price}¢ | order={fav_order_id[:12]}… | total={avg_price + actual_fav_price}¢ + fees')
        bot_log('PHANTOM_LADDER_WS_HEDGE_POSTED', bot_id, {
            'fav_side': fav_side, 'fav_price': actual_fav_price,
            'fav_bid': _fav_bid, 'fav_ask': _fav_ask, 'fav_spread': _fav_spread,
            'fav_order_id': fav_order_id[:12], 'avg_dog': avg_price,
            'combined': avg_price + actual_fav_price, 'hedge_qty': total_fill_qty,
            'path': 'ws_fast',
        })
        _audit('LADDER_HEDGE_POSTED', bot_id, {'ticker': hedge_ticker, 'fav_side': fav_side, 'hedge_qty': total_fill_qty, 'fav_price': actual_fav_price, 'fav_order_id': fav_order_id})
        # ── THEN cancel unfilled rungs + verify late fills (background — don't block hedge worker) ──
        def _cancel_and_verify_rungs(_bid, _bot):
            # FAST PATH: Use order group cancel to nuke all remaining orders in ONE call
            _og_id = _bot.get('_order_group_id')
            if _og_id:
                try:
                    api_rate_limiter.wait()
                    kalshi_client.cancel_order_group(_og_id)
                    print(f'   ✅ BATCH CANCEL: {_bid} order group {_og_id[:12]} cancelled in one call')
                    bot_log('PHANTOM_LADDER_BATCH_CANCEL', _bid, {'order_group_id': _og_id[:12]})
                except Exception as _bg_err:
                    print(f'   ⚠ BATCH CANCEL FAIL: {_bid} group {_og_id[:12]}: {_bg_err} — falling back to individual')
                    bot_log('PHANTOM_LADDER_BATCH_CANCEL_FAIL', _bid, {'error': str(_bg_err)[:200]})

            # Verify each rung on Kalshi to find late fills that snuck through
            cancelled_rungs = 0
            late_fill_qty = 0
            for rung in _bot.get('rungs', []):
                if rung.get('fill_qty', 0) >= rung['qty'] or not rung.get('order_id'):
                    continue  # already filled or no order
                try:
                    api_read_limiter.wait()
                    resp = kalshi_client.get_order(rung['order_id'])
                    ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
                    actual_fills = _parse_fill_count(ord_data)
                    _ord_status = ord_data.get('status', '')
                    if actual_fills > 0:
                        rung['fill_qty'] = actual_fills
                        if actual_fills >= rung['qty'] and not rung.get('filled_at'):
                            rung['filled_at'] = time.time()
                        late_fill_qty += actual_fills
                        print(f'   ⚡ RUNG RACE FILL: {_bid} rung @{rung.get("price")}¢ has {actual_fills} fills — amending hedge')
                        bot_log('PHANTOM_LADDER_LATE_FILL_DETECTED', _bid, {
                            'rung_price': rung.get('price'), 'actual_fills': actual_fills,
                            'rung_qty': rung['qty'], 'order_id': rung['order_id'][:12],
                        })
                    elif _ord_status in ('canceled', 'cancelled'):
                        rung['cancelled'] = True
                        cancelled_rungs += 1
                    else:
                        try:
                            _cancel_with_retry(rung['order_id'])
                            rung['cancelled'] = True
                            cancelled_rungs += 1
                        except Exception as _fc_err:
                            print(f'⚠ RUNG ORPHAN: {_bid} rung @{rung.get("price")}¢ — stuck on Kalshi: {_fc_err}')
                            bot_log('PHANTOM_LADDER_RUNG_ORPHAN', _bid, {
                                'rung_price': rung.get('price'), 'order_id': rung['order_id'][:12],
                                'error': str(_fc_err)[:200],
                            }, level='ERROR')
                except Exception as _oc_err:
                    print(f'⚠ RUNG VERIFY FAIL: {_bid} rung {rung.get("price")}¢ — {_oc_err}')
            # Cancel stashed old order IDs from previous reposts
            _prev_oids = _bot.get('_prev_rung_order_ids', [])
            if _prev_oids:
                _prev_cancelled = 0
                for _poid in _prev_oids:
                    if _cancel_with_retry(_poid):
                        _prev_cancelled += 1
                if _prev_cancelled:
                    print(f'   🧹 Cancelled {_prev_cancelled}/{len(_prev_oids)} stale repost orders')
                _bot['_prev_rung_order_ids'] = []

            if cancelled_rungs:
                print(f'   🔄 Cancelled {cancelled_rungs} unfilled rungs')
            # If late fills found, amend hedge with updated qty + price
            if late_fill_qty <= 0:
                save_state()
                return
            late_fill_qty_total = late_fill_qty
            new_total_fill = sum(r.get('fill_qty', 0) for r in bot.get('rungs', []))
            new_avg = round(sum(r['price'] * r.get('fill_qty', 0) for r in bot.get('rungs', []) if r.get('fill_qty', 0) > 0) / new_total_fill) if new_total_fill > 0 else avg_price
            bot['avg_fill_price'] = new_avg
            _old_hedge_qty_before = bot.get('hedge_qty', 0) or hedge_qty
            bot['hedge_qty'] = new_total_fill
            target_width = bot.get('target_width', 5)
            new_hedge_target = max(1, 100 - new_avg - target_width)
            # Walk offset: how much the hedge has already walked from original target
            old_target = max(1, 100 - avg_price - target_width)
            walk_offset = max(0, bot.get('fav_price', old_target) - old_target)
            amend_price = max(1, new_hedge_target + walk_offset)
            if bot.get('fav_order_id'):
                _old_hedge_qty = _old_hedge_qty_before
                _extra_needed = new_total_fill - _old_hedge_qty
                try:
                    fav_side = bot.get('fav_side', 'yes')
                    amend_kwargs = {f'{fav_side}_price': amend_price}
                    # Acquire shared lock — prevents race with monitor walk and WS instant drop
                    _phantom_drop_lock.acquire()
                    try:
                        fav_oid = bot.get('fav_order_id')  # Re-read after lock (may have changed)
                        if not fav_oid:
                            save_state()
                            return
                        api_rate_limiter.wait()
                        _amend_resp = kalshi_client.amend_order(fav_oid, ticker=hedge_ticker, side=fav_side, count=_old_hedge_qty, **amend_kwargs)
                        # Capture new order ID
                        _ao = _amend_resp.get('order', _amend_resp) if isinstance(_amend_resp, dict) else {}
                        _new_oid = _ao.get('order_id', '')
                        if _new_oid and _new_oid != fav_oid:
                            bot['fav_order_id'] = _new_oid
                            if fav_side == 'yes':
                                bot['yes_order_id'] = _new_oid
                            else:
                                bot['no_order_id'] = _new_oid
                    finally:
                        _phantom_drop_lock.release()
                    bot['fav_price'] = amend_price
                    if fav_side == 'yes':
                        bot['yes_price'] = amend_price
                    else:
                        bot['no_price'] = amend_price
                    # Stragglers: sell back extra contracts — hedge window is gone
                    if _extra_needed > 0:
                        dog_side = bot.get('dog_side', 'yes')
                        print(f'   🔙 STRAGGLER SELLBACK: {bot_id} {_extra_needed} late fills — selling back (hedge window closed)')
                        bot_log('PHANTOM_LADDER_STRAGGLER_SELLBACK', bot_id, {
                            'extra_qty': _extra_needed, 'dog_side': dog_side,
                            'old_hedge_qty': _old_hedge_qty, 'total_fills': new_total_fill,
                        })
                        try:
                            _sold, _sell_info = execute_sell(bot.get('ticker',''), dog_side, _extra_needed,
                                                            reason=f'phantom_straggler_{bot_id}')
                            _sell_p = (_sell_info or {}).get('avg_price', 0) if isinstance(_sell_info, dict) else 0
                            _strag_loss = max(0, new_avg - _sell_p) * _extra_needed if _sell_p else new_avg * _extra_needed
                            session_pnl['gross_loss_cents'] += _strag_loss
                            print(f'   🔙 STRAGGLER SOLD: {bot_id} {_extra_needed}× @ {_sell_p}¢ loss={_strag_loss}¢')
                            bot_log('PHANTOM_LADDER_STRAGGLER_SOLD', bot_id, {
                                'qty': _extra_needed, 'sell_price': _sell_p, 'loss': _strag_loss,
                            })
                        except Exception as _se:
                            print(f'   ⚠ STRAGGLER SELLBACK FAIL: {bot_id}: {_se}')
                    print(f'   📈 LATE FILL AMEND: {bot_id} qty={new_total_fill} avg={new_avg}¢ hedge@{amend_price}¢ (walk+{walk_offset}¢)')
                    bot_log('PHANTOM_LADDER_LATE_FILL_AMEND', bot_id, {
                        'new_total_fill': new_total_fill, 'new_avg': new_avg,
                        'amend_price': amend_price, 'walk_offset': walk_offset,
                        'late_fill_qty': late_fill_qty,
                    })
                    _audit('PHANTOM_LADDER_LATE_FILL_AMEND', bot_id, {
                        'ticker': ticker, 'new_qty': new_total_fill, 'amend_price': amend_price,
                    })
                except Exception as ae:
                    # Amend failed — restore hedge_qty to avoid state mismatch
                    bot['hedge_qty'] = _old_hedge_qty_before
                    print(f'   ⚠ LATE FILL AMEND FAIL: {bot_id}: {ae} — restored hedge_qty={_old_hedge_qty_before}')
                    bot_log('PHANTOM_LADDER_LATE_FILL_AMEND_FAIL', bot_id, {
                        'error': str(ae)[:300], 'new_total_fill': new_total_fill,
                        'amend_price': amend_price, 'restored_hedge_qty': _old_hedge_qty_before,
                    }, level='ERROR')
            save_state()

        threading.Thread(target=_cancel_and_verify_rungs, args=(bot_id, bot), daemon=True).start()
        save_state()
    except Exception as e:
        print(f'❌ PHANTOM HEDGE {bot_id}: {e}')
        bot_log('PHANTOM_LADDER_WS_HEDGE_ERROR', bot_id, {'error': str(e)[:300], 'path': 'ws_fast'}, level='ERROR')
        _audit('PHANTOM_LADDER_WS_HEDGE_ERROR', bot_id, {'error': str(e)[:200]})
        bot = active_bots.get(bot_id)
        if bot:
            bot['status'] = 'ladder_filled_no_fav'
            save_state()
    finally:
        bot = active_bots.get(bot_id)
        if bot:
            bot['_hedge_thread_active'] = False


def _ladder_sweep_then_hedge(bot_id):
    """Fire immediately on first rung fill — cancel unfilled rungs + hedge.
    The ~100ms of API calls to cancel orders IS the sweep window:
    any fills that arrive via WS during that time get included automatically."""
    try:
        bot = active_bots.get(bot_id)
        if not bot or bot.get('status') != 'ladder_posted':
            return
        print(f'⚡ PHANTOM INSTANT HEDGE: {bot_id} — cancelling unfilled + hedging')
        bot['dog_filled_at'] = time.time()
        _execute_phantom_ladder_hedge(bot_id)
    finally:
        # Clear sweep flag so monitor can retry if thread crashed
        bot = active_bots.get(bot_id)
        if bot and bot.get('status') == 'ladder_posted':
            bot['_sweep_timer_started'] = False


def _phantom_ladder_sell_back(bot_id, bot, avg_price, fav_bid, total_cost, actions):
    """Sell all filled ladder rung contracts back."""
    now = time.time()
    ticker = bot['ticker']
    dog_side = bot['dog_side']
    total_fill_qty = bot.get('hedge_qty') or sum(r.get('fill_qty', 0) for r in bot.get('rungs', []))
    bot_log('PHANTOM_LADDER_SELLBACK_START', bot_id, {
        'avg_price': avg_price, 'fav_bid': fav_bid, 'total_cost': total_cost,
        'total_fill_qty': total_fill_qty, 'dog_side': dog_side, 'ticker': ticker,
    })
    _audit('PHANTOM_LADDER_SELLBACK_START', bot_id, {
        'ticker': ticker, 'avg_price': avg_price, 'total_fill_qty': total_fill_qty,
    })

    # Verify actual fills by checking each rung's ORDER on Kalshi (not positions —
    # positions are aggregate across all bots on the same ticker)
    try:
        verified_fill = 0
        for rung in bot.get('rungs', []):
            oid = rung.get('order_id')
            if not oid:
                verified_fill += rung.get('fill_qty', 0)
                continue
            try:
                api_read_limiter.wait()
                resp = kalshi_client.get_order(oid)
                ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
                actual = _parse_fill_count(ord_data)
                if actual > rung.get('fill_qty', 0):
                    print(f'⚠ PHANTOM SELLBACK: {bot_id} rung @{rung.get("price")}¢ local={rung.get("fill_qty",0)} Kalshi={actual} — updating')
                    rung['fill_qty'] = actual
                verified_fill += actual
            except Exception:
                verified_fill += rung.get('fill_qty', 0)
        if verified_fill > total_fill_qty:
            print(f'⚠ PHANTOM SELLBACK ORDER CHECK: {bot_id} local={total_fill_qty} verified={verified_fill} — using verified')
            bot_log('PHANTOM_LADDER_SELLBACK_VERIFY_UPDATE', bot_id, {
                'local_fill': total_fill_qty, 'verified_fill': verified_fill,
            })
            total_fill_qty = verified_fill
            bot['hedge_qty'] = verified_fill
    except Exception as vf_err:
        print(f'⚠ PHANTOM SELLBACK order check failed: {bot_id}: {vf_err} — using local qty')
        bot_log('PHANTOM_LADDER_SELLBACK_VERIFY_FAIL', bot_id, {'error': str(vf_err)[:300]}, level='ERROR')

    if total_fill_qty <= 0:
        bot_log('PHANTOM_LADDER_SELLBACK_ZERO_QTY', bot_id, {'total_fill_qty': 0, 'status': 'completed'})
        bot['status'] = 'completed'
        bot['completed_at'] = now
        save_state()
        return

    sold_back, sell_info = execute_sell(ticker, dog_side, total_fill_qty,
                                        reason=f'ladder_sellback_{bot_id}')

    if not sold_back:
        attempts = bot.get('_sellback_attempts', 0) + 1
        bot['_sellback_attempts'] = attempts
        bot_log('PHANTOM_LADDER_SELLBACK_FAIL', bot_id, {
            'attempt': attempts, 'total_fill_qty': total_fill_qty,
            'avg_price': avg_price, 'dog_side': dog_side,
        }, level='WARN')
        # After 3 failed attempts, verify position on Kalshi before giving up
        if attempts >= 3:
            # CHECK: does the position actually exist on Kalshi?
            try:
                api_read_limiter.wait()
                _pos_resp = kalshi_client.get_positions(ticker=ticker)
                _positions = _pos_resp.get('market_positions', _pos_resp.get('positions', []))
                for _p in _positions:
                    if _p.get('ticker') == ticker:
                        _actual = abs(_parse_position_qty(_p))
                        if _actual > 0:
                            # Position EXISTS — don't ghost-complete, keep retrying
                            print(f'⚠ PHANTOM SELLBACK: {bot_id} — {attempts} sells failed but Kalshi still shows {_actual} contracts! Keeping alive.')
                            bot_log('PHANTOM_LADDER_SELLBACK_POSITION_EXISTS', bot_id, {
                                'attempts': attempts, 'kalshi_qty': _actual,
                                'resetting': True,
                            })
                            bot['_sellback_attempts'] = 0  # reset so we retry
                            bot['status'] = 'ladder_filled_no_fav'
                            actions.append({'bot_id': bot_id, 'action': 'sellback_position_exists', 'kalshi_qty': _actual})
                            return
            except Exception as _pe:
                print(f'⚠ PHANTOM SELLBACK position check failed: {_pe} — proceeding with ghost complete')
                bot_log('PHANTOM_LADDER_SELLBACK_POS_CHECK_FAIL', bot_id, {'error': str(_pe)[:300]}, level='ERROR')
            print(f'🔧 PHANTOM SELLBACK GHOST: {bot_id} — {attempts} sell attempts failed, position confirmed gone. Completing bot.')
            bot_log('PHANTOM_LADDER_SELLBACK_GHOST', bot_id, {
                'attempts': attempts, 'est_loss': avg_price * total_fill_qty,
                'total_fill_qty': total_fill_qty,
            })
            # Record estimated loss so trade doesn't disappear from history
            est_loss = avg_price * total_fill_qty  # worst case: dog price × qty
            session_pnl['gross_loss_cents'] += est_loss
            session_pnl['stopped_bots'] += 1
            _record_trade({
                'bot_id': bot_id, 'ticker': bot.get('ticker', ''),
                'yes_price': avg_price if bot.get('dog_side') == 'yes' else 0,
                'no_price': avg_price if bot.get('dog_side') == 'no' else 0,
                'quantity': total_fill_qty, 'profit_cents': 0, 'loss_cents': est_loss,
                'fee_cents': 0, 'result': 'ladder_sellback_ghost',
                'exit_via': 'ghost_complete', 'timestamp': now,
                'bot_category': 'anchor_ladder',
            }, bot)
            bot['status'] = 'completed'
            bot['completed_at'] = now
            bot['_trade_recorded'] = True
            save_state()
            return
        print(f'⚠ PHANTOM SELLBACK FAILED: {bot_id} — sell did not fill, keeping bot alive for retry (attempt {attempts})')
        _audit('LADDER_SELLBACK_FAIL', bot_id, {'ticker': ticker, 'dog_side': dog_side, 'attempt': attempts})
        bot['status'] = 'ladder_filled_no_fav'  # go back so monitor retries
        actions.append({'bot_id': bot_id, 'action': 'sellback_retry', 'attempt': attempts})
        return

    already_cleared = (sell_info or {}).get('already_cleared', False)
    sell_price = (sell_info or {}).get('actual_fill_price', 0)
    bot_log('PHANTOM_LADDER_SELLBACK_SUCCESS', bot_id, {
        'sold_back': True, 'sell_price': sell_price, 'avg_price': avg_price,
        'total_fill_qty': total_fill_qty, 'already_cleared': already_cleared,
    })

    if already_cleared and not sell_price:
        # Position was already gone — but re-verify after 2s to catch late fills
        # (amend race: fav order fills 1 contract during cancel+repost, settles late)
        time.sleep(2)
        _recheck_qty = 0
        try:
            api_read_limiter.wait()
            _recheck_resp = kalshi_client.get_positions(ticker=ticker)
            for _p in _recheck_resp.get('market_positions', _recheck_resp.get('positions', [])):
                if _p.get('ticker') == ticker:
                    _net = _parse_position_qty(_p)
                    _recheck_qty = abs(_net)
                    break
        except Exception:
            pass
        if _recheck_qty > 0:
            print(f'⚠ PHANTOM SELLBACK LATE FILL: {bot_id} | re-check found {_recheck_qty} contracts after 2s — selling')
            bot_log('PHANTOM_LADDER_SELLBACK_LATE_FILL', bot_id, {
                'recheck_qty': _recheck_qty, 'ticker': ticker,
            })
            # Sell the late-fill contracts
            try:
                _late_sell_ok, _late_info = _execute_sell(
                    ticker, dog_side, _recheck_qty, bot_id, reason='late_fill_cleanup')
                if _late_sell_ok:
                    _late_price = (_late_info or {}).get('actual_fill_price', 0)
                    print(f'   ✅ Late fill sold: {_recheck_qty}x @{_late_price}¢')
            except Exception as _ls_err:
                print(f'   ⚠ Late fill sell failed: {_ls_err}')
        else:
            print(f'🔙 PHANTOM SELLBACK: {bot_id} | position confirmed cleared after re-check')
        bot_log('PHANTOM_LADDER_SELLBACK_ALREADY_CLEARED', bot_id, {
            'avg_price': avg_price, 'total_fill_qty': total_fill_qty,
            'recheck_qty': _recheck_qty,
        })
        loss_cents = 0
        sell_price = avg_price  # assume break-even since we don't know actual price
    else:
        loss_cents = (avg_price - sell_price) * total_fill_qty if sell_price else avg_price * total_fill_qty

    # Calculate fees: maker fee on original buy (post_only) + taker fee on sell (crosses spread)
    buy_fee = sum(
        _kalshi_side_fee_cents(r['price'], r.get('fill_qty', 0))
        for r in bot.get('rungs', []) if r.get('fill_qty', 0) > 0
    )
    sell_fee = _kalshi_taker_side_fee_cents(sell_price, total_fill_qty) if sell_price else 0
    total_fees = buy_fee + sell_fee
    loss_cents += total_fees

    # Handle profitable sellbacks (sell_price > avg_price minus fees)
    if loss_cents < 0:
        profit_cents = abs(loss_cents)
        loss_cents = 0
        session_pnl['gross_profit_cents'] = session_pnl.get('gross_profit_cents', 0) + profit_cents
    else:
        profit_cents = 0
        session_pnl['gross_loss_cents'] += loss_cents

    session_pnl['stopped_bots'] += 1
    bot['_trade_recorded'] = True

    # Repeat logic — sellback counts as a cycle, re-anchor if repeats remain
    repeats_done_now = bot.get('repeats_done', 0) + 1
    bot['repeats_done'] = repeats_done_now
    repeat_total = bot.get('repeat_count', 0)
    if repeats_done_now <= repeat_total:
        bot['status'] = 'waiting_repeat'
        bot['waiting_repeat_since'] = now
        bot['dog_filled_at'] = None
        bot['raw_hedge_ms'] = None
        bot['hedge_latency_ms'] = None
        bot['fav_order_id'] = None
        bot['fav_fill_qty'] = 0
        bot['total_dog_fill_qty'] = 0
        bot['_hedge_fired'] = False
        bot['_trade_recorded'] = False
        bot['_sellback_attempts'] = 0
        for rung in bot.get('rungs', []):
            rung['fill_qty'] = 0
            rung['order_id'] = None
        print(f'🔄 PHANTOM SELLBACK REPEAT: {bot_id} cycle {repeats_done_now}/{repeat_total} — re-anchoring')
        bot_log('PHANTOM_LADDER_SELLBACK_REPEAT', bot_id, {
            'cycle': repeats_done_now, 'total': repeat_total,
            'profit_cents': profit_cents, 'loss_cents': loss_cents,
        })
        _audit('LADDER_SELLBACK_REPEAT', bot_id, {'ticker': ticker, 'cycle': repeats_done_now, 'total': repeat_total})
        _audit_position_check(bot_id, ticker, dog_side, 'entering_sellback_repeat')
    else:
        bot['status'] = 'stopped'
        bot['stopped_at'] = now
        bot_log('PHANTOM_LADDER_SELLBACK_STOPPED', bot_id, {
            'profit_cents': profit_cents, 'loss_cents': loss_cents,
            'sell_price': sell_price, 'avg_price': avg_price,
            'total_fill_qty': total_fill_qty,
        })

    filled_rungs_detail = [
        {'price': r['price'], 'qty': r.get('fill_qty', 0)}
        for r in bot.get('rungs', []) if r.get('fill_qty', 0) > 0
    ]

    bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + (profit_cents - loss_cents)
    print(f'🔙 PHANTOM SELLBACK: {bot_id} | dog={dog_side.upper()} avg@{avg_price}¢ → sold@{sell_price}¢ | qty={total_fill_qty} | {"profit" if profit_cents else "loss"}={profit_cents or loss_cents}¢ | fav_bid={fav_bid}¢ ceiling={total_cost}¢')
    _audit('LADDER_SELLBACK', bot_id, {'ticker': ticker, 'dog_side': dog_side, 'qty': total_fill_qty, 'sold': True})
    _audit_position_check(bot_id, ticker, dog_side, 'after_ladder_sellback')

    # Verify no leftover positions from race condition fills
    try:
        api_read_limiter.wait()
        _pos_resp = kalshi_client.get_positions(ticker=ticker)
        _positions = _pos_resp.get('market_positions', _pos_resp.get('positions', []))
        _leftover = 0
        for _p in _positions:
            if _p.get('ticker') == ticker:
                _pqty = _parse_position_qty(_p)
                if (dog_side == 'yes' and _pqty > 0) or (dog_side == 'no' and _pqty < 0):
                    _leftover = abs(_pqty)
        _leftover = min(_leftover, total_fill_qty)  # cap at this bot's qty
        if _leftover > 0:
            _sold, _sell_info = execute_sell(ticker, dog_side, _leftover,
                                             reason=f'phantom_sellback_leftover_{bot_id}')
            _sell_price = (_sell_info or {}).get('avg_price', 0) if isinstance(_sell_info, dict) else 0
            _extra_loss = max(0, avg_price - _sell_price) * _leftover if _sell_price else avg_price * _leftover
            loss_cents += _extra_loss
            session_pnl['gross_loss_cents'] += _extra_loss
            bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) - _extra_loss
            print(f'🔙 PHANTOM SELLBACK LEFTOVER: {bot_id} {_leftover} extra contracts sold @{_sell_price}¢ extra_loss={_extra_loss}¢')
            bot_log('PHANTOM_LADDER_SELLBACK_LEFTOVER', bot_id, {
                'leftover': _leftover, 'sell_price': _sell_price, 'extra_loss': _extra_loss,
            })
    except Exception as _pe:
        print(f'⚠ PHANTOM SELLBACK LEFTOVER CHECK FAIL: {bot_id}: {_pe}')

    _record_trade({
        'bot_id': bot_id, 'ticker': ticker,
        'yes_price': avg_price if dog_side == 'yes' else (sell_price or fav_bid),
        'no_price': avg_price if dog_side == 'no' else (sell_price or fav_bid),
        'quantity': total_fill_qty,
        'profit_cents': profit_cents, 'loss_cents': loss_cents, 'fee_cents': total_fees,
        'result': 'ladder_sellback',
        'exit_via': f'sell_back_{dog_side}',
        'first_leg': dog_side,
        'dog_side': dog_side,
        'dog_price': avg_price,
        'fav_price': fav_bid,
        'sell_back_price': sell_price,
        'hard_ceiling_total': total_cost,
        'rungs_detail': filled_rungs_detail,
        'hedge_latency_ms': bot.get('hedge_latency_ms'),
        'raw_hedge_ms': bot.get('raw_hedge_ms'),
        'timestamp': now,
        'placed_at': bot.get('created_at', now),
        'arb_width': bot.get('target_width', 0),
        'game_phase': bot.get('game_phase', 'live'),
        'game_context': _get_game_context(ticker),
        'fill_source': 'ladder_sellback',
        'bot_category': 'anchor_ladder',
        'cross_market': bot.get('cross_market', False),
        'hedge_ticker': bot.get('hedge_ticker', ''),
    }, bot)
    save_state()
    actions.append({'bot_id': bot_id, 'action': 'ladder_sellback', 'loss_cents': loss_cents})


def _execute_ws_dog_post(bot_id):
    """
    Post the underdog leg immediately after the favorite fills.
    Called from WS fill handler in a background thread.
    """
    with ws_fill_lock:
        bot = active_bots.get(bot_id)
        if not bot or bot['status'] in ('stopped', 'completed'):
            if bot:
                bot.pop('_ws_fill_handling', None)
            return

        # Double-check status — another thread may have already handled this
        if bot['status'] != 'fav_posted':
            bot.pop('_ws_fill_handling', None)
            return

        now = time.time()
        ticker = bot['ticker']
        qty = bot['quantity']
        fav_side = bot.get('fav_side', 'yes')
        dog_side = bot.get('dog_side', 'no' if fav_side == 'yes' else 'yes')
        dog_price = bot.get('dog_price', bot['no_price'] if dog_side == 'no' else bot['yes_price'])
        fav_price = bot.get('fav_price', bot['yes_price'] if fav_side == 'yes' else bot['no_price'])
        fav_filled = bot.get('yes_fill_qty', 0) if fav_side == 'yes' else bot.get('no_fill_qty', 0)

        try:
            # Fetch fresh orderbook to verify arb is still viable
            try:
                api_read_limiter.wait()
                ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
                ob = ob_data.get('orderbook', ob_data)
                if dog_side == 'no':
                    dog_levels = sorted(ob.get('no', []),
                        key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                    live_dog_bid = (dog_levels[0][0] if isinstance(dog_levels[0], list) else dog_levels[0].get('price', 0)) if dog_levels else 0
                else:
                    dog_levels = sorted(ob.get('yes', []),
                        key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                    live_dog_bid = (dog_levels[0][0] if isinstance(dog_levels[0], list) else dog_levels[0].get('price', 0)) if dog_levels else 0

                # NEVER post above the current bid
                if dog_price > live_dog_bid and live_dog_bid > 0:
                    dog_price = live_dog_bid
                    print(f'📉 WS PHANTOM: Adjusted {dog_side.upper()} price to bid {live_dog_bid}¢')
            except Exception as ob_err:
                print(f'⚠ WS PHANTOM: Orderbook check failed: {ob_err} — using planned price')

            # Verify arb width still makes sense
            actual_profit = 100 - fav_price - dog_price
            min_width = max(1, bot.get('arb_width', bot.get('profit_per', 3)) // 2)
            if actual_profit < min_width:
                print(f'⚠ WS PHANTOM: Arb no longer viable for {bot_id}: profit={actual_profit}¢ < min={min_width}¢ — letting SL handle')
                if fav_side == 'yes':
                    bot['status'] = 'yes_filled'
                else:
                    bot['status'] = 'no_filled'
                bot['first_fill_at'] = now
                bot['first_leg'] = fav_side
                bot['posted_at'] = now
                bot.pop('_ws_fill_handling', None)
                save_state()
                return

            # Post the underdog order
            api_rate_limiter.wait()
            if dog_side == 'no':
                dog_order = kalshi_client.create_order(
                    ticker=ticker, side='no', action='buy',
                    count=qty, no_price=dog_price, post_only=True)
                dog_oid = _extract_order_id(dog_order, f'WS phantom dog post {bot_id}')
                if not dog_oid:
                    return
                bot['no_order_id'] = dog_oid
                bot['no_price'] = dog_price
                bot['yes_fill_qty'] = fav_filled
                bot['status'] = 'yes_filled'
            else:
                dog_order = kalshi_client.create_order(
                    ticker=ticker, side='yes', action='buy',
                    count=qty, yes_price=dog_price, post_only=True)
                dog_oid = _extract_order_id(dog_order, f'WS phantom dog post {bot_id}')
                if not dog_oid:
                    return
                bot['yes_order_id'] = dog_oid
                bot['yes_price'] = dog_price
                bot['no_fill_qty'] = fav_filled
                bot['status'] = 'no_filled'

            bot['first_fill_at'] = now
            bot['first_leg'] = fav_side
            bot['posted_at'] = now
            bot['profit_per'] = 100 - bot['yes_price'] - bot['no_price']

            # Subscribe to the new order's ticker on WS (already subscribed, but ensure fill tracking)
            if ws_manager and ws_manager.connected:
                ws_manager.add_ticker(ticker)

            bot_log('FAV_FILLED_DOG_POSTED', bot_id, {
                'fav_side': fav_side, 'fav_price': fav_price,
                'dog_side': dog_side, 'dog_price': dog_price,
                'profit_per': bot['profit_per'],
                'source': 'ws_realtime'
            })
            print(f'⚡ WS FAV-FILL → PHANTOM POSTED: {bot_id} {fav_side.upper()} filled at {fav_price}¢ → '
                  f'posted {dog_side.upper()} at {dog_price}¢ '
                  f'(profit target: {bot["profit_per"]}¢) [INSTANT]')
            save_state()

        except Exception as err:
            print(f'⚠ WS PHANTOM post failed for {bot_id}: {err} — monitor will retry')

        bot.pop('_ws_fill_handling', None)

        # ── Race-condition guard: dog side may have filled while we held the lock ──
        # If the WS fill handler already incremented no_fill_qty (or yes_fill_qty)
        # while _ws_fill_handling was True, it would have skipped completion.
        # Re-check now and trigger completion if both legs are done.
        if bot and bot.get('status') not in ('stopped', 'completed', 'waiting_repeat'):
            yes_f = bot.get('yes_fill_qty', 0)
            no_f  = bot.get('no_fill_qty', 0)
            q     = bot.get('quantity', 0)
            if yes_f >= q and no_f >= q:
                print(f'⚡ WS RACE FIX: {bot_id} dog already filled during post — completing now!')
                bot['_ws_fill_handling'] = True
                # Release lock briefly, then call completion
                threading.Thread(
                    target=_execute_ws_completion,
                    args=(bot_id,),
                    daemon=True
                ).start()


def _execute_ws_completion(bot_id):
    """
    Handle both-legs-filled completion instantly from WS fill event.
    Called in a background thread.
    """
    with ws_fill_lock:
        bot = active_bots.get(bot_id)
        if not bot or bot['status'] in ('stopped', 'completed'):
            if bot:
                bot.pop('_ws_fill_handling', None)
            return

        # ── Guard: if monitor is amending this bot, let the monitor record the trade ──
        # Without this, BOTH WS handler and monitor record a trade → double-count PnL.
        if bot.get('status') in ('amending_yes', 'amending_no'):
            print(f'⚡ WS COMPLETION SKIP: {bot_id} is {bot["status"]} — monitor will record trade')
            bot.pop('_ws_fill_handling', None)
            return

        # ── Guard: if monitor already recorded a trade for this cycle, skip ──
        if bot.get('_trade_recorded'):
            print(f'⚡ WS COMPLETION SKIP: {bot_id} — trade already recorded by monitor')
            bot.pop('_ws_fill_handling', None)
            return

        now = time.time()
        ticker = bot['ticker']
        qty = bot['quantity']

        # ── REPEAT check runs unconditionally — API call failures must not prevent it ──
        repeats_done_now = bot.get('repeats_done', 0) + 1
        bot['repeats_done'] = repeats_done_now
        repeat_total = bot.get('repeat_count', 0)
        will_repeat = repeats_done_now <= repeat_total

        bot['completed_at'] = now
        bot['status'] = 'waiting_repeat' if will_repeat else 'completed'
        if will_repeat:
            bot['waiting_repeat_since'] = time.time()
            bot['first_fill_at'] = None
            bot['first_leg'] = None
            print(f'🔄 WS REPEAT: {bot_id} entering waiting_repeat — cycle {repeats_done_now}/{repeat_total}')

        # Record trade + P&L — wrapped separately so failures don't break repeat logic
        try:
            actual_yes = get_actual_fill_price(bot['yes_order_id'], 'yes')
            actual_no  = get_actual_fill_price(bot['no_order_id'], 'no')
            real_yes = actual_yes if actual_yes else bot['yes_price']
            real_no  = actual_no  if actual_no  else bot['no_price']
            fee = kalshi_fee_cents(real_yes, real_no, qty)
            profit_cents = (100 - real_yes - real_no) * qty - fee

            session_pnl['gross_profit_cents'] += profit_cents
            session_pnl['completed_bots']     += 1
            bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + profit_cents

            _record_trade({
                'bot_id': bot_id, 'ticker': ticker,
                'yes_price': real_yes, 'no_price': real_no,
                'original_yes': bot['yes_price'], 'original_no': bot['no_price'],
                'quantity': qty, 'profit_cents': profit_cents,
                'fee_cents': fee,
                'result': 'completed', 'timestamp': now,
                'verified_prices': actual_yes is not None and actual_no is not None,
                'placed_at': bot.get('created_at', now),
                'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                'arb_width': bot.get('arb_width', bot.get('profit_per', 0)),
                'first_leg': bot.get('first_leg', ''),
                'fill_duration_s': round(now - bot['first_fill_at']) if bot.get('first_fill_at') else None,
                'game_phase': bot.get('game_phase', ''),
                'flip_threshold': bot.get('flip_threshold', FLIP_THRESHOLD_CENTS),
                'stop_loss_cents': bot.get('stop_loss_cents', 0),
                'game_context': _get_game_context(ticker),
                'repeats_done': repeats_done_now,
                'repeat_count': repeat_total,
                'fill_source': 'ws_realtime',
            }, bot)
            bot['_trade_recorded'] = True  # Prevent monitor from double-recording
            bot_log('ARB_COMPLETED', bot_id, {
                'real_yes': real_yes, 'real_no': real_no, 'profit_cents': profit_cents,
                'fill_duration_s': round(now - bot['first_fill_at']) if bot.get('first_fill_at') else None,
                'source': 'ws_realtime', 'will_repeat': will_repeat,
            })
            print(f'⚡ WS COMPLETED: {bot_id} +{profit_cents}¢ (YES={real_yes}¢ NO={real_no}¢)'
                  + (f' → repeat {repeats_done_now}/{repeat_total}' if will_repeat else ' → done'))
            _audit('WS_COMPLETION', bot_id, {'ticker': ticker, 'yes_fill': bot.get('yes_fill_qty'), 'no_fill': bot.get('no_fill_qty'), 'will_repeat': will_repeat})
            _audit_position_check(bot_id, ticker, bot.get('dog_side', 'yes'), 'after_ws_completion')
            # Queue action so frontend gets confetti/sound/notification
            with _pending_ws_actions_lock:
                _pending_ws_actions.append({'bot_id': bot_id, 'action': 'completed', 'profit_cents': profit_cents})
                if will_repeat:
                    _pending_ws_actions.append({
                        'bot_id': bot_id, 'action': 'repeat_spawned',
                        'repeat_num': repeats_done_now, 'repeat_total': repeat_total,
                        'yes_price': bot.get('yes_price', 0), 'no_price': bot.get('no_price', 0),
                        'profit_per': 100 - bot.get('yes_price', 0) - bot.get('no_price', 0),
                    })
        except Exception as err:
            print(f'⚠ WS trade record failed for {bot_id}: {err} — repeat status already set, continuing')

        save_state()

        bot.pop('_ws_fill_handling', None)


# ─── Session P&L (Upgrade #6: P&L dashboard) ──────────────────────────────────

session_pnl = {
    'gross_profit_cents': 0,
    'gross_loss_cents':   0,
    'completed_bots':     0,
    'stopped_bots':       0,
    'session_start':      time.time(),
    'day_key':            datetime.now(AZ_TZ).date().isoformat(),  # for daily auto-reset
}

# ─── LATENCY TRACKER ──────────────────────────────────────────────────────────
from collections import deque

_latency_log = {
    'order_place':    deque(maxlen=200),
    'orderbook':      deque(maxlen=200),
    'fill_to_hedge_phantom': deque(maxlen=50),
    'fill_to_hedge_apex':    deque(maxlen=50),
    'raw_hedge_phantom':     deque(maxlen=50),
    'raw_hedge_apex':        deque(maxlen=50),
    'api_generic':    deque(maxlen=200),
    'api_ping':       deque(maxlen=200),
}
_latency_lock = threading.Lock()

def _record_latency(category, ms, meta=None):
    """Record a latency measurement."""
    with _latency_lock:
        entry = {'ms': round(ms, 1), 'ts': time.time()}
        if meta:
            entry.update(meta)
        _latency_log[category].append(entry)

def _latency_stats(category):
    """Get min/avg/max/p95/count for a latency category."""
    with _latency_lock:
        entries = list(_latency_log[category])
    if not entries:
        return {'min': 0, 'avg': 0, 'max': 0, 'p95': 0, 'count': 0, 'recent': []}
    vals = [e['ms'] for e in entries]
    vals_sorted = sorted(vals)
    p95_idx = max(0, int(len(vals_sorted) * 0.95) - 1)
    return {
        'min':    round(vals_sorted[0], 1),
        'avg':    round(sum(vals) / len(vals), 1),
        'max':    round(vals_sorted[-1], 1),
        'p95':    round(vals_sorted[p95_idx], 1),
        'count':  len(vals),
        'recent': [e for e in entries[-10:]],  # last 10
    }

def _timed_orderbook(ticker, **kwargs):
    """Wrapper around kalshi_client.get_market_orderbook with latency tracking."""
    t0 = time.time()
    result = kalshi_client._original_get_market_orderbook(ticker, **kwargs)
    _record_latency('orderbook', (time.time() - t0) * 1000, {'ticker': ticker})
    return result

def _patch_kalshi_orderbook():
    """Monkey-patch the orderbook method to add latency tracking."""
    if kalshi_client and not hasattr(kalshi_client, '_original_get_market_orderbook'):
        kalshi_client._original_get_market_orderbook = kalshi_client.get_market_orderbook
        kalshi_client.get_market_orderbook = _timed_orderbook

# Per-day reset timestamps.  Maps "YYYY-MM-DD" → float-timestamp.
# Trades on that day BEFORE the stored timestamp are excluded from P&L.
# Set via /api/pnl/reset — persisted in data.json.
pnl_resets: dict = {}  # e.g. {'2026-03-12': 1773350487.02}

def _pnl_reset_for_day(day: str) -> float:
    """Return the reset-timestamp for a given date string, or 0.0 if none."""
    return pnl_resets.get(day, 0.0)

def auto_reset_daily_pnl():
    """Reset P&L counters if the day has changed since last check."""
    global session_pnl
    today = datetime.now(AZ_TZ).date().isoformat()
    if session_pnl.get('day_key') != today:
        print(f'📅 New day detected ({session_pnl.get("day_key")} → {today}) — resetting daily P&L')
        session_pnl = {
            'gross_profit_cents': 0,
            'gross_loss_cents':   0,
            'completed_bots':     0,
            'stopped_bots':       0,
            'session_start':      time.time(),
            'day_key':            today,
        }
        save_state()

# ─── Bot Config (Upgrades #4, #8) ─────────────────────────────────────────────
REPOST_AFTER_MINUTES = 3    # Re-post orders that haven't filled after this long (fallback timer)


def _phantom_gap_threshold(bot, current_dog_bid):
    """Adaptive gap threshold based on recent bid volatility.
    Calm market (bid moved <3¢ in 60s) → 3¢ gap triggers repost, 15s cooldown
    Normal (3-8¢ in 60s) → 5¢ gap, 20s cooldown
    Volatile (>8¢ in 60s) → 8¢ gap, 30s cooldown
    Returns (gap_threshold, cooldown_seconds)."""
    bid_history = bot.get('_bid_history', [])
    now = time.time()
    bid_history.append((now, current_dog_bid))
    # Trim to last 60s
    bid_history = [(t, b) for t, b in bid_history if now - t <= 60]
    bot['_bid_history'] = bid_history
    if len(bid_history) < 2:
        bot['_volatility'] = 0
        bot['_market_condition'] = 'calm'
        bot['_gap_threshold'] = 3
        bot['_gap_cooldown'] = 15
        return 3, 15
    bids = [b for _, b in bid_history]
    volatility = max(bids) - min(bids)
    if volatility > 8:
        thresh, cd, cond = 8, 30, 'volatile'
    elif volatility > 3:
        thresh, cd, cond = 5, 20, 'normal'
    else:
        thresh, cd, cond = 3, 15, 'calm'
    bot['_volatility'] = volatility
    bot['_market_condition'] = cond
    bot['_gap_threshold'] = thresh
    bot['_gap_cooldown'] = cd
    return thresh, cd
STALE_CANCEL_MINUTES = 10   # Resize to matched fills after this long

# ── Arb Bot Stop-Loss: Flip Threshold ──────────────────────────────────────────
# Game markets use a FLIP THRESHOLD instead of cent-based stop-loss.
# A favorite entered at ≥60¢ triggers: sell when bid drops to max(entry-15, 60).
# e.g. entry=80¢ → trigger=65¢ (15¢ room); entry=70¢ → trigger=60¢ (floor).
# This caps max loss at 15¢ regardless of entry, while giving high entries
# proportionally more room before cutting. Entries below 60¢ ride to settlement.
# Watch bots (straight bets / props) keep the old instant entry-minus-X SL.
FLIP_THRESHOLD_CENTS = 60   # Default hard floor: trigger never goes below 60¢
FLIP_ENTRY_MARGIN   = 15   # Trigger = max(entry-15, min(floor, entry-10)) — always gives ≥10¢ room
MIN_FAV_ENTRY_CENTS = 65    # Guardrail: never deploy fav side below 65¢ (65-69¢ entries use entry-10 floor)

# ─── Kalshi Milestones Cache (authoritative live detection for tennis) ────────
# Maps event_ticker → {status, start_date} from milestone data
_milestones_cache = {'data': {}, 'ts': 0}
_MILESTONES_CACHE_TTL = 60  # seconds

def _refresh_milestones_cache():
    """Fetch Kalshi milestones for tennis series — cached, lazy refresh."""
    global _milestones_cache
    if time.time() - _milestones_cache['ts'] < _MILESTONES_CACHE_TTL:
        return
    if not kalshi_client:
        return
    event_info = {}  # event_ticker → {status, start_date}
    for i, series in enumerate(('KXATPCHALLENGERMATCH', 'KXWTACHALLENGERMATCH', 'KXATPMATCH', 'KXWTAMATCH')):
        for attempt in range(2):
            try:
                if i > 0 or attempt > 0:
                    time.sleep(0.5)  # 500ms spacing to avoid 429s
                resp = kalshi_client.get_events(status='open', with_milestones=True, series_ticker=series)
                milestones = resp.get('milestones', [])
                events = resp.get('events', [])
                if not milestones:
                    print(f'🎾 DEBUG {series}: no milestones key. keys={list(resp.keys())[:5]}, events={len(events)}')
                    for ev in events:
                        ev_milestones = ev.get('milestones', [])
                        for ms in ev_milestones:
                            ms_status = ms.get('details', {}).get('status', 'not_started')
                            start_date = ms.get('start_date', '')
                            et = ev.get('event_ticker', '')
                            if et:
                                event_info[et] = {'status': ms_status, 'start_date': start_date}
                else:
                    for m in milestones:
                        ms_status = m.get('details', {}).get('status', 'not_started')
                        start_date = m.get('start_date', '')
                        for et in m.get('related_event_tickers', []):
                            event_info[et] = {'status': ms_status, 'start_date': start_date}
                break  # success
            except Exception as e:
                if attempt == 0 and '429' in str(e):
                    time.sleep(1.0)  # back off on rate limit
                    continue
                print(f'⚠ Milestones fetch failed for {series}: {e}')
                break
    _milestones_cache = {'data': event_info, 'ts': time.time()}
    live_events = [k for k, v in event_info.items() if _is_milestone_live(v)]
    if live_events:
        print(f'🎾 Milestones cache: {len(live_events)} live — {", ".join(live_events[:5])}')


def _is_milestone_live(info: dict) -> bool:
    """Determine if a tennis match is live from milestone data.
    Uses status if reliable, falls back to start_date for ATP/Challenger
    where Kalshi often leaves status as 'not_started' during live play."""
    if not info:
        return False
    status = info.get('status', '')
    if status == 'live':
        return True
    if status == 'ended':
        return False
    # status is 'not_started' but might be wrong — check start_date
    start_date = info.get('start_date', '')
    if start_date:
        try:
            from datetime import datetime, timezone
            sd = datetime.fromisoformat(start_date.replace('Z', '+00:00'))
            now = datetime.now(timezone.utc)
            # Match started (start_date in the past) → likely live
            if sd <= now:
                return True
        except Exception:
            pass
    return False


def _get_milestone_status(event_ticker: str):
    """Get milestone-derived live status for a tennis event.
    Returns 'live', 'not_started', 'ended', or None."""
    _refresh_milestones_cache()
    info = _milestones_cache['data'].get(event_ticker)
    if not info:
        return None
    if _is_milestone_live(info):
        return 'live'
    return info.get('status', 'not_started')

# ─── ESPN Live Game Cache (for auto-phase detection) ──────────────────────────
_espn_cache = {'data': {}, 'ts': 0}  # {team_abbr: {'live': bool, 'game_time': str, 'status': str}}
_ESPN_CACHE_TTL = 60  # seconds

# REST orderbook price cache — fallback when WS has no data (display only, 10s TTL)
_rest_price_cache = {}  # {ticker: {yes_bid, no_bid, yes_ask, no_ask, _ts}}

# Kalshi 3-letter codes that differ from ESPN abbreviations
_KALSHI_TO_ESPN = {
    'WAS': 'WSH', 'NYK': 'NY', 'NOP': 'NO', 'SAS': 'SA',
    'GSW': 'GS', 'UTA': 'UTAH', 'PHX': 'PHO',
}

# Reverse map ESPN → Kalshi for game time lookups
_ESPN_TO_KALSHI = {v: k for k, v in _KALSHI_TO_ESPN.items()}


def _parse_game_date(event_ticker: str) -> str:
    """Parse game date from event ticker like KXNBAGAME-26MAR05LALDEN → 'Mar 5'.
    Returns empty string if unable to parse."""
    parts = event_ticker.split('-')
    if len(parts) < 2:
        return ''
    date_match = re.match(r'^(\d{2})([A-Z]{3})(\d{2})', parts[1])
    if not date_match:
        return ''
    year_2d = date_match.group(1)
    month_abbr = date_match.group(2)  # 'MAR', 'APR', etc.
    day = int(date_match.group(3))
    # Format nicely: "Mar 5"
    month_map = {'JAN': 'Jan', 'FEB': 'Feb', 'MAR': 'Mar', 'APR': 'Apr',
                 'MAY': 'May', 'JUN': 'Jun', 'JUL': 'Jul', 'AUG': 'Aug',
                 'SEP': 'Sep', 'OCT': 'Oct', 'NOV': 'Nov', 'DEC': 'Dec'}
    month = month_map.get(month_abbr.upper(), month_abbr.capitalize())
    return f'{month} {day}'

def _refresh_espn_cache():
    """Fetch all ESPN scoreboards and cache team info including game times."""
    global _espn_cache
    if time.time() - _espn_cache['ts'] < _ESPN_CACHE_TTL:
        return
    team_info = {}  # {ABBR: {'live': bool, 'game_time': 'HH:MM', 'status': 'pre'|'in'|'post'}}
    sport_paths = {
        'nba': 'basketball/nba',
        'nhl': 'hockey/nhl',
        'nfl': 'football/nfl',
        'mlb': 'baseball/mlb',
        'ncaab': 'basketball/mens-college-basketball',
        'ncaaw': 'basketball/womens-college-basketball',
        'mls': 'soccer/usa.1',
        'epl': 'soccer/eng.1',
        'ucl': 'soccer/uefa.champions',
        'atp': 'tennis/atp',
        'wta': 'tennis/wta',
    }
    for sport, path in sport_paths.items():
        try:
            url = f'https://site.api.espn.com/apis/site/v2/sports/{path}/scoreboard'
            # NCAAB/NCAAW: groups=50 includes NIT/CBI/CIT (default only shows conf tournaments)
            params = {}
            if sport in ('ncaab', 'ncaaw'):
                params['groups'] = '50'
            resp = requests.get(url, params=params, timeout=4)
            resp.raise_for_status()
            raw_data = resp.json()

            # Tennis: flatten groupings into events using shared helper
            if sport in ('atp', 'wta'):
                raw_data = _flatten_tennis_scoreboard(raw_data)

            events = raw_data.get('events', [])
            for ev in events:
                comp = (ev.get('competitions') or [{}])[0]
                ev_status_obj = (ev.get('status') or {}).get('type', {})
                status = ev_status_obj.get('state', 'pre')
                short_detail = ev_status_obj.get('shortDetail', '').lower()
                # ESPN briefly marks halftime as 'post' — treat it as 'in'
                if status == 'post' and 'half' in short_detail:
                    status = 'in'
                is_live = status == 'in'
                # Game start time (ISO 8601) → local time string
                game_dt_str = ev.get('date', '')  # e.g. "2026-03-05T00:00Z"
                game_time = ''
                if game_dt_str:
                    try:
                        dt_utc = datetime.fromisoformat(game_dt_str.replace('Z', '+00:00'))
                        # Convert to ET (UTC-5, approximate — good enough for display)
                        dt_et = dt_utc - timedelta(hours=5)
                        game_time = dt_et.strftime('%-I:%M %p')
                    except Exception:
                        pass
                for team in comp.get('competitors', []):
                    abbr = (team.get('team') or {}).get('abbreviation', '')
                    if abbr:
                        abbr_upper = abbr.upper()
                        # Get scores for game context
                        competitors = comp.get('competitors', [])
                        home_score = 0
                        away_score = 0
                        for c in competitors:
                            try:
                                sc = int(c.get('score', 0))
                            except (ValueError, TypeError):
                                sc = 0
                            if c.get('homeAway') == 'home':
                                home_score = sc
                            else:
                                away_score = sc
                        # Period/quarter info
                        ev_status = ev.get('status', {})
                        period = ev_status.get('period', 0)
                        clock = ev_status.get('displayClock', '')
                        status_detail = (ev_status.get('type', {}).get('shortDetail', ''))
                        is_home = team.get('homeAway') == 'home'
                        team_own_score = home_score if is_home else away_score
                        team_opp_score = away_score if is_home else home_score

                        new_entry = {
                            'live': is_live,
                            'game_time': game_time,
                            'status': status,
                            'period': period,
                            'clock': clock,
                            'status_detail': status_detail,
                            'home_score': home_score,
                            'away_score': away_score,
                            'score_diff': abs(home_score - away_score),
                            'team_score': team_own_score,   # THIS team's score
                            'opp_score': team_opp_score,    # opponent's score
                            'espn_sport': sport,            # e.g. 'nba','atp','wta' — for cross-sport filtering
                            'home_team': '',                # populated below
                            'away_team': '',
                        }
                        # Populate team abbreviations from competitors
                        for _ct in comp.get('competitors', []):
                            _ct_abbr = (_ct.get('team') or {}).get('abbreviation', '')
                            if _ct.get('homeAway') == 'home':
                                new_entry['home_team'] = _ct_abbr
                            else:
                                new_entry['away_team'] = _ct_abbr
                        # Don't overwrite a live game with a finished game from another sport
                        # (e.g., NHL BOS=post shouldn't overwrite NBA BOS=in)
                        existing = team_info.get(abbr_upper)
                        if existing and existing.get('status') == 'in' and status != 'in':
                            # Store under sport-qualified key instead
                            team_info[f'{sport}:{abbr_upper}'] = new_entry
                        else:
                            team_info[abbr_upper] = new_entry
                        # Also store under Kalshi code if different
                        kalshi_code = _ESPN_TO_KALSHI.get(abbr_upper)
                        if kalshi_code:
                            _existing_k = team_info.get(kalshi_code)
                            if _existing_k and _existing_k.get('status') == 'in' and status != 'in':
                                team_info[f'{sport}:{kalshi_code}'] = new_entry
                            else:
                                team_info[kalshi_code] = new_entry
        except Exception:
            continue
    _espn_cache = {'data': team_info, 'ts': time.time()}
    live_teams = [k for k, v in team_info.items() if v.get('live')]
    if live_teams:
        print(f'🏟 ESPN cache refreshed: {len(live_teams)} live teams: {", ".join(sorted(live_teams))}')


def _detect_sport(ticker: str) -> str:
    """Detect sport from ticker prefix.
    Returns 'nba', 'ncaab', 'nfl', 'nhl', 'mlb', 'mls', 'epl', 'ucl', 'tennis', etc.
    Basketball sports: 'nba', 'ncaab', 'ncaaw', 'intl_basketball'
    """
    prefix = ticker.split('-')[0].upper() if ticker else ''
    if prefix.startswith('KXNBA'):
        return 'nba'
    if prefix.startswith('KXNCAAMB') or prefix.startswith('KXMARMAD'):
        return 'ncaab'
    if prefix.startswith('KXNCAAWB'):
        return 'ncaaw'
    if prefix.startswith('KXNFL') or prefix.startswith('KXNCAAF'):
        return 'nfl'
    if prefix.startswith('KXNHL'):
        return 'nhl'
    if prefix.startswith('KXMLB') or prefix.startswith('KXWBC'):
        return 'mlb'
    if prefix.startswith('KXMLS'):
        return 'mls'
    if prefix.startswith('KXEPL'):
        return 'epl'
    if prefix.startswith('KXUCL'):
        return 'ucl'
    if prefix.startswith('KXATP') or prefix.startswith('KXWTA'):
        return 'tennis'
    if prefix.startswith(('KXVTB', 'KXBSL', 'KXABA')):
        return 'intl_basketball'
    return 'unknown'


def _detect_market_type(ticker: str) -> str:
    """Detect market type from ticker prefix: 'spread', 'total', 'moneyline', 'prop', etc."""
    prefix = ticker.split('-')[0].upper() if ticker else ''
    if 'SPREAD' in prefix:
        return 'spread'
    if 'TOTAL' in prefix:
        return 'total'
    if 'GAME' in prefix or 'WINNER' in prefix or 'MATCH' in prefix:
        return 'moneyline'
    if any(k in prefix for k in ('PTS', 'REB', 'AST', '3PT', 'STL', 'BLK', 'GOAL', 'BTTS', 'MVP')):
        return 'prop'
    return 'moneyline'


def _extract_spread_line(ticker: str) -> str:
    """Extract spread line label from a spread ticker.

    For spread tickers like KXNBASPREAD-26MAR07UTAMIL-UTA1:
      - suffix = 'UTA1', team_code = 'UTA', tier_digit = '1'
      - Fetches Kalshi market title (e.g. 'Utah wins by over 3.5 Points?')
      - Returns 'UTA -3.5' (team favored if YES = team wins by that many)

    For non-spread tickers, returns ''.
    """
    if _detect_market_type(ticker) != 'spread':
        return ''
    parts = ticker.split('-')
    if len(parts) < 3:
        return ''
    suffix = parts[-1]  # e.g. 'UTA1', 'ORL3', 'BEL8'
    # Extract team code (alphabetic prefix) and tier digit
    code_match = re.match(r'^([A-Z]+)', suffix)
    team_code = code_match.group(1) if code_match else suffix

    # Try to get spread number from Kalshi market title
    try:
        if kalshi_client:
            api_read_limiter.wait()
            mkt = kalshi_client.get_market(ticker)
            market_data = mkt.get('market', mkt)
            title = market_data.get('title', '')
            # "Utah wins by over 3.5 Points?" → spread = 3.5
            sp_match = re.search(r'wins?\s+by\s+over\s+([\d.]+)', title, re.IGNORECASE)
            if sp_match:
                return f'{team_code} -{sp_match.group(1)}'
            # Fallback: "UTA -3.5" style
            sp_match2 = re.search(r'([A-Z]{2,5})\s*([+-][\d.]+)', title)
            if sp_match2:
                return f'{sp_match2.group(1)} {sp_match2.group(2)}'
    except Exception as e:
        print(f'⚠ Could not fetch spread line for {ticker}: {e}')

    # Fallback: just show team code without line number
    return team_code


def _enrich_trade_record(record: dict, bot: dict = None) -> dict:
    """Add market_type and spread_line to a trade history record.
    Uses bot data if available, falls back to ticker parsing."""
    ticker = record.get('ticker', '')
    if bot:
        record['market_type'] = bot.get('market_type') or _detect_market_type(ticker)
        record['spread_line'] = bot.get('spread_line', '')
    else:
        record['market_type'] = _detect_market_type(ticker)
        record['spread_line'] = ''
    # Clean team_label for spread tickers — strip trailing digits
    tl = record.get('team_label', '')
    if record['market_type'] == 'spread' and tl:
        record['team_label'] = re.sub(r'\d+$', '', tl)
    # Correct stale pregame phase: if bot was deployed pregame but game is
    # actually live at trade completion time, record it as live.
    if record.get('game_phase') == 'pregame' and ticker and _is_game_live(ticker):
        record['game_phase'] = 'live'
    # Bot category for split P&L tracking (preserve if already set)
    if 'bot_category' not in record:
        # Use bot's actual bot_category first, fall back to type-based detection
        _bot_cat = (bot.get('bot_category') if bot else None)
        if _bot_cat:
            record['bot_category'] = _bot_cat
        else:
            bot_type = record.get('type') or (bot.get('type') if bot else None) or 'arb'
            if bot_type == 'watch':
                record['bot_category'] = 'bet'
            elif bot_type == 'middle':
                record['bot_category'] = 'middle'
            else:
                record['bot_category'] = 'arb'
    # Sport from series ticker prefix
    series = ticker.split('-')[0].upper() if ticker else ''
    _SPORT_MAP = {
        'KXNBAGAME':'NBA','KXNBASPREAD':'NBA','KXNBATOTAL':'NBA',
        'KXNBAPTS':'NBA','KXNBAREB':'NBA','KXNBAAST':'NBA','KXNBA3PT':'NBA',
        'KXNBASTL':'NBA','KXNBABLK':'NBA','KXNBAMVP':'NBA',
        'KXNFLGAME':'NFL','KXNFLSPREAD':'NFL','KXNFLTOTAL':'NFL',
        'KXNHLGAME':'NHL','KXNHLSPREAD':'NHL','KXNHLTOTAL':'NHL','KXNHLGOAL':'NHL',
        'KXMLBGAME':'MLB','KXMLBSPREAD':'MLB','KXMLBTOTAL':'MLB','KXMLBSTGAME':'MLB',
        'KXMLSGAME':'MLS','KXMLSSPREAD':'MLS','KXMLSTOTAL':'MLS',
        'KXNCAAMBGAME':'NCAAB','KXNCAAMBSPREAD':'NCAAB','KXNCAAMBTOTAL':'NCAAB',
        'KXNCAAMBPTS':'NCAAB','KXNCAAMBREB':'NCAAB','KXNCAAMBAST':'NCAAB',
        'KXNCAAMB3PT':'NCAAB','KXNCAAMBSTL':'NCAAB','KXNCAAMBBLK':'NCAAB',
        'KXNCAAMB1HWINNER':'NCAAB','KXNCAAMB1HSPREAD':'NCAAB','KXNCAAMB1HTOTAL':'NCAAB',
        'KXMARMAD':'NCAAB','KXNCAAWBGAME':'NCAAW',
        'KXNCAAFGAME':'NCAAF','KXNCAAFSPREAD':'NCAAF','KXNCAAFTOTAL':'NCAAF',
        'KXEPLGAME':'EPL','KXEPLSPREAD':'EPL','KXEPLTOTAL':'EPL','KXEPLGOAL':'EPL',
        'KXUCLGAME':'UCL','KXUCLSPREAD':'UCL','KXUCLTOTAL':'UCL','KXUCLGOAL':'UCL',
        'KXATPMATCH':'Tennis','KXWTAMATCH':'Tennis',
        'KXWBCGAME':'WBC','KXVTBGAME':'Volleyball','KXBSLGAME':'Basketball','KXABAGAME':'ABA',
    }
    record['sport'] = _SPORT_MAP.get(series, 'Other')
    return record


def _record_trade(record: dict, bot: dict = None):
    """Insert an enriched trade record into trade_history and immediately
    append it to the crash-safe trades.jsonl log."""
    _enrich_trade_record(record, bot)
    import uuid
    record.setdefault('_trade_id', str(uuid.uuid4()))
    # Attach order IDs from bot for trade history debugging
    if bot:
        record.setdefault('yes_order_id', bot.get('yes_order_id'))
        record.setdefault('no_order_id', bot.get('no_order_id'))
        record.setdefault('dog_order_id', bot.get('dog_order_id'))
        record.setdefault('fav_order_id', bot.get('fav_order_id'))
        record.setdefault('hedge_order_id', bot.get('hedge_order_id'))
    trade_history.insert(0, record)
    # Crash-safe append — survives server crashes between save_state() calls
    try:
        with _save_lock:
            with open(TRADES_FILE, 'a') as _tf:
                _tf.write(json.dumps(record, default=str) + '\n')
    except Exception as _te:
        print(f'⚠ trades.jsonl append failed: {_te}')


def _parse_ticker_teams(ticker: str):
    """Extract team codes from a Kalshi ticker. Returns list of candidate codes.
    Handles variable-length codes (2-6 chars) used by college sports.
    e.g. KXNCAAMBGAME-26MAR06WEBBHP → ['WEB', 'WEBB', 'BHP', 'WEBBH', 'HP', 'WEBBHP']
    """
    parts = ticker.split('-')
    if len(parts) < 2:
        return None, None
    stripped = re.sub(r'^\d{2}[A-Z]{3}\d{2}', '', parts[1])
    if len(stripped) < 4:
        return None, None
    # Try classic 3+3 first
    if len(stripped) >= 6:
        t1, t2 = stripped[:3].upper(), stripped[3:6].upper()
    else:
        t1, t2 = stripped[:2].upper(), stripped[2:].upper()
    return t1, t2


def _get_all_ticker_team_candidates(ticker: str):
    """Get all possible team code substrings from a ticker for ESPN matching.
    Returns a list of candidate codes to try against the ESPN cache."""
    parts = ticker.split('-')
    if len(parts) < 2:
        return []
    stripped = re.sub(r'^\d{2}[A-Z]{3}\d{2}', '', parts[1])
    if not stripped or len(stripped) < 4:
        return []
    candidates = []
    for i in range(2, min(7, len(stripped) - 1)):
        candidates.append(stripped[:i].upper())
        candidates.append(stripped[i:].upper())
    candidates.append(stripped.upper())
    return list(dict.fromkeys(candidates))  # dedupe preserving order


def _is_game_live(ticker: str) -> bool:
    """Check if the game referenced by a Kalshi ticker is currently live.

    Tennis: Kalshi milestones (authoritative — details.status == 'live').
    Other sports: ESPN scoreboard cache (authoritative for NBA/NHL/MLB etc).
    Fallback: Kalshi expected_expiration_time window.
    """
    # ── TENNIS: Use Kalshi milestones (authoritative) ──
    is_tennis = ticker.startswith('KXATP') or ticker.startswith('KXWTA')
    if is_tennis:
        # Extract event_ticker from market ticker (strip the player suffix)
        # e.g. KXATPMATCH-26MAR17SVASMI-SVA → KXATPMATCH-26MAR17SVASMI
        parts = ticker.split('-')
        if len(parts) >= 2:
            event_ticker = '-'.join(parts[:2])
            ms_status = _get_milestone_status(event_ticker)
            if ms_status is not None:
                return ms_status == 'live'
        # Milestones didn't have this event — fall through to expiration check

    # ── OTHER SPORTS: Check ESPN first (authoritative "game in progress") ──
    is_sports = any(ticker.startswith(p) for p in ('KXNBA', 'KXNCAA', 'KXNHL', 'KXMLB', 'KXMLS', 'KXEPL', 'KXUCL'))
    if is_sports:
        try:
            _refresh_espn_cache()
            info = _espn_cache['data']
            if info:
                candidates = _get_all_ticker_team_candidates(ticker)
                if not candidates:
                    t1, t2 = _parse_ticker_teams(ticker)
                    candidates = [c for c in [t1, t2] if c]
                for code in candidates:
                    espn_code = _KALSHI_TO_ESPN.get(code, code)
                    entry = info.get(code) or info.get(espn_code)
                    if entry and entry.get('live'):
                        return True
                # ESPN says game is NOT live — trust ESPN over Kalshi timing
                # (Kalshi timing can say "live" for pregame games near tipoff)
                return False
        except Exception:
            pass  # ESPN failed, fall through to Kalshi check

    # ── FALLBACK: Check Kalshi expected_expiration_time ──
    try:
        if kalshi_client:
            api_read_limiter.wait()
            mkt_resp = kalshi_client.get_market(ticker)
            mkt = mkt_resp.get('market', mkt_resp) if isinstance(mkt_resp, dict) else {}
            exp_str = mkt.get('expected_expiration_time', '')
            result = mkt.get('result', '')

            # Already settled → not live
            if result and result != '':
                return False

            if exp_str:
                exp_time = datetime.fromisoformat(exp_str.replace('Z', '+00:00'))
                now_utc = datetime.now(timezone.utc)
                hours_until_exp = (exp_time - now_utc).total_seconds() / 3600.0

                max_hours = 3.5
                if -0.5 < hours_until_exp < max_hours:
                    return True
                return False
    except Exception as e:
        print(f'⚠ Kalshi live check failed for {ticker}: {e}')

    # ── Last resort: ESPN fallback for non-sports tickers ──
    try:
        parts_fb = ticker.split('-')
        if len(parts_fb) >= 2:
            m_fb = re.match(r'^(\d{2})([A-Z]{3})(\d{2})', parts_fb[1])
            if m_fb:
                mo_fb = _MONTH_ABBR.get(m_fb.group(2))
                if mo_fb:
                    fb_date = date(2000 + int(m_fb.group(1)), mo_fb, int(m_fb.group(3)))
                    from datetime import timedelta
                    if fb_date not in (date.today(), date.today() + timedelta(days=1)):
                        return False  # Future or past game — never trust ESPN fallback
    except Exception:
        pass
    _refresh_espn_cache()
    info = _espn_cache['data']
    if not info:
        return False
    candidates = _get_all_ticker_team_candidates(ticker)
    if not candidates:
        t1, t2 = _parse_ticker_teams(ticker)
        candidates = [c for c in [t1, t2] if c]
    for code in candidates:
        espn_code = _KALSHI_TO_ESPN.get(code, code)
        entry = info.get(code) or info.get(espn_code)
        if entry and entry.get('live'):
            return True
    return False


def _get_game_context(ticker: str) -> dict:
    """Get live game context (quarter, score diff, clock) for blocking decisions.
    Always force-refreshes ESPN cache (bypasses TTL) so blocking uses fresh data.
    Also applies the same date guard as _get_game_score_for_ticker to avoid
    matching a different same-team game."""
    # Guard: if ticker is for a game >1 day away, no live context exists
    # Allow tomorrow's date because late-night games (10+ PM) use the next day's date
    try:
        parts_chk = ticker.split('-')
        if len(parts_chk) >= 2:
            m_chk = re.match(r'^(\d{2})([A-Z]{3})(\d{2})', parts_chk[1])
            if m_chk:
                mo = _MONTH_ABBR.get(m_chk.group(2))
                if mo:
                    ticker_date = date(2000 + int(m_chk.group(1)), mo, int(m_chk.group(3)))
                    from datetime import timedelta
                    if ticker_date > date.today() + timedelta(days=1):
                        return {}
    except Exception:
        pass
    # Force-refresh: zero out timestamp so we always get fresh data for blocking
    global _espn_cache
    _espn_cache['ts'] = 0
    _refresh_espn_cache()
    info = _espn_cache['data']
    if not info:
        return {}
    candidates = _get_all_ticker_team_candidates(ticker)
    if not candidates:
        t1, t2 = _parse_ticker_teams(ticker)
        candidates = [c for c in [t1, t2] if c]
    for code in candidates:
        espn_code = _KALSHI_TO_ESPN.get(code, code)
        entry = info.get(code) or info.get(espn_code)
        if entry and entry.get('status') == 'in':
            return {
                'period': entry.get('period', 0),
                'clock': entry.get('clock', ''),
                'score_diff': entry.get('score_diff', 0),
                'status_detail': entry.get('status_detail', ''),
            }
    return {}


_MONTH_ABBR = {'JAN':1,'FEB':2,'MAR':3,'APR':4,'MAY':5,'JUN':6,'JUL':7,'AUG':8,'SEP':9,'OCT':10,'NOV':11,'DEC':12}

def _parse_clock_seconds(clock_str):
    """Parse 'MM:SS' countdown clock to total seconds remaining. Returns None if unparseable."""
    try:
        parts = clock_str.strip().split(':')
        if len(parts) == 2:
            return int(parts[0]) * 60 + int(parts[1])
    except Exception:
        pass
    return None

# Late-game bot blocking rules: don't open new bots when game is nearly over.
# Keys are ticker series prefixes (matched by startswith).
# final: total regular periods; block_period: period to start blocking in;
# block_secs: block when clock (seconds remaining) <= this value; block_ot: block all OT.
def _is_halftime(ticker: str) -> bool:
    """Return True if the ESPN game data indicates we're currently at halftime/intermission.
    During halftime, price movement stalls — clocks should be paused, not exited."""
    try:
        score_info = _get_game_score_for_ticker(ticker)
        if not score_info:
            return False
        detail = score_info.get('status_detail', '').lower()
        return 'half' in detail or 'intermission' in detail
    except Exception:
        return False


def _is_game_ending(ticker: str) -> bool:
    """Return True if ESPN says the game is over (status='post') or in the final 60 seconds.
    Used to auto-exit bots — cancel unfilled, amend one-leg-filled.
    Only applies to sports with known timing rules (_LATE_GAME_RULES)."""
    try:
        score_info = _get_game_score_for_ticker(ticker)
        if not score_info:
            return False
        # Only trust game-ending for sports we have rules for
        series = ticker.split('-')[0].upper() if ticker else ''
        rule = None
        for prefix, r in _LATE_GAME_RULES.items():
            if series.startswith(prefix):
                if rule is None or len(prefix) > len(rule[0]):
                    rule = (prefix, r)
        if not rule:
            return False  # Unknown sport — don't trust ESPN status
        status = score_info.get('status', '')
        if status == 'post':
            return True
        if status == 'in':
            r = rule[1]
            period = score_info.get('period', 0)
            # Tennis: no clock — check if one player has match-winning sets
            if r.get('tennis'):
                home_sets = score_info.get('home_score', 0)
                away_sets = score_info.get('away_score', 0)
                sets_to_win = 2  # best of 3 (ATP main + WTA)
                # One player has already won enough sets
                if home_sets >= sets_to_win or away_sets >= sets_to_win:
                    return True
                return False
            # Clock-based sports: check final 60 seconds
            clock = score_info.get('clock', '')
            secs = _parse_clock_seconds(clock)
            # Final period with ≤60s remaining
            if period >= r['block_period'] and secs is not None and secs <= 60:
                return True
        return False
    except Exception:
        return False


_LATE_GAME_RULES = {
    # block_secs: only block the FINAL minute of each sport — just enough to avoid
    # getting stuck with a losing leg in the last seconds.  Volatility happens ALL
    # through the 4th quarter, so we allow bots there and just shorten their timeout.
    # block_ot: False — overtime is valid arb territory.
    'KXNBA':    {'final': 4, 'block_period': 4, 'block_secs': 60,  'block_ot': False, 'name': 'NBA Q4'},
    'KXNCAAMB': {'final': 2, 'block_period': 2, 'block_secs': 60,  'block_ot': False, 'name': 'NCAAB 2nd Half'},
    'KXNCAAWB': {'final': 4, 'block_period': 4, 'block_secs': 60,  'block_ot': False, 'name': 'NCAAWB Q4'},
    'KXNFL':    {'final': 4, 'block_period': 4, 'block_secs': 60,  'block_ot': False, 'name': 'NFL Q4'},
    'KXNHL':    {'final': 3, 'block_period': 3, 'block_secs': 60,  'block_ot': False, 'name': 'NHL P3'},
    # Tennis: no clock, set-based. period = current set number, score = sets won.
    'KXATP':    {'final': 3, 'block_period': 3, 'block_secs': None, 'block_ot': False, 'name': 'ATP Set 3', 'tennis': True},
    'KXWTA':    {'final': 3, 'block_period': 3, 'block_secs': None, 'block_ot': False, 'name': 'WTA Set 3', 'tennis': True},
}

def _is_late_game(ticker):
    """Returns (blocked, reason_str). True if game is in the last-60-seconds no-deploy window."""
    series = ticker.split('-')[0].upper() if ticker else ''
    # Match longest applicable prefix
    rule = None
    rule_key = ''
    for prefix, r in _LATE_GAME_RULES.items():
        if series.startswith(prefix) and len(prefix) > len(rule_key):
            rule = r
            rule_key = prefix
    if not rule:
        return False, ''
    gc = _get_game_context(ticker)
    if not gc:
        return False, ''  # game not live or can't get context
    period = gc.get('period', 0)
    clock_str = gc.get('clock', '')
    secs = _parse_clock_seconds(clock_str)
    # Block OT only if configured
    if rule.get('block_ot') and period > rule['final']:
        return True, f"{rule['name']}: OT — too late to open new bots"
    # Block only in the final 60s of the last regulation period
    if period >= rule['block_period'] and secs is not None and secs <= rule['block_secs']:
        espn_age = time.time() - (_espn_cache.get('ts', 0) or 0)
        print(f'🚫 LATE GAME BLOCK: {ticker} period={period} clock={clock_str} secs={secs} rule={rule["name"]} espn_age={espn_age:.0f}s')
        return True, f"{rule['name']}: Q{period} {clock_str} ({secs}s left)"
    return False, ''


# Sport-specific standard timeouts (fav, dog) in minutes.
# College games (NCAAB/NCAAWB) move slower → need longer fill windows.
# Sports without live game clocks (golf, tennis, UFC, F1, cricket) get generous windows.
