# ─── Width-based timeout tiers (per sport group) ──────────────────────────
# Each entry maps a sport prefix to a dict of width ranges → timeout minutes.
# Format: { (min_width, max_width): timeout_min, ... }
# Falls back to the last tier if width exceeds all ranges.
_WIDTH_TIMEOUTS: dict = {
    # NBA: fast pace, prices move quickly. Short timeouts across the board.
    'KXNBA': {
        (5, 7):   1.5,   # tiny margin, get out fast
        (8, 10):  2.0,   # moderate buffer
        (11, 16): 2.5,   # decent margin, slightly more patience
    },
    # NCAAB: slower pace than NBA, but still basketball
    'KXNCAAMB': {
        (5, 7):   2.0,   # narrow — quick exit
        (8, 10):  3.0,   # moderate
        (11, 16): 4.0,   # wide — can afford to wait
    },
    'KXNCAAWB': {
        (5, 7):   2.0,
        (8, 10):  3.0,
        (11, 16): 4.0,
    },
    # Tennis: serve-aware logic handled separately in _tennis_timeout_min
    # These are fallback defaults if serve detection fails
    'KXATP': {
        (5, 7):   1.0,   # tennis moves FAST mid-game
        (8, 10):  1.5,
        (11, 16): 2.0,
    },
    'KXWTA': {
        (5, 7):   1.0,
        (8, 10):  1.5,
        (11, 16): 2.0,
    },
}

def _width_timeout_min(sport_prefix: str, arb_width: int) -> float:
    """Get timeout based on sport and arb width. Returns None if no rule found."""
    for prefix, tiers in _WIDTH_TIMEOUTS.items():
        if sport_prefix.startswith(prefix):
            for (lo, hi), timeout in tiers.items():
                if lo <= arb_width <= hi:
                    return timeout
            # Width outside defined ranges — use the widest tier
            max_tier = max(tiers.items(), key=lambda x: x[0][1])
            return max_tier[1]
    return None  # no width rule for this sport


def _tennis_timeout_min(ticker: str, arb_width: int) -> float:
    """Tennis-specific timeout: shorter mid-game, longer during changeover.
    Tennis prices swing hard on breaks of serve — mid-point is dangerous."""
    gc = _get_game_context(ticker)
    # Default: use width-based tennis timeout
    series = ticker.split('-')[0].upper() if ticker else ''
    base = _width_timeout_min(series, arb_width) or 1.5

    if not gc:
        return base

    # Check if between games (changeover) — prices are more stable
    status = gc.get('status_detail', '').lower()
    clock = gc.get('clock', '')
    is_changeover = ('changeover' in status or 'end of' in status
                     or 'warm' in status or clock == '0:00')

    if is_changeover:
        return max(base, 2.0)  # changeover: use at least 2 min
    else:
        # Mid-game (ball in play): cut timeout in half, minimum 0.5 min (30 sec)
        return max(base * 0.5, 0.5)


def _late_game_timeout_min(ticker, is_fav_filled: bool, arb_width: int = 0) -> float:
    """Return timeout considering: sport, width, late-game, and tennis serve state.
    Priority: late-game override > tennis serve > width-based > sport fav/dog default."""
    series = ticker.split('-')[0].upper() if ticker else ''

    # ── 1. Late-game override: final period <5 min = always tight ──
    rule = None
    rule_key = ''
    for prefix, r in _LATE_GAME_RULES.items():
        if series.startswith(prefix) and len(prefix) > len(rule_key):
            rule = r
            rule_key = prefix
    if rule:
        gc = _get_game_context(ticker)
        if gc:
            period = gc.get('period', 0)
            secs = _parse_clock_seconds(gc.get('clock', ''))
            is_final_period = (period == rule['block_period']) or (period > rule['final'])
            if is_final_period and secs is not None and secs <= 300:  # last 5 minutes
                # NCAAB last 4 min: even tighter
                if secs <= 240 and (series.startswith('KXNCAAMB') or series.startswith('KXNCAAWB')):
                    return 1.5
                return 1.5  # tight window for any sport in final minutes

    # ── 2. Tennis: serve-aware timeout ──
    if series.startswith('KXATP') or series.startswith('KXWTA'):
        return _tennis_timeout_min(ticker, arb_width)

    # ── 3. Width-based timeout (NBA, NCAAB) ──
    if arb_width > 0:
        wt = _width_timeout_min(series, arb_width)
        if wt is not None:
            return wt

    # ── 4. Fallback: sport fav/dog defaults ──
    sport_key = rule_key or series
    best_t = None
    best_len = 0
    for sp_prefix, sp_vals in _SPORT_TIMEOUTS.items():
        if sport_key.startswith(sp_prefix) and len(sp_prefix) > best_len:
            best_t = sp_vals
            best_len = len(sp_prefix)
    fav_t, dog_t = best_t if best_t else (6.0, 4.0)
    return fav_t if is_fav_filled else dog_t

def _get_game_score_for_ticker(ticker: str) -> dict:
    """Get live game score info for a ticker (for bot list UI display).
    Returns {home_team, away_team, home_score, away_score, period, clock, status_detail, status} or {}."""
    # Guard: skip if ticker date is in the future (avoids showing today's PHI game
    # on a bot whose ticker is for tomorrow's PHI vs CLE game)
    try:
        parts_chk = ticker.split('-')
        if len(parts_chk) >= 2:
            m_chk = re.match(r'^(\d{2})([A-Z]{3})(\d{2})', parts_chk[1])
            if m_chk:
                mo = _MONTH_ABBR.get(m_chk.group(2))
                if mo:
                    ticker_date = date(2000 + int(m_chk.group(1)), mo, int(m_chk.group(3)))
                    from datetime import timedelta
                    if ticker_date > date.today() + timedelta(days=1):
                        return {}  # Future game — don't match today's team scores
    except Exception:
        pass
    _refresh_espn_cache()
    info = _espn_cache['data']
    if not info:
        return {}
    # Determine allowed ESPN sports for this ticker to prevent cross-sport collisions
    # e.g. tennis ticker "TRUHOU" should NOT match NBA Houston ("HOU")
    ticker_sport = _detect_sport(ticker)
    _SPORT_TO_ESPN = {
        'nba': {'nba'}, 'ncaab': {'ncaab'}, 'ncaaw': {'ncaaw'}, 'nfl': {'nfl'},
        'nhl': {'nhl'}, 'mlb': {'mlb'}, 'mls': {'mls'}, 'epl': {'epl'}, 'ucl': {'ucl'},
        'tennis': {'atp', 'wta'},
    }
    allowed_espn_sports = _SPORT_TO_ESPN.get(ticker_sport)  # None = allow all (unknown sport)

    candidates = _get_all_ticker_team_candidates(ticker)
    if not candidates:
        t1, t2 = _parse_ticker_teams(ticker)
        candidates = [c for c in [t1, t2] if c]
    # Find best candidate: ALWAYS prefer 'in' (live) over 'post' (finished).
    # A finished match from a different player with a colliding abbreviation
    # must NEVER override a live match or cause false 'critical' urgency.
    best_entry = None
    for code in candidates:
        espn_code = _KALSHI_TO_ESPN.get(code, code)
        # Try direct key, then sport-qualified key for cross-sport collision cases
        entry = info.get(code) or info.get(espn_code)
        if entry and (entry.get('status') in ('in', 'post')):
            # Cross-sport guard: reject if ESPN entry is from a different sport
            entry_sport = entry.get('espn_sport', '')
            if allowed_espn_sports and entry_sport and entry_sport not in allowed_espn_sports:
                # Try sport-qualified key as fallback (e.g., 'nba:BOS')
                for _qs in (allowed_espn_sports or []):
                    _qentry = info.get(f'{_qs}:{code}') or info.get(f'{_qs}:{espn_code}')
                    if _qentry and _qentry.get('status') in ('in', 'post'):
                        entry = _qentry
                        break
                else:
                    continue  # No matching sport entry found
        if entry and (entry.get('status') in ('in', 'post')):
            entry_sport = entry.get('espn_sport', '')
            if allowed_espn_sports and entry_sport and entry_sport not in allowed_espn_sports:
                continue
            # Prefer live matches — a 'post' match might be a different player with same abbr
            if entry.get('status') == 'in':
                best_entry = entry
                break  # Live match found — use it immediately
            elif best_entry is None:
                best_entry = entry  # First post match — keep as fallback, keep looking for live
    # Safety: for 'post' matches, verify BOTH teams from the ESPN entry appear in the ticker
    # to prevent single-abbreviation collisions (e.g. tennis "CAD" matching wrong finished match)
    if best_entry and best_entry.get('status') == 'post':
        _home = best_entry.get('home_team', '').upper()
        _away = best_entry.get('away_team', '').upper()
        _cand_set = set(c.upper() for c in candidates)
        _both_match = (_home in _cand_set or any(_home in c for c in _cand_set)) and \
                      (_away in _cand_set or any(_away in c for c in _cand_set))
        if not _both_match:
            best_entry = None  # Single-team collision with a finished match — ignore
    if best_entry:
        return {
            'home_score': best_entry.get('home_score', 0),
            'away_score': best_entry.get('away_score', 0),
            'score_diff': best_entry.get('score_diff', 0),
            'period': best_entry.get('period', 0),
            'clock': best_entry.get('clock', ''),
            'status_detail': best_entry.get('status_detail', ''),
            'status': best_entry.get('status', ''),
            'home_team': best_entry.get('home_team', ''),
            'away_team': best_entry.get('away_team', ''),
        }
    return {}


def _get_team_margin_for_spread_ticker(ticker: str, spread_value=0):
    """Get a specific team's score margin for a spread ticker.
    Extracts the team code from the last ticker segment (e.g. OKC from ...OKC24),
    looks it up in ESPN cache, and returns directional margin vs the spread.

    Returns dict with keys: margin, team_code, covering, period, secs_remaining, status
    or {} if ESPN data unavailable.
    """
    try:
        parts = ticker.split('-')
        if len(parts) < 3:
            return {}
        # Extract team code from last segment: "OKC24" → "OKC"
        last_seg = parts[-1]
        code_match = re.match(r'^([A-Z]+)', last_seg)
        if not code_match:
            return {}
        team_code = code_match.group(1)

        # Look up in ESPN cache
        _refresh_espn_cache()
        info = _espn_cache.get('data', {})
        if not info:
            return {}

        # Try direct lookup, then Kalshi-to-ESPN mapping
        espn_code = _KALSHI_TO_ESPN.get(team_code, team_code)
        entry = info.get(team_code) or info.get(espn_code)
        if not entry or entry.get('status') not in ('in', 'post'):
            return {}

        # Cross-sport guard (same as _get_game_score_for_ticker)
        ticker_sport = _detect_sport(ticker)
        _SPORT_TO_ESPN = {
            'nba': {'nba'}, 'ncaab': {'ncaab'}, 'ncaaw': {'ncaaw'}, 'nfl': {'nfl'},
            'nhl': {'nhl'}, 'mlb': {'mlb'},
        }
        allowed = _SPORT_TO_ESPN.get(ticker_sport)
        entry_sport = entry.get('espn_sport', '')
        if allowed and entry_sport and entry_sport not in allowed:
            return {}

        team_score = entry.get('team_score', 0)
        opp_score = entry.get('opp_score', 0)
        margin = team_score - opp_score  # positive = team winning
        clock = entry.get('clock', '')
        secs = _parse_clock_seconds(clock)

        return {
            'margin': margin,
            'team_code': team_code,
            'covering': margin >= spread_value,  # team is covering the spread
            'period': entry.get('period', 0),
            'clock': clock,
            'secs_remaining': secs,
            'status': entry.get('status', ''),
        }
    except Exception:
        return {}


def _get_game_time(ticker: str) -> str:
    """Get game start time from ESPN cache for a given ticker. Returns e.g. '7:30 PM' or ''."""
    _refresh_espn_cache()
    info = _espn_cache['data']
    if not info:
        return ''
    t1, t2 = _parse_ticker_teams(ticker)
    if not t1:
        return ''
    for code in [t1, t2]:
        espn_code = _KALSHI_TO_ESPN.get(code, code)
        entry = info.get(code) or info.get(espn_code)
        if entry and entry.get('game_time'):
            return entry['game_time']
    return ''


# ─── Single Order Endpoint ─────────────────────────────────────────────────────
@app.route('/api/order/single', methods=['POST'])
def place_single_order():
    """
    Place a single limit order (one side only).
    Used for middle spreads where you need YES on one market, NO on a different market.
    Does NOT create a dual-arb bot — just places the order and returns the order ID.
    """
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        data = request.json
        ticker = data.get('ticker')
        side   = data.get('side')        # 'yes' or 'no'
        price  = int(data.get('price'))   # price in cents
        qty    = int(data.get('quantity', 1))

        if not ticker or not side or not price:
            return jsonify({'error': 'Missing required fields: ticker, side, price'}), 400

        if side not in ('yes', 'no'):
            return jsonify({'error': f"Invalid side '{side}' — must be 'yes' or 'no'"}), 400

        if price < 1 or price > 99:
            return jsonify({'error': f'Price {price}¢ out of range (1-99)'}), 400

        price_kwargs = {'yes_price': price} if side == 'yes' else {'no_price': price}
        order = kalshi_client.create_order(
            ticker=ticker, side=side, action='buy',
            count=qty, post_only=True, **price_kwargs
        )

        oid = _extract_order_id(order, f'simple order {ticker} {side}')
        if not oid:
            return jsonify({'error': 'Order placed but no order_id returned — check Kalshi positions'}), 500

        return jsonify({
            'success':  True,
            'order_id': oid,
            'ticker':   ticker,
            'side':     side,
            'price':    price,
            'quantity': qty,
            'message':  f'Placed {side.upper()} limit buy on {ticker} at {price}¢ × {qty}'
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


# ═══════════════════════════════════════════════════════════════════
# STRAIGHT BET — single-side limit order (no arb bot, no monitoring)
# ═══════════════════════════════════════════════════════════════════

@app.route('/api/order/place', methods=['POST'])
def place_straight_order():
    """
    Place a simple one-sided limit order — buy YES or buy NO at a specified price.
    No dual-arb logic, no bot monitoring. Just a plain limit order on Kalshi.
    Optionally creates a watch-bot to auto stop-loss / take-profit.
    """
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        data = request.json
        ticker   = data.get('ticker')
        side     = data.get('side', 'yes')         # 'yes' or 'no'
        price    = int(data.get('price', 0))        # limit price in cents
        quantity = int(data.get('quantity', 1))
        add_watch = data.get('add_watch', False)    # auto-create watch bot for SL
        stop_loss_cents = int(data.get('stop_loss_cents', 5))
        take_profit_cents = int(data.get('take_profit_cents', 0))
        fair_value_cents = data.get('fair_value_cents')  # from OddsJam no-vig calc (optional)

        if not ticker:
            return jsonify({'error': 'Missing ticker'}), 400
        if price < 1 or price > 99:
            return jsonify({'error': f'Price must be 1-99¢, got {price}'}), 400
        if quantity < 1:
            return jsonify({'error': 'Quantity must be at least 1'}), 400

        # Place limit order
        order_kwargs = {
            'ticker': ticker,
            'side': side,
            'action': 'buy',
            'count': quantity,
            'post_only': True,
        }
        if side == 'yes':
            order_kwargs['yes_price'] = price
        else:
            order_kwargs['no_price'] = price

        api_rate_limiter.wait()
        order_resp = kalshi_client.create_order(**order_kwargs)
        order_id = _extract_order_id(order_resp, f'watch order {ticker} {side}')
        if not order_id:
            return jsonify({'error': 'Order placed but no order_id returned — check Kalshi positions'}), 500

        # Optionally create a watch bot for SL/TP + fill monitoring
        watch_bot_id = None
        if add_watch:
            # Check if the order filled immediately (at or above ask)
            initial_fill_qty = 0
            try:
                api_read_limiter.wait()
                order_check = kalshi_client.get_order(order_id)
                order_obj = order_check.get('order', order_check)
                initial_fill_qty = _parse_fill_count(order_obj) or order_obj.get('amount_filled', 0)
            except Exception:
                pass  # Order may have been rejected/removed — treat as unfilled

            watch_bot_id = f"watch_{ticker}_{side}_{int(time.time())}"
            active_bots[watch_bot_id] = {
                'type':             'watch',
                'ticker':           ticker,
                'side':             side,
                'entry_price':      price,
                'quantity':         quantity,
                'stop_loss_cents':  stop_loss_cents,
                'take_profit_cents': take_profit_cents,
                'fair_value_cents': fair_value_cents,
                'has_sl_tp':        stop_loss_cents > 0 or take_profit_cents > 0,
                'status':           'watching',
                'created_at':       time.time(),
                'order_id':         order_id,
                'order_filled':     initial_fill_qty >= quantity,
                'fill_qty':         initial_fill_qty,
            }
            save_state()
            # Subscribe WS to this ticker so we get real-time prices
            if ws_manager.connected:
                ws_manager.add_ticker(ticker)

        cost_dollars = (price * quantity) / 100
        payout_dollars = quantity  # $1 per contract at settlement
        profit_dollars = payout_dollars - cost_dollars
        bot_log('ORDER_PLACED', watch_bot_id or '', {'ticker': ticker, 'side': side, 'price': price, 'qty': quantity, 'order_id': order_id, 'watch': add_watch, 'fair_value': fair_value_cents})

        return jsonify({
            'success':    True,
            'order_id':   order_id,
            'side':       side,
            'price':      price,
            'quantity':   quantity,
            'cost':       cost_dollars,
            'potential_profit': profit_dollars,
            'watch_bot_id': watch_bot_id,
            'message':    f'{side.upper()} limit buy: {quantity}× at {price}¢ (cost ${cost_dollars:.2f}, pays ${payout_dollars:.2f} if wins)'
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/bot/create', methods=['POST'])
def create_bot():
    """
    Dual Arb Bot: immediately places LIMIT BUY orders on both YES and NO sides.
    Both are market-maker orders (resting in the book) — no taker fees on entry.
    Profit = 100 - yes_price - no_price cents per contract, locked at settlement.

    game_phase: 'pregame' or 'live' — controls timeout behavior.
      - pregame: patient, orders sit until game starts. No repost, no time-based stop loss.
      - live: aggressive, repost / stop-loss after timeout windows.
    """
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        data = request.json
        ticker         = data.get('ticker')
        yes_price      = int(data.get('yes_price'))   # limit buy price for YES, in cents
        no_price       = int(data.get('no_price'))    # limit buy price for NO, in cents
        quantity       = int(data.get('quantity', 1))
        stop_loss_cents = max(1, int(data.get('stop_loss_cents', 5)))  # ¢ drop for watch bots (props/straight)
        # Auto-detect game phase from ESPN — no manual setting needed
        # But allow manual override for games ESPN doesn't cover (NIT, CBI, etc.)
        manual_phase = data.get('game_phase')
        if manual_phase in ('live', 'pregame'):
            game_phase = manual_phase
        else:
            game_phase = 'live' if _is_game_live(ticker) else 'pregame'

        # Late-game block: refuse new bots when game clock is nearly expired
        if game_phase == 'live':
            late_blocked, late_reason = _is_late_game(ticker)
            if late_blocked:
                return jsonify({'error': f'⏰ Late-game block — {late_reason}'}), 400

        repeat_count   = int(data.get('repeat_count', 0))      # 0 = no repeat, N = repeat N more times (N+1 total runs)
        arb_width      = int(data.get('arb_width', 0))         # remember target width for repeat

        if not ticker or yes_price is None or no_price is None:
            return jsonify({'error': 'Missing required fields: ticker, yes_price, no_price'}), 400

        profit_per = 100 - yes_price - no_price
        if profit_per <= 0:
            return jsonify({'error': f'Not an arb: yes({yes_price}¢) + no({no_price}¢) = {yes_price+no_price}¢ ≥ 100¢'}), 400

        # ── PER-TICKER BOT CAP ─────────────────────────────────
        MAX_BOTS_PER_TICKER = 5
        active_on_ticker = sum(
            1 for b in active_bots.values()
            if b.get('ticker') == ticker
            and b.get('status') not in ('completed', 'stopped', 'cancelled')
        )
        if active_on_ticker >= MAX_BOTS_PER_TICKER:
            return jsonify({'error': f'Bot cap: {active_on_ticker} active bots on {ticker} (max {MAX_BOTS_PER_TICKER}). Cancel some first.'}), 400

        # ── CEILING CHECK — no fees in bot logic, 98¢ = breakeven ──
        combined = yes_price + no_price
        if combined >= HARD_CEILING_CENTS:
            return jsonify({'error': f'Combined {combined}¢ >= {HARD_CEILING_CENTS}¢ ceiling — not profitable'}), 400

        # ── PRICE VALIDATION: fetch ORDERBOOK for real-time best bids ──────────
        # The market endpoint returns stale prices; orderbook is real-time
        live_yes_bid = 0
        live_no_bid = 0
        live_yes_ask = 99
        live_no_ask = 99
        try:
            api_read_limiter.wait()
            ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
            ob = ob_data.get('orderbook', ob_data)
            yes_levels = sorted(ob.get('yes', []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
            no_levels  = sorted(ob.get('no',  []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
            live_yes_bid = (yes_levels[0][0] if isinstance(yes_levels[0], list) else yes_levels[0].get('price', 0)) if yes_levels else 0
            live_no_bid  = (no_levels[0][0]  if isinstance(no_levels[0], list)  else no_levels[0].get('price', 0))  if no_levels  else 0

            # Derive live asks via market identity
            live_yes_ask = 100 - live_no_bid if live_no_bid > 0 else 99
            live_no_ask  = 100 - live_yes_bid if live_yes_bid > 0 else 99

            # Ask-side pricing intentionally places orders BETWEEN bid and ask (above bid).
            # Allow up to the ask price — anything at or above the ask would cross the spread
            # and fill immediately as a taker (bad). Anything below ask is a resting limit (good).
            if yes_price >= live_yes_ask and live_yes_ask > 0:
                return jsonify({'error': f'YES price {yes_price}¢ is AT or ABOVE ask {live_yes_ask}¢ — would cross spread. Refresh and retry.'}), 400
            if no_price >= live_no_ask and live_no_ask > 0:
                return jsonify({'error': f'NO price {no_price}¢ is AT or ABOVE ask {live_no_ask}¢ — would cross spread. Refresh and retry.'}), 400

            # bid sum >= 100 is normal — volatility play, not instant arb
            live_total = live_yes_bid + live_no_bid

            print(f'✅ Price validation: YES {yes_price}¢ (bid={live_yes_bid}¢ ask={live_yes_ask}¢), NO {no_price}¢ (bid={live_no_bid}¢ ask={live_no_ask}¢)')

            # Block deployment when either side has NO real bids.
            # A derived price (e.g. YES=87¢ from 100-1-12) isn't a real order —
            # nobody is there to fill it. Both sides need real liquidity.
            if live_yes_bid <= 0:
                return jsonify({'error': f'No YES bids in the orderbook — the YES price is derived, not real. This arb is phantom.'}), 400
            if live_no_bid <= 0:
                return jsonify({'error': f'No NO bids in the orderbook — the NO price is derived, not real. This arb is phantom.'}), 400
        except Exception as pv_err:
            print(f'⚠ Price validation skipped: {pv_err}')

        # ── SIMULTANEOUS DUAL LIMIT ORDER PLACEMENT ───────────────
        # Place both YES and NO limit orders in a single batch call.
        # If both fill → profit locked at settlement.
        # If one fills but other is pending after 8 min → cancel pending, sell filled at market.
        batch_results = create_orders_batch([
            {'ticker': ticker, 'side': 'yes', 'count': quantity, 'price': yes_price},
            {'ticker': ticker, 'side': 'no',  'count': quantity, 'price': no_price},
        ])
        yes_order, yes_price = batch_results[0]
        no_order, no_price   = batch_results[1]
        yes_order_id = yes_order['order']['order_id']
        no_order_id  = no_order['order']['order_id']
        profit_per   = 100 - yes_price - no_price  # recalc in case post_only retry adjusted

        print(f'⚡ DUAL POSTED: YES {yes_price}¢ (bid={live_yes_bid}¢) + NO {no_price}¢ (bid={live_no_bid}¢) — both live simultaneously')

        # Subscribe WS to this ticker for real-time price updates
        if ws_manager.connected:
            ws_manager.add_ticker(ticker)

        # Use YES order ID suffix for uniqueness — multiple widths placed in parallel
        # all land within the same second, making int(time.time()) collide and overwrite bots.
        bot_id = f"{ticker}_{yes_order_id[-8:]}"
        # Fallback: if somehow still collides, append timestamp millis
        if bot_id in active_bots:
            bot_id = f"{ticker}_{yes_order_id[-8:]}_{int(time.time() * 1000)}"
        active_bots[bot_id] = {
            'ticker':           ticker,
            'yes_price':        yes_price,
            'no_price':         no_price,
            'quantity':         quantity,
            'profit_per':       profit_per,
            'game_phase':       game_phase,
            'status':           'both_posted',
            'yes_order_id':     yes_order_id,
            'no_order_id':      no_order_id,
            'order_group_id':   None,
            'yes_fill_qty':     0,
            'no_fill_qty':      0,
            'created_at':       time.time(),
            'posted_at':        time.time(),
            'repost_count':     0,
            'repeat_count':     repeat_count,
            'repeats_done':     0,
            'arb_width':        arb_width if arb_width > 0 else profit_per,
            'live_yes_bid':     live_yes_bid,
            'live_no_bid':      live_no_bid,
            'live_yes_ask':     live_yes_ask,
            'live_no_ask':      live_no_ask,
            'last_price_update': time.time(),
            'market_type':      _detect_market_type(ticker),
            'spread_line':      _extract_spread_line(ticker),
            'timeout_min':      _late_game_timeout_min(ticker, yes_price >= no_price, arb_width if arb_width > 0 else profit_per),
        }
        save_state()
        bot_log('BOT_CREATED', bot_id, {'yes_price': yes_price, 'no_price': no_price, 'profit_per': profit_per, 'qty': quantity, 'game_phase': game_phase, 'repeat_count': repeat_count})

        return jsonify({
            'success':      True,
            'bot_id':       bot_id,
            'yes_order_id': yes_order_id,
            'no_order_id':  no_order_id,
            'profit_per':   profit_per,
            'game_phase':   game_phase,
            'repeat_count': repeat_count,
            'message':      f'[{game_phase.upper()}] Both YES and NO orders posted simultaneously — '
                            f'YES {yes_price}¢ + NO {no_price}¢ → {profit_per}¢ profit/contract'
                            + (f' (repeat {repeat_count}x)' if repeat_count > 0 else '')
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


# ═══════════════════════════════════════════════════════════════════
# LADDER-ARB BOT — unified multi-width arb with averaged walk
# ═══════════════════════════════════════════════════════════════════

def _calculate_arb_prices_server(yes_bid, no_bid, yes_ask, no_ask, width):
    """Server-side port of frontend calculateArbPrices().
    Returns (target_yes, target_no) in cents."""
    effective_yes_bid = yes_bid
    effective_no_bid = no_bid
    target_total = 100 - width

    if effective_yes_bid <= 0 and effective_no_bid <= 0:
        effective_yes_bid = target_total // 2
        effective_no_bid = target_total - effective_yes_bid
    elif effective_yes_bid <= 0:
        effective_yes_bid = 100 - effective_no_bid - width
    elif effective_no_bid <= 0:
        effective_no_bid = 100 - effective_yes_bid - width

    bid_sum = effective_yes_bid + effective_no_bid
    total_shave = bid_sum - target_total

    yes_spread = (yes_ask - yes_bid) if yes_ask > 0 and yes_bid > 0 else 0
    no_spread = (no_ask - no_bid) if no_ask > 0 and no_bid > 0 else 0
    has_room = yes_ask > 0 and no_ask > 0 and (yes_spread > 1 or no_spread > 1)

    yes_is_fav = effective_yes_bid >= effective_no_bid

    if has_room:
        # Ask-side pricing
        ask_sum = yes_ask + no_ask
        ask_shave = max(0, ask_sum - target_total)
        fav_ask_shave = ask_shave * 6 // 10
        dog_ask_shave = ask_shave - fav_ask_shave
        max_yes = max(1, yes_ask - 1)
        max_no = max(1, no_ask - 1)
        if yes_is_fav:
            target_yes = min(max_yes, yes_ask - fav_ask_shave)
            target_no = min(max_no, no_ask - dog_ask_shave)
        else:
            target_yes = min(max_yes, yes_ask - dog_ask_shave)
            target_no = min(max_no, no_ask - fav_ask_shave)
        ask_profit = 100 - target_yes - target_no
        if ask_profit < width:
            if yes_is_fav:
                target_yes = max(1, 100 - target_no - width)
            else:
                target_no = max(1, 100 - target_yes - width)
    else:
        # Bid-side pricing
        fav_shave = total_shave * 6 // 10
        dog_shave = total_shave - fav_shave
        dog_bid_val = effective_no_bid if yes_is_fav else effective_yes_bid
        dog_max_shave = max(0, dog_bid_val - 1)
        if dog_shave > dog_max_shave:
            overflow = dog_shave - dog_max_shave
            dog_shave = dog_max_shave
            fav_shave += overflow
        if yes_is_fav:
            target_yes = effective_yes_bid - fav_shave
            target_no = effective_no_bid - dog_shave
        else:
            target_yes = effective_yes_bid - dog_shave
            target_no = effective_no_bid - fav_shave
        if yes_bid > 0:
            target_yes = min(target_yes, yes_bid)
        if no_bid > 0:
            target_no = min(target_no, no_bid)

    target_yes = max(1, min(target_yes, 98))
    target_no = max(1, min(target_no, 98))

    # Enforce width: if dog hit 1c floor, push fav down
    actual_profit = 100 - target_yes - target_no
    if actual_profit < width:
        if yes_is_fav:
            target_yes = max(1, 100 - target_no - width)
        else:
            target_no = max(1, 100 - target_yes - width)

    return int(target_yes), int(target_no)


def _recompute_apex_fills(bot):
    """Recompute weighted averages and total fills across all rungs.
    When consolidated, distributes hedge fills across anchor-filled rungs in order."""
    qty_per = bot.get('quantity', 1)

    # When consolidated, redistribute hedge-side fills across anchor-filled rungs
    if bot.get('_consolidated'):
        filled_side = bot.get('first_fill_side')
        # Infer from status if cleared by previous hedge gen completion
        if not filled_side:
            st = bot.get('status', '')
            if 'yes_filled' in st:
                filled_side = 'yes'
            elif 'no_filled' in st:
                filled_side = 'no'

        if filled_side:
            hedge_side = 'no' if filled_side == 'yes' else 'yes'

            # Use bot-level hedge fill tracking (not rung-level which caps at qty_per)
            current_hedge_fills = min(bot.get('_hedge_fill_count', 0), bot.get('hedge_qty', 0) or 999)
            # Completed hedges from previous generations
            history_fills = sum(h.get('fill_qty', 0) for h in bot.get('hedge_history', []))
            # Total REAL hedge fills = current hedge + history
            total_hedge_fills = current_hedge_fills + history_fills

            # Distribute hedge fills across anchor-filled rungs in order.
            # Skip already-completed rungs (their hedge fills were already assigned).
            remaining = total_hedge_fills
            for rung in bot.get('rungs', []):
                rq = rung.get('quantity', qty_per)
                anchor_fill = min(rung.get(f'{filled_side}_fill_qty', 0), rq)
                rung[f'{filled_side}_fill_qty'] = anchor_fill
                if rung.get('completed'):
                    # Already had hedge fills assigned — consume from budget
                    rung[f'{hedge_side}_fill_qty'] = rq
                    remaining -= rq
                elif anchor_fill > 0 and remaining > 0:
                    assign = min(rq, remaining)
                    rung[f'{hedge_side}_fill_qty'] = assign
                    remaining -= assign
                    # Mark rung completed when both sides fully filled
                    if anchor_fill >= rq and assign >= rq:
                        rung['completed'] = True
                else:
                    rung[f'{hedge_side}_fill_qty'] = 0

    # Cap fills and compute totals
    total_yes_qty = 0
    total_no_qty = 0
    weighted_yes_sum = 0
    weighted_no_sum = 0
    for rung in bot.get('rungs', []):
        rq = rung.get('quantity', qty_per)
        yf = min(rung.get('yes_fill_qty', 0), rq)
        nf = min(rung.get('no_fill_qty', 0), rq)
        rung['yes_fill_qty'] = yf
        rung['no_fill_qty'] = nf
        total_yes_qty += yf
        total_no_qty += nf
        weighted_yes_sum += rung['yes_price'] * yf
        weighted_no_sum += rung['no_price'] * nf
    bot['filled_yes_qty'] = total_yes_qty
    bot['filled_no_qty'] = total_no_qty
    bot['yes_fill_qty'] = total_yes_qty
    bot['no_fill_qty'] = total_no_qty
    bot['avg_yes_price'] = round(weighted_yes_sum / total_yes_qty) if total_yes_qty > 0 else None
    bot['avg_no_price'] = round(weighted_no_sum / total_no_qty) if total_no_qty > 0 else None
    if bot['avg_yes_price']:
        bot['yes_price'] = bot['avg_yes_price']
    if bot['avg_no_price']:
        bot['no_price'] = bot['avg_no_price']




def _record_rung_completion(bot_id, bot, rung):
    """Record profit for a single completed rung. Called when both sides filled on a rung."""
    # Guard: set _profit_recorded IMMEDIATELY to prevent race condition double-recording
    # (monitor + WS handler + completion handler can all call _check_apex_rung_completions)
    if rung.get('_profit_recorded'):
        return  # already recorded — shouldn't reach here but guard anyway
    rung['_profit_recorded'] = True  # set BEFORE any work to prevent concurrent re-entry

    now = time.time()
    ticker = bot['ticker']
    qty_per = bot.get('quantity', 1)
    rq = rung.get('quantity', qty_per)
    yes_p = rung['yes_price']
    no_p = rung['no_price']
    width = rung.get('width', 0)

    # When consolidated, the hedge side was filled at the actual hedge price, not the rung's
    # original deployment price. Use the real hedge price for accurate P&L.
    if bot.get('bot_category') == 'ladder_arb' and (bot.get('_consolidated') or bot.get('hedge_history')):
        hedge_side = 'no' if bot.get('first_fill_side') == 'yes' else 'yes'
        # Current active hedge price takes priority over history
        actual_hedge_price = bot.get('hedge_price', 0)
        if not actual_hedge_price:
            # Fall back to most recent hedge_history entry
            for hh in reversed(bot.get('hedge_history', [])):
                if hh.get('price'):
                    actual_hedge_price = hh['price']
                    break
        if actual_hedge_price > 0:
            if hedge_side == 'yes':
                yes_p = actual_hedge_price
            else:
                no_p = actual_hedge_price

    pnl_cents = (100 - yes_p - no_p) * rq

    # Fee calculation: anchor side = separate order per rung (ceil per-rung is correct).
    # Hedge side = single consolidated order — compute fee on total qty and prorate to this rung
    # to match what Kalshi actually charges (one ceil on full order, not ceil-per-rung).
    filled_side = bot.get('first_fill_side', 'yes')
    anchor_price = yes_p if filled_side == 'yes' else no_p
    hedge_price_val = no_p if filled_side == 'yes' else yes_p
    anchor_fee = _kalshi_side_fee_cents(anchor_price, rq)

    hedge_total_qty = bot.get('hedge_qty', rq)
    if hedge_total_qty > 0 and hedge_total_qty != rq:
        total_hedge_fee = _kalshi_side_fee_cents(hedge_price_val, hedge_total_qty)
        rung_hedge_fee = round(total_hedge_fee * rq / hedge_total_qty)
    else:
        rung_hedge_fee = _kalshi_side_fee_cents(hedge_price_val, rq)

    fee = anchor_fee + rung_hedge_fee
    net_pnl = pnl_cents - fee

    if net_pnl >= 0:
        session_pnl['gross_profit_cents'] += net_pnl
    else:
        session_pnl['gross_loss_cents'] += abs(net_pnl)

    # Track cumulative P&L on the bot
    bot['cumulative_pnl'] = bot.get('cumulative_pnl', 0) + net_pnl
    bot['completed_rungs_count'] = bot.get('completed_rungs_count', 0) + 1
    if not bot.get('_first_rung_completed_at'):
        bot['_first_rung_completed_at'] = now

    _record_trade({
        'bot_id': bot_id, 'ticker': ticker,
        'yes_price': yes_p, 'no_price': no_p,
        'quantity': rq,
        'profit_cents': net_pnl if net_pnl >= 0 else 0,
        'loss_cents': abs(net_pnl) if net_pnl < 0 else 0,
        'fee_cents': fee,
        'result': 'completed' if net_pnl >= 0 else 'arb_loss',
        'exit_via': 'ladder_arb_rung_complete',
        'rung_width': width,
        'rungs_completed': bot.get('completed_rungs_count', 1),
        'rungs_total': len(bot.get('rungs', [])),
        'hedge_latency_ms': bot.get('hedge_latency_ms'),
        'raw_hedge_ms': bot.get('raw_hedge_ms'),
        'fill_duration_s': round(now - bot['first_fill_at']) if bot.get('first_fill_at') else None,
        'timestamp': now,
        'placed_at': bot.get('created_at', now),
        'arb_width': width,
        'game_phase': bot.get('game_phase', 'live'),
        'game_context': _get_game_context(ticker),
        'fill_source': 'ladder_arb',
        'bot_category': 'ladder_arb',
        'type': 'arb',
        'repeat_cycle': bot.get('repeats_done', 0) + 1,
        'repeat_total': (bot.get('repeat_count', 0) or 0) + 1,
        'walk_count': bot.get('walk_count', 0),
        'hard_ceiling': bot.get('hard_ceiling', 98),
    }, bot)

    # Calculate hedge latency from rung fill timestamps
    filled_side = bot.get('first_fill_side', 'yes')
    hedge_side = 'no' if filled_side == 'yes' else 'yes'
    anchor_fill_at = rung.get(f'{filled_side}_filled_at')
    hedge_fill_at = rung.get(f'{hedge_side}_filled_at')
    hedge_latency_s = round(hedge_fill_at - anchor_fill_at, 1) if anchor_fill_at and hedge_fill_at else None

    print(f'✅ RUNG COMPLETE: {bot_id} width={width}¢ YES@{yes_p}¢ NO@{no_p}¢ +{net_pnl}¢ ({bot.get("completed_rungs_count",1)}/{len(bot.get("rungs",[]))} rungs) hedge_lat={hedge_latency_s}s')
    bot_log('RUNG_COMPLETE', bot_id, {
        'rung_idx': bot.get('rungs', []).index(rung) if rung in bot.get('rungs', []) else None,
        'width': width, 'yes_price': yes_p, 'no_price': no_p,
        'combined': yes_p + no_p, 'quantity': rq,
        'gross_pnl': pnl_cents, 'fee': fee, 'net_pnl': net_pnl,
        'anchor_fill_at': anchor_fill_at, 'hedge_fill_at': hedge_fill_at,
        'hedge_latency_s': hedge_latency_s,
        'walk_count': bot.get('walk_count', 0),
        'completed_rungs': bot.get('completed_rungs_count', 1),
        'total_rungs': len(bot.get('rungs', [])),
        'cumulative_pnl': bot.get('cumulative_pnl', 0),
    })

    with _pending_ws_actions_lock:
        _pending_ws_actions.append({
            'bot_id': bot_id, 'action': 'rung_completed',
            'width': width, 'profit_cents': net_pnl,
            'completed_count': bot.get('completed_rungs_count', 1),
        })


def _check_apex_rung_completions(bot_id, bot):
    """Check for newly completed rungs, record their profit, handle hedge history.
    Returns True if ALL rungs are resolved (bot can fully complete)."""
    qty_per = bot.get('quantity', 1)
    newly_completed = []

    for rung in bot.get('rungs', []):
        if rung.get('completed') and not rung.get('_profit_recorded'):
            newly_completed.append(rung)

    for rung in newly_completed:
        _record_rung_completion(bot_id, bot, rung)

    # Propagate hedge-side fill timestamps to individual rungs (consolidated bots)
    # When a single consolidated hedge covers all rungs, the individual rungs don't
    # get {hedge_side}_filled_at set automatically — we back-fill it here.
    if bot.get('_consolidated') and bot.get('_hedge_fill_count', 0) > 0:
        # Verify hedge order actually exists on Kalshi before backfilling
        hedge_oid = bot.get('hedge_order_id')
        if hedge_oid and not bot.get('_hedge_verified'):
            try:
                api_read_limiter.wait()
                order_resp = kalshi_client.get_order(hedge_oid)
                order_data = order_resp.get('order', order_resp) if isinstance(order_resp, dict) else {}
                actual_fills = _parse_fill_count(order_data)
                order_status = order_data.get('status', '')
                _local_hfc = bot.get('_hedge_fill_count', 0)
                _order_count = order_data.get('count', order_data.get('count_fp', ''))
                if actual_fills == 0 and order_status in ('canceled', 'cancelled', 'expired', ''):
                    print(f'🚨 HEDGE VERIFICATION FAILED: {bot_id} order {hedge_oid[:12]} has 0 fills (status={order_status}) — clearing phantom fills')
                    bot_log('APEX_HEDGE_VERIFY_PHANTOM', bot_id, {
                        'order_id': hedge_oid, 'kalshi_status': order_status,
                        'kalshi_fills': 0, 'kalshi_count': _order_count,
                        'local_hedge_fill_count': _local_hfc,
                        'hedge_qty': bot.get('hedge_qty', 0),
                    })
                    bot['_hedge_fill_count'] = 0
                    bot['_hedge_verified'] = True
                    bot['_hedge_phantom'] = True
                else:
                    if actual_fills != _local_hfc:
                        print(f'🔧 HEDGE FILL CORRECTION: {bot_id} local={_local_hfc} actual={actual_fills}')
                    bot_log('APEX_HEDGE_VERIFIED', bot_id, {
                        'order_id': hedge_oid, 'kalshi_status': order_status,
                        'kalshi_fills': actual_fills, 'kalshi_count': _order_count,
                        'local_hedge_fill_count': _local_hfc,
                        'hedge_qty': bot.get('hedge_qty', 0),
                        'corrected': actual_fills != _local_hfc,
                    })
                    bot['_hedge_fill_count'] = actual_fills
                    bot['_hedge_verified'] = True
            except Exception as e:
                if '404' in str(e):
                    print(f'🚨 HEDGE ORDER GONE: {bot_id} order {hedge_oid[:12]} — 404, clearing phantom fills')
                    bot_log('APEX_HEDGE_VERIFY_404', bot_id, {
                        'order_id': hedge_oid, 'local_hedge_fill_count': bot.get('_hedge_fill_count', 0),
                        'hedge_qty': bot.get('hedge_qty', 0),
                    })
                    bot['_hedge_fill_count'] = 0
                    bot['_hedge_verified'] = True
                    bot['_hedge_phantom'] = True
                else:
                    print(f'⚠ Hedge verification failed for {bot_id}: {e}')

        # Only backfill timestamps if verified fills > 0
        if bot.get('_hedge_fill_count', 0) > 0 and not bot.get('_hedge_phantom'):
            _fs = bot.get('first_fill_side', 'yes')
            _hs = 'no' if _fs == 'yes' else 'yes'
            _hedge_fill_ts = bot.get('hedge_fill_at') or time.time()
            _filled_count = 0
            for _r in bot.get('rungs', []):
                _rq = _r.get('quantity', qty_per)
                if _r.get(f'{_fs}_fill_qty', 0) >= _rq and not _r.get(f'{_hs}_filled_at'):
                    if _filled_count + _rq <= bot.get('_hedge_fill_count', 0):
                        _r[f'{_hs}_filled_at'] = _hedge_fill_ts
                        _filled_count += _rq

    # NOTE: Hedge gen completion + state reset is handled by
    # _execute_apex_completion which properly clears rung fill counts.
    # Do NOT reset consolidation state here — doing so leaves orphaned anchor fills
    # that trigger duplicate hedges.

    # Check if ALL rungs are resolved
    all_resolved = True
    # When hedge is fully filled (consolidated), partial rungs are resolved
    # Also verify hedge covers all anchor fills (late anchors may still be amending)
    _fs_chk = bot.get('first_fill_side', 'yes')
    _total_af = sum(
        min(r.get(f'{_fs_chk}_fill_qty', 0), r.get('quantity', qty_per))
        for r in bot.get('rungs', [])
    )
    hedge_fully_done = (bot.get('_consolidated')
                        and bot.get('_hedge_fill_count', 0) >= bot.get('hedge_qty', 0)
                        and bot.get('hedge_qty', 0) > 0
                        and bot.get('hedge_qty', 0) >= _total_af)
    for rung in bot.get('rungs', []):
        if rung.get('completed'):
            continue
        rq = rung.get('quantity', qty_per)
        filled_side = bot.get('first_fill_side')
        if filled_side and rung.get(f'{filled_side}_fill_qty', 0) > 0:
            if hedge_fully_done:
                # Partial fill but hedge is done — treat as resolved
                continue
            # Has anchor fill but not completed — not resolved
            all_resolved = False
            break
        # Has active orders? Check if order IDs exist
        if rung.get('yes_order_id') or rung.get('no_order_id'):
            if hedge_fully_done:
                continue  # Hedge done — unfilled anchors will be cancelled by full completion
            all_resolved = False
            break

    return all_resolved


def _cancel_with_retry(oid, max_retries=2):
    """Cancel an order with rate limiting + retry on 429.
    Returns True on success, False on failure. Logs last error for debugging."""
    _last_err = None
    for attempt in range(max_retries + 1):
        try:
            api_rate_limiter.wait()
            kalshi_client.cancel_order(oid)
            return True
        except Exception as e:
            _last_err = e
            err_str = str(e)
            # 404 = already cancelled/filled — treat as success
            if '404' in err_str:
                return True
            if '429' in err_str and attempt < max_retries:
                time.sleep(0.5)
                continue
            # Log the actual error so we can debug orphans
            print(f'⚠ _cancel_with_retry({oid[:12]}) failed after {attempt+1} attempts: {err_str[:200]}')
    return False


def _handle_late_anchor_fill(bot_id, bot, rung_idx, fill_count):
    """Late Fill Protocol — recalc weighted avg, amend hedge PRICE only, preserve walk timer.

    Serialized via _late_anchor_amend_lock to prevent race conditions.
    Only amends PRICE (to account for new weighted avg). Does NOT change qty.
    Completion handler detects anchor_qty > hedge_qty and handles the difference.
    """
    # Phase 1: quick pre-check inside ws_fill_lock (fast, no API calls)
    with ws_fill_lock:
        filled_side = bot.get('first_fill_side')
        unfilled_side = 'no' if filled_side == 'yes' else 'yes'
        qty_per = bot.get('quantity', 1)

        # Quick total_qty check — if no fills, bail early
        total_qty = 0
        for r in bot.get('rungs', []):
            fq = min(r.get(f'{filled_side}_fill_qty', 0), r.get('quantity', qty_per))
            if fq > 0:
                total_qty += fq
        if total_qty <= 0:
            return

    # Phase 2: serialized amend — only one thread amends at a time
    with _late_anchor_amend_lock:
        # Re-read everything inside ws_fill_lock to get FRESH state
        with ws_fill_lock:
            filled_side = bot.get('first_fill_side')
            unfilled_side = 'no' if filled_side == 'yes' else 'yes'
            qty_per = bot.get('quantity', 1)

            # 1. Recalculate weighted average across ALL filled anchors
            total_qty = 0
            total_cost = 0
            total_width_x_qty = 0
            for r in bot.get('rungs', []):
                fq = min(r.get(f'{filled_side}_fill_qty', 0), r.get('quantity', qty_per))
                if fq > 0:
                    total_qty += fq
                    total_cost += fq * r.get(f'{filled_side}_price', 0)
                    total_width_x_qty += fq * r.get('width', 0)
            if total_qty <= 0:
                return

            new_avg_price = total_cost / total_qty
            new_avg_width = total_width_x_qty / total_qty
            new_target = round(100 - new_avg_price - new_avg_width)

            bot[f'avg_{filled_side}_price'] = round(new_avg_price, 1)
            old_target = bot.get('_target_hedge_price', new_target)
            bot['_target_hedge_price'] = new_target
            bot['_avg_width'] = new_avg_width

            # 2. Price = new target + walk offset (preserve walk progress)
            hedge_oid = bot.get('hedge_order_id')
            if not hedge_oid:
                return

            old_hedge_qty = bot.get('hedge_qty', 0)
            current_hedge_price = bot.get('hedge_price', 0)
            walk_offset = max(0, current_hedge_price - old_target)
            amend_price = max(1, new_target + walk_offset)
            # Cap at hard ceiling to prevent combined from exceeding user-set limit
            _amend_ceiling = bot.get('hard_ceiling', HARD_CEILING_CENTS)
            _amend_max_hedge = _amend_ceiling - round(new_avg_price)
            if _amend_max_hedge >= 1:
                amend_price = min(amend_price, _amend_max_hedge)
            else:
                # Anchor already at/above ceiling — can't hedge profitably
                amend_price = max(1, _amend_max_hedge)
            ticker = bot['ticker']

            # Subtract already-completed hedge generations from total
            # so we only hedge the REMAINING unhedged anchors
            _completed_hedge_qty = sum(h.get('fill_qty', h.get('qty', 0)) for h in bot.get('hedge_history', []))
            _needed_hedge_qty = max(1, total_qty - _completed_hedge_qty)

            # Skip if nothing changed
            if amend_price == current_hedge_price and _needed_hedge_qty == old_hedge_qty:
                return

        # API call OUTSIDE ws_fill_lock but INSIDE _late_anchor_amend_lock
        # Single amend: update BOTH price AND qty on the existing hedge order
        try:
            # Pre-amend diagnostic: check order status before attempting
            try:
                api_read_limiter.wait()
                _pre_check = kalshi_client.get_order(hedge_oid)
                _pre_data = _pre_check.get('order', _pre_check) if isinstance(_pre_check, dict) else {}
                _pre_status = _pre_data.get('status', 'unknown')
                _pre_fills = _parse_fill_count(_pre_data)
                if _pre_status != 'resting':
                    print(f'⚠ LATE ANCHOR PRE-CHECK: {bot_id} hedge {hedge_oid[:12]} status={_pre_status} fills={_pre_fills} — NOT RESTING, skipping amend')
                    bot_log('APEX_LATE_ANCHOR_PRE_CHECK', bot_id, {
                        'hedge_oid': hedge_oid[:12], 'status': _pre_status, 'fills': _pre_fills,
                        'needed_qty': _needed_hedge_qty, 'rung_idx': rung_idx,
                    }, level='WARN')
                    with ws_fill_lock:
                        if _pre_fills > bot.get('_hedge_fill_count', 0):
                            bot['_hedge_fill_count'] = _pre_fills
                        if _pre_status == 'executed':
                            bot['_hedge_verified'] = True
                    return  # Don't try to amend a non-resting order — 404 recovery will handle it
            except Exception as _pc_err:
                print(f'⚠ LATE ANCHOR PRE-CHECK failed: {bot_id}: {_pc_err}')

            amend_kwargs = {f'{unfilled_side}_price': max(1, amend_price)}
            api_rate_limiter.wait()
            kalshi_client.amend_order(
                hedge_oid, ticker=ticker,
                side=unfilled_side, count=_needed_hedge_qty,
                **amend_kwargs
            )

            with ws_fill_lock:
                bot['hedge_price'] = amend_price
                bot['hedge_qty'] = _needed_hedge_qty

            print(f'📈 LATE ANCHOR: {bot_id} hedge {old_hedge_qty}→{_needed_hedge_qty}× @ {amend_price}¢ (anchors={total_qty} completed_hedges={_completed_hedge_qty})')
            bot_log('APEX_LATE_ANCHOR_AMEND', bot_id, {
                'old_hedge_qty': old_hedge_qty, 'new_hedge_qty': _needed_hedge_qty,
                'total_anchors': total_qty, 'completed_hedges': _completed_hedge_qty,
                'old_price': current_hedge_price, 'amend_price': amend_price,
                'avg_width': round(new_avg_width, 1), 'new_target': new_target,
                'walk_offset': walk_offset, 'rung_idx': rung_idx,
            })

        except Exception as e:
            err_str = str(e)
            print(f'⚠️ LATE ANCHOR AMEND FAIL {bot_id}: {err_str}')
            bot_log('APEX_LATE_ANCHOR_AMEND_FAIL', bot_id, {
                'total_anchor_qty': total_qty, 'hedge_qty': _needed_hedge_qty,
                'amend_price': amend_price, 'hedge_order_id': hedge_oid,
                'error': err_str[:300], 'rung_idx': rung_idx,
            }, level='ERROR')
            # If 404, hedge order is gone — verify fills then repost with correct qty
            if '404' in err_str:
                try:
                    api_read_limiter.wait()
                    _verify_resp = kalshi_client.get_order(hedge_oid)
                    _verify_data = _verify_resp.get('order', _verify_resp) if isinstance(_verify_resp, dict) else {}
                    _verify_fills = _parse_fill_count(_verify_data)
                    _verify_status = _verify_data.get('status', '')
                    print(f'   AMEND FAIL VERIFY: status={_verify_status} fills={_verify_fills}')
                    with ws_fill_lock:
                        if _verify_fills > 0:
                            bot['_hedge_fill_count'] = max(bot.get('_hedge_fill_count', 0), _verify_fills)
                        if _verify_status == 'executed':
                            bot['_hedge_verified'] = True
                    # Repost hedge for the needed qty (minus any fills already counted)
                    _repost_needed = _needed_hedge_qty - bot.get('_hedge_fill_count', 0)
                    if _repost_needed > 0 and _verify_status != 'executed':
                        _rp_price = max(1, amend_price)
                        try:
                            _rp_resp, _rp_actual = create_order_maker(
                                ticker=ticker, side=unfilled_side, action='buy',
                                count=_repost_needed, price=_rp_price,
                            )
                            _rp_oid = _rp_resp['order']['order_id']
                            with ws_fill_lock:
                                bot['hedge_order_id'] = _rp_oid
                                bot['hedge_price'] = _rp_actual
                                bot['hedge_qty'] = _repost_needed
                                _all_ids = bot.get('_all_hedge_order_ids', [])
                                _all_ids.append(_rp_oid)
                                bot['_all_hedge_order_ids'] = _all_ids
                            print(f'🔄 LATE ANCHOR REPOST: {bot_id} {unfilled_side} {_repost_needed}× @ {_rp_actual}¢ (old order 404d)')
                            bot_log('APEX_LATE_ANCHOR_REPOST_404', bot_id, {
                                'new_oid': _rp_oid[:12], 'qty': _repost_needed,
                                'price': _rp_actual, 'old_oid': hedge_oid[:12],
                            })
                        except Exception as _rp_err:
                            print(f'⚠ LATE ANCHOR REPOST FAIL: {bot_id}: {_rp_err}')
                except Exception:
                    pass


def _execute_ladder_arb_sweep_and_hedge(bot_id):
    """Spawned from WS fill handler on first anchor fill.
    Phase 1a: Compute weighted avg inside lock (fast)
    Phase 1b: Place consolidated hedge OUTSIDE lock (API call — instant, no lock contention)
    Phase 1c: Store results back inside lock
    Phase 2: Cancel all opposite-side (hedge-side) orders
    Anchor-side orders stay alive — late fills handled by _handle_late_anchor_fill"""

    # ── Phase 1a: Compute inside lock ──
    unfilled_oids = []
    computed = None  # will hold computed values for Phase 1b
    with ws_fill_lock:
        bot = active_bots.get(bot_id)
        if not bot:
            return
        status = bot.get('status', '')
        if status not in ('ladder_arb_yes_filled', 'ladder_arb_no_filled'):
            bot.pop('_sweep_thread_running', None)
            return
        if bot.get('_consolidated'):
            bot.pop('_sweep_thread_running', None)
            save_state()
            return

        filled_side = 'yes' if status == 'ladder_arb_yes_filled' else 'no'
        unfilled_side = 'no' if filled_side == 'yes' else 'yes'
        ticker = bot['ticker']
        qty_per = bot.get('quantity', 1)

        # Clear monitor's sweep flag so it doesn't double-cancel
        bot.pop('_sweep_at', None)

        # Single-pass rung scan: collect unfilled OIDs + filled qty + weighted width
        total_filled_qty = 0
        total_width_x_qty = 0
        for rung in bot.get('rungs', []):
            oid = rung.get(f'{unfilled_side}_order_id')
            if oid:
                unfilled_oids.append(oid)
                rung[f'{unfilled_side}_order_id'] = None
            rq = rung.get('quantity', qty_per)
            fq = min(rung.get(f'{filled_side}_fill_qty', 0), rq)
            if fq > 0:
                total_filled_qty += fq
                total_width_x_qty += rung.get('width', 0) * fq

        if total_filled_qty <= 0:
            bot.pop('_sweep_thread_running', None)
            save_state()
            return

        # Use avg price already computed by WS handler's _recompute_apex_fills
        avg_filled_price = bot.get(f'avg_{filled_side}_price', 0) or 0

        weighted_avg_width = total_width_x_qty / total_filled_qty
        target_hedge = round(100 - avg_filled_price - weighted_avg_width)
        hedge_price = max(1, target_hedge)  # Use calculated price, not bid
        bot['_target_hedge_price'] = target_hedge
        bot['_avg_width'] = weighted_avg_width

        _bot_ceiling = bot.get('hard_ceiling', HARD_CEILING_CENTS)
        max_safe = _bot_ceiling - avg_filled_price
        if hedge_price > max_safe:
            hedge_price = max(max_safe, 1)

        # Save computed values for Phase 1b (outside lock)
        computed = {
            'ticker': ticker, 'unfilled_side': unfilled_side, 'filled_side': filled_side,
            'hedge_price': hedge_price, 'total_filled_qty': total_filled_qty,
            'avg_filled_price': avg_filled_price, 'target_hedge': target_hedge,
            'weighted_avg_width': weighted_avg_width,
            '_fill_at': bot.get('first_fill_at'),  # for raw speed measurement
        }
        # No save_state() here — Phase 1c saves after hedge is placed

    if not computed or computed['hedge_price'] <= 0:
        with ws_fill_lock:
            bot = active_bots.get(bot_id)
            if bot:
                bot.pop('_sweep_thread_running', None)
                save_state()
        return

    # ── Phase 1b: Place hedge OUTSIDE lock — instant API call, no lock contention ──
    _ticker = computed['ticker']
    _unfilled_side = computed['unfilled_side']
    _filled_side = computed['filled_side']
    _hedge_price = computed['hedge_price']
    _total_qty = computed['total_filled_qty']
    _avg_filled = computed['avg_filled_price']

    # Record raw hedge speed RIGHT before API call — nothing between this and HTTP send
    _raw_fill_at = computed.get('_fill_at')
    if _raw_fill_at:
        _raw_ms = (time.time() - _raw_fill_at) * 1000
        with ws_fill_lock:
            _b = active_bots.get(bot_id)
            if _b:
                _b['raw_hedge_ms'] = round(_raw_ms, 1)
        _record_latency('raw_hedge_apex', _raw_ms, {'bot_id': bot_id, 'type': 'apex_sweep'})

    hedge_oid = None
    actual_hedge = None
    _api_start = time.time()
    try:
        hedge_resp, actual_hedge = create_order_maker(
            ticker=_ticker, side=_unfilled_side, action='buy',
            count=_total_qty, price=_hedge_price, priority=True,
            skip_rate_limit=True,
        )
        hedge_oid = hedge_resp['order']['order_id']
        # Round trip = fill → order confirmed on Kalshi
        _rt_ms = (time.time() - _raw_fill_at) * 1000 if _raw_fill_at else None
        _api_ms = (time.time() - _api_start) * 1000
        if _rt_ms is not None:
            _record_latency('fill_to_hedge_apex', _rt_ms, {'bot_id': bot_id, 'type': 'apex_sweep', 'hedge_price': actual_hedge, 'avg_anchor': _avg_filled})
        print(f'📊 APEX HEDGE: {bot_id} @{actual_hedge}¢ × {_total_qty} | raw={round(_raw_ms, 1) if _raw_fill_at else "?"}ms api={round(_api_ms, 1)}ms rt={round(_rt_ms, 1) if _rt_ms else "?"}ms')
        bot_log('APEX_SWEEP_HEDGE_PLACED', bot_id, {
            'side': _unfilled_side, 'qty_sent': _total_qty, 'price_sent': _hedge_price,
            'actual_price': actual_hedge, 'order_id': hedge_oid,
            'avg_anchor_price': _avg_filled, 'target_hedge': computed['target_hedge'],
            'avg_width': round(computed['weighted_avg_width'], 1),
            'raw_ms': round(_raw_ms, 1) if _raw_fill_at else None,
            'api_ms': round(_api_ms, 1),
            'round_trip_ms': round(_rt_ms, 1) if _rt_ms else None,
        })
    except Exception as e:
        print(f'❌ WS SWEEP HEDGE FAIL {bot_id}: {e}')
        bot_log('APEX_SWEEP_HEDGE_FAIL', bot_id, {
            'side': _unfilled_side, 'qty_sent': _total_qty, 'price_sent': _hedge_price,
            'error': str(e),
        }, level='ERROR')

    # ── Phase 1c: Store results back inside lock ──
    with ws_fill_lock:
        bot = active_bots.get(bot_id)
        if not bot:
            return
        if hedge_oid and actual_hedge is not None:
            bot['hedge_order_id'] = hedge_oid
            bot['hedge_price'] = actual_hedge
            # Use max to avoid overwriting a higher value set by late anchor threads
            bot['hedge_qty'] = max(bot.get('hedge_qty', 0), _total_qty)
            bot['_hedge_fill_count'] = 0
            all_ids = bot.get('_all_hedge_order_ids', [])
            all_ids.append(hedge_oid)
            bot['_all_hedge_order_ids'] = all_ids
            master_ids = bot.get('_all_placed_order_ids', [])
            master_ids.append(hedge_oid)
            bot['_all_placed_order_ids'] = master_ids
            if bot.get('rungs'):
                bot['rungs'][0][f'{_unfilled_side}_order_id'] = hedge_oid
                for r in bot['rungs'][1:]:
                    r[f'{_unfilled_side}_order_id'] = None
            bot['_consolidated'] = True
            print(f'🎯 WS SWEEP CONSOLIDATE: {bot_id} {_filled_side.upper()} avg={_avg_filled}¢ → {_unfilled_side.upper()} hedge @{actual_hedge}¢ × {_total_qty}')
            _audit('APEX_HEDGE_POSTED', bot_id, {'ticker': _ticker, 'filled_side': _filled_side, 'hedge_side': _unfilled_side, 'hedge_price': actual_hedge, 'hedge_qty': _total_qty, 'hedge_order_id': hedge_oid, 'source': 'ws_sweep'})
            # Track fill-to-hedge latency (bot-level only — stats already recorded at line 6022)
            fill_at = bot.get('first_fill_at')
            if fill_at:
                f2h_ms = (time.time() - fill_at) * 1000
                bot['hedge_latency_ms'] = round(f2h_ms, 1)
                print(f'   ⏱ Hedge placed latency: {f2h_ms:.0f}ms')

        # ── Anchor-side orders stay alive — do NOT cancel them ──
        # Late fills will be handled by _handle_late_anchor_fill()

        bot.pop('_sweep_thread_running', None)
        save_state()

    # ── Phase 2: Cancel opposite-side orders AFTER hedge is placed ──
    if unfilled_oids:
        cancel_ok = sum(1 for oid in unfilled_oids if _cancel_with_retry(oid))
        print(f'△ APEX SWEEP PHASE2: {bot_id} — cancelled {cancel_ok}/{len(unfilled_oids)} {_unfilled_side} orders')

    # ── Phase 3: Verify anchor fills against Kalshi — catch missed WS fills ──
    if hedge_oid:
        try:
            _p3_bot = active_bots.get(bot_id)
            if _p3_bot and _p3_bot.get('_consolidated'):
                _p3_fs = _p3_bot.get('first_fill_side', _filled_side)
                _p3_missed = 0
                for _p3_ri, _p3_rung in enumerate(_p3_bot.get('rungs', [])):
                    _p3_oid = _p3_rung.get(f'{_p3_fs}_order_id')
                    if not _p3_oid:
                        continue
                    _p3_rq = _p3_rung.get('quantity', _p3_bot.get('quantity', 1))
                    _p3_tracked = _p3_rung.get(f'{_p3_fs}_fill_qty', 0)
                    if _p3_tracked >= _p3_rq:
                        continue  # already fully filled
                    try:
                        api_read_limiter.wait()
                        _p3_resp = kalshi_client.get_order(_p3_oid)
                        _p3_data = _p3_resp.get('order', _p3_resp) if isinstance(_p3_resp, dict) else {}
                        _p3_actual = _parse_fill_count(_p3_data)
                        if _p3_actual > _p3_tracked:
                            _p3_diff = _p3_actual - _p3_tracked
                            _p3_missed += _p3_diff
                            with ws_fill_lock:
                                _p3_rung[f'{_p3_fs}_fill_qty'] = min(_p3_actual, _p3_rq)
                                if not _p3_rung.get(f'{_p3_fs}_filled_at'):
                                    _p3_rung[f'{_p3_fs}_filled_at'] = time.time()
                            print(f'⚡ SWEEP VERIFY: {bot_id} rung[{_p3_ri}] missed {_p3_diff} {_p3_fs} fills (tracked {_p3_tracked} → actual {_p3_actual})')
                    except Exception:
                        pass
                if _p3_missed > 0:
                    bot_log('APEX_SWEEP_MISSED_FILLS', bot_id, {
                        'missed_fills': _p3_missed,
                        'old_hedge_qty': _p3_bot.get('hedge_qty', 0),
                    })
                    # Trigger late anchor amend to update hedge qty
                    _handle_late_anchor_fill(bot_id, _p3_bot, 0, _p3_missed)
        except Exception as _p3_err:
            print(f'⚠ SWEEP VERIFY failed {bot_id}: {_p3_err}')


def _execute_apex_completion(bot_id):
    """Handle full completion of a ladder-arb bot — all rungs resolved.
    Lock strategy: hold ws_fill_lock only for state reads/writes, release for API calls."""

    # ═══ PHASE 1: Guards + Snapshot (LOCKED) ═══
    with ws_fill_lock:
        bot = active_bots.get(bot_id)
        if not bot or bot['status'] in ('stopped', 'completed'):
            return
        if bot.get('_bot_completed'):
            bot['status'] = 'completed'
            return
        if bot.get('_completion_in_progress'):
            return
        bot['_completion_in_progress'] = True

        now = time.time()
        qty_per = bot.get('quantity', 1)

        # ── Record any pending rung completions BEFORE finalizing ──
        _recompute_apex_fills(bot)
        _check_apex_rung_completions(bot_id, bot)

        # ── Guard: don't complete if bot just reset for repeat (no fills yet) ──
        if bot.get('status') == 'waiting_repeat' or (not bot.get('_consolidated') and not bot.get('first_fill_at')):
            print(f'⏳ APEX COMPLETION SKIP: {bot_id} — waiting for repeat or no fills yet')
            bot['_ws_fill_handling'] = False
            bot['_completion_in_progress'] = False
            return

        # ── Guard: don't complete with 0 rungs if there are filled positions ──
        # But allow completion if the hedge is fully filled (consolidated pair is done)
        filled_side_for_guard = bot.get('first_fill_side', 'yes')
        filled_rungs_count = sum(1 for r in bot.get('rungs', [])
                                 if r.get(f'{filled_side_for_guard}_fill_qty', 0) > 0)
        _hedge_done = bot.get('_hedge_fill_count', 0) >= bot.get('hedge_qty', 0) and bot.get('hedge_qty', 0) > 0
        if bot.get('completed_rungs_count', 0) == 0 and filled_rungs_count > 0 and not _hedge_done:
            print(f'🚨 APEX ABORT COMPLETION: {bot_id} has {filled_rungs_count} filled rungs but 0 completions recorded — NOT completing')
            bot_log('ERROR', bot_id, {'step': 'apex_completion_aborted',
                                      'reason': '0_rungs_with_fills',
                                      'filled_rungs': filled_rungs_count})
            _audit('APEX_COMPLETION_ABORTED', bot_id, {'filled_rungs': filled_rungs_count, 'completed_rungs': 0})
            bot['_completion_in_progress'] = False
            return

        # ── Log full state entering completion ──
        bot_log('APEX_COMPLETION_START', bot_id, {
            'hedge_qty': bot.get('hedge_qty', 0),
            '_hedge_fill_count': bot.get('_hedge_fill_count', 0),
            '_hedge_verified': bot.get('_hedge_verified', False),
            '_consolidated': bot.get('_consolidated', False),
            'hedge_order_id': bot.get('hedge_order_id'),
            '_all_hedge_order_ids': bot.get('_all_hedge_order_ids', []),
            'filled_yes_qty': bot.get('filled_yes_qty', 0),
            'filled_no_qty': bot.get('filled_no_qty', 0),
            'first_fill_side': bot.get('first_fill_side'),
            'completed_rungs_count': bot.get('completed_rungs_count', 0),
            '_extra_hedge_placed': bot.get('_extra_hedge_placed', False),
            'cumulative_pnl': bot.get('cumulative_pnl', 0),
        })

        # ── Build cancel set + snapshot values needed for API phase ──
        _og = bot.get('_order_group_id')
        _group_cancelled = False
        if _og:
            try:
                api_rate_limiter.wait()
                kalshi_client.cancel_order_group(_og)
                _group_cancelled = True
                print(f'⚡ APEX COMPLETION: {bot_id} order group cancelled instantly')
            except Exception as _cge:
                # 404 = group already cancelled (by sweep phase 2) — that's OK, orders are gone
                if '404' in str(_cge):
                    _group_cancelled = True
                    print(f'⚡ APEX COMPLETION: {bot_id} order group already cancelled (404)')
                else:
                    print(f'⚠ APEX COMPLETION group cancel failed: {_cge} — falling back to individual')

        # Build master set of ALL order IDs to cancel (catches hedges + anything group missed)
        all_cancel_ids = set()
        _anchor_oids = {}  # oid → (rung_idx, side) for cancel-race fill detection
        # From rungs
        for _ri, rung in enumerate(bot.get('rungs', [])):
            for side in ('yes', 'no'):
                oid = rung.get(f'{side}_order_id')
                if oid:
                    all_cancel_ids.add(oid)
                    if side == bot.get('first_fill_side', 'yes'):
                        _anchor_oids[oid] = (_ri, side)
                    rung[f'{side}_order_id'] = None
        # From hedge tracking
        if bot.get('hedge_order_id'):
            all_cancel_ids.add(bot['hedge_order_id'])
        for oid in bot.get('_all_hedge_order_ids', []):
            all_cancel_ids.add(oid)
        # From hedge history
        for hg in bot.get('hedge_history', []):
            if hg.get('order_id'):
                all_cancel_ids.add(hg['order_id'])
            for oid in hg.get('order_ids', []):
                all_cancel_ids.add(oid)
        # From master placement list (catches any lost refs)
        for oid in bot.get('_all_placed_order_ids', []):
            all_cancel_ids.add(oid)

        cancel_ok = 0
        cancel_fail = 0
        # If group cancel succeeded, rung orders are already gone — only cancel hedge orders
        if _group_cancelled:
            # Only cancel hedge-related orders (not rungs, they were in the group)
            hedge_only_ids = set()
            if bot.get('hedge_order_id'):
                hedge_only_ids.add(bot['hedge_order_id'])
            for oid in bot.get('_all_hedge_order_ids', []):
                hedge_only_ids.add(oid)
            for hg in bot.get('hedge_history', []):
                if hg.get('order_id'):
                    hedge_only_ids.add(hg['order_id'])
                for oid in hg.get('order_ids', []):
                    hedge_only_ids.add(oid)
            all_cancel_ids = hedge_only_ids

        # Snapshot values needed outside lock
        _hedge_oids_set = set(bot.get('_all_hedge_order_ids', []))
        _snap_all_oids = list(set(bot.get('_all_placed_order_ids', []) + bot.get('_all_hedge_order_ids', [])))
        _snap_filled_side = bot.get('first_fill_side', 'yes')
        _snap_unfilled_side = 'no' if _snap_filled_side == 'yes' else 'yes'
        _snap_ticker = bot.get('ticker', '')
        _snap_avg_anchor = bot.get(f'avg_{_snap_filled_side}_price', 0)
        _snap_avg_width = bot.get('_avg_width', 5)
        _snap_extra_hedge_placed = bot.get('_extra_hedge_placed', False)
        _snap_hedge_oid = bot.get('hedge_order_id')
        # Snapshot fill counts for Phase 2 logging (before lock released)
        anchor_qty = bot.get(f'filled_{_snap_filled_side}_qty', 0)
        hedge_qty = bot.get(f'filled_{_snap_unfilled_side}_qty', 0)
    # ═══ END PHASE 1 — lock released, WS fills can process ═══

    _phase3_entered = False
    try:
        # ═══ PHASE 2: All API calls (UNLOCKED) ═══

        # ── Pre-cancel audit: check fills on hedge orders before killing them ──
        _pre_cancel_fills = {}
        for oid in all_cancel_ids:
            if oid in _hedge_oids_set:
                try:
                    api_read_limiter.wait()
                    _pc_resp = kalshi_client.get_order(oid)
                    _pc_data = _pc_resp.get('order', _pc_resp) if isinstance(_pc_resp, dict) else {}
                    _pc_fills = _parse_fill_count(_pc_data)
                    _pc_status = _pc_data.get('status', '')
                    _pc_count = _pc_data.get('count', _pc_data.get('count_fp', ''))
                    _pre_cancel_fills[oid] = {'fills': _pc_fills, 'status': _pc_status, 'count': _pc_count}
                except Exception:
                    _pre_cancel_fills[oid] = {'fills': 'error', 'status': 'unknown'}
        if _pre_cancel_fills:
            bot_log('APEX_PRE_CANCEL_HEDGE_AUDIT', bot_id, {
                'hedge_orders': {k[:12]: v for k, v in _pre_cancel_fills.items()},
                'total_hedge_fills': sum(v['fills'] for v in _pre_cancel_fills.values() if isinstance(v.get('fills'), int)),
            })

        _failed_cancel_oids = []
        for oid in all_cancel_ids:
            if _cancel_with_retry(oid):
                cancel_ok += 1
            else:
                cancel_fail += 1
                if oid in _anchor_oids:
                    _failed_cancel_oids.append(oid)
        print(f'🧹 FULL COMPLETION {bot_id}: cancelled {cancel_ok}/{len(all_cancel_ids)} orders ({cancel_fail} already gone)')
        bot_log('APEX_COMPLETION_CANCELLED', bot_id, {
            'total_orders': len(all_cancel_ids), 'cancelled': cancel_ok, 'already_gone': cancel_fail,
            'group_cancelled': _group_cancelled,
        })

        # ── Cancel-race detection: check if any anchor orders filled instead of cancelling ──
        _cancel_race_fills = 0
        if _failed_cancel_oids or _group_cancelled:
            # After group cancel, check ALL anchor orders since we can't tell which filled
            _oids_to_check = list(_anchor_oids.keys()) if _group_cancelled else _failed_cancel_oids
            for _cr_oid in _oids_to_check:
                try:
                    api_read_limiter.wait()
                    _cr_resp = kalshi_client.get_order(_cr_oid)
                    _cr_data = _cr_resp.get('order', _cr_resp) if isinstance(_cr_resp, dict) else {}
                    _cr_fills = _parse_fill_count(_cr_data)
                    _cr_ri, _cr_side = _anchor_oids[_cr_oid]
                    _rung = bot['rungs'][_cr_ri]
                    _tracked = _rung.get(f'{_cr_side}_fill_qty', 0)
                    if _cr_fills > _tracked:
                        _surprise = _cr_fills - _tracked
                        _cancel_race_fills += _surprise
                        _rung[f'{_cr_side}_fill_qty'] = _cr_fills
                        if not _rung.get(f'{_cr_side}_filled_at'):
                            _rung[f'{_cr_side}_filled_at'] = now
                        print(f'⚡ CANCEL-RACE FILL: {bot_id} rung[{_cr_ri}] {_cr_side} +{_surprise} (tracked {_tracked} → actual {_cr_fills})')
                except Exception:
                    pass
            if _cancel_race_fills > 0:
                _recompute_apex_fills(bot)
                bot_log('APEX_CANCEL_RACE_FILLS', bot_id, {
                    'surprise_fills': _cancel_race_fills,
                    'checked_orders': len(_oids_to_check),
                    'filled_yes_qty': bot.get('filled_yes_qty', 0),
                    'filled_no_qty': bot.get('filled_no_qty', 0),
                })

        # ── Safety: verify ACTUAL fills on Kalshi for every order this bot placed ──
        # Local fill tracking can be wrong (post_only price adjustment, WS race, etc.)
        # The only source of truth is each order's fill count on Kalshi.
        filled_side = _snap_filled_side
        unfilled_side = _snap_unfilled_side

        # Query every order this bot ever placed and sum actual fills per side
        # Uses snapshot of order IDs from Phase 1
        _all_oids = _snap_all_oids
        _verified_yes = 0
        _verified_no = 0
        _verified_count = 0
        _verify_errors = 0
        try:
            for _oid in _all_oids:
                if not _oid:
                    continue
                try:
                    api_read_limiter.wait()
                    _ord_resp = kalshi_client.get_order(_oid)
                    _ord_data = _ord_resp.get('order', _ord_resp) if isinstance(_ord_resp, dict) else {}
                    _ord_fills = _parse_fill_count(_ord_data)
                    _ord_side = _ord_data.get('side', '')
                    if _ord_fills > 0:
                        if _ord_side == 'yes':
                            _verified_yes += _ord_fills
                        elif _ord_side == 'no':
                            _verified_no += _ord_fills
                    _verified_count += 1
                except Exception:
                    _verify_errors += 1
            # Only unhedged when anchor side exceeds hedge side — never the reverse
            # (reverse means Kalshi settled/closed out, extra hedges already covered it)
            _anchor_verified = _verified_yes if filled_side == 'yes' else _verified_no
            _hedge_verified = _verified_no if filled_side == 'yes' else _verified_yes
            unhedged = max(0, _anchor_verified - _hedge_verified)
            _heavy_side = filled_side if _anchor_verified > _hedge_verified else unfilled_side
            if unhedged > 0:
                print(f'⚠ APEX ORDER VERIFY: {bot_id} Kalshi fills anchor({filled_side.upper()})={_anchor_verified} hedge({unfilled_side.upper()})={_hedge_verified} → {unhedged} unhedged')
            else:
                print(f'✅ APEX ORDER VERIFY: {bot_id} balanced anchor={_anchor_verified} hedge={_hedge_verified}')
            bot_log('APEX_ORDER_VERIFY', bot_id, {
                'verified_yes': _verified_yes, 'verified_no': _verified_no,
                'unhedged': unhedged, 'heavy_side': _heavy_side if unhedged > 0 else None,
                'orders_checked': _verified_count, 'errors': _verify_errors,
                'total_orders': len(_all_oids),
                'local_anchor_qty': anchor_qty, 'local_hedge_qty': hedge_qty,
                'local_unhedged': anchor_qty - hedge_qty,
            })
        except Exception as _pv_err:
            print(f'⚠ APEX ORDER VERIFY failed: {bot_id}: {_pv_err} — falling back to local')
            bot_log('APEX_ORDER_VERIFY_FAIL', bot_id, {
                'error': str(_pv_err)[:200],
                'local_anchor_qty': anchor_qty, 'local_hedge_qty': hedge_qty,
            }, level='ERROR')
            unhedged = max(0, anchor_qty - hedge_qty)
        # ═══ PHASE 3: Write results + finalize (RE-ACQUIRE LOCK) ═══
        ws_fill_lock.acquire()
        _phase3_entered = True
        bot = active_bots.get(bot_id)
        if not bot:
            return

        # Apply cancel-race results + recompute with fresh state
        _recompute_apex_fills(bot)
        anchor_qty = bot.get(f'filled_{filled_side}_qty', 0)
        hedge_qty = bot.get(f'filled_{unfilled_side}_qty', 0)
        # Use verified counts if available, else fall back to local
        if _verified_count > 0:
            unhedged = max(0, (_verified_yes if filled_side == 'yes' else _verified_no) - (_verified_no if filled_side == 'yes' else _verified_yes))

        bot_log('APEX_UNHEDGED_CHECK', bot_id, {
            'anchor_qty': anchor_qty, 'hedge_qty': hedge_qty, 'unhedged': unhedged,
            'filled_side': filled_side, 'unfilled_side': unfilled_side,
            'filled_yes_qty': bot.get('filled_yes_qty', 0),
            'filled_no_qty': bot.get('filled_no_qty', 0),
            '_hedge_fill_count': bot.get('_hedge_fill_count', 0),
            'hedge_order_id': bot.get('hedge_order_id'),
            '_extra_hedge_placed': bot.get('_extra_hedge_placed', False),
        })
        if unhedged > 0:
            # Guard: don't re-place if we already have a live hedge for this exact scenario
            existing_hedge = bot.get('hedge_order_id')
            if existing_hedge and bot.get('_extra_hedge_placed'):
                # Verify the extra hedge order still exists on Kalshi
                try:
                    api_read_limiter.wait()
                    _eh_resp = kalshi_client.get_order(existing_hedge)
                    _eh_data = _eh_resp.get('order', _eh_resp) if isinstance(_eh_resp, dict) else {}
                    _eh_status = _eh_data.get('status', '')
                    _eh_fills = _parse_fill_count(_eh_data)
                    _eh_count = _eh_data.get('count', _eh_data.get('count_fp', ''))
                    bot_log('APEX_EXTRA_HEDGE_CHECK', bot_id, {
                        'order_id': existing_hedge, 'kalshi_status': _eh_status,
                        'kalshi_fills': _eh_fills, 'kalshi_count': _eh_count,
                        'local_hedge_qty': bot.get('hedge_qty', 0),
                        'local_hedge_fill_count': bot.get('_hedge_fill_count', 0),
                    })
                    if _eh_fills > 0:
                        # Extra hedge fills settle against unhedged anchors on Kalshi instantly.
                        # Query Kalshi for ACTUAL remaining position instead of using stale local counts.
                        try:
                            api_read_limiter.wait()
                            _pos_resp = kalshi_client.get_positions(ticker=bot.get('ticker', ''))
                            _positions = _pos_resp.get('market_positions', _pos_resp.get('positions', []))
                            _real_qty = 0
                            for _p in _positions:
                                if _p.get('ticker') == bot.get('ticker', ''):
                                    _real_qty = abs(_parse_position_qty(_p))
                                    break
                            if _real_qty == 0:
                                # No position on Kalshi — everything settled, we're done
                                print(f'✅ APEX EXTRA HEDGE SETTLED: {bot_id} — Kalshi position is 0, all settled')
                                bot_log('APEX_EXTRA_HEDGE_SETTLED', bot_id, {
                                    'order_id': existing_hedge, 'fills': _eh_fills, 'kalshi_position': 0,
                                })
                                unhedged = 0
                            else:
                                unhedged = _real_qty
                                print(f'✅ APEX EXTRA HEDGE UPDATE: {bot_id} hedge {existing_hedge[:12]} has {_eh_fills} fills, Kalshi position={_real_qty}, unhedged={unhedged}')
                                bot_log('APEX_EXTRA_HEDGE_PARTIAL', bot_id, {
                                    'order_id': existing_hedge, 'fills': _eh_fills,
                                    'kalshi_position': _real_qty, 'unhedged': unhedged,
                                })
                        except Exception as _pe:
                            # Can't verify — fall back to local tracking
                            already_counted = bot.get('_hedge_fill_count', 0)
                            extra_new = max(0, _eh_fills - already_counted)
                            if extra_new > 0:
                                hedge_qty += extra_new
                            unhedged = max(0, anchor_qty - hedge_qty)
                            print(f'✅ APEX EXTRA HEDGE UPDATE: {bot_id} hedge {existing_hedge[:12]} fills={_eh_fills} (Kalshi check failed: {_pe}), unhedged={unhedged}')
                            bot_log('APEX_EXTRA_HEDGE_FALLBACK', bot_id, {
                                'order_id': existing_hedge, 'fills': _eh_fills,
                                'already_counted': already_counted, 'extra_new': extra_new,
                                'unhedged': unhedged, 'error': str(_pe),
                            })
                    elif _eh_status in ('resting', 'pending'):
                        # Still alive and waiting — don't spam new ones
                        return
                    else:
                        # Order is cancelled/expired/gone — clear flag, proceed to complete
                        print(f'⚠ APEX EXTRA HEDGE GONE: {bot_id} hedge {existing_hedge[:12]} status={_eh_status} — accepting {unhedged} unhedged, completing')
                        bot_log('APEX_EXTRA_HEDGE_GONE', bot_id, {
                            'order_id': existing_hedge, 'kalshi_status': _eh_status,
                            'fills': _eh_fills, 'unhedged': unhedged,
                        })
                        bot['_extra_hedge_placed'] = False
                        unhedged = 0  # Accept the loss, proceed to completion
                except Exception as _eh_err:
                    if '404' in str(_eh_err):
                        # Order gone from Kalshi — clear flag and complete
                        print(f'⚠ APEX EXTRA HEDGE 404: {bot_id} hedge {existing_hedge[:12]} — accepting {unhedged} unhedged, completing')
                        bot_log('APEX_EXTRA_HEDGE_404', bot_id, {
                            'order_id': existing_hedge, 'unhedged': unhedged,
                        })
                        bot['_extra_hedge_placed'] = False
                        unhedged = 0  # Accept the loss, proceed to completion
                    else:
                        # Can't verify — wait and retry next cycle
                        return
            # Late anchor fills came in — save completed hedge to history, place new generation
            _old_hedge_oid = bot.get('hedge_order_id')
            _old_hedge_fills = bot.get('_hedge_fill_count', 0)
            _old_hedge_qty = bot.get('hedge_qty', 0)
            _old_hedge_price = bot.get('hedge_price', 0)
            if _old_hedge_oid and _old_hedge_fills > 0:
                _hh = bot.get('hedge_history', [])
                _hh.append({
                    'order_id': _old_hedge_oid,
                    'order_ids': list(bot.get('_all_hedge_order_ids', [])),
                    'side': unfilled_side,
                    'price': _old_hedge_price,
                    'qty': _old_hedge_qty,
                    'fill_qty': _old_hedge_fills,
                })
                bot['hedge_history'] = _hh
                bot_log('APEX_HEDGE_GEN_COMPLETE', bot_id, {
                    'old_hedge_oid': _old_hedge_oid, 'old_fills': _old_hedge_fills,
                    'old_qty': _old_hedge_qty, 'old_price': _old_hedge_price,
                    'unhedged': unhedged,
                })

            ticker = bot.get('ticker', '')
            avg_anchor = bot.get(f'avg_{filled_side}_price', 0)
            target_hedge = round(100 - avg_anchor - bot.get('_avg_width', 5))
            _bc = bot.get('hard_ceiling', HARD_CEILING_CENTS)
            max_safe = _bc - avg_anchor
            if max_safe < 2:
                # Anchor already at/above ceiling — extra hedge would complete at a loss
                print(f'⚠ APEX EXTRA HEDGE SKIP: {bot_id} max_safe={max_safe}¢ (anchor={avg_anchor}¢ ceiling={_bc}¢) — unprofitable')
                bot_log('APEX_EXTRA_HEDGE_SKIP', bot_id, {
                    'avg_anchor': avg_anchor, 'max_safe': max_safe, 'ceiling': _bc,
                    'unhedged': unhedged, 'reason': 'ceiling_exceeded',
                })
                unhedged = 0  # Skip extra hedge, fall through to completion
            hedge_price = min(max(1, target_hedge), max(1, max_safe))
            # Re-check unhedged — GONE/404 paths above may have zeroed it
            if unhedged <= 0:
                print(f'✅ APEX EXTRA HEDGE: {bot_id} unhedged resolved to 0 after verify — proceeding to completion')
                # Fall through to completion below
            else:
                print(f'⚠ APEX UNHEDGED ANCHORS: {bot_id} anchor={anchor_qty} hedge={hedge_qty} → placing {unhedged} extra hedge @ {hedge_price}¢')
                bot_log('APEX_EXTRA_HEDGE_PLACING', bot_id, {
                    'anchor_qty': anchor_qty, 'hedge_qty': hedge_qty, 'unhedged': unhedged,
                    'side': unfilled_side, 'price': hedge_price, 'avg_anchor': avg_anchor,
                    'target_hedge': target_hedge, 'max_safe': max_safe,
                    '_all_hedge_order_ids': bot.get('_all_hedge_order_ids', []),
                })
                try:
                    resp, actual_price = create_order_maker(
                        ticker=ticker, side=unfilled_side, action='buy',
                        count=unhedged, price=hedge_price, priority=True,
                        skip_rate_limit=True,
                    )
                    extra_oid = resp['order']['order_id']
                    print(f'   ✅ Extra hedge placed: {unfilled_side.upper()} {unhedged}x @{actual_price}¢ | {extra_oid[:12]}')
                    bot_log('APEX_EXTRA_HEDGE_PLACED', bot_id, {
                        'order_id': extra_oid, 'side': unfilled_side,
                        'qty': unhedged, 'price_sent': hedge_price, 'actual_price': actual_price,
                        'anchor_qty': anchor_qty, 'hedge_qty_before': hedge_qty,
                    })
                    # Don't mark bot complete yet — let monitor handle the extra hedge fill
                    bot['hedge_order_id'] = extra_oid
                    bot['hedge_price'] = actual_price
                    bot['hedge_qty'] = unhedged
                    bot['_hedge_fill_count'] = 0
                    bot['_hedge_verified'] = False
                    bot['_ws_fill_handling'] = False
                    bot['_bot_completed'] = False
                    bot['_completion_repeat_processed'] = False  # Allow re-completion after extra hedge fills
                    bot['_extra_hedge_placed'] = True
                    bot['status'] = f'ladder_arb_{filled_side}_filled'
                    all_ids = bot.get('_all_hedge_order_ids', [])
                    all_ids.append(extra_oid)
                    bot['_all_hedge_order_ids'] = all_ids
                    # Also track in placed IDs so verify loop counts its fills
                    _placed = bot.get('_all_placed_order_ids', [])
                    _placed.append(extra_oid)
                    bot['_all_placed_order_ids'] = _placed
                    save_state()
                    return  # Don't complete — wait for extra hedge to fill
                except Exception as e:
                    _err_str = str(e)
                    print(f'   Extra hedge failed: {e}')
                    bot_log('APEX_EXTRA_HEDGE_FAIL', bot_id, {
                        'side': unfilled_side, 'qty': unhedged, 'price': hedge_price,
                        'error': _err_str[:200],
                    }, level='ERROR')
                    bot['_extra_hedge_placed'] = False
                    # 400 = bad request (market closed, invalid order) — don't retry, accept loss
                    if '400' in _err_str:
                        print(f'   400 error — accepting {unhedged} unhedged, completing')
                        # Fall through to completion below
                    else:
                        return

        total_pnl = bot.get('cumulative_pnl', 0)
        completed_count = bot.get('completed_rungs_count', 0)

        # Calculate hedge fill latency (first anchor fill → completion)
        _first_fill = bot.get('first_fill_at')
        if _first_fill:
            bot['hedge_fill_latency_ms'] = round((now - _first_fill) * 1000, 1)

        # Guard: prevent double-completion from incrementing repeats_done twice
        if bot.get('_completion_repeat_processed'):
            print(f'⚠ APEX COMPLETION SKIP: {bot_id} repeat already processed')
            return
        bot['_completion_repeat_processed'] = True

        # ── Orphan check: verify Kalshi position is actually 0 before completing ──
        # CRITICAL: subtract positions held by OTHER active bots on same ticker
        # (e.g. phantom ladders), otherwise we'd hedge THEIR positions as "orphans"
        _ticker_for_pos = bot.get('ticker', '')
        _orphan_qty = 0
        _orphan_side = None
        try:
            api_read_limiter.wait()
            _pos_resp = kalshi_client.get_positions(ticker=_ticker_for_pos)
            _pos_list = _pos_resp.get('market_positions', _pos_resp.get('positions', []))
            for _p in _pos_list:
                if _p.get('ticker') == _ticker_for_pos:
                    _net_pos = float(_p.get('position_fp', '0') or '0')
                    # Subtract positions held by OTHER active bots on this ticker
                    _other_bot_pos = 0
                    for _ob_id, _ob in active_bots.items():
                        if _ob_id == bot_id:
                            continue
                        if _ob.get('ticker') != _ticker_for_pos and _ob.get('hedge_ticker') != _ticker_for_pos:
                            continue
                        if _ob.get('status') in ('stopped', 'completed'):
                            continue
                        _ob_yes = _ob.get('yes_fill_qty', 0) or 0
                        _ob_no = _ob.get('no_fill_qty', 0) or 0
                        _other_bot_pos += (_ob_yes - _ob_no)
                    _this_bot_pos = _net_pos - _other_bot_pos
                    if abs(_this_bot_pos) >= 1:
                        _orphan_qty = int(abs(_this_bot_pos))
                        _orphan_side = 'yes' if _this_bot_pos > 0 else 'no'
                        print(f'⚠ APEX ORPHAN CHECK: {bot_id} Kalshi net={_net_pos} other_bots={_other_bot_pos} this_bot={_this_bot_pos} → {_orphan_qty} orphan {_orphan_side.upper()}')
                        bot_log('APEX_ORPHAN_DETECTED', bot_id, {
                            'ticker': _ticker_for_pos, 'net_position': _net_pos,
                            'other_bot_position': _other_bot_pos, 'this_bot_position': _this_bot_pos,
                            'orphan_qty': _orphan_qty, 'orphan_side': _orphan_side,
                        })
                    elif abs(_net_pos) >= 1:
                        print(f'👻 APEX ORPHAN SKIP: {bot_id} Kalshi net={_net_pos} but {_other_bot_pos} held by other bots — not orphaned')
                    break
        except Exception as _pe:
            print(f'⚠ APEX ORPHAN CHECK failed: {bot_id}: {_pe}')
            bot_log('APEX_ORPHAN_CHECK_FAIL', bot_id, {'error': str(_pe)[:200]}, level='ERROR')

        if _orphan_qty > 0 and _orphan_side:
            # Hedge the orphans: buy the opposite side to close out
            _hedge_orphan_side = 'no' if _orphan_side == 'yes' else 'yes'
            _orphan_bid = (fresh_no_bid if _hedge_orphan_side == 'no' else fresh_yes_bid) if 'fresh_no_bid' in dir() else 0
            if _orphan_bid <= 0:
                try:
                    api_read_limiter.wait()
                    _ob = kalshi_client.get_market_orderbook(_ticker_for_pos)
                    _orphan_bid = _best_bid(_ob, _hedge_orphan_side)
                except Exception:
                    _orphan_bid = 50  # fallback
            _orphan_price = max(1, _orphan_bid)
            try:
                print(f'🔧 APEX ORPHAN HEDGE: {bot_id} placing {_hedge_orphan_side.upper()} {_orphan_qty}x @{_orphan_price}¢ to close orphans')
                _orph_resp, _orph_actual = create_order_maker(
                    ticker=_ticker_for_pos, side=_hedge_orphan_side, action='buy',
                    count=_orphan_qty, price=_orphan_price, priority=True,
                    skip_rate_limit=True,
                )
                _orph_oid = _orph_resp['order']['order_id']
                bot_log('APEX_ORPHAN_HEDGE_PLACED', bot_id, {
                    'side': _hedge_orphan_side, 'qty': _orphan_qty,
                    'price': _orph_actual, 'order_id': _orph_oid,
                })
                print(f'   ✅ Orphan hedge placed: {_hedge_orphan_side.upper()} {_orphan_qty}x @{_orph_actual}¢ | {_orph_oid[:12]}')
                # Track it so the monitor can walk it
                bot['_orphan_hedge_oid'] = _orph_oid
                bot['_orphan_hedge_qty'] = _orphan_qty
                bot['_orphan_hedge_side'] = _hedge_orphan_side
            except Exception as _oe:
                print(f'⚠ APEX ORPHAN HEDGE FAILED: {bot_id}: {_oe}')
                bot_log('APEX_ORPHAN_HEDGE_FAIL', bot_id, {
                    'side': _hedge_orphan_side, 'qty': _orphan_qty,
                    'price': _orphan_price, 'error': str(_oe)[:200],
                }, level='ERROR')

        # Repeat logic — repeat_count = number of ADDITIONAL runs after the first
        repeats_done_now = bot.get('repeats_done', 0) + 1
        bot['repeats_done'] = repeats_done_now
        repeat_total = bot.get('repeat_count', 0)
        will_repeat = repeats_done_now <= repeat_total

        bot['completed_at'] = now
        bot['status'] = 'waiting_repeat' if will_repeat else 'completed'
        bot['_bot_completed'] = True
        bot['lifetime_pnl'] = bot.get('lifetime_pnl', 0) + total_pnl
        session_pnl['completed_bots'] += 1

        if will_repeat:
            bot['waiting_repeat_since'] = now
            bot['first_fill_at'] = None
            bot['first_fill_side'] = None
            bot['_consolidated'] = False
            # DO NOT reset _bot_completed or _completion_repeat_processed here —
            # second completion trigger can fire before repeat posts new orders.
            # These get reset when the repeat actually places orders (waiting_repeat handler).
            bot['_hedge_verified'] = False
            bot['_apex_sellback_attempted'] = False
            bot['_extra_hedge_placed'] = False
            bot['hedge_history'] = []
            # lifetime_pnl already updated above — don't double-add
            bot['cumulative_pnl'] = 0
            bot['completed_rungs_count'] = 0
            bot['hedge_order_id'] = None
            bot['hedge_price'] = 0
            bot['hedge_qty'] = 0
            bot['_hedge_fill_count'] = 0
            bot['_all_hedge_order_ids'] = []
            bot['_all_placed_order_ids'] = []
            bot['walk_count'] = 0
            bot['first_fill_at'] = None
            bot['first_fill_side'] = None
            for rung in bot.get('rungs', []):
                rung['completed'] = False
                rung['_profit_recorded'] = False
                rung['yes_fill_qty'] = 0
                rung['no_fill_qty'] = 0
                rung['yes_filled_at'] = None
                rung['no_filled_at'] = None
                rung['yes_order_id'] = None
                rung['no_order_id'] = None

        bot_log('LADDER_ARB_FULL_COMPLETE', bot_id, {
            'total_pnl': total_pnl, 'completed_rungs': completed_count,
            'will_repeat': will_repeat,
        })
        print(f'🏁 APEX FULLY DONE: {bot_id} {completed_count} rungs completed, total P&L: {total_pnl}¢'
              + (f' → repeat {repeats_done_now}/{repeat_total}' if will_repeat else ' → done'))
        _audit('APEX_COMPLETE', bot_id, {'ticker': bot.get('ticker', ''), 'total_pnl': total_pnl, 'completed_rungs': completed_count, 'will_repeat': will_repeat})

        ws_fill_lock.release()
        _phase3_entered = False
        with _pending_ws_actions_lock:
            _pending_ws_actions.append({'bot_id': bot_id, 'action': 'completed', 'profit_cents': total_pnl})
            if will_repeat:
                _pending_ws_actions.append({
                    'bot_id': bot_id, 'action': 'repeat_spawned',
                    'repeat_num': repeats_done_now, 'repeat_total': repeat_total,
                })

        save_state()
    finally:
        if _phase3_entered:
            try:
                ws_fill_lock.release()
            except RuntimeError:
                pass  # already released
        bot = active_bots.get(bot_id)
        if bot:
            bot['_completion_in_progress'] = False


@app.route('/api/bot/ladder-arb', methods=['POST'])
def create_ladder_arb_bot():
    """Apex bot: unified multi-width arb, places YES+NO at each selected width as rungs.
    One bot watches all fills, computes weighted averages, and walks the unfilled side."""
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        data = request.json or {}
        ticker = data.get('ticker', '')
        widths = data.get('widths', [])
        quantity = int(data.get('quantity', 1))
        repeat_count = int(data.get('repeat_count', 0))
        hard_ceiling = min(98, max(96, int(data.get('hard_ceiling', HARD_CEILING_CENTS))))

        if not ticker:
            return jsonify({'error': 'Missing ticker'}), 400
        if not widths or len(widths) < 1 or len(widths) > 20:
            return jsonify({'error': 'Need 1-20 widths'}), 400

        widths = sorted([int(w) for w in widths])
        width_scaling = data.get('width_scaling', len(widths) >= 2)

        # Auto-detect game phase
        manual_phase = data.get('game_phase')
        if manual_phase in ('live', 'pregame'):
            game_phase = manual_phase
        else:
            game_phase = 'live' if _is_game_live(ticker) else 'pregame'

        # Apex has NO late-game block — Meridian rebalancer handles late-game exits
        # (late game block is only on phantom/anchor bots)

        # One Apex per ticker — prevent duplicate bots on same line
        existing_apex = next(
            (bid for bid, b in active_bots.items()
             if b.get('ticker') == ticker and b.get('bot_category') == 'ladder_arb'
             and b.get('status') not in ('completed', 'stopped', 'cancelled', 'dead')),
            None
        )
        if existing_apex:
            return jsonify({'error': f'Already have an active Apex bot on this line: {existing_apex[:30]}'}), 400

        # Phantom interference check — Apex has both-side orders, phantom positions would net
        _phantom_conflict = next(
            (bid for bid, b in active_bots.items()
             if b.get('bot_category') in ('anchor_dog', 'anchor_ladder')
             and b.get('status') not in ('completed', 'stopped', 'cancelled', 'dead')
             and (b.get('ticker') == ticker or b.get('hedge_ticker') == ticker)),
            None
        )
        if _phantom_conflict:
            return jsonify({'error': f'Phantom bot active on {ticker} — Apex positions would interfere: {_phantom_conflict[:30]}'}), 400

        # Bot cap
        MAX_BOTS_PER_TICKER = 5
        active_on_ticker = sum(
            1 for b in active_bots.values()
            if b.get('ticker') == ticker
            and b.get('status') not in ('completed', 'stopped', 'cancelled', 'dead')
        )
        if active_on_ticker >= MAX_BOTS_PER_TICKER:
            return jsonify({'error': f'Bot cap: {active_on_ticker} bots on {ticker} (max {MAX_BOTS_PER_TICKER})'}), 400

        # Fetch live orderbook
        api_read_limiter.wait()
        ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
        ob = ob_data.get('orderbook', ob_data)
        yes_levels = sorted(ob.get('yes', []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
        no_levels  = sorted(ob.get('no',  []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
        live_yes_bid = (yes_levels[0][0] if isinstance(yes_levels[0], list) else yes_levels[0].get('price', 0)) if yes_levels else 0
        live_no_bid  = (no_levels[0][0]  if isinstance(no_levels[0], list)  else no_levels[0].get('price', 0))  if no_levels  else 0
        live_yes_ask = 100 - live_no_bid if live_no_bid > 0 else 99
        live_no_ask  = 100 - live_yes_bid if live_yes_bid > 0 else 99

        if live_yes_bid <= 0:
            return jsonify({'error': 'No YES bids in orderbook — phantom arb'}), 400
        if live_no_bid <= 0:
            return jsonify({'error': 'No NO bids in orderbook — phantom arb'}), 400
        # NOTE: bid sum >= 100 is normal for most markets. The strategy is posting
        # maker orders and letting game volatility fill them — NOT waiting for instant arb.
        # Only block if there are literally no bids (dead market).


        # Compute prices for each width and validate
        rung_specs = []
        for w in widths:
            target_yes, target_no = _calculate_arb_prices_server(
                live_yes_bid, live_no_bid, live_yes_ask, live_no_ask, w
            )
            profit = 100 - target_yes - target_no
            if profit <= 0:
                continue
            rung_qty = _scale_qty_for_width(quantity, w) if width_scaling else quantity
            if target_yes + target_no >= HARD_CEILING_CENTS:
                continue
            if target_yes >= live_yes_ask and live_yes_ask > 0:
                continue
            if target_no >= live_no_ask and live_no_ask > 0:
                continue
            rung_specs.append({'width': w, 'yes_price': target_yes, 'no_price': target_no, 'rung_qty': rung_qty})

        if not rung_specs:
            return jsonify({'error': 'No valid widths after price computation'}), 400

        # Place orders for all rungs via BATCH API (2 calls instead of 2×N)
        placed_rungs = []
        total_scaled_qty = 0
        all_placed_oids = []  # Master list of ALL order IDs for cleanup

        _order_group_id = _create_order_group()
        print(f'△ APEX PLACING: {ticker} | {len(rung_specs)} rungs to place (base_qty={quantity}, scaling={width_scaling}) group={(_order_group_id or "none")[:8]}')

        # Batch YES orders and NO orders
        yes_specs = [{'ticker': ticker, 'side': 'yes', 'count': s['rung_qty'], 'price': s['yes_price']} for s in rung_specs]
        no_specs  = [{'ticker': ticker, 'side': 'no',  'count': s['rung_qty'], 'price': s['no_price']}  for s in rung_specs]
        yes_results = create_orders_batch(yes_specs, order_group_id=_order_group_id)
        no_results  = create_orders_batch(no_specs, order_group_id=_order_group_id)

        for spec_idx, spec in enumerate(rung_specs):
            try:
                if yes_results[spec_idx] is None or no_results[spec_idx] is None:
                    print(f'  ⚠ Rung {spec_idx+1}/{len(rung_specs)}: w={spec["width"]}¢ SKIPPED (batch partial failure)')
                    continue
                yr, yes_actual = yes_results[spec_idx]
                nr, no_actual  = no_results[spec_idx]
                yes_oid = yr['order']['order_id']
                no_oid  = nr['order']['order_id']
                all_placed_oids.extend([yes_oid, no_oid])
                # Recalculate width from actual posted prices (post_only may have adjusted them)
                actual_width = 100 - yes_actual - no_actual
                if yes_actual != spec['yes_price'] or no_actual != spec['no_price']:
                    print(f'  ⚠ PRICE ADJUSTED rung {spec_idx+1}: Y{spec["yes_price"]}→{yes_actual}¢ N{spec["no_price"]}→{no_actual}¢ (width {spec["width"]}→{actual_width}¢)')
                    bot_log('APEX_RUNG_PRICE_ADJUSTED', '', {
                        'rung_idx': spec_idx, 'ticker': ticker,
                        'req_yes': spec['yes_price'], 'actual_yes': yes_actual,
                        'req_no': spec['no_price'], 'actual_no': no_actual,
                        'req_width': spec['width'], 'actual_width': actual_width,
                    })
                placed_rungs.append({
                    'width': actual_width,
                    'yes_price': yes_actual, 'no_price': no_actual,
                    'yes_order_id': yes_oid, 'no_order_id': no_oid,
                    'yes_fill_qty': 0, 'no_fill_qty': 0,
                    'yes_filled_at': None, 'no_filled_at': None,
                    'quantity': spec['rung_qty'],
                })
                total_scaled_qty += spec['rung_qty']
                print(f'  ✅ Rung {spec_idx+1}/{len(rung_specs)}: w={actual_width}¢ Y{yes_actual}¢ N{no_actual}¢ ×{spec["rung_qty"]}')
            except Exception as rung_err:
                print(f'  ❌ Rung {spec_idx+1}/{len(rung_specs)}: w={spec["width"]}¢ FAILED: {rung_err}')
                continue

        if not placed_rungs:
            return jsonify({'error': 'No rungs placed successfully'}), 500
        # Sort rungs by width for consistent display
        placed_rungs.sort(key=lambda r: r['width'])

        # Subscribe WS
        if ws_manager and ws_manager.connected:
            ws_manager.add_ticker(ticker)

        bot_id = f'larb_{ticker}_{int(time.time() * 1000)}'
        narrowest_width = min(r['width'] for r in placed_rungs)

        active_bots[bot_id] = {
            'ticker': ticker,
            'bot_category': 'ladder_arb',
            'status': 'ladder_arb_posted',
            'rungs': placed_rungs,
            'quantity': quantity,
            'width_scaling': width_scaling,
            'total_rungs': len(placed_rungs),
            'game_phase': game_phase,
            'created_at': time.time(),
            'posted_at': time.time(),
            'repeat_count': repeat_count,
            'repeats_done': 0,
            'hard_ceiling': hard_ceiling,
            'arb_width': narrowest_width,
            'live_yes_bid': live_yes_bid,
            'live_no_bid': live_no_bid,
            'live_yes_ask': live_yes_ask,
            'live_no_ask': live_no_ask,
            'last_price_update': time.time(),
            'market_type': _detect_market_type(ticker),
            'spread_line': _extract_spread_line(ticker),
            'timeout_min': _late_game_timeout_min(ticker, live_yes_bid >= live_no_bid, narrowest_width),
            # Per-rung completion tracking
            'hedge_history': [],
            'cumulative_pnl': 0,
            'completed_rungs_count': 0,
            # Hedge fill tracking (bot-level, not rung-level)
            '_hedge_fill_count': 0,
            '_all_hedge_order_ids': [],
            # Master list of ALL order IDs ever placed (for cleanup)
            '_all_placed_order_ids': all_placed_oids,
            '_order_group_id': _order_group_id,
            # Walk state
            'walk_count': 0,
            'last_walk_at': None,
            'first_fill_at': None,
            'first_fill_side': None,
            # Weighted averages
            'avg_yes_price': None,
            'avg_no_price': None,
            'filled_yes_qty': 0,
            'filled_no_qty': 0,
            # Compat
            'yes_fill_qty': 0,
            'no_fill_qty': 0,
            'yes_price': placed_rungs[0]['yes_price'],
            'no_price': placed_rungs[0]['no_price'],
            'profit_per': 100 - placed_rungs[0]['yes_price'] - placed_rungs[0]['no_price'],
            'repost_count': 0,
        }
        save_state()

        rung_desc = ', '.join(f'{r["width"]}¢: Y{r["yes_price"]}+N{r["no_price"]}×{r["quantity"]}' for r in placed_rungs)
        bot_log('LADDER_ARB_CREATED', bot_id, {
            'rungs': len(placed_rungs), 'widths': [r['width'] for r in placed_rungs],
            'base_qty': quantity, 'width_scaling': width_scaling,
            'per_rung_qtys': {r['width']: r['quantity'] for r in placed_rungs},
            'game_phase': game_phase, 'repeat_count': repeat_count,
        })
        print(f'△ APEX CREATED: {bot_id} | {len(placed_rungs)} rungs: {rung_desc}')

        return jsonify({
            'success': True,
            'bot_id': bot_id,
            'rungs': len(placed_rungs),
            'total_qty': total_scaled_qty,
            'width_scaling': width_scaling,
            'per_rung_qtys': {r['width']: r['quantity'] for r in placed_rungs},
            'message': f'[LADDER ARB] {len(placed_rungs)} rungs posted: {rung_desc}',
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


# ═══════════════════════════════════════════════════════════════════
# ANCHOR-DOG BOT — posts ONLY the dog leg first, fav on fill
# ═══════════════════════════════════════════════════════════════════
def _check_phantom_netting_risk(ticker, hedge_ticker, dog_side, cross_market):
    """Check if creating this phantom would cause position netting with existing bots.

    Returns (error_message, conflicting_bot_id) or (None, None) if safe.

    Netting rules (Kalshi auto-nets YES+NO on same ticker):
    1. Cross-market correlated: two cross-market phantoms with swapped tickers
       and opposite dog sides fire on the same game event → hedges cross-net
       all positions to zero. E.g. LAKERS-YES→SUNS-YES + SUNS-NO→LAKERS-NO
       both fire when Lakers lose.
    2. Apex interference: Apex has both YES+NO orders on its ticker. Phantom
       positions on the same ticker would tangle with Apex fills/sellbacks.
    """
    for bid, b in active_bots.items():
        if b.get('status') in ('completed', 'stopped', 'cancelled', 'dead'):
            continue
        b_cat = b.get('bot_category', '')
        b_ticker = b.get('ticker', '')
        b_hedge = b.get('hedge_ticker', b_ticker)
        b_side = b.get('dog_side', '')
        b_cross = b.get('cross_market', False)

        # ── Guard 1: Apex on same ticker as phantom dog or hedge ──
        # Apex places both YES+NO orders. Phantom positions would net with Apex.
        if b_cat == 'ladder_arb':
            if b_ticker == ticker:
                return (f'Apex bot active on {b_ticker} — phantom dog would interfere with Apex positions', bid)
            if b_ticker == hedge_ticker and hedge_ticker != ticker:
                return (f'Apex bot active on {b_ticker} — phantom hedge would interfere with Apex positions', bid)

        # Only check phantom-vs-phantom from here
        if b_cat not in ('anchor_dog', 'anchor_ladder'):
            continue

        # ── Guard 2: Duplicate check (existing logic) ──
        if cross_market:
            # Block exact same cross-market arb
            if b_cross and b_ticker == ticker and b_hedge == hedge_ticker and b_side == dog_side:
                return (f'Cross-market Phantom ({dog_side.upper()}) already active', bid)
            # Block reverse with same side
            if b_cross and b_hedge == ticker and b_ticker == hedge_ticker and b_side == dog_side:
                return (f'Reverse cross-market Phantom ({dog_side.upper()}) already covers this pair', bid)
            # ── Guard 3: Cross-market correlated netting ──
            # Swapped tickers + opposite dog sides = same game outcome = cross-net to zero
            # E.g. (LAKERS-YES→SUNS-YES) + (SUNS-NO→LAKERS-NO) both fire when Lakers lose
            if b_cross and b_hedge == ticker and b_ticker == hedge_ticker and b_side != dog_side:
                return (
                    f'Netting risk: {b_side.upper()} on {b_ticker} fires on same game event as '
                    f'{dog_side.upper()} on {ticker} — hedges would cross-net all positions to zero',
                    bid
                )
        else:
            # Same-market: block duplicate on same ticker+side
            if not b_cross and b_ticker == ticker and b_side == dog_side:
                return (f'Same-market Phantom ({dog_side.upper()}) already active on {ticker}', bid)

    return (None, None)


@app.route('/api/bot/anchor', methods=['POST'])
def create_anchor_bot():
    """
    Anchor-Dog Arb Bot: posts only the underdog (cheap) leg as a deep
    maker order.  When it fills (volatility spike), immediately hedges
    by posting the favorite at the current best bid.

    Body:
        ticker:          market ticker
        dog_price:       price for the dog anchor (cents, 1-99)
        target_width:    target arb profit per contract (cents, e.g. 5 or 10)
        quantity:        contracts per fill (default 1)
        hedge_timeout_s: seconds to wait for fav fill before sell-back (default 120)
        repeat_count:    how many times to repeat after completion (default 0)
        dog_side:        'yes' or 'no' — which side is the dog (auto-detect if omitted)
    """
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        data = request.json or {}
        ticker        = data.get('ticker', '').strip()
        dog_price     = int(data.get('dog_price', 0))
        target_width  = int(data.get('target_width', 5))
        quantity      = int(data.get('quantity', 1))
        hedge_timeout = int(data.get('hedge_timeout_s', 120))
        repeat_count  = int(data.get('repeat_count', 0))
        dog_side      = data.get('dog_side', '').lower()
        cross_market  = data.get('cross_market', False)
        hedge_ticker  = data.get('hedge_ticker', '').strip() or ticker

        if not ticker or dog_price < 1 or dog_price > 99:
            return jsonify({'error': 'Required: ticker, dog_price (1-99)'}), 400

        # Netting / duplicate / interference guardrails
        _net_err, _net_bid = _check_phantom_netting_risk(ticker, hedge_ticker, dog_side, cross_market)
        if _net_err:
            return jsonify({'error': f'{_net_err}: {_net_bid[:30]}'}), 400

        if target_width < 1:
            return jsonify({'error': 'target_width must be >= 1'}), 400

        # Auto-detect game phase
        game_phase = 'live' if _is_game_live(ticker) else 'pregame'

        # Late-game block
        if game_phase == 'live':
            late_blocked, late_reason = _is_late_game(ticker)
            if late_blocked:
                return jsonify({'error': f'Late-game block — {late_reason}'}), 400

        # Per-ticker bot cap
        MAX_BOTS_PER_TICKER = 5
        active_on_ticker = sum(
            1 for b in active_bots.values()
            if b.get('ticker') == ticker
            and b.get('status') not in ('completed', 'stopped', 'cancelled')
        )
        if active_on_ticker >= MAX_BOTS_PER_TICKER:
            return jsonify({'error': f'Bot cap: {active_on_ticker} bots on {ticker} (max {MAX_BOTS_PER_TICKER})'}), 400

        # Auto-detect dog side from orderbook if not specified
        # Always fetch live orderbook for smart pricing
        try:
            api_read_limiter.wait()
            ob = kalshi_client.get_market_orderbook(ticker)
            live_dog_bid = _best_bid(ob, dog_side if dog_side in ('yes', 'no') else 'no')
            live_dog_ask = _best_ask(ob, dog_side if dog_side in ('yes', 'no') else 'no')
            if dog_side not in ('yes', 'no'):
                yes_bid = _best_bid(ob, 'yes')
                no_bid  = _best_bid(ob, 'no')
                dog_side = 'no' if no_bid <= yes_bid else 'yes'
                live_dog_bid = _best_bid(ob, dog_side)
                live_dog_ask = _best_ask(ob, dog_side)
        except Exception:
            live_dog_bid = 0
            live_dog_ask = 0
            if dog_side not in ('yes', 'no'):
                dog_side = 'no'

        # Anchor depth: all depth shaved off dog, fav posts at bid
        # Floor: 3¢ for 1¢ width, 5¢ for 2-3¢ width, width itself for wider
        anchor_depth = int(data.get('anchor_depth', 0))  # 0 = auto-calculate
        if anchor_depth <= 0:
            if target_width <= 1:
                anchor_depth = 3
            elif target_width <= 3:
                anchor_depth = 5
            else:
                anchor_depth = max(5, target_width)
        fav_shave = 0  # fav always posts at bid, no shave needed

        # Smart pricing: anchor_depth below bid if tight spread (≤2c), below ask if broken spread
        if live_dog_bid > 0:
            spread = (live_dog_ask - live_dog_bid) if live_dog_ask > 0 else 1
            anchor_base = live_dog_ask if spread > 2 else live_dog_bid
            smart_price = max(1, anchor_base - anchor_depth)
            print(f'🎯 SMART PRICE: bid={live_dog_bid} ask={live_dog_ask} spread={spread} '
                  f'base={"ask" if spread > 2 else "bid"} depth={anchor_depth}¢ fav_shave={fav_shave}¢ '
                  f'→ {smart_price}¢ (frontend sent {dog_price}¢)')
            dog_price = smart_price

        if cross_market and hedge_ticker != ticker:
            fav_side = dog_side  # same side, different ticker
        else:
            fav_side = 'yes' if dog_side == 'no' else 'no'

        # Place ONLY the dog order — maker, post_only
        dog_resp, actual_dog_price = create_order_maker(
            ticker=ticker, side=dog_side, action='buy',
            count=quantity, price=dog_price
        )
        dog_order_id = dog_resp['order']['order_id']

        # Subscribe WS
        if ws_manager.connected:
            ws_manager.add_ticker(ticker)
            if hedge_ticker != ticker:
                ws_manager.add_ticker(hedge_ticker)

        import uuid as _uuid
        bot_id = f"anchor_{ticker}_{dog_order_id[-8:]}"
        if bot_id in active_bots:
            bot_id = f"anchor_{ticker}_{dog_order_id[-8:]}_{int(time.time() * 1000)}"

        active_bots[bot_id] = {
            'ticker':              ticker,
            'hedge_ticker':        hedge_ticker,
            'cross_market':        bool(cross_market),
            'bot_category':        'anchor_dog',
            'status':              'dog_anchor_posted',
            'dog_side':            dog_side,
            'fav_side':            fav_side,
            'dog_price':           actual_dog_price,
            'dog_order_id':        dog_order_id,
            'fav_order_id':        None,
            'fav_price':           None,
            'target_width':        target_width,
            'quantity':            quantity,
            'hedge_timeout_s':     hedge_timeout,
            'dog_fill_qty':        0,
            'fav_fill_qty':        0,
            'game_phase':          game_phase,
            'created_at':          time.time(),
            'posted_at':           time.time(),
            'dog_filled_at':       None,
            'repeat_count':        repeat_count,
            'repeats_done':        0,
            'anchor_depth':        anchor_depth,
            'fav_shave':           fav_shave,
            'fav_walk_count':      0,
            'fav_walk_ceiling':    HARD_CEILING_CENTS,  # max combined cost for walk-up
            'fav_last_walk_at':    None,
            'market_type':         _detect_market_type(ticker),
            'spread_line':         _extract_spread_line(ticker),
            # Compat fields so existing monitor/WS code can read these
            'yes_price':           actual_dog_price if dog_side == 'yes' else None,
            'no_price':            actual_dog_price if dog_side == 'no' else None,
            'yes_order_id':        dog_order_id if dog_side == 'yes' else None,
            'no_order_id':         dog_order_id if dog_side == 'no' else None,
            'yes_fill_qty':        0,
            'no_fill_qty':         0,
            'arb_width':           target_width,
            # Pre-calculated hedge price — ready to fire instantly on dog fill
            '_precalc_hedge_price': _precalc_phantom_hedge(actual_dog_price, target_width, dog_side, quantity),
            '_bid_at_post':        live_dog_bid if live_dog_bid > 0 else 0,
            '_last_repost_at':     0,
            '_all_dog_order_ids':  [dog_order_id],
        }
        save_state()
        bot_log('ANCHOR_DOG_CREATED', bot_id, {
            'dog_side': dog_side, 'dog_price': actual_dog_price,
            'target_width': target_width, 'qty': quantity,
            'hedge_timeout_s': hedge_timeout,
        })

        return jsonify({
            'success':       True,
            'bot_id':        bot_id,
            'dog_order_id':  dog_order_id,
            'dog_side':      dog_side,
            'dog_price':     actual_dog_price,
            'target_width':  target_width,
            'message':       f'[ANCHOR] {dog_side.upper()} dog posted at {actual_dog_price}¢ — '
                             f'waiting for fill, then hedge {fav_side.upper()} (target {target_width}¢ width)'
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/bot/ladder', methods=['POST'])
def create_ladder_bot():
    """Create a multi-rung anchor-ladder bot."""
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not logged in'}), 401
        data = request.json or {}
        ticker = data.get('ticker', '')
        rungs_input = data.get('rungs', [])
        target_width = int(data.get('target_width', 5))
        hedge_timeout = int(data.get('hedge_timeout_s', 120))
        bounce_threshold = int(data.get('bounce_threshold', 2))
        repeat_count = int(data.get('repeat_count', 0))
        dog_side = data.get('dog_side', '')
        cross_market = data.get('cross_market', False)
        hedge_ticker = data.get('hedge_ticker', '').strip() or ticker

        if not ticker:
            return jsonify({'error': 'Missing ticker'}), 400

        # Netting / duplicate / interference guardrails
        _net_err, _net_bid = _check_phantom_netting_risk(ticker, hedge_ticker, dog_side, cross_market)
        if _net_err:
            return jsonify({'error': f'{_net_err}: {_net_bid[:30]}'}), 400

        if not rungs_input or len(rungs_input) < 1 or len(rungs_input) > 3:
            return jsonify({'error': 'Need 1-3 rungs'}), 400
        if target_width < 1:
            return jsonify({'error': 'target_width must be >= 1'}), 400

        # Validate each rung
        for r in rungs_input:
            p = int(r.get('price', 0))
            q = int(r.get('qty', 1))
            if p < 1 or p > 50:
                return jsonify({'error': f'Rung price {p}¢ out of range (1-50)'}), 400
            if q < 1 or q > 20:
                return jsonify({'error': f'Rung qty {q} out of range (1-20)'}), 400

        # Game phase
        game_phase = 'live' if _is_game_live(ticker) else 'pregame'

        # Bot cap
        MAX_BOTS_PER_TICKER = 5
        active_on_ticker = sum(1 for b in active_bots.values()
                               if b.get('ticker') == ticker
                               and b.get('status') not in ('completed', 'stopped', 'cancelled', 'dead'))
        if active_on_ticker >= MAX_BOTS_PER_TICKER:
            return jsonify({'error': f'Bot cap: {active_on_ticker} bots on {ticker} (max {MAX_BOTS_PER_TICKER})'}), 400

        # Auto-detect dog side if not provided + fetch live orderbook for smart pricing
        api_read_limiter.wait()
        ob = kalshi_client.get_market_orderbook(ticker)
        if not dog_side:
            yes_bid = _best_bid(ob, 'yes')
            no_bid = _best_bid(ob, 'no')
            dog_side = 'no' if no_bid <= yes_bid else 'yes'
        if cross_market and hedge_ticker != ticker:
            fav_side = dog_side  # same side, different ticker
        else:
            fav_side = 'no' if dog_side == 'yes' else 'yes'

        current_dog_bid = _best_bid(ob, dog_side)
        current_dog_ask = _best_ask(ob, dog_side)

        # Anchor depth: all depth shaved off dog, fav posts at bid
        anchor_depth = int(data.get('anchor_depth', 0))
        if anchor_depth <= 0:
            if target_width <= 1:
                anchor_depth = 3
            elif target_width <= 3:
                anchor_depth = 5
            else:
                anchor_depth = max(5, target_width)
        fav_shave = 0

        # Smart pricing: adjust all rungs relative to live price at order creation time
        # Depth floor anchors to rung 0 (first rung) — all rungs sit at or below anchor_depth
        rung_spacing = 2
        if current_dog_bid > 0:
            spread = (current_dog_ask - current_dog_bid) if current_dog_ask > 0 else 1
            anchor_base = current_dog_ask if spread > 2 else current_dog_bid
            # Rung[0] = anchor_base - anchor_depth (first rung is the depth floor)
            smart_first = max(1, anchor_base - anchor_depth)

            # Apply per-rung stagger from smart_first
            print(f'👻 PHANTOM SMART PRICE: bid={current_dog_bid} ask={current_dog_ask} spread={spread} '
                  f'base={"ask" if spread > 2 else "bid"} anchor_depth={anchor_depth} smart_first={smart_first} '
                  f'(depth floor on rung 0)')
            for idx, r in enumerate(rungs_input):
                r['price'] = max(1, smart_first - (idx * rung_spacing))
                print(f'   rung[{idx}] → {r["price"]}¢ (depth={anchor_base - r["price"]}¢)')

        # Place all rung orders via batch
        phantom_group_id = _create_order_group()
        rung_specs = [{'ticker': ticker, 'side': dog_side, 'count': int(r.get('qty', 1)), 'price': int(r['price'])} for r in rungs_input]
        try:
            batch_results = create_orders_batch(rung_specs, order_group_id=phantom_group_id)
        except Exception as batch_err:
            return jsonify({'error': f'Failed to place rungs: {batch_err}'}), 500

        placed_rungs = []
        for i, result in enumerate(batch_results):
            if result is None:
                continue  # Partial batch failure — skip this rung
            resp, actual_price = result
            placed_rungs.append({
                'price': actual_price,
                'qty': rung_specs[i]['count'],
                'order_id': resp['order']['order_id'],
                'fill_qty': 0,
                'filled_at': None,
            })

        total_dog_qty = sum(r['qty'] for r in placed_rungs)
        bot_id = f'ladder_{ticker}_{int(time.time() * 1000)}'

        # Subscribe WS
        if ws_manager:
            ws_manager.add_ticker(ticker)
            if hedge_ticker != ticker:
                ws_manager.add_ticker(hedge_ticker)

        # Pre-calculate hedge prices + avg fill prices for every fill count
        _precalc_h, _precalc_a = _precalc_phantom_ladder_hedges(placed_rungs, target_width, dog_side)

        active_bots[bot_id] = {
            'ticker': ticker,
            'hedge_ticker': hedge_ticker,
            'cross_market': bool(cross_market),
            'bot_category': 'anchor_ladder',
            'status': 'ladder_posted',
            'dog_side': dog_side,
            'fav_side': fav_side,
            'rungs': placed_rungs,
            'total_dog_qty': total_dog_qty,
            'total_dog_fill_qty': 0,
            'fav_order_id': None,
            'fav_price': None,
            'fav_fill_qty': 0,
            'target_width': target_width,
            'hedge_timeout_s': hedge_timeout,
            'bounce_threshold': bounce_threshold,
            'lowest_dog_bid_seen': current_dog_bid if current_dog_bid > 0 else 999,
            'lowest_dog_bid_at': time.time(),
            'bounce_detected_at': None,
            'avg_fill_price': None,
            'hedge_qty': None,
            'game_phase': game_phase,
            'created_at': time.time(),
            'posted_at': time.time(),
            'dog_filled_at': None,
            'market_type': _detect_market_type(ticker),
            'spread_line': _extract_spread_line(ticker),
            # Compat fields
            'yes_order_id': None,
            'no_order_id': None,
            'yes_fill_qty': 0,
            'no_fill_qty': 0,
            'yes_price': None,
            'no_price': None,
            'quantity': total_dog_qty,
            'arb_width': target_width,
            'repeat_count': repeat_count,
            'repeats_done': 0,
            'anchor_depth': anchor_depth,
            'rung_spacing': rung_spacing,
            'fav_shave': fav_shave,
            'fav_walk_count': 0,
            'fav_walk_ceiling': HARD_CEILING_CENTS,
            'fav_last_walk_at': None,
            # Pre-calculated hedge prices + avg prices for every fill count (1, 2, 3 rungs)
            '_precalc_hedge_prices': _precalc_h,
            '_precalc_avg_prices': _precalc_a,
            '_bid_at_post': current_dog_bid if current_dog_bid > 0 else 0,
            '_last_repost_at': 0,
            '_order_group_id': phantom_group_id,
        }
        save_state()

        rung_desc = ', '.join(f'{r["price"]}¢×{r["qty"]}' for r in placed_rungs)
        return jsonify({
            'success': True,
            'bot_id': bot_id,
            'rungs': len(placed_rungs),
            'total_qty': total_dog_qty,
            'message': f'[LADDER] {dog_side.upper()} {len(placed_rungs)} rungs posted: {rung_desc}'
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/bot/ladder/simulate', methods=['POST'])
def simulate_ladder():
    """Dry-run simulation: shows what a ladder/anchor bot WOULD do without placing real orders.
    Simulates fill scenarios and hedge math so you can verify averaging + pricing logic."""
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        data = request.json or {}
        ticker = data.get('ticker', '').strip()
        rungs_input = data.get('rungs', [])  # [{price, qty}]
        target_width = int(data.get('target_width', 5))
        dog_side = data.get('dog_side', '').lower()

        if not ticker:
            return jsonify({'error': 'Required: ticker'}), 400

        # Get live orderbook
        api_read_limiter.wait()
        ob = kalshi_client.get_market_orderbook(ticker)

        # Auto-detect dog side
        yes_bid = _best_bid(ob, 'yes')
        no_bid = _best_bid(ob, 'no')
        if dog_side not in ('yes', 'no'):
            dog_side = 'no' if no_bid <= yes_bid else 'yes'
        fav_side = 'yes' if dog_side == 'no' else 'no'
        dog_bid = yes_bid if dog_side == 'yes' else no_bid
        fav_bid = yes_bid if fav_side == 'yes' else no_bid

        # Default rungs if none provided (single anchor at dog_bid - 5)
        if not rungs_input:
            rungs_input = [{'price': max(1, dog_bid - 5), 'qty': 1}]

        rungs = []
        for r in rungs_input:
            rungs.append({'price': int(r['price']), 'qty': int(r.get('qty', 1))})

        # Simulate each fill scenario
        scenarios = []

        # Scenario 1: All rungs fill
        total_qty = sum(r['qty'] for r in rungs)
        total_cost = sum(r['price'] * r['qty'] for r in rungs)
        avg_dog_price = round(total_cost / total_qty) if total_qty > 0 else 0
        max_fav_price = 100 - avg_dog_price - target_width
        hedge_price = min(fav_bid, max_fav_price)
        est_fees = sum(
            kalshi_fee_cents(
                r['price'] if dog_side == 'yes' else hedge_price,
                r['price'] if dog_side == 'no' else hedge_price,
                r['qty']
            ) for r in rungs
        )
        total_arb_cost = avg_dog_price + hedge_price + est_fees
        net_profit = (100 - avg_dog_price - hedge_price) * total_qty - est_fees
        hard_ceiling_hit = total_arb_cost > HARD_CEILING_CENTS

        scenarios.append({
            'name': f'All {len(rungs)} rungs fill',
            'rungs_filled': len(rungs),
            'total_qty': total_qty,
            'avg_dog_price': avg_dog_price,
            'fav_bid_now': fav_bid,
            'max_fav_price': max_fav_price,
            'hedge_price': hedge_price,
            'est_fees': est_fees,
            'total_cost_per_contract': avg_dog_price + hedge_price,
            'total_cost_with_fees': total_arb_cost,
            'net_profit_cents': net_profit,
            'net_profit_dollars': round(net_profit / 100, 2),
            'hard_ceiling_hit': hard_ceiling_hit,
            'action': 'SELLBACK — over ceiling' if hard_ceiling_hit else ('HEDGE at ' + str(hedge_price) + '¢' if hedge_price >= 1 else 'SELLBACK — hedge too low'),
        })

        # Scenario per partial fill (each rung individually)
        for i, rung in enumerate(rungs):
            partial_qty = rung['qty']
            partial_avg = rung['price']
            max_fav = 100 - partial_avg - target_width
            h_price = min(fav_bid, max_fav)
            p_fees = kalshi_fee_cents(
                partial_avg if dog_side == 'yes' else h_price,
                partial_avg if dog_side == 'no' else h_price,
                partial_qty
            )
            p_cost = partial_avg + h_price + p_fees
            p_net = (100 - partial_avg - h_price) * partial_qty - p_fees
            scenarios.append({
                'name': f'Only rung #{i+1} fills ({rung["price"]}¢ × {rung["qty"]})',
                'rungs_filled': 1,
                'total_qty': partial_qty,
                'avg_dog_price': partial_avg,
                'fav_bid_now': fav_bid,
                'max_fav_price': max_fav,
                'hedge_price': h_price,
                'est_fees': p_fees,
                'total_cost_per_contract': partial_avg + h_price,
                'total_cost_with_fees': p_cost,
                'net_profit_cents': p_net,
                'net_profit_dollars': round(p_net / 100, 2),
                'hard_ceiling_hit': p_cost > HARD_CEILING_CENTS,
                'action': 'SELLBACK' if p_cost > HARD_CEILING_CENTS else ('HEDGE at ' + str(h_price) + '¢' if h_price >= 1 else 'SELLBACK'),
            })

        return jsonify({
            'success': True,
            'ticker': ticker,
            'dog_side': dog_side,
            'fav_side': fav_side,
            'dog_bid': dog_bid,
            'fav_bid': fav_bid,
            'target_width': target_width,
            'hard_ceiling': HARD_CEILING_CENTS,
            'rungs': rungs,
            'scenarios': scenarios,
            'summary': {
                'best_case_profit': scenarios[0]['net_profit_cents'],
                'worst_rung_profit': min(s['net_profit_cents'] for s in scenarios),
                'any_ceiling_hit': any(s['hard_ceiling_hit'] for s in scenarios),
            }
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


# ─── ORDER GROUP CREATION ──────────────────────────────────────────
def _create_order_group(contracts_limit=200):
    """Create an order group via Kalshi API for atomic cancel.
    Returns order_group_id string, or None on failure."""
    try:
        api_rate_limiter.wait()
        return kalshi_client.create_order_group(contracts_limit=contracts_limit)
    except Exception as e:
        print(f'⚠ Failed to create order group: {e}')
        return None


# ─── BATCH ORDER PLACEMENT ─────────────────────────────────────────
def create_orders_batch(order_specs, order_group_id=None):
    """Place multiple orders in a single API call.
    order_specs: list of dicts with keys: ticker, side, action, count, price
    order_group_id: optional UUID string — all orders share one group for atomic cancel.
    Returns: list of (response_dict, actual_price) tuples.  None entries = failed orders.
    On batch failure, falls back to individual create_order_maker calls.
    """
    if not order_specs:
        return []

    # Build batch payload
    batch_orders = []
    for spec in order_specs:
        price_key = 'yes_price' if spec['side'] == 'yes' else 'no_price'
        order = {
            'ticker': spec['ticker'],
            'side': spec['side'],
            'action': spec.get('action', 'buy'),
            'count': spec['count'],
            'type': 'limit',
            'post_only': True,
            price_key: spec['price'],
        }
        if order_group_id:
            order['order_group_id'] = order_group_id
        batch_orders.append(order)

    try:
        # Retry batch up to 3 times on 429 (rate limit) before falling back to individual
        resp = None
        for _attempt in range(3):
            api_rate_limiter.wait(priority=True)  # priority so monitor loop doesn't starve us
            try:
                t0 = time.time()
                resp = kalshi_client.create_orders_batch(batch_orders)
                _record_latency('order_place', (time.time() - t0) * 1000,
                                {'ticker': order_specs[0]['ticker'], 'batch': len(batch_orders)})
                break  # success
            except Exception as batch_err:
                if '429' in str(batch_err) and _attempt < 2:
                    _wait = 2.0 * (_attempt + 1)  # 2s, 4s backoff
                    print(f'  ⚠ Batch 429 — retrying in {_wait}s (attempt {_attempt + 2}/3)')
                    time.sleep(_wait)
                    continue
                raise  # non-429 error or final attempt
        results = resp.get('orders', [])
        out = []
        for i, spec in enumerate(order_specs):
            if i < len(results) and results[i].get('order', {}).get('order_id'):
                order_data = results[i]['order']
                price_key = 'yes_price' if spec['side'] == 'yes' else 'no_price'
                actual_price = order_data.get(price_key, spec['price'])
                # Verify: if Kalshi didn't return price, read back the order to get actual price
                if actual_price == spec['price'] and price_key not in order_data:
                    try:
                        oid = order_data['order_id']
                        api_read_limiter.wait()
                        verify_resp = kalshi_client.get_order(oid)
                        verify_data = verify_resp.get('order', verify_resp) if isinstance(verify_resp, dict) else {}
                        verified_price = verify_data.get(price_key)
                        if verified_price and verified_price != spec['price']:
                            print(f'  ⚠ BATCH PRICE MISMATCH: {spec["side"]}@{spec["price"]}¢ → Kalshi has {verified_price}¢ (post_only adjusted)')
                            actual_price = verified_price
                    except Exception:
                        pass  # Non-critical — use what we have
                out.append((results[i], actual_price))
            else:
                # This order failed in the batch — fall back to individual
                try:
                    r, p = create_order_maker(
                        ticker=spec['ticker'], side=spec['side'],
                        action=spec.get('action', 'buy'),
                        count=spec['count'], price=spec['price'],
                        order_group_id=order_group_id,
                    )
                    out.append((r, p))
                except Exception as ind_err:
                    print(f'  ⚠ Individual fallback failed [{spec["side"]}@{spec["price"]}¢]: {ind_err}')
                    out.append(None)
        return out
    except Exception as e:
        print(f'⚠ Batch order failed ({len(batch_orders)} orders): {e} — falling back to individual')
        out = []
        for spec in order_specs:
            try:
                r, p = create_order_maker(
                    ticker=spec['ticker'], side=spec['side'],
                    action=spec.get('action', 'buy'),
                    count=spec['count'], price=spec['price'],
                    order_group_id=order_group_id,
                )
                out.append((r, p))
            except Exception as ind_err:
                print(f'  ⚠ Individual fallback failed [{spec["side"]}@{spec["price"]}¢]: {ind_err}')
                out.append(None)
        return out


# ─── POST-ONLY AWARE ORDER PLACEMENT ──────────────────────────────
def create_order_maker(ticker, side, action, count, price, post_only=True,
                       order_group_id=None, max_retries=2, skip_rate_limit=False,
                       priority=False):
    """Place a limit order with post_only=True.  If Kalshi rejects because the
    price would cross the spread, retry at a more passive price (price - 1 for
    buys, price + 1 for sells) up to *max_retries* times.

    Returns the Kalshi order response dict on success, or raises on failure.
    Also returns the actual price used (may differ from requested after retries).
    Return: (response_dict, actual_price)
    """
    price_key = 'yes_price' if side == 'yes' else 'no_price'
    attempt_price = price

    for attempt in range(max_retries + 1):
        try:
            if not skip_rate_limit:
                api_rate_limiter.wait(priority=priority)
            kwargs = {
                'ticker': ticker,
                'side': side,
                'action': action,
                'count': count,
                price_key: attempt_price,
                'post_only': post_only,
            }
            if order_group_id is not None:
                kwargs['order_group_id'] = order_group_id
            t0 = time.time()
            resp = kalshi_client.create_order(**kwargs)
            _record_latency('order_place', (time.time() - t0) * 1000,
                            {'ticker': ticker, 'side': side, 'price': attempt_price})

            # Parse actual fees from response for tracking
            order_data = resp.get('order', {})
            maker_fees = order_data.get('maker_fees_dollars', '0')
            taker_fees = order_data.get('taker_fees_dollars', '0')
            if taker_fees and float(taker_fees) > 0:
                print(f'⚠ TAKER FEE detected on {side} {action} {ticker}@{attempt_price}¢: ${taker_fees}')

            if attempt_price != price:
                print(f'📌 post_only retry: {side} {action} {ticker} {price}¢→{attempt_price}¢ (attempt {attempt+1})')
            return resp, attempt_price

        except Exception as e:
            err_text = ''
            if hasattr(e, 'response') and hasattr(e.response, 'text'):
                err_text = e.response.text
            # post_only rejection — order would have crossed spread
            if 'post_only' in err_text.lower() or 'would cross' in err_text.lower() or \
               (hasattr(e, 'response') and hasattr(e.response, 'status_code') and e.response.status_code == 400 and 'post' in err_text.lower()):
                if attempt < max_retries:
                    # Adjust price to be more passive
                    if action == 'buy':
                        attempt_price = max(1, attempt_price - 1)
                    else:  # sell
                        attempt_price = min(99, attempt_price + 1)
                    print(f'🔄 post_only rejected {side} {action} {ticker}@{price}¢ — retrying at {attempt_price}¢')
                    continue
                else:
                    print(f'❌ post_only rejected {side} {action} {ticker}@{attempt_price}¢ — max retries hit')
                    raise
            else:
                raise


def get_actual_fill_price(order_id, side='yes', retries=2):
    """
    Get the actual average fill price from Kalshi for a completed order.
    side='yes' → use yes_price field, side='no' → use no_price field.
    Returns price in cents, or None if not available.
    Retries up to `retries` times with a short delay to handle Kalshi fill latency.
    """
    for attempt in range(retries + 1):
      try:
        api_read_limiter.wait()
        # Check fills for this order to get actual execution price
        fills_resp = kalshi_client.get_fills()
        fills = fills_resp.get('fills', [])
        order_fills = [f for f in fills if f.get('order_id') == order_id]
        if order_fills:
            total_cents = 0
            total_count = 0
            for f in order_fills:
                # Kalshi fills contain BOTH yes_price and no_price (complements).
                # Use the correct one based on which side this order was for.
                # Handle both old int-cents format and new _dollars float-string format.
                price_d = f.get('no_price_dollars' if side == 'no' else 'yes_price_dollars')
                price_c = f.get('no_price' if side == 'no' else 'yes_price', f.get('yes_price', f.get('no_price', 0)))
                if price_d is not None:
                    price = int(round(float(price_d) * 100))
                else:
                    price = int(price_c) if price_c else 0
                cnt_fp = f.get('count_fp')
                cnt = int(float(cnt_fp)) if cnt_fp else f.get('count', 1)
                total_cents += price * cnt
                total_count += cnt
            if total_count > 0:
                return round(total_cents / total_count)
        # Fallback: check the order status itself
        api_read_limiter.wait()
        order_resp = kalshi_client.get_order(order_id)
        order_data = order_resp.get('order', order_resp) if isinstance(order_resp, dict) else {}
        avg = order_data.get('average_fill_price', order_data.get('avg_fill_price'))
        if avg:
            return round(float(avg) * 100) if float(avg) < 1 else int(avg)
        # New FP format: derive from yes_price_dollars / no_price_dollars
        price_d = order_data.get('no_price_dollars' if side == 'no' else 'yes_price_dollars')
        if price_d:
            return int(round(float(price_d) * 100))
        # If not found yet, retry after a short delay
        if attempt < retries:
            time.sleep(0.8)
            continue
      except Exception as e:
        print(f'⚠ get_actual_fill_price error (attempt {attempt+1}): {e}')
        if attempt < retries:
            time.sleep(0.8)
    return None


def verify_position_cleared(ticker, side, count):
    """Check if a position has been cleared after a sell order."""
    try:
        api_read_limiter.wait()
        pos_resp = kalshi_client.get_positions(ticker=ticker)
        positions = pos_resp.get('market_positions', pos_resp.get('positions', []))
        for p in positions:
            if p.get('ticker') == ticker:
                qty = _parse_position_qty(p)
                if side == 'yes' and qty > 0:
                    print(f'⚠ verify_position: still holding {qty} YES on {ticker}')
                    return False, qty
                elif side == 'no' and qty < 0:
                    print(f'⚠ verify_position: still holding {abs(qty)} NO on {ticker}')
                    return False, abs(qty)
        print(f'✅ verify_position: {side} position on {ticker} confirmed CLEARED')
        return True, 0
    except Exception as e:
        print(f'⚠ verify_position error: {e} — treating as unverified')
        return False, -1


def execute_sell(ticker, side, count, reason='stop_loss'):
    """
    Reliably sell contracts at the current bid price.
    If the sell doesn't fill within a few seconds, cancel and return False
    so the bot stays active and retries next cycle at the new bid.
    After a successful fill, VERIFIES via Kalshi positions API that
    the contracts are actually gone.

    Returns (success: bool, order_info: dict)
    """
    MAX_ATTEMPTS = 3
    remaining_to_sell = count  # Track how many we still need to sell
    total_sold = 0
    last_sell_price = None

    for attempt in range(1, MAX_ATTEMPTS + 1):
        try:
            # ALWAYS verify actual position before placing sell order.
            # On Kalshi, selling a position you don't own = buying the opposite side.
            # Guards against manually-cancelled positions and double-execution.
            try:
                # First: try ticker-filtered query
                api_read_limiter.wait()
                pos_resp = kalshi_client.get_positions(ticker=ticker)
                positions = pos_resp.get('market_positions', pos_resp.get('positions', []))
                actual_held = 0
                for p in positions:
                    if p.get('ticker') == ticker:
                        pos_qty = _parse_position_qty(p)
                        if side == 'yes' and pos_qty > 0:
                            actual_held = pos_qty
                        elif side == 'no' and pos_qty < 0:
                            actual_held = abs(pos_qty)

                # Second: if filtered returned nothing, do an unfiltered scan.
                # The Kalshi positions `ticker` param may be an event slug filter,
                # not an exact market ticker, so it can miss GAME market positions.
                if actual_held == 0:
                    api_read_limiter.wait()
                    all_pos_resp = kalshi_client.get_positions(limit=200)
                    all_positions = all_pos_resp.get('market_positions', all_pos_resp.get('positions', []))
                    for p in all_positions:
                        if p.get('ticker') == ticker:
                            pos_qty = _parse_position_qty(p)
                            if side == 'yes' and pos_qty > 0:
                                actual_held = pos_qty
                            elif side == 'no' and pos_qty < 0:
                                actual_held = abs(pos_qty)
                    if actual_held > 0:
                        print(f'   execute_sell({reason}): found {actual_held} {side} in unfiltered scan (ticker filter missed it)')

                if actual_held == 0:
                    if total_sold > 0:
                        # We already sold some — position legitimately cleared
                        print(f'✅ execute_sell({reason}): position cleared after selling {total_sold} — done')
                        return True, {'order_id': 'already_cleared', 'filled': count,
                                      'sell_price': last_sell_price or 0, 'already_cleared': True,
                                      'verified_cleared': True, 'remaining': 0,
                                      'actual_fill_price': last_sell_price}
                    else:
                        # Check if position netted against opposite side (arb already cleared)
                        # On Kalshi, YES + NO on same ticker net automatically.
                        # If we bought YES but net shows NO, our YES was consumed by netting.
                        _net_pos = 0
                        for p in positions or all_positions:
                            if p.get('ticker') == ticker:
                                _net_pos = _parse_position_qty(p)
                                break
                        opposite_held = (side == 'yes' and _net_pos < 0) or (side == 'no' and _net_pos > 0)
                        if opposite_held:
                            print(f'✅ execute_sell({reason}): no {side} position — netted against opposite side (net={_net_pos}). Position already cleared by arb.')
                            return True, {'order_id': 'arb_netted', 'filled': count,
                                          'sell_price': 0, 'already_cleared': True,
                                          'verified_cleared': True, 'remaining': 0,
                                          'actual_fill_price': 0}
                        # No position at all — might be API race
                        print(f'⚠ execute_sell({reason}): no {side} position found on Kalshi (net={_net_pos}) — returning False to retry')
                        return False, {'error': 'position_not_found_no_prior_sell', 'position_check_empty': True}
                if actual_held < remaining_to_sell:
                    print(f'   execute_sell({reason}) attempt {attempt}: Kalshi shows {actual_held} {side} (bot thinks {remaining_to_sell}) — capping to Kalshi position')
                    remaining_to_sell = actual_held
                # NEVER sell more than the caller requested — Kalshi nets positions
                # across all bots on the same ticker, so actual_held can be HIGHER
                # than this bot's fill count. Selling more = stealing other bots' positions.
                remaining_to_sell = min(remaining_to_sell, count)
            except Exception as pos_err:
                # SAFETY: if we can't verify position, DON'T sell — selling without
                # verification can buy the opposite side if position was already netted.
                print(f'⚠ Position check before sell FAILED: {pos_err} — aborting sell to prevent buying opposite side')
                return False, {'error': str(pos_err), 'position_check_failed': True}

            # Fetch the CURRENT bid for this side right before selling
            api_read_limiter.wait()
            mkt_resp = kalshi_client.get_market(ticker)
            mkt = mkt_resp.get('market', mkt_resp)

            def _tc(field):
                d = mkt.get(field + '_dollars')
                if d: return round(float(d) * 100)
                return mkt.get(field, 0)

            cur_bid = _tc(f'{side}_bid')
            if cur_bid <= 0:
                # Bid is 0 — try selling at 1¢ (minimum). If this is a settled/
                # nearly-settled market, Kalshi will either fill it or reject it.
                # Better than spinning forever holding a worthless position.
                cur_bid = 1
                print(f'⚠ execute_sell({reason}) attempt {attempt}: {side} bid is 0¢ — trying sell at 1¢ (emergency exit)')

            # Place limit sell at the current bid
            sell_kwargs = {
                'ticker': ticker,
                'side': side,
                'action': 'sell',
                'count': remaining_to_sell,
            }
            if side == 'yes':
                sell_kwargs['yes_price'] = cur_bid
            else:
                sell_kwargs['no_price'] = cur_bid

            try:
                api_rate_limiter.wait()
                resp = kalshi_client.create_order(**sell_kwargs)
            except Exception as sell_err:
                err_str = str(sell_err)
                # 409 Conflict = market closed/settled — position will auto-settle
                if '409' in err_str or 'Conflict' in err_str:
                    print(f'✅ execute_sell({reason}): 409 Conflict — market is settled/closed. Position will auto-settle.')
                    return True, {'order_id': 'market_settled', 'filled': count,
                                  'sell_price': 0, 'already_cleared': True,
                                  'verified_cleared': True, 'remaining': 0,
                                  'actual_fill_price': 0}
                print(f'❌ execute_sell({reason}) attempt {attempt}: exception: {sell_err}')
                if attempt < MAX_ATTEMPTS:
                    time.sleep(1)
                    continue
                return False, {'error': err_str}
            resp_ord = resp.get('order', resp) if isinstance(resp, dict) else {}
            order_id = resp_ord.get('order_id')

            if not order_id:
                print(f'⚠ execute_sell({reason}) attempt {attempt}: no order_id in response: {resp}')
                if attempt < MAX_ATTEMPTS:
                    time.sleep(1)
                    continue
                return False, resp

            # Check if it filled immediately
            time.sleep(0.5)
            api_read_limiter.wait()
            check = kalshi_client.get_order(order_id)
            order_data = check.get('order', check) if isinstance(check, dict) else {}
            filled = _parse_fill_count(order_data)

            if filled >= remaining_to_sell:
                # VERIFY: confirm position is actually gone on Kalshi
                cleared, remaining = verify_position_cleared(ticker, side, count)
                actual_price = get_actual_fill_price(order_id, side)
                sell_price = actual_price if actual_price else cur_bid
                print(f'✅ execute_sell({reason}): {side} {remaining_to_sell}x {ticker} SOLD at {sell_price}¢ (attempt {attempt}) | verified={cleared}')
                return True, {'order_id': order_id, 'filled': filled, 'sell_price': sell_price,
                              'verified_cleared': cleared, 'remaining': remaining,
                              'actual_fill_price': actual_price}

            # Wait a bit more and check again
            time.sleep(1.5)
            api_read_limiter.wait()
            check2 = kalshi_client.get_order(order_id)
            order_data2 = check2.get('order', check2) if isinstance(check2, dict) else {}
            filled2 = _parse_fill_count(order_data2)

            if filled2 >= remaining_to_sell:
                # VERIFY: confirm position is actually gone on Kalshi
                cleared, remaining = verify_position_cleared(ticker, side, count)
                actual_price = get_actual_fill_price(order_id, side)
                sell_price = actual_price if actual_price else cur_bid
                print(f'✅ execute_sell({reason}): {side} {remaining_to_sell}x {ticker} SOLD at {sell_price}¢ (attempt {attempt}, 2nd check) | verified={cleared}')
                return True, {'order_id': order_id, 'filled': filled2, 'sell_price': sell_price,
                              'verified_cleared': cleared, 'remaining': remaining,
                              'actual_fill_price': actual_price}

            # Not fully filled — cancel remaining and retry at the NEW bid
            last_sell_price = cur_bid  # Track for partial fill P&L
            total_sold += filled2
            print(f'⚠ execute_sell({reason}) attempt {attempt}: {side} {remaining_to_sell}x {ticker} not filled at {cur_bid}¢ ({filled2}/{remaining_to_sell}), cancelling...')
            _safe_cancel(order_id, f'execute_sell timeout {reason} {ticker}')

            if attempt < MAX_ATTEMPTS:
                print(f'   Retrying at new bid...')
                time.sleep(0.5)
                continue

        except Exception as e:
            print(f'❌ execute_sell({reason}) attempt {attempt}: exception: {e}')
            if attempt < MAX_ATTEMPTS:
                time.sleep(1)
                continue
            return False, {'error': str(e)}

    print(f'⚠ execute_sell({reason}): {side} {count}x {ticker} FAILED after {MAX_ATTEMPTS} attempts — will retry next monitor cycle')
    return False, {'attempts': MAX_ATTEMPTS, 'status': 'all_attempts_failed'}


def execute_net_via_amend(order_id, amend_side, amend_price, qty, ticker, reason='timeout', action='buy'):
    """
    Complete an open leg by AMENDING its resting limit order price to the
    current bid (where buyers already ARE), so it fills quickly and Kalshi
    auto-nets YES + NO → $1.

    Uses Kalshi POST /portfolio/orders/{order_id}/amend — atomic, no orphan risk.

    ticker      : event ticker (required by Kalshi amend API)
    amend_side  : 'yes' or 'no' — the side of the PENDING order
    amend_price : cents — current BID on that side (NOT the ask / complement)
    qty         : expected fill quantity

    Returns (success: bool, info: dict)
      info keys: actual_fill_price, filled, order_id, method
    """
    try:
        # 1. Check if order is still resting
        api_read_limiter.wait()
        ord_resp = kalshi_client.get_order(order_id)
        ord_data  = ord_resp.get('order', ord_resp)
        ord_status = ord_data.get('status', '')
        pre_filled = _parse_fill_count(ord_data)

        if ord_status in ('executed', 'filled', 'closed') or pre_filled >= qty:
            filled_price = get_actual_fill_price(order_id, amend_side) or amend_price
            print(f'✅ execute_net_via_amend({reason}): order {order_id} already filled at {filled_price}¢')
            return True, {'order_id': order_id, 'filled': qty,
                          'actual_fill_price': filled_price, 'sell_price': filled_price,
                          'method': 'already_filled', 'verified_cleared': True}

        if ord_status in ('cancelled', 'canceled', 'expired'):
            print(f'⚠ execute_net_via_amend({reason}): order {order_id} is {ord_status} — order gone, needs fallback')
            return False, {'error': f'order_gone:{ord_status}', 'order_was_gone': True}

        # 2. PATCH amend the order price to the current bid
        print(f'🔧 execute_net_via_amend({reason}): amending {order_id} → {amend_side}@{amend_price}¢ qty={qty}')
        api_rate_limiter.wait()
        amend_kwargs = {'order_id': order_id, 'ticker': ticker, 'side': amend_side, 'count': qty, 'action': action}
        if amend_side == 'yes':
            amend_kwargs['yes_price'] = amend_price
        else:
            amend_kwargs['no_price'] = amend_price

        try:
            amend_resp = kalshi_client.amend_order(**amend_kwargs)
            amend_data = amend_resp.get('order', amend_resp)
            amend_status = amend_data.get('status', '')
            amend_filled = _parse_fill_count(amend_data)
            print(f'📥 execute_net_via_amend({reason}): amend response status={amend_status} filled={amend_filled}')
        except Exception as amend_err:
            err_str = str(amend_err)
            if '404' in err_str or 'not found' in err_str.lower():
                print(f'⚠ execute_net_via_amend({reason}): amend got 404, order already gone')
                return False, {'error': 'amend_404', 'order_was_gone': True}
            print(f'❌ execute_net_via_amend({reason}): amend failed: {amend_err}')
            return False, {'error': f'amend_failed:{amend_err}'}

        # 3. Check if amend caused immediate fill
        if amend_status in ('executed', 'filled', 'closed') or amend_filled >= qty:
            filled_price = get_actual_fill_price(order_id, amend_side) or amend_price
            print(f'✅ execute_net_via_amend({reason}): instant fill at {filled_price}¢')
            return True, {'order_id': order_id, 'filled': qty,
                          'actual_fill_price': filled_price, 'sell_price': filled_price,
                          'method': 'amend', 'verified_cleared': True}

        # 4. Poll up to 10s for fill
        for poll_i in range(5):
            time.sleep(0.5)
            try:
                ws_filled = ws_manager.get_total_fills(order_id)
                if ws_filled >= qty:
                    filled_price = get_actual_fill_price(order_id, amend_side) or amend_price
                    print(f'✅ execute_net_via_amend({reason}): WS fill @{filled_price}¢ (poll {poll_i+1})')
                    return True, {'order_id': order_id, 'filled': qty,
                                  'actual_fill_price': filled_price,
                                  'sell_price': filled_price, 'method': 'amend', 'verified_cleared': True}

                api_read_limiter.wait()
                chk = kalshi_client.get_order(order_id).get('order', {})
                chk_status = chk.get('status', '')
                chk_filled = _parse_fill_count(chk)
                if chk_status in ('executed', 'filled', 'closed') or chk_filled >= qty:
                    filled_price = get_actual_fill_price(order_id, amend_side) or amend_price
                    print(f'✅ execute_net_via_amend({reason}): REST fill @{filled_price}¢ (poll {poll_i+1})')
                    return True, {'order_id': order_id, 'filled': qty,
                                  'actual_fill_price': filled_price,
                                  'sell_price': filled_price, 'method': 'amend', 'verified_cleared': True}
                if chk_status in ('cancelled', 'canceled', 'expired'):
                    print(f'⚠ execute_net_via_amend({reason}): order {order_id} became {chk_status} after amend')
                    return False, {'error': f'order_{chk_status}_after_amend', 'order_was_gone': True}
            except Exception as pe:
                print(f'⚠ execute_net_via_amend poll {poll_i+1}: {pe}')

        # Timed out — order is still resting at the new price, same order_id
        print(f'⚠ execute_net_via_amend({reason}): not filled after 10s, still resting at {amend_price}¢')
        return False, {'error': 'fill_timeout'}

    except Exception as e:
        print(f'❌ execute_net_via_amend({reason}): {e}')
        return False, {'error': str(e)}


@app.route('/api/bot/monitor', methods=['POST'])
def monitor_bots():
    """
    Check all active bots and handle fills / timeouts.

    PREGAME bots:
      - Orders sit patiently. No repost, no time-based stop-loss.
      - Only action: detect fills and mark completed.
      - If you cancel manually, that's fine.

    LIVE bots:
      - Repost stale unfilled orders after REPOST_AFTER_MINUTES
        (but NEVER above the current bid — repost AT the bid).
      - Partial fill resize after STALE_CANCEL_MINUTES.
      - Stop-loss if one side fills and the bid drops by stop_loss_cents.

    Both phases: if both sides fill → completed → profit locked at settlement.
    """
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        # ── CRITICAL: prevent concurrent monitor calls from double-executing ──
        acquired = monitor_lock.acquire(blocking=False)
        if not acquired:
            return jsonify({'success': True, 'actions': [], 'active_bots': 0, 'skipped': 'monitor already running'})

        try:
            return _run_monitor()
        finally:
            monitor_lock.release()

    except Exception as e:
        return jsonify({'error': str(e)}), 500


def _fire_timeout_amend(bot_id, bot, order_id, amend_side, amend_price, qty, ticker, is_fav_filled, timeout_min, actions):
    """Fire an amend in a background thread so the monitor doesn't block."""
    def _do_amend():
        try:
            sold, sell_info = execute_net_via_amend(
                order_id, amend_side, amend_price, qty,
                ticker=ticker, reason=f'timeout_exit_{amend_side}_{bot_id}'
            )
            now = time.time()
            filled_leg = 'yes' if amend_side == 'no' else 'no'
            fill_key = 'yes_price' if amend_side == 'no' else 'no_price'

            if sold:
                if bot.get('_trade_recorded') or bot.get('status') in ('completed', 'stopped', 'waiting_repeat'):
                    return
                fill_price = sell_info.get('actual_fill_price') or amend_price
                bot[f'{amend_side}_price'] = fill_price
                orig_repeat_count = bot.get('repeat_count', 0)
                yes_p = bot['yes_price']
                no_p = bot['no_price']
                filled_qty = bot.get(f'{filled_leg}_fill_qty') or qty
                pnl_cents = (100 - yes_p - no_p) * filled_qty
                if pnl_cents >= 0:
                    session_pnl['gross_profit_cents'] += pnl_cents
                else:
                    session_pnl['gross_loss_cents'] += abs(pnl_cents)
                session_pnl['completed_bots'] += 1
                bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + pnl_cents
                bot['_trade_recorded'] = True
                _record_trade({
                    'bot_id': bot_id, 'ticker': ticker,
                    'yes_price': yes_p, 'no_price': no_p,
                    'original_yes': bot.get('original_yes', yes_p), 'original_no': bot.get('original_no', no_p),
                    'quantity': filled_qty,
                    'profit_cents': pnl_cents if pnl_cents >= 0 else 0,
                    'loss_cents': abs(pnl_cents) if pnl_cents < 0 else 0,
                    'result': 'completed' if pnl_cents >= 0 else 'amended',
                    'exit_via': 'timeout_amend',
                    'first_leg': filled_leg,
                    'timeout_min': timeout_min,
                    'timestamp': now,
                    'placed_at': bot.get('created_at', now),
                    'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                    'arb_width': bot.get('arb_width', bot.get('profit_per', 0)),
                    'fill_duration_s': round(now - bot['first_fill_at']) if bot.get('first_fill_at') else None,
                    'game_phase': bot.get('game_phase', 'live'),
                    'game_context': _get_game_context(ticker),
                    'repeats_done': bot.get('repeats_done', 0),
                    'repeat_count': orig_repeat_count,
                    'fill_source': 'timeout_amend',
                }, bot)
                bot_log('ARB_COMPLETED', bot_id, {
                    'real_yes': yes_p, 'real_no': no_p,
                    'profit_cents': pnl_cents, 'timeout_min': timeout_min,
                    'source': f'timeout_amend_{amend_side}',
                })
                # Push notification so frontend picks it up next monitor cycle
                action_type = 'timeout_exit_yes' if amend_side == 'no' else 'timeout_exit_no'
                with _pending_ws_actions_lock:
                    _pending_ws_actions.append({'bot_id': bot_id, 'action': action_type, 'pnl_cents': pnl_cents})
                # Repeat logic
                bot['timeout_exits_count'] = bot.get('timeout_exits_count', 0) + 1
                repeats_done_now = bot.get('repeats_done', 0) + 1
                bot['repeats_done'] = repeats_done_now
                repeat_total = orig_repeat_count
                if repeats_done_now <= repeat_total:
                    bot['status'] = 'waiting_repeat'
                    bot['waiting_repeat_since'] = time.time()
                    bot['first_fill_at'] = None
                    bot['first_leg'] = None
                    bot['sl_retry_count'] = 0
                    print(f'🔄 TIMEOUT REPEAT: {bot_id} via thread — cycle {repeats_done_now}/{repeat_total}')
                else:
                    bot['status'] = 'stopped'
                    bot['stopped_at'] = now
                    bot['repeat_count'] = 0
                save_state()
            else:
                # Amend didn't fill — revert status so next monitor cycle retries
                bot['sl_retry_count'] = bot.get('sl_retry_count', 0) + 1
                revert_status = f'{filled_leg}_filled'
                bot['status'] = revert_status
                print(f'⚠ TIMEOUT amend {amend_side} failed for {bot_id} (attempt {bot["sl_retry_count"]})')
        except Exception as e:
            print(f'❌ _fire_timeout_amend {bot_id}: {e}')
            bot['status'] = f'{"yes" if amend_side == "no" else "no"}_filled'

    threading.Thread(target=_do_amend, daemon=True).start()


# ═══════════════════════════════════════════════════════════════════
# ANCHOR-DOG MONITOR LOGIC
# ═══════════════════════════════════════════════════════════════════
HARD_CEILING_CENTS = 98
SNAP_CEILING_CENTS = 96  # snap to bid only when combined <= 96¢ (2¢ minimum profit after fees)

# ── Game urgency system: adaptive behavior based on game phase ──
URGENCY_PARAMS = {
    'normal':    {'walk_interval': 20, 'snap_ceiling': 96, 'sellback_urgency': 'normal'},
    'late':      {'walk_interval': 8,  'snap_ceiling': 97, 'sellback_urgency': 'high'},
    'critical':  {'walk_interval': 3,  'snap_ceiling': 97, 'sellback_urgency': 'immediate'},
    'halftime':  {'walk_interval': 20, 'snap_ceiling': 96, 'sellback_urgency': 'paused'},
}

# ── Price velocity fallback: urgency from bid drops when no score data ──
_price_velocity_history = {}  # ticker -> deque([(timestamp, yes_bid, no_bid)])
_PRICE_VELOCITY_MAXLEN = 120  # ~2 min of snapshots

def _record_price_for_velocity(ticker, yes_bid, no_bid):
    """Record a price snapshot for velocity-based urgency detection.
    Called from monitor loop when WS prices are available."""
    if not ticker or (not yes_bid and not no_bid):
        return
    if ticker not in _price_velocity_history:
        _price_velocity_history[ticker] = deque(maxlen=_PRICE_VELOCITY_MAXLEN)
    _price_velocity_history[ticker].append((time.time(), yes_bid or 0, no_bid or 0))

def _get_price_velocity_urgency(ticker):
    """Fallback urgency based on price velocity.
    ONLY called when _get_game_score_for_ticker() returns None (no score data).
    Checks if either side's bid has dropped significantly in the last 2 minutes."""
    history = _price_velocity_history.get(ticker)
    if not history or len(history) < 3:
        return 'normal'

    now = time.time()
    latest_yes = history[-1][1]
    latest_no = history[-1][2]

    # Find peak bid for each side in the last 2 minutes
    peak_yes = latest_yes
    peak_no = latest_no
    for ts, yb, nb in history:
        if now - ts <= 120:
            peak_yes = max(peak_yes, yb)
            peak_no = max(peak_no, nb)

    # Biggest drop on either side
    yes_drop = peak_yes - latest_yes
    no_drop = peak_no - latest_no
    max_drop = max(yes_drop, no_drop)

    if max_drop >= 25:
        dropping_side = 'YES' if yes_drop >= no_drop else 'NO'
        print(f'🚨 PRICE VELOCITY CRITICAL: {ticker} {dropping_side} dropped {max_drop}¢ in 2min (peak {max(peak_yes, peak_no)}→{min(latest_yes, latest_no)})')
        return 'critical'   # 25+ cent crash in 2 min
    elif max_drop >= 15:
        dropping_side = 'YES' if yes_drop >= no_drop else 'NO'
        print(f'⚠ PRICE VELOCITY LATE: {ticker} {dropping_side} dropped {max_drop}¢ in 2min (peak {max(peak_yes, peak_no)}→{min(latest_yes, latest_no)})')
        return 'late'        # 15+ cent drop in 2 min
    return 'normal'

def _get_game_urgency(ticker):
    """Return game urgency level based on live game state.
    Returns: 'normal', 'late', 'critical', or 'halftime'.
    Falls back to price velocity when no score data exists."""
    try:
        if _is_game_ending(ticker):
            return 'critical'
        if _is_halftime(ticker):
            return 'halftime'
        # Check if we're in a late-game period
        score_info = _get_game_score_for_ticker(ticker)

        # No score data at all — fall back to price velocity
        if not score_info:
            return _get_price_velocity_urgency(ticker)

        if score_info.get('status') != 'in':
            return 'normal'
        series = ticker.split('-')[0].upper() if ticker else ''
        rule = None
        for prefix, r in _LATE_GAME_RULES.items():
            if series.startswith(prefix):
                if rule is None or len(prefix) > len(rule[0]):
                    rule = (prefix, r)
        if not rule:
            # Sport has ESPN data but no late-game rules (MLB, MLS, etc.)
            # If game is live ('in'), trust ESPN — don't use price velocity
            # (normal bid swings get misread as 'critical' and trigger early sell-back)
            if score_info.get('status') == 'in':
                return 'normal'
            # Game is 'post' — it ended, but _is_game_ending already checked this
            return 'normal'
        r = rule[1]
        period = score_info.get('period', 0)

        # Tennis: set-based urgency (no clock)
        if r.get('tennis'):
            home_sets = score_info.get('home_score', 0)
            away_sets = score_info.get('away_score', 0)
            sets_to_win = 2  # best of 3
            # Deciding set (1-1 in sets, now in set 3+) → late
            if period >= r['block_period']:
                return 'late'
            # One player is 1 set from winning AND in a set where they could close it
            # e.g. up 1-0 and in set 2 → match could end this set
            if (home_sets == sets_to_win - 1 or away_sets == sets_to_win - 1) and period >= 2:
                return 'late'
            return 'normal'

        # Clock-based sports
        clock = score_info.get('clock', '')
        secs = _parse_clock_seconds(clock)
        # Final period (Q4/P3/2nd Half) = 'late'
        if period >= r['block_period']:
            return 'late'
        # Second-to-last period with < 5 min left = 'late' (approaching crunch time)
        if period == r['block_period'] - 1 and secs is not None and secs < 300:
            return 'late'
    except Exception:
        pass
    return 'normal'

def _calc_walk_interval(combined, urgency, snap_ready, at_ceiling, needs_drop):
    """Adaptive walk interval based on ceiling proximity and game phase.
    Returns interval in seconds. 0 = instant."""
    # Instant actions always stay instant
    if snap_ready or at_ceiling or needs_drop:
        return 0
    # Base interval from game urgency
    base = URGENCY_PARAMS.get(urgency, {}).get('walk_interval', 20)
    # Tighten based on ceiling proximity
    if combined >= 96:
        return min(base, 3)
    elif combined >= 92:
        return min(base, 8)
    elif combined >= 88:
        return min(base, 15)
    return base

def _handle_phantom(bot_id, bot, actions):
    """Handle all states for an anchor-dog bot in the monitor loop."""
    now = time.time()
    ticker = bot['ticker']
    hedge_ticker = bot.get('hedge_ticker', ticker)
    qty = bot.get('quantity', 1)
    dog_side = bot['dog_side']
    fav_side = bot['fav_side']
    status = bot['status']

    # ── State validation: recover from half-updated state after prior exceptions ──
    if bot.get('_hedge_fired') and not bot.get('fav_order_id') and status == 'dog_filled':
        # Hedge was flagged but never posted (exception mid-hedge) — reset so we retry
        print(f'🔧 PHANTOM RECOVERY: {bot_id} _hedge_fired but no fav_order_id — resetting flag')
        bot_log('PHANTOM_RECOVERY', bot_id, {
            '_hedge_fired': True, 'fav_order_id': None, 'status': status,
            'dog_price': bot.get('dog_price'), 'dog_side': dog_side,
        })
        bot['_hedge_fired'] = False

    # Update live bid/ask from WS cache
    try:
        ws_p = ws_manager.get_price(ticker) if ws_manager else None
        if ws_p:
            bot['live_yes_bid'] = ws_p.get('yes_bid', 0)
            bot['live_no_bid'] = ws_p.get('no_bid', 0)
            bot['live_yes_ask'] = ws_p.get('yes_ask', 0)
            bot['live_no_ask'] = ws_p.get('no_ask', 0)
            _record_price_for_velocity(ticker, ws_p.get('yes_bid', 0), ws_p.get('no_bid', 0))
        # Cross-market: also cache hedge_ticker prices for fav walk
        if hedge_ticker != ticker:
            ws_p_hedge = ws_manager.get_price(hedge_ticker) if ws_manager else None
            if ws_p_hedge:
                bot['live_hedge_yes_bid'] = ws_p_hedge.get('yes_bid', 0)
                bot['live_hedge_no_bid'] = ws_p_hedge.get('no_bid', 0)
                bot['live_hedge_yes_ask'] = ws_p_hedge.get('yes_ask', 0)
                bot['live_hedge_no_ask'] = ws_p_hedge.get('no_ask', 0)
    except Exception:
        pass

    # ── STATE: dog_anchor_posted — waiting for dog to fill ────────
    if status == 'dog_anchor_posted':
        dog_order_id = bot.get('dog_order_id')
        if not dog_order_id:
            bot_log('PHANTOM_NO_DOG_ORDER', bot_id, {'status': status}, level='WARN')
            return

        api_read_limiter.wait()
        dog_resp = kalshi_client.get_order(dog_order_id)
        dog_ord = dog_resp.get('order', dog_resp) if isinstance(dog_resp, dict) else {}
        dog_filled = _parse_fill_count(dog_ord)
        bot['dog_fill_qty'] = dog_filled

        # Update the compat fill fields
        if dog_side == 'yes':
            bot['yes_fill_qty'] = dog_filled
        else:
            bot['no_fill_qty'] = dog_filled

        if dog_filled >= qty:
            # Guard: WS handler may have already fired the hedge
            if bot.get('_hedge_fired'):
                bot_log('PHANTOM_DOG_FILLED_WS_HANDLING', bot_id, {
                    'dog_filled': dog_filled, 'qty': qty, '_hedge_fired': True,
                    'fav_order_id': bot.get('fav_order_id', 'none')[:12] if bot.get('fav_order_id') else 'none',
                })
                bot['status'] = 'dog_filled'  # let WS thread handle it
                return
            # DOG FILLED — immediately hedge the favorite
            bot['_hedge_fired'] = True
            bot['dog_filled_at'] = now
            actual_dog_price = get_actual_fill_price(dog_order_id, dog_side) or bot['dog_price']
            bot['dog_price'] = actual_dog_price
            print(f'🐕 PHANTOM DOG FILLED: {bot_id} {dog_side.upper()}@{actual_dog_price}¢ qty={qty} (monitor path)')
            bot_log('PHANTOM_DOG_FILLED', bot_id, {
                'dog_side': dog_side, 'dog_price': actual_dog_price, 'qty': qty,
                'dog_order_id': dog_order_id[:12], 'path': 'monitor',
            })
            _audit('DOG_FILLED', bot_id, {'ticker': ticker, 'dog_side': dog_side, 'dog_price': actual_dog_price, 'qty': qty})
            _audit_position_check(bot_id, ticker, dog_side, 'after_dog_fill')

            # Get current fav bid from orderbook (hedge_ticker for cross-market)
            try:
                api_read_limiter.wait()
                ob = kalshi_client.get_market_orderbook(hedge_ticker)
                fav_bid = _best_bid(ob, fav_side)
            except Exception:
                fav_bid = 0

            if fav_bid <= 0:
                print(f'⚠ PHANTOM {bot_id}: dog filled but no fav bid — holding')
                bot_log('PHANTOM_NO_FAV_BID', bot_id, {
                    'dog_price': actual_dog_price, 'fav_side': fav_side, 'fav_bid': 0,
                    'path': 'monitor',
                })
                bot['status'] = 'dog_filled'
                actions.append({'bot_id': bot_id, 'action': 'dog_filled_no_fav_bid'})
                return

            # Start fav at max_fav_price (preserves target width), walk-up moves toward bid
            target_width = bot.get('target_width', 5)
            max_fav_price = 100 - actual_dog_price - target_width
            hedge_price = max_fav_price
            if hedge_price < 1:
                print(f'⚠ PHANTOM {bot_id}: hedge price {hedge_price}¢ too low — selling dog back')
                bot_log('PHANTOM_HEDGE_TOO_LOW_SELLBACK', bot_id, {
                    'hedge_price': hedge_price, 'dog_price': actual_dog_price,
                    'fav_bid': fav_bid, 'target_width': target_width,
                })
                _phantom_sell_back(bot_id, bot, actual_dog_price, fav_bid, 999, actions)
                return

            # Hard ceiling check — no fees in bot logic, 98¢ combined = breakeven
            total_cost = actual_dog_price + hedge_price
            if total_cost > HARD_CEILING_CENTS:
                safe_hedge = HARD_CEILING_CENTS - actual_dog_price
                if safe_hedge < 1:
                    print(f'🛑 PHANTOM CEILING: {bot_id} safe_hedge={safe_hedge}¢ too low — selling dog back')
                    bot_log('PHANTOM_CEILING_SELLBACK', bot_id, {
                        'dog_price': actual_dog_price, 'hedge_price': hedge_price,
                        'total_cost': total_cost, 'safe_hedge': safe_hedge,
                    })
                    _phantom_sell_back(bot_id, bot, actual_dog_price, fav_bid, total_cost, actions)
                    return
                print(f'⚠ PHANTOM CEILING CAP: {bot_id} dog@{actual_dog_price}¢ capped hedge {hedge_price}→{safe_hedge}¢ (was {total_cost}¢)')
                bot_log('PHANTOM_CEILING_CAP', bot_id, {
                    'dog_price': actual_dog_price, 'original_hedge': hedge_price,
                    'capped_hedge': safe_hedge, 'total_was': total_cost,
                })
                hedge_price = safe_hedge

            # Guard: WS handler may have already posted the fav hedge
            if bot.get('_hedge_fired') and bot.get('fav_order_id'):
                return

            # Post the fav hedge at target-width-capped price (maker)
            try:
                fav_resp, actual_fav_price = create_order_maker(
                    ticker=hedge_ticker, side=fav_side, action='buy',
                    count=qty, price=hedge_price
                )
                fav_order_id = fav_resp['order']['order_id']
                bot['fav_order_id'] = fav_order_id
                bot['fav_price'] = actual_fav_price
                bot['status'] = 'fav_hedge_posted'
                bot['fav_posted_at'] = now

                # Update compat fields
                if fav_side == 'yes':
                    bot['yes_price'] = actual_fav_price
                    bot['yes_order_id'] = fav_order_id
                else:
                    bot['no_price'] = actual_fav_price
                    bot['no_order_id'] = fav_order_id

                print(f'👻 PHANTOM HEDGE: {bot_id} dog filled @{actual_dog_price}¢ → fav {fav_side.upper()} posted @{actual_fav_price}¢ (total {actual_dog_price + actual_fav_price}¢)')
                _audit('FAV_HEDGE_POSTED', bot_id, {'ticker': ticker, 'fav_side': fav_side, 'fav_price': actual_fav_price, 'fav_order_id': fav_order_id})
                bot_log('PHANTOM_FAV_POSTED', bot_id, {
                    'dog_price': actual_dog_price, 'fav_price': actual_fav_price,
                    'fav_order_id': fav_order_id[:12], 'fav_bid': fav_bid,
                    'combined': actual_dog_price + actual_fav_price,
                    'target_width': target_width, 'path': 'monitor',
                })
                actions.append({'bot_id': bot_id, 'action': 'anchor_fav_posted',
                                'dog_price': actual_dog_price, 'fav_price': actual_fav_price})
            except Exception as e:
                print(f'❌ PHANTOM {bot_id}: fav post failed: {e} — holding dog')
                bot_log('PHANTOM_FAV_POST_ERROR', bot_id, {
                    'error': str(e)[:300], 'dog_price': actual_dog_price,
                    'hedge_price': hedge_price, 'fav_side': fav_side,
                    'path': 'monitor',
                }, level='ERROR')
                _audit('PHANTOM_FAV_POST_ERROR', bot_id, {'error': str(e)[:200], 'ticker': ticker})
                bot['status'] = 'dog_filled'
            save_state()
            return

        # Dog not filled yet — check for stale/drift cancel + repost
        age_min = (now - bot.get('posted_at', now)) / 60.0

        # Game ending: cancel to free capital
        if bot.get('game_phase') == 'live' and _is_game_ending(ticker):
            print(f'🏁 PHANTOM ENDING: {bot_id} game ending, dog unfilled — cancelling')
            _safe_cancel(dog_order_id, f'phantom ending cancel {bot_id}')
            bot['status'] = 'completed'
            bot['completed_at'] = now
            actions.append({'bot_id': bot_id, 'action': 'anchor_game_ending_cancel'})
            save_state()
            return

        # Repost: adaptive gap-based (instant when bid drifts) + 3-min timer fallback
        DOG_REPOST_MINUTES = REPOST_AFTER_MINUTES  # 3 min fallback

        # Gap detection from WS cache (free, no API call)
        ws_dog_bid = bot.get(f'live_{dog_side}_bid', 0)
        gap_thresh, cooldown_s = _phantom_gap_threshold(bot, ws_dog_bid) if ws_dog_bid > 0 else (3, 15)
        bid_at_post = bot.get('_bid_at_post', 0)
        # Only repost when bid moves AWAY from dog (increases). Bid moving toward dog = good, stay put.
        gap = max(0, ws_dog_bid - bid_at_post) if ws_dog_bid > 0 and bid_at_post > 0 else 0
        since_last_repost = now - bot.get('_last_repost_at', 0)

        gap_triggered = gap >= gap_thresh and since_last_repost >= cooldown_s and dog_filled == 0
        timer_triggered = age_min >= DOG_REPOST_MINUTES and dog_filled == 0

        # Retreat check: if bid crept within 2¢ of dog order, retreat to restore depth
        retreat_triggered = False
        if dog_filled == 0 and ws_dog_bid > 0 and since_last_repost >= cooldown_s:
            _anchor_depth = bot.get('anchor_depth', 5)
            _dog_price = bot.get('dog_price', 0)
            _depth_gap = ws_dog_bid - _dog_price if _dog_price > 0 else 999
            _retreat_threshold = 2  # retreat if bid crept 2¢+ toward our order
            if 0 <= _depth_gap and _depth_gap <= (_anchor_depth - _retreat_threshold):
                retreat_triggered = True

        if gap_triggered or timer_triggered or retreat_triggered:
            trigger_reason = (f'retreat depth={_depth_gap}¢<{_anchor_depth}¢' if retreat_triggered
                              else f'gap={gap}¢≥{gap_thresh}¢' if gap_triggered
                              else f'timer={age_min:.1f}m')
            try:
                api_read_limiter.wait()
                ob = kalshi_client.get_market_orderbook(ticker)
                current_dog_bid = _best_bid(ob, dog_side)
                current_dog_ask = _best_ask(ob, dog_side)

                if current_dog_bid <= 0:
                    # No bid — market might be dead, just wait
                    return

                # Dead market guard: bid at 1c = market is settled/dead, stop bot
                if current_dog_bid <= 1:
                    print(f'🛑 PHANTOM DEAD MARKET: {bot_id} dog bid={current_dog_bid}¢ — cancelling')
                    _safe_cancel(dog_order_id, f'phantom dead market {bot_id}')
                    for _dm_key in ('fav_order_id', 'hedge_order_id'):
                        _dm_oid = bot.get(_dm_key)
                        if _dm_oid:
                            _safe_cancel(_dm_oid, f'phantom dead market {_dm_key} {bot_id}')
                    for _dm_oid in bot.get('_all_dog_order_ids', []):
                        if _dm_oid and _dm_oid != dog_order_id:
                            _safe_cancel(_dm_oid, f'phantom dead market old dog {bot_id}')
                    bot['status'] = 'completed'
                    bot['completed_at'] = now
                    bot['repeat_count'] = 0
                    bot_log('PHANTOM_DEAD_MARKET', bot_id, {'dog_bid': current_dog_bid})
                    _audit('PHANTOM_DEAD_MARKET', bot_id, {'dog_bid': current_dog_bid})
                    actions.append({'bot_id': bot_id, 'action': 'anchor_dead_market_cancel'})
                    save_state()
                    return

                # Drift guard: if dog side bid is very high (>50c), the market
                # has moved too far — this isn't a dog anymore, cancel
                if current_dog_bid > 50:
                    print(f'🚫 PHANTOM DRIFT: {bot_id} dog bid now {current_dog_bid}¢ (>50¢) — no longer underdog, cancelling')
                    # Cancel ALL tracked orders — dog, fav, and any old repost IDs
                    _safe_cancel(dog_order_id, f'phantom drift cancel {bot_id}')
                    for _drift_key in ('fav_order_id', 'hedge_order_id'):
                        _drift_oid = bot.get(_drift_key)
                        if _drift_oid:
                            _safe_cancel(_drift_oid, f'phantom drift cancel {_drift_key} {bot_id}')
                    for _drift_oid in bot.get('_all_dog_order_ids', []):
                        if _drift_oid and _drift_oid != dog_order_id:
                            _safe_cancel(_drift_oid, f'phantom drift cancel old dog {bot_id}')
                    bot['status'] = 'completed'
                    bot['completed_at'] = now
                    actions.append({'bot_id': bot_id, 'action': 'anchor_drift_cancel', 'dog_bid': current_dog_bid})
                    save_state()
                    return

                # Smart reprice: same logic as initial placement — use stored anchor_depth
                anchor_depth = bot.get('anchor_depth', 5)
                spread = (current_dog_ask - current_dog_bid) if current_dog_ask > 0 else 1
                anchor_base = current_dog_ask if spread > 2 else current_dog_bid
                new_dog_price = max(1, anchor_base - anchor_depth)

                # Don't repost if price hasn't changed meaningfully
                # Retreat also requires ≥2¢ move to avoid jitter (1¢ bid oscillation is noise)
                _price_delta = abs(new_dog_price - bot['dog_price'])
                if _price_delta <= 1 and not retreat_triggered:
                    bot['posted_at'] = now
                    return
                if retreat_triggered and _price_delta < 2:
                    return  # retreat jitter filter: don't waste API calls on <2¢ moves

                # Track old order ID before overwriting (in case cancel fails)
                all_dog_ids = bot.get('_all_dog_order_ids', [])
                all_dog_ids.append(dog_order_id)
                bot['_all_dog_order_ids'] = all_dog_ids

                # Cancel old, place new
                _safe_cancel(dog_order_id, f'phantom dog repost {bot_id}')

                new_resp, actual_new_price = create_order_maker(
                    ticker=ticker, side=dog_side, action='buy',
                    count=qty, price=new_dog_price
                )
                new_order_id = _extract_order_id(new_resp, f'phantom dog repost {bot_id}')
                if not new_order_id:
                    return
                old_price = bot['dog_price']
                bot['dog_order_id'] = new_order_id
                bot['dog_price'] = actual_new_price
                bot['posted_at'] = now
                bot['_bid_at_post'] = current_dog_bid
                bot['_last_repost_at'] = now
                bot['dog_repost_count'] = bot.get('dog_repost_count', 0) + 1
                # Update compat fields
                if dog_side == 'yes':
                    bot['yes_order_id'] = new_order_id
                    bot['yes_price'] = actual_new_price
                else:
                    bot['no_order_id'] = new_order_id
                    bot['no_price'] = actual_new_price

                # Recalculate precalc hedge price for new dog price
                target_width = bot.get('target_width', 5)
                bot['_precalc_hedge_price'] = _precalc_phantom_hedge(actual_new_price, target_width, dog_side, qty)

                print(f'🔄 PHANTOM REPOST: {bot_id} dog {old_price}¢→{actual_new_price}¢ '
                      f'({trigger_reason} bid={current_dog_bid}¢ ask={current_dog_ask}¢ #{bot["dog_repost_count"]})')
                bot_log('PHANTOM_DOG_REPOST', bot_id, {
                    'old_price': old_price, 'new_price': actual_new_price,
                    'dog_bid': current_dog_bid, 'dog_ask': current_dog_ask,
                    'trigger': trigger_reason, 'repost_count': bot['dog_repost_count'],
                    'new_order_id': new_order_id[:12],
                    'precalc_hedge': bot.get('_precalc_hedge_price'),
                    'anchor_depth': anchor_depth, 'spread': spread,
                })
                _audit('PHANTOM_DOG_REPOST', bot_id, {
                    'ticker': ticker, 'old_price': old_price, 'new_price': actual_new_price,
                    'trigger': trigger_reason, 'new_order_id': new_order_id,
                })
                actions.append({'bot_id': bot_id, 'action': 'anchor_dog_repost',
                                'old_price': old_price, 'new_price': actual_new_price,
                                'dog_bid': current_dog_bid, 'trigger': trigger_reason})
                save_state()
            except Exception as rp_err:
                print(f'⚠ PHANTOM REPOST {bot_id}: {rp_err}')
                bot_log('PHANTOM_REPOST_ERROR', bot_id, {'error': str(rp_err)[:300]}, level='ERROR')
        return

    # ── STATE: dog_filled — dog filled but fav post failed, retry ──
    if status == 'dog_filled':
        bot_log('PHANTOM_DOG_FILLED_POLL', bot_id, {
            'dog_price': bot['dog_price'], 'dog_side': dog_side,
            'fav_side': fav_side, '_hedge_fired': bot.get('_hedge_fired'),
            'fav_order_id': (bot.get('fav_order_id') or 'none')[:12],
            'dog_filled_at': bot.get('dog_filled_at'),
            'sellback_attempts': bot.get('_sellback_attempts', 0),
        })
        # Settlement check: if market is closed/settled, record result based on outcome
        try:
            api_read_limiter.wait()
            mkt_resp = kalshi_client.get_market(ticker)
            mkt = mkt_resp.get('market', mkt_resp) if isinstance(mkt_resp, dict) else {}
            mkt_status = mkt.get('status', '').lower()
            mkt_result = mkt.get('result', '').lower()
            if mkt_status in ('settled', 'finalized', 'closed'):
                dog_price = bot['dog_price']
                # Dog side won → position pays 100¢
                dog_won = (dog_side == 'yes' and mkt_result == 'yes') or \
                          (dog_side == 'no' and mkt_result == 'no')
                if dog_won:
                    profit = (100 - dog_price) * qty
                    session_pnl['gross_profit_cents'] += profit
                    print(f'🏆 PHANTOM SETTLED WIN: {bot_id} dog {dog_side}@{dog_price}¢ won — +{profit}¢')
                else:
                    loss = dog_price * qty
                    session_pnl['gross_loss_cents'] += loss
                    profit = -loss
                    print(f'⚠ PHANTOM SETTLED LOSS: {bot_id} dog {dog_side}@{dog_price}¢ lost — -{loss}¢')
                session_pnl['completed_bots'] += 1
                bot['_trade_recorded'] = True
                _record_trade({
                    'bot_id': bot_id, 'ticker': ticker,
                    'yes_price': dog_price if dog_side == 'yes' else 0,
                    'no_price': dog_price if dog_side == 'no' else 0,
                    'quantity': qty,
                    'profit_cents': max(0, profit), 'loss_cents': max(0, -profit),
                    'result': f'settled_{"win" if dog_won else "loss"}_{dog_side}',
                    'exit_via': 'anchor_settlement',
                    'first_leg': dog_side,
                    'hedge_latency_ms': bot.get('hedge_latency_ms'),
                    'raw_hedge_ms': bot.get('raw_hedge_ms'),
                    'timestamp': now,
                    'placed_at': bot.get('created_at', now),
                    'arb_width': bot.get('target_width', 0),
                    'game_phase': 'settled',
                    'fill_source': 'anchor_settlement',
                    'bot_category': 'anchor_dog',
                }, bot)
                bot['status'] = 'completed'
                bot['completed_at'] = now
                _audit('PHANTOM_SETTLED', bot_id, {'ticker': ticker, 'dog_side': dog_side, 'result': mkt_result, 'dog_won': dog_won, 'profit': profit})
                _audit_position_check(bot_id, ticker, dog_side, 'after_settlement')
                save_state()
                actions.append({'bot_id': bot_id, 'action': 'anchor_settled', 'won': dog_won, 'pnl': profit})
                return
        except Exception as sett_err:
            # Non-fatal — fall through to normal retry
            pass

        # Retry posting the fav (hedge_ticker for cross-market)
        try:
            api_read_limiter.wait()
            ob = kalshi_client.get_market_orderbook(hedge_ticker)
            fav_bid = _best_bid(ob, fav_side)
        except Exception:
            fav_bid = 0

        if fav_bid <= 0:
            # Check max holdtime — don't hold dog position forever
            dog_filled_at = bot.get('dog_filled_at', now)
            max_hold_s = 600  # 10 minutes max
            if (now - dog_filled_at) > max_hold_s:
                print(f'⚠ PHANTOM {bot_id}: dog held {(now - dog_filled_at)/60:.1f}m with no fav bid — selling back')
                _phantom_sell_back(bot_id, bot, bot['dog_price'], 0, 999, actions)
                return
            actions.append({'bot_id': bot_id, 'action': 'dog_filled_waiting_fav_bid'})
            return

        dog_price = bot['dog_price']
        target_width = bot.get('target_width', 5)
        fav_shave = bot.get('fav_shave', 0)
        max_hedge = HARD_CEILING_CENTS - dog_price  # 98¢ ceiling only
        # Initial hedge: post at bid (or bid - shave), capped only by walk ceiling
        initial_fav_target = max(1, fav_bid - fav_shave) if fav_shave > 0 else fav_bid
        hedge_price = min(initial_fav_target, max_hedge)
        if hedge_price < 1:
            _phantom_sell_back(bot_id, bot, dog_price, fav_bid, 999, actions)
            return

        total_cost = dog_price + hedge_price
        if total_cost >= HARD_CEILING_CENTS:
            # At breakeven or worse — sell back, don't waste time hedging
            print(f'🚫 PHANTOM CEILING: {bot_id} combined {total_cost}¢ >= {HARD_CEILING_CENTS}¢ — selling dog back')
            bot_log('PHANTOM_CEILING_NO_HEDGE', bot_id, {
                'dog_price': dog_price, 'hedge_price': hedge_price,
                'fav_bid': fav_bid, 'total_cost': total_cost,
            })
            _phantom_sell_back(bot_id, bot, dog_price, fav_bid, total_cost, actions)
            return

        # Guard: WS handler may have already posted the fav hedge
        if bot.get('_hedge_fired') and bot.get('fav_order_id'):
            return

        try:
            fav_resp, actual_fav_price = create_order_maker(
                ticker=hedge_ticker, side=fav_side, action='buy',
                count=qty, price=hedge_price
            )
            fav_order_id = fav_resp['order']['order_id']
            bot['fav_order_id'] = fav_order_id
            bot['fav_price'] = actual_fav_price
            bot['status'] = 'fav_hedge_posted'
            bot['fav_posted_at'] = now
            bot['fav_walk_count'] = 0
            bot['fav_last_walk_at'] = None
            # Record hedge placement latency (monitor path)
            dog_fill_at = bot.get('dog_filled_at')
            if dog_fill_at and not bot.get('hedge_latency_ms'):
                bot['hedge_latency_ms'] = round((now - dog_fill_at) * 1000, 1)
            if fav_side == 'yes':
                bot['yes_price'] = actual_fav_price
                bot['yes_order_id'] = fav_order_id
            else:
                bot['no_price'] = actual_fav_price
                bot['no_order_id'] = fav_order_id
            print(f'👻 PHANTOM HEDGE RETRY: {bot_id} fav posted @{actual_fav_price}¢ (shave={fav_shave}¢)')
            bot_log('PHANTOM_FAV_RETRY_POSTED', bot_id, {
                'fav_price': actual_fav_price, 'dog_price': dog_price,
                'fav_bid': fav_bid, 'fav_shave': fav_shave,
                'combined': dog_price + actual_fav_price,
                'fav_order_id': fav_order_id[:12],
                'hedge_latency_ms': bot.get('hedge_latency_ms'),
            })
            _audit('PHANTOM_FAV_RETRY_POSTED', bot_id, {
                'ticker': ticker, 'fav_price': actual_fav_price, 'fav_order_id': fav_order_id,
            })
            save_state()
        except Exception as e:
            print(f'❌ PHANTOM {bot_id}: fav retry failed: {e}')
            bot_log('PHANTOM_FAV_RETRY_ERROR', bot_id, {
                'error': str(e)[:300], 'dog_price': dog_price,
                'hedge_price': hedge_price, 'fav_bid': fav_bid,
            }, level='ERROR')
        return

    # ── STATE: fav_hedge_posted — fav posted, waiting for fill ────
    if status == 'fav_hedge_posted':
        fav_order_id = bot.get('fav_order_id')
        if not fav_order_id:
            bot_log('PHANTOM_NO_FAV_ORDER', bot_id, {'status': status}, level='WARN')
            return

        api_read_limiter.wait()
        fav_resp = kalshi_client.get_order(fav_order_id)
        fav_ord = fav_resp.get('order', fav_resp) if isinstance(fav_resp, dict) else {}
        fav_filled = _parse_fill_count(fav_ord)
        bot['fav_fill_qty'] = fav_filled

        # Update compat fill fields
        if fav_side == 'yes':
            bot['yes_fill_qty'] = fav_filled
        else:
            bot['no_fill_qty'] = fav_filled

        bot_log('PHANTOM_FAV_POLL', bot_id, {
            'fav_filled': fav_filled, 'qty': qty,
            'fav_price': bot.get('fav_price'), 'dog_price': bot.get('dog_price'),
            'fav_order_id': fav_order_id[:12],
            'fav_walk_count': bot.get('fav_walk_count', 0),
            'wait_s': round(now - (bot.get('fav_posted_at') or now), 1),
        })

        if fav_filled >= qty:
            # Guard: if _trade_recorded is already True but status never changed (crash recovery),
            # re-run the completion so the trade actually gets recorded in history
            if bot.get('_trade_recorded') and bot.get('status') != 'completed':
                print(f'🔄 PHANTOM RECOVERY: {bot_id} _trade_recorded=True but status={bot.get("status")} — re-running completion')
                bot['_trade_recorded'] = False  # clear so completion path runs fully

            # BOTH LEGS FILLED — arb complete!
            actual_fav_price = get_actual_fill_price(fav_order_id, fav_side) or bot['fav_price']
            bot['fav_price'] = actual_fav_price
            dog_price = bot['dog_price']

            if fav_side == 'yes':
                yes_p, no_p = actual_fav_price, dog_price
            else:
                yes_p, no_p = dog_price, actual_fav_price
            bot['yes_price'] = yes_p
            bot['no_price'] = no_p

            pnl_cents = (100 - yes_p - no_p) * qty
            fee = kalshi_fee_cents(yes_p, no_p, qty)
            net_pnl = pnl_cents - fee

            # Compute hedge speed BEFORE recording trade so it's included
            dog_fill_at = bot.get('dog_filled_at')
            if dog_fill_at and not bot.get('hedge_fill_latency_ms'):
                bot['hedge_fill_latency_ms'] = round((now - dog_fill_at) * 1000, 1)

            _record_trade({
                'bot_id': bot_id, 'ticker': ticker,
                'yes_price': yes_p, 'no_price': no_p,
                'quantity': qty,
                'profit_cents': net_pnl if net_pnl >= 0 else 0,
                'loss_cents': abs(net_pnl) if net_pnl < 0 else 0,
                'fee_cents': fee,
                'result': 'completed' if net_pnl >= 0 else 'arb_loss',
                'exit_via': 'anchor_dog_complete',
                'first_leg': dog_side,
                'dog_side': dog_side,
                'dog_price': dog_price,
                'fav_price': actual_fav_price,
                'hedge_latency_ms': bot.get('hedge_latency_ms'),
                'hedge_fill_latency_ms': bot.get('hedge_fill_latency_ms'),
                'raw_hedge_ms': bot.get('raw_hedge_ms'),
                'fill_duration_s': round(now - bot['dog_filled_at']) if bot.get('dog_filled_at') else None,
                'timestamp': now,
                'placed_at': bot.get('created_at', now),
                'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                'arb_width': bot.get('target_width', 0),
                'game_phase': bot.get('game_phase', 'live'),
                'game_context': _get_game_context(ticker),
                'fill_source': 'anchor_dog',
                'bot_category': 'anchor_dog',
                'cross_market': bot.get('cross_market', False),
                'hedge_ticker': bot.get('hedge_ticker', ''),
            }, bot)

            # Only update session P&L and mark recorded AFTER successful trade record
            if net_pnl >= 0:
                session_pnl['gross_profit_cents'] += net_pnl
            else:
                session_pnl['gross_loss_cents'] += abs(net_pnl)
            session_pnl['completed_bots'] += 1
            bot['_trade_recorded'] = True
            bot_log('ANCHOR_COMPLETE', bot_id, {
                'dog': dog_price, 'fav': actual_fav_price,
                'pnl': pnl_cents, 'fee': fee, 'net': net_pnl,
                'hedge_fill_latency_ms': bot.get('hedge_fill_latency_ms'),
            })
            print(f'✅ PHANTOM COMPLETE: {bot_id} dog@{dog_price}¢ + fav@{actual_fav_price}¢ = {dog_price+actual_fav_price}¢ → pnl {pnl_cents}¢ (net {net_pnl}¢) hedge_fill={bot.get("hedge_fill_latency_ms", "?")}ms')
            _audit('PHANTOM_COMPLETE', bot_id, {'ticker': ticker, 'dog_price': dog_price, 'fav_price': actual_fav_price, 'pnl': net_pnl, 'qty': qty})

            # Verify ACTUAL fills on Kalshi — check every order this bot placed
            try:
                _ph_oids = [bot.get('dog_order_id'), bot.get('fav_order_id')]
                _ph_oids += bot.get('_all_dog_order_ids', [])
                _ph_oids = [o for o in _ph_oids if o]
                _ph_yes = 0
                _ph_no = 0
                _ph_checked = 0
                for _oid in set(_ph_oids):
                    try:
                        api_read_limiter.wait()
                        _ord_resp = kalshi_client.get_order(_oid)
                        _ord_data = _ord_resp.get('order', _ord_resp) if isinstance(_ord_resp, dict) else {}
                        _ord_fills = _parse_fill_count(_ord_data)
                        _ord_side = _ord_data.get('side', '')
                        if _ord_fills > 0:
                            if _ord_side == 'yes':
                                _ph_yes += _ord_fills
                            elif _ord_side == 'no':
                                _ph_no += _ord_fills
                        _ph_checked += 1
                    except Exception:
                        pass
                _ph_unhedged = abs(_ph_yes - _ph_no)
                if _ph_yes != _ph_no:
                    _ph_heavy = 'yes' if _ph_yes > _ph_no else 'no'
                    print(f'⚠ PHANTOM ORDER VERIFY: {bot_id} Kalshi fills YES={_ph_yes} NO={_ph_no} → {_ph_unhedged} unhedged {_ph_heavy}')
                    _push_notification('orphan_detected', f'⚠ Phantom {bot_id}: {_ph_unhedged} unhedged {_ph_heavy} on {ticker}', {
                        'bot_id': bot_id, 'ticker': ticker, 'side': _ph_heavy, 'qty': _ph_unhedged,
                    })
                else:
                    print(f'✅ PHANTOM ORDER VERIFY: {bot_id} balanced YES={_ph_yes} NO={_ph_no}')
                bot_log('PHANTOM_ORDER_VERIFY', bot_id, {
                    'verified_yes': _ph_yes, 'verified_no': _ph_no,
                    'unhedged': _ph_unhedged, 'orders_checked': _ph_checked,
                    'local_dog_fill': bot.get('dog_fill_qty', 0), 'local_fav_fill': fav_filled,
                })
            except Exception as _pv_err:
                bot_log('PHANTOM_ORDER_VERIFY_FAIL', bot_id, {'error': str(_pv_err)[:200]}, level='ERROR')

            # Repeat logic
            repeats_done_now = bot.get('repeats_done', 0) + 1
            bot['repeats_done'] = repeats_done_now
            repeat_total = bot.get('repeat_count', 0)
            if repeats_done_now <= repeat_total:
                bot['status'] = 'waiting_repeat'
                bot['waiting_repeat_since'] = time.time() + 3  # 3s linger to show completion
                bot['_just_completed'] = True
                bot['_last_pnl'] = net_pnl
                bot['_last_result'] = 'win' if net_pnl >= 0 else 'loss'
                bot['lifetime_pnl'] = bot.get('lifetime_pnl', 0) + net_pnl
                bot['dog_filled_at'] = None
                bot['raw_hedge_ms'] = None
                bot['hedge_latency_ms'] = None
                bot['fav_order_id'] = None
                bot['fav_fill_qty'] = 0
                bot['dog_fill_qty'] = 0
                bot['yes_fill_qty'] = 0
                bot['no_fill_qty'] = 0
                bot['_hedge_fired'] = False
                bot['_trade_recorded'] = False
                bot['_all_dog_order_ids'] = []  # clear so verify doesn't double-count prior repeats
                bot['_bid_at_post'] = bot.get(f'live_{dog_side}_bid', 0)
                bot['_last_repost_at'] = 0
                print(f'🔄 PHANTOM REPEAT: {bot_id} cycle {repeats_done_now}/{repeat_total} pnl={net_pnl}¢')
                _audit('PHANTOM_REPEAT_ENTER', bot_id, {'ticker': ticker, 'cycle': repeats_done_now, 'total': repeat_total})
                _audit_position_check(bot_id, ticker, dog_side, 'entering_repeat')
            else:
                bot['status'] = 'completed'
                bot['completed_at'] = now
                bot['_just_completed'] = True
                bot['_last_pnl'] = net_pnl
                bot['lifetime_pnl'] = bot.get('lifetime_pnl', 0) + net_pnl
            save_state()
            actions.append({'bot_id': bot_id, 'action': 'anchor_complete', 'profit_cents': net_pnl})
            return

        # Fav not filled yet — check if game/market is over
        if bot.get('game_phase') == 'live' and _is_game_ending(ticker):
            # Game ending with fav unfilled — check if market settled
            try:
                api_read_limiter.wait()
                mkt_resp = kalshi_client.get_market(ticker)
                mkt = mkt_resp.get('market', mkt_resp) if isinstance(mkt_resp, dict) else {}
                mkt_status = mkt.get('status', '').lower()
                mkt_result = mkt.get('result', '').lower()
                if mkt_status in ('settled', 'finalized', 'closed'):
                    # Cancel unfilled fav order
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(fav_order_id)
                    except Exception:
                        pass
                    dog_price = bot['dog_price']
                    dog_won = (dog_side == 'yes' and mkt_result == 'yes') or \
                              (dog_side == 'no' and mkt_result == 'no')
                    profit = ((100 - dog_price) * qty) if dog_won else (-(dog_price * qty))
                    if dog_won:
                        session_pnl['gross_profit_cents'] += profit
                    else:
                        session_pnl['gross_loss_cents'] += abs(profit)
                    bot['_trade_recorded'] = True
                    _record_trade({
                        'bot_id': bot_id, 'ticker': ticker,
                        'yes_price': dog_price if dog_side == 'yes' else 0,
                        'no_price': dog_price if dog_side == 'no' else 0,
                        'quantity': qty,
                        'profit_cents': profit if profit > 0 else 0,
                        'loss_cents': abs(profit) if profit < 0 else 0,
                        'result': 'settled_win' if dog_won else 'settled_loss',
                        'exit_via': 'phantom_settlement',
                        'timestamp': now, 'placed_at': bot.get('created_at', now),
                        'fill_source': 'anchor_dog', 'bot_category': 'anchor_dog',
                    }, bot)
                    print(f'🏁 PHANTOM GAME OVER: {bot_id} fav unfilled, market settled → {"WIN" if dog_won else "LOSS"} {profit}¢')
                    bot['status'] = 'completed'
                    bot['completed_at'] = now
                    save_state()
                    actions.append({'bot_id': bot_id, 'action': 'anchor_settled', 'won': dog_won, 'pnl': profit})
                    return
            except Exception:
                pass  # non-fatal, fall through to normal timeout

        hedge_timeout_s = bot.get('hedge_timeout_s', 120)
        fav_posted_at = bot.get('fav_posted_at') or bot.get('dog_filled_at') or now
        wait_s = now - fav_posted_at

        # Pause hedge timeout during halftime — don't sell the dog during halftime
        if _is_halftime(ticker):
            bot['fav_posted_at'] = now  # reset timer so it restarts after halftime
            bot['fav_last_walk_at'] = now  # also pause walk-up timer
            actions.append({'bot_id': bot_id, 'action': 'anchor_fav_halftime_pause'})
            return

        # ── Fav Bid-Follow System ──
        # Snap to bid every cycle. Hold at 98. Timeout sells back.
        WALK_CEILING = bot.get('fav_walk_ceiling', HARD_CEILING_CENTS)
        dog_price = bot['dog_price']

        # Check absolute timeout — give up after hedge_timeout_s total
        # But ONLY if hedge is already at or near the bid (snap first, then timeout)
        _current_fav = bot.get('fav_price', 0)
        _live_bid = bot.get(f'live_{fav_side}_bid', 0)
        _at_bid = _current_fav >= _live_bid - 1 if _live_bid > 0 and _current_fav > 0 else True
        if wait_s >= hedge_timeout_s and _at_bid:
            bot_log('PHANTOM_TIMEOUT_CHECK', bot_id, {
                'wait_s': round(wait_s, 1), 'timeout_s': hedge_timeout_s,
                'fav_filled': bot.get('fav_fill_qty', 0), 'qty': bot.get('quantity', 1),
                'fav_price': bot.get('fav_price'), 'dog_price': dog_price,
                'fav_walk_count': bot.get('fav_walk_count', 0),
            })
            # Query fav fill count before cancelling — partial fills may exist
            fav_filled = bot.get('fav_fill_qty', 0)
            try:
                api_read_limiter.wait()
                fav_order = kalshi_client.get_order(fav_order_id)
                fav_filled = max(fav_filled, _parse_fill_count(fav_order.get('order', fav_order)))
                bot['fav_fill_qty'] = fav_filled
            except Exception:
                pass
            qty = bot.get('quantity', 1)
            try:
                api_rate_limiter.wait()
                kalshi_client.cancel_order(fav_order_id)
            except Exception:
                pass
            if fav_filled > 0 and fav_filled < qty:
                # Partial fav fill — record partial arb completion, sell back only the uncovered dogs
                sell_qty = qty - fav_filled
                print(f'⏰ PHANTOM TIMEOUT (PARTIAL): {bot_id} fav filled {fav_filled}/{qty} — selling back {sell_qty} dogs, recording {fav_filled} partial arb')
                # Record the partial arb as profit
                fav_price = bot.get('fav_price', 0)
                profit_per = 100 - dog_price - fav_price
                est_fee = kalshi_fee_cents(
                    dog_price if bot['dog_side'] == 'yes' else fav_price,
                    dog_price if bot['dog_side'] == 'no' else fav_price,
                    fav_filled
                )
                net_profit = max(0, profit_per * fav_filled - est_fee)
                session_pnl['gross_profit_cents'] += net_profit
                bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + net_profit
                _record_trade({
                    'bot_id': bot_id, 'ticker': ticker,
                    'yes_price': dog_price if bot['dog_side'] == 'yes' else fav_price,
                    'no_price': dog_price if bot['dog_side'] == 'no' else fav_price,
                    'quantity': fav_filled, 'profit_cents': net_profit, 'loss_cents': 0,
                    'fee_cents': est_fee, 'result': 'anchor_partial_arb',
                    'timestamp': now, 'placed_at': bot.get('created_at', now),
                    'arb_width': bot.get('target_width', 0),
                })
                # Now sell back only the uncovered dogs
                bot['quantity'] = sell_qty  # temporarily set qty for sell-back
                _phantom_sell_back(bot_id, bot, dog_price, bot.get('fav_price', 0), 999, actions)
                bot['quantity'] = qty  # restore original qty
            elif fav_filled >= qty:
                # Fully filled during timeout check — complete normally
                print(f'⏰ PHANTOM TIMEOUT: {bot_id} fav actually filled {fav_filled}/{qty} — completing')
                # Let monitor handle completion on next cycle
                bot['status'] = 'fav_hedge_posted'
            else:
                # No fav fills — sell all dogs back
                print(f'⏰ PHANTOM TIMEOUT: {bot_id} waited {wait_s:.0f}s, 0 fav fills — selling dog back')
                _phantom_sell_back(bot_id, bot, dog_price, bot.get('fav_price', 0), 999, actions)
            return

        # ── Phantom Walk + Snap System ──
        # Priority 1: Drop to bid if above it (instant)
        # Priority 2: Profit snap to bid if combined <= 96¢ (instant, up or down)
        # Priority 3: Normal walk +1¢ toward bid (every 20s)
        # Hard ceiling: combined (dog + fav) never exceeds WALK_CEILING (98¢)
        current_fav_price = bot.get('fav_price', 0)
        if current_fav_price <= 0:
            return

        # Fetch current bid + ask (hedge_ticker for cross-market fav)
        try:
            api_read_limiter.wait()
            ob = kalshi_client.get_market_orderbook(hedge_ticker)
            current_fav_bid = _best_bid(ob, fav_side)
            current_fav_ask = _best_ask(ob, fav_side)
        except Exception:
            current_fav_bid = 0
            current_fav_ask = 0

        if current_fav_bid <= 0:
            # No fav bid — patience tier logic before bailing
            # First half of timeout: only bail on confirmed blowout (dog price crashed 50%+)
            # Second half: bail if no fav bid (existing behavior)
            _no_bid_count = bot.get('_no_fav_bid_count', 0) + 1
            bot['_no_fav_bid_count'] = _no_bid_count
            _dog_bid_now = bot.get(f'live_{bot["dog_side"]}_bid', dog_price)  # current dog bid from WS
            _dog_crashed = _dog_bid_now < dog_price * 0.5  # dog lost 50%+ value
            _patience_half = hedge_timeout_s * 0.5
            _bail_threshold = hedge_timeout_s * 0.75
            # No game-phase urgency for phantom — fixed timeout behavior
            _force_bail = False
            _should_bail = _force_bail or (wait_s >= _bail_threshold) or (wait_s >= _patience_half and _dog_crashed and _no_bid_count >= 2)
            _patience_tier = 'critical_bail' if _force_bail else 'blowout_bail' if (_dog_crashed and _no_bid_count >= 2) else 'timeout_bail' if wait_s >= _bail_threshold else 'waiting'
            bot_log('PHANTOM_NO_FAV_BID_WALK', bot_id, {
                'wait_s': round(wait_s, 1), 'timeout_s': hedge_timeout_s,
                'bail_threshold': round(_bail_threshold, 1),
                'patience_tier': _patience_tier, 'no_bid_count': _no_bid_count,
                'dog_price': dog_price, 'dog_bid_now': _dog_bid_now,
                'dog_crashed': _dog_crashed,
                'will_bail': _should_bail,
            })
            if _should_bail:
                try:
                    api_rate_limiter.wait()
                    kalshi_client.cancel_order(fav_order_id)
                except Exception:
                    pass
                _phantom_sell_back(bot_id, bot, dog_price, 0, 999, actions)
            return

        # Fav bid is back — reset no-bid counter
        bot['_no_fav_bid_count'] = 0

        # Walk target: always bid — phantom needs ceiling margin, walk handles the rest
        walk_target = current_fav_bid

        # Hard ceiling: 98¢ = hold for fill, 99¢+ = sellback
        max_fav_hold = WALK_CEILING - dog_price       # 98 - dog = hold here
        max_fav_sellback = WALK_CEILING + 1 - dog_price  # 99 - dog = sellback
        walk_target = min(walk_target, max_fav_hold)

        if walk_target <= 0:
            return

        # No premature ceiling sellback — snap to max_fav_hold and hold.
        # The normal hedge timeout handles exits if the fill never comes.
        # Bid above ceiling just means we sit at max_fav_hold (combined=98) and wait.

        # ── Check if bid has gone past ceiling — sell back ──
        if current_fav_bid > max_fav_hold and current_fav_price >= max_fav_hold:
            # Bid is above ceiling AND we're already at ceiling — can't profit, sell back
            try:
                api_rate_limiter.wait()
                kalshi_client.cancel_order(fav_order_id)
            except Exception:
                pass
            _over_combined = dog_price + current_fav_bid
            print(f'🚫 PHANTOM CEILING EXIT: {bot_id} bid={current_fav_bid}¢ > max={max_fav_hold}¢ combined_at_bid={_over_combined}¢ — selling back')
            bot_log('PHANTOM_CEILING_EXIT', bot_id, {
                'dog_price': dog_price, 'fav_bid': current_fav_bid,
                'fav_price': current_fav_price, 'max_fav_hold': max_fav_hold,
                'combined_at_bid': _over_combined, 'ceiling': WALK_CEILING,
            })
            _phantom_sell_back(bot_id, bot, dog_price, current_fav_price, 999, actions)
            return

        # ── Bid-follow: always snap to bid, no walk intervals ──
        new_fav_price = walk_target
        if new_fav_price == current_fav_price:
            return  # already at bid/ceiling, holding

        walk_type = 'snap_to_bid'
        combined = dog_price + new_fav_price
        if combined > WALK_CEILING:
            # Bid is above ceiling — sell back, can't hedge profitably
            try:
                api_rate_limiter.wait()
                kalshi_client.cancel_order(fav_order_id)
            except Exception:
                pass
            print(f'🚫 PHANTOM CEILING EXIT: {bot_id} bid={current_fav_bid}¢ would make combined={combined}¢ > {WALK_CEILING}¢ — selling back')
            bot_log('PHANTOM_CEILING_EXIT', bot_id, {
                'dog_price': dog_price, 'fav_bid': current_fav_bid,
                'combined': combined, 'ceiling': WALK_CEILING,
            })
            _phantom_sell_back(bot_id, bot, dog_price, current_fav_price, 999, actions)
            return

        # Amend fav order (shared lock with WS instant drop to prevent race)
        try:
            _phantom_drop_lock.acquire()
            try:
                fav_order_id = bot.get('fav_order_id', fav_order_id)
                amend_kwargs = {'yes_price': new_fav_price} if fav_side == 'yes' else {'no_price': new_fav_price}
                api_rate_limiter.wait()
                kalshi_client.amend_order(
                    fav_order_id, ticker=hedge_ticker, side=fav_side,
                    count=qty, **amend_kwargs
                )
            finally:
                _phantom_drop_lock.release()
            walk_count = bot.get('fav_walk_count', 0) + 1
            direction = '↓' if new_fav_price < current_fav_price else '↑'
            print(f'📈 PHANTOM {walk_type.upper()}: {bot_id} fav {current_fav_price}¢{direction}{new_fav_price}¢ '
                  f'(bid={current_fav_bid}¢ combined={combined}¢ ceiling={WALK_CEILING}¢ step #{walk_count})')
            bot_log('PHANTOM_WALK_SUCCESS', bot_id, {
                'walk_type': walk_type, 'old_price': current_fav_price,
                'new_price': new_fav_price, 'fav_bid': current_fav_bid,
                'fav_ask': current_fav_ask,
                'dog_price': dog_price, 'combined': combined,
                'ceiling': WALK_CEILING,
                'walk_count': walk_count, 'wait_s': round(wait_s, 1),
            })
            bot['fav_price'] = new_fav_price
            bot['fav_walk_count'] = walk_count
            bot['fav_last_walk_at'] = now
            if fav_side == 'yes':
                bot['yes_price'] = new_fav_price
            else:
                bot['no_price'] = new_fav_price
            save_state()
            actions.append({'bot_id': bot_id, 'action': f'anchor_fav_{walk_type}',
                            'old_price': current_fav_price, 'new_price': new_fav_price,
                            'walk_count': walk_count, 'combined': combined})
        except Exception as e:
                err_str = str(e)
                print(f'❌ PHANTOM {bot_id}: fav {walk_type} amend failed: {e}')
                bot_log('PHANTOM_WALK_ERROR', bot_id, {
                    'walk_type': walk_type, 'error': err_str[:300],
                    'old_price': current_fav_price, 'target_price': new_fav_price,
                    'fav_order_id': fav_order_id[:12],
                }, level='ERROR')
                bot['fav_last_walk_at'] = now
                # 404 = order no longer exists on Kalshi — check if it was filled
                if '404' in err_str:
                    try:
                        api_read_limiter.wait()
                        _fav_resp = kalshi_client.get_order(fav_order_id)
                        _fav_data = _fav_resp.get('order', _fav_resp) if isinstance(_fav_resp, dict) else {}
                        _fav_fills = _parse_fill_count(_fav_data)
                        _fav_status = _fav_data.get('status', '')
                        print(f'   🔍 PHANTOM FAV ORDER CHECK: {bot_id} status={_fav_status} fills={_fav_fills}/{qty}')
                        bot_log('PHANTOM_FAV_404_CHECK', bot_id, {
                            'fav_order_id': fav_order_id[:12], 'kalshi_status': _fav_status,
                            'kalshi_fills': _fav_fills, 'expected_qty': qty,
                        })
                        if _fav_fills >= qty:
                            # Fav was fully filled! Complete the bot.
                            print(f'   ✅ PHANTOM FAV FILLED (404 recovery): {bot_id} {_fav_fills}/{qty} fills')
                            bot[f'{fav_side}_fill_qty'] = _fav_fills
                            # Let the next monitor cycle handle completion
                        elif _fav_fills > 0:
                            # Partial fill — sell back unfilled portion
                            print(f'   ⚠ PHANTOM FAV PARTIAL (404 recovery): {bot_id} {_fav_fills}/{qty}')
                            bot[f'{fav_side}_fill_qty'] = _fav_fills
                        else:
                            # Order gone with 0 fills — sell back the dog
                            print(f'   🔙 PHANTOM FAV GONE (404 recovery): {bot_id} — triggering sellback')
                            bot['fav_order_id'] = None
                            bot['status'] = 'dog_filled'
                    except Exception as _check_err:
                        if '404' in str(_check_err):
                            # Order completely gone from Kalshi — sell back
                            print(f'   🔙 PHANTOM FAV GONE 404 (recovery): {bot_id} — triggering sellback')
                            bot['fav_order_id'] = None
                            bot['status'] = 'dog_filled'
        return

    # ── STATE: waiting_repeat — wait for spread to reopen, re-anchor ──
    if status == 'waiting_repeat':
        wait_since = bot.get('waiting_repeat_since', now)
        if now - wait_since < 10:  # 10s cooldown between repeats
            return
        # Clear completion linger flag
        bot.pop('_just_completed', None)
        bot.pop('_last_pnl', None)
        bot.pop('_last_result', None)

        # Recalculate smart price from current orderbook (don't reuse stale price)
        try:
            api_read_limiter.wait()
            ob = kalshi_client.get_market_orderbook(ticker)
            current_dog_bid = _best_bid(ob, dog_side)
            current_dog_ask = _best_ask(ob, dog_side)
            if current_dog_bid <= 0:
                bot['status'] = 'completed'
                bot['completed_at'] = now
                bot['repeat_count'] = 0
                print(f'🛑 PHANTOM DRIFT STOP: {bot_id} dog_bid=0 — no market, stopping')
                save_state()
                return
            # Smart pricing first — need new_dog_price for hedge fill check
            fav_side = bot.get('fav_side', 'no' if dog_side == 'yes' else 'yes')
            if hedge_ticker != ticker:
                api_read_limiter.wait()
                _fav_ob = kalshi_client.get_market_orderbook(hedge_ticker)
            else:
                _fav_ob = ob
            _current_fav_bid = _best_bid(_fav_ob, fav_side)
            anchor_depth = bot.get('anchor_depth', 5)
            spread = (current_dog_ask - current_dog_bid) if current_dog_ask > 0 else 1
            anchor_base = current_dog_ask if spread > 2 else current_dog_bid
            new_dog_price = max(1, anchor_base - anchor_depth)

            # Hedge fill drift guard: at this bot's target width, would the hedge still fill?
            _target_width = bot.get('target_width', 3)
            _hedge_price = 100 - new_dog_price - _target_width
            _hedge_gap = (_current_fav_bid - _hedge_price) if _current_fav_bid and _hedge_price > 0 else 99
            # gap <= 0 = instant fill, 1-2 = fast, 3-5 = walk, >5 = unlikely
            if _hedge_gap > 5 or current_dog_bid <= 3:
                bot_log('PHANTOM_REPEAT_DRIFT_SKIP', bot_id, {
                    'dog_bid': current_dog_bid, 'fav_bid': _current_fav_bid,
                    'new_dog_price': new_dog_price, 'target_width': _target_width,
                    'hedge_price': _hedge_price, 'hedge_gap': _hedge_gap,
                    'reason': 'hedge_unfillable' if _hedge_gap > 5 else 'dog_dead',
                })
                # Market is dead — stop the bot completely
                bot['status'] = 'completed'
                bot['completed_at'] = now
                bot['repeat_count'] = 0
                print(f'🛑 PHANTOM DRIFT STOP: {bot_id} dog_bid={current_dog_bid}¢ — market dead, stopping')
                save_state()
                return
        except Exception:
            new_dog_price = bot.get('dog_price', 10)  # fallback to old price

        # Defensive: cancel old dog order and track it before placing new one
        old_dog_oid = bot.get('dog_order_id')
        if old_dog_oid:
            _safe_cancel(old_dog_oid, f'phantom repeat cleanup {bot_id}')
            all_dog_ids = bot.get('_all_dog_order_ids', [])
            all_dog_ids.append(old_dog_oid)
            bot['_all_dog_order_ids'] = all_dog_ids

        try:
            dog_resp, actual_price = create_order_maker(
                ticker=ticker, side=dog_side, action='buy',
                count=qty, price=new_dog_price
            )
            bot['dog_order_id'] = dog_resp['order']['order_id']
            bot['dog_price'] = actual_price
            # Recalculate precalc hedge for new dog price (stale precalc = wrong hedge)
            bot['_precalc_hedge_price'] = _precalc_phantom_hedge(actual_price, bot.get('target_width', 5), dog_side, qty)
            bot['dog_fill_qty'] = 0
            bot['fav_fill_qty'] = 0
            bot['yes_fill_qty'] = 0
            bot['no_fill_qty'] = 0
            bot['_hedge_fired'] = False  # clear so next fill can hedge
            bot['_trade_recorded'] = False
            bot['fav_order_id'] = None
            bot['fav_price'] = None
            bot['fav_walk_count'] = 0
            bot['fav_last_walk_at'] = None
            bot['dog_filled_at'] = None
            bot['raw_hedge_ms'] = None
            bot['hedge_latency_ms'] = None
            bot['_sellback_attempts'] = 0
            bot['status'] = 'dog_anchor_posted'
            bot['posted_at'] = now

            if dog_side == 'yes':
                bot['yes_order_id'] = bot['dog_order_id']
                bot['yes_price'] = actual_price
            else:
                bot['no_order_id'] = bot['dog_order_id']
                bot['no_price'] = actual_price

            print(f'🔄 PHANTOM REPOST: {bot_id} dog re-anchored @{actual_price}¢ (smart price from orderbook)')
            _audit('PHANTOM_REANCHOR', bot_id, {'ticker': ticker, 'new_dog_price': actual_price, 'dog_order_id': bot['dog_order_id']})
            _audit_position_check(bot_id, ticker, dog_side, 'after_reanchor')
            save_state()
        except Exception as e:
            print(f'❌ PHANTOM {bot_id}: repeat repost failed: {e}')
        return


def _handle_phantom_ladder(bot_id, bot, actions):
    """Handle all states for an anchor-ladder bot in the monitor loop."""
    now = time.time()
    ticker = bot['ticker']
    hedge_ticker = bot.get('hedge_ticker', ticker)
    dog_side = bot['dog_side']
    fav_side = bot['fav_side']
    status = bot['status']

    # Update live bid/ask from WS cache
    try:
        ws_p_lad = ws_manager.get_price(ticker) if ws_manager else None
        if ws_p_lad:
            bot['live_yes_bid'] = ws_p_lad.get('yes_bid', 0)
            bot['live_no_bid'] = ws_p_lad.get('no_bid', 0)
            bot['live_yes_ask'] = ws_p_lad.get('yes_ask', 0)
            bot['live_no_ask'] = ws_p_lad.get('no_ask', 0)
            _record_price_for_velocity(ticker, ws_p_lad.get('yes_bid', 0), ws_p_lad.get('no_bid', 0))
        # Cross-market: also cache hedge_ticker prices for fav walk
        if hedge_ticker != ticker:
            ws_p_hedge_lad = ws_manager.get_price(hedge_ticker) if ws_manager else None
            if ws_p_hedge_lad:
                bot['live_hedge_yes_bid'] = ws_p_hedge_lad.get('yes_bid', 0)
                bot['live_hedge_no_bid'] = ws_p_hedge_lad.get('no_bid', 0)
                bot['live_hedge_yes_ask'] = ws_p_hedge_lad.get('yes_ask', 0)
                bot['live_hedge_no_ask'] = ws_p_hedge_lad.get('no_ask', 0)
    except Exception:
        pass

    # ── STATE: awaiting_settlement — cross-market arb complete, holding until settlement ──
    if status == 'awaiting_settlement':
        # Check positions every 60s — when both clear, mark completed
        if now - bot.get('_last_settlement_check', 0) < 60:
            return
        bot['_last_settlement_check'] = now
        _hedge_t = bot.get('hedge_ticker', ticker)
        try:
            api_read_limiter.wait()
            _pos1 = kalshi_client.get_positions(ticker=ticker)
            _p1_list = _pos1.get('market_positions', _pos1.get('positions', []))
            _pos1_qty = sum(abs(_parse_position_qty(p)) for p in _p1_list if p.get('ticker') == ticker)

            api_read_limiter.wait()
            _pos2 = kalshi_client.get_positions(ticker=_hedge_t)
            _p2_list = _pos2.get('market_positions', _pos2.get('positions', []))
            _pos2_qty = sum(abs(_parse_position_qty(p)) for p in _p2_list if p.get('ticker') == _hedge_t)

            if _pos1_qty == 0 and _pos2_qty == 0:
                bot['status'] = 'completed'
                bot['completed_at'] = now
                print(f'✅ SETTLED: {bot_id} both positions cleared ({ticker} + {_hedge_t})')
                bot_log('PHANTOM_CROSS_MARKET_SETTLED', bot_id, {
                    'ticker': ticker, 'hedge_ticker': _hedge_t,
                })
                save_state()
        except Exception as _se:
            print(f'⚠ awaiting_settlement check {bot_id}: {_se}')
        return

    # ── Settlement guard: if market is closed/settled, stop the bot (check every 30s) ──
    _last_settle_check = bot.get('_last_settle_check', 0)
    if now - _last_settle_check >= 30:
      bot['_last_settle_check'] = now
      try:
        api_read_limiter.wait()
        mkt_al = kalshi_client.get_market(ticker)
        mkt_al_data = mkt_al.get('market', mkt_al) if isinstance(mkt_al, dict) else {}
        mkt_al_status = mkt_al_data.get('status', 'active')
        mkt_al_result = mkt_al_data.get('result', '')
        if mkt_al_status not in ('active', 'open') or mkt_al_result:
            print(f'👻 PHANTOM SETTLEMENT: {bot_id} market={mkt_al_status} result={mkt_al_result} status={status}')
            bot_log('PHANTOM_LADDER_SETTLEMENT_DETECTED', bot_id, {
                'market_status': mkt_al_status, 'result': mkt_al_result,
                'bot_status': status, 'ticker': ticker,
            })
            # Market is done — cancel unfilled orders and stop
            for rung in bot.get('rungs', []):
                oid = rung.get('order_id')
                if oid and rung.get('fill_qty', 0) < rung.get('qty', 1):
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(oid)
                    except Exception:
                        pass
            # Also cancel fav hedge order if posted
            fav_oid = bot.get('fav_order_id')
            if fav_oid:
                try:
                    api_rate_limiter.wait()
                    kalshi_client.cancel_order(fav_oid)
                except Exception:
                    pass
            # If we had fills, handle fav side
            total_fill = sum(r.get('fill_qty', 0) for r in bot.get('rungs', []))
            if total_fill > 0:
                # Check if dog side won (result matches dog_side)
                dog_won = (mkt_al_result == 'yes' and dog_side == 'yes') or (mkt_al_result == 'no' and dog_side == 'no')
                if dog_won:
                    avg_price = sum(r['price'] * r.get('fill_qty', 0) for r in bot.get('rungs', []) if r.get('fill_qty', 0) > 0) / max(total_fill, 1)
                    pnl = int((100 - avg_price) * total_fill)
                    session_pnl['gross_profit_cents'] += pnl
                    session_pnl['completed_bots'] += 1
                    print(f'🏁 PHANTOM LADDER SETTLED WIN: {bot_id} dog={dog_side} result={mkt_al_result} pnl={pnl}¢')
                    bot_log('PHANTOM_LADDER_SETTLED_WIN', bot_id, {
                        'dog_side': dog_side, 'result': mkt_al_result,
                        'pnl': pnl, 'avg_price': round(avg_price), 'total_fill': total_fill,
                    })
                else:
                    avg_price = sum(r['price'] * r.get('fill_qty', 0) for r in bot.get('rungs', []) if r.get('fill_qty', 0) > 0) / max(total_fill, 1)
                    loss = int(avg_price * total_fill)
                    session_pnl['gross_loss_cents'] += loss
                    session_pnl['stopped_bots'] += 1
                    print(f'🏁 PHANTOM LADDER SETTLED LOSS: {bot_id} dog={dog_side} result={mkt_al_result} loss={loss}¢')
                    bot_log('PHANTOM_LADDER_SETTLED_LOSS', bot_id, {
                        'dog_side': dog_side, 'result': mkt_al_result,
                        'loss': loss, 'avg_price': round(avg_price), 'total_fill': total_fill,
                    })
                profit = pnl if dog_won else -loss
                _record_trade({
                    'bot_id': bot_id, 'ticker': ticker,
                    'yes_price': int(avg_price) if dog_side == 'yes' else 0,
                    'no_price': int(avg_price) if dog_side == 'no' else 0,
                    'quantity': total_fill,
                    'profit_cents': max(0, profit), 'loss_cents': max(0, -profit),
                    'result': f'settled_{"win" if dog_won else "loss"}_{dog_side}',
                    'exit_via': 'anchor_ladder_settlement',
                    'first_leg': dog_side,
                    'hedge_latency_ms': bot.get('hedge_latency_ms'),
                    'raw_hedge_ms': bot.get('raw_hedge_ms'),
                    'timestamp': now,
                    'placed_at': bot.get('created_at', now),
                    'arb_width': bot.get('target_width', 0),
                    'game_phase': 'settled',
                    'fill_source': 'anchor_ladder_settlement',
                    'bot_category': 'anchor_ladder',
                }, bot)
            bot['status'] = 'completed'
            bot['completed_at'] = now
            bot['_trade_recorded'] = True
            _audit('LADDER_SETTLED', bot_id, {'ticker': ticker, 'market_status': mkt_al_status, 'result': mkt_al_result, 'total_fill': total_fill})
            _audit_position_check(bot_id, ticker, dog_side, 'after_ladder_settlement')
            actions.append({'bot_id': bot_id, 'action': 'anchor_ladder_settled', 'result': mkt_al_result})
            save_state()
            return
      except Exception as e:
        print(f'⚠ anchor_ladder settlement check {bot_id}: {e}')
        bot_log('PHANTOM_LADDER_SETTLEMENT_CHECK_ERROR', bot_id, {'error': str(e)[:300]}, level='ERROR')

    # ── STATE: waiting_repeat — repost ladder rungs fresh ──
    if status == 'waiting_repeat':
        wait_since = bot.get('waiting_repeat_since', now)
        if now - wait_since < 10:  # 10s cooldown
            return
        bot_log('PHANTOM_LADDER_WAITING_REPEAT_CHECK', bot_id, {
            'wait_s': round(now - wait_since, 1),
            'repeats_done': bot.get('repeats_done', 0),
            'repeat_count': bot.get('repeat_count', 0),
        })
        qty = bot.get('quantity', 1)
        anchor_depth = bot.get('anchor_depth', 5)
        try:
            api_read_limiter.wait()
            ob = kalshi_client.get_market_orderbook(ticker)
            current_dog_bid = _best_bid(ob, dog_side)
            current_dog_ask = _best_ask(ob, dog_side)
            if current_dog_bid <= 0:
                # No bids at all — market is completely dead, stop the bot
                bot['status'] = 'completed'
                bot['completed_at'] = now
                bot['repeat_count'] = 0
                print(f'🛑 PHANTOM DRIFT STOP: {bot_id} dog_bid=0 — no market, stopping')
                save_state()
                return
            # Hedge fill drift guard: at this bot's target width, would the hedge still fill?
            fav_side = bot.get('fav_side', 'no' if dog_side == 'yes' else 'yes')
            if hedge_ticker != ticker:
                api_read_limiter.wait()
                _fav_ob = kalshi_client.get_market_orderbook(hedge_ticker)
            else:
                _fav_ob = ob
            _current_fav_bid = _best_bid(_fav_ob, fav_side)
            spread = (current_dog_ask - current_dog_bid) if current_dog_ask > 0 else 1
            anchor_base = current_dog_ask if spread > 2 else current_dog_bid
            _avg_dog_est = max(1, anchor_base - anchor_depth)  # estimate new avg dog price
            _target_width = bot.get('target_width', 3)
            _hedge_price = 100 - _avg_dog_est - _target_width
            _hedge_gap = (_current_fav_bid - _hedge_price) if _current_fav_bid and _hedge_price > 0 else 99
            if _hedge_gap > 5 or current_dog_bid <= 3:
                bot_log('PHANTOM_LADDER_REPEAT_DRIFT_SKIP', bot_id, {
                    'dog_bid': current_dog_bid, 'fav_bid': _current_fav_bid,
                    'avg_dog_est': _avg_dog_est, 'target_width': _target_width,
                    'hedge_price': _hedge_price, 'hedge_gap': _hedge_gap,
                    'reason': 'hedge_unfillable' if _hedge_gap > 5 else 'dog_dead',
                })
                # Market is dead — stop the bot, don't leave it hanging
                bot['status'] = 'completed'
                bot['completed_at'] = now
                bot['repeat_count'] = 0  # cancel remaining repeats
                print(f'🛑 PHANTOM DRIFT STOP: {bot_id} dog_bid={current_dog_bid}¢ hedge_gap={_hedge_gap} — market dead, stopping')
                save_state()
                return
            # Don't repost if market is dead (bid at 1c = pointless)
            if current_dog_bid <= 1:
                bot['status'] = 'completed'
                bot['completed_at'] = now
                bot['repeat_count'] = 0
                print(f'🛑 PHANTOM REPEAT SKIP: {bot_id} dog bid={current_dog_bid}¢ — market dead, stopping')
                bot_log('PHANTOM_REPEAT_SKIP', bot_id, {'dog_bid': current_dog_bid, 'reason': 'market_dead'})
                _audit('PHANTOM_REPEAT_SKIP', bot_id, {'dog_bid': current_dog_bid})
                save_state()
                return
            # spread and anchor_base already computed above for hedge check

            # Batch-place all rungs for new cycle — depth floor anchored to rung 0
            repeat_ph_group = _create_order_group()
            repeat_specs = []
            repeat_qtys = []
            _rung_spacing = bot.get('rung_spacing', 2)
            _num_rungs = len(bot.get('rungs', []))
            _first_rung_price = max(1, anchor_base - anchor_depth)
            _lowest_rung_price = max(1, _first_rung_price - ((_num_rungs - 1) * _rung_spacing)) if _num_rungs > 0 else _first_rung_price
            if _lowest_rung_price <= 3:
                # All rungs would hit the floor — market too thin, stop
                bot['status'] = 'completed'
                bot['completed_at'] = now
                bot['repeat_count'] = 0
                print(f'🛑 PHANTOM REPEAT FLOOR: {bot_id} lowest rung={_lowest_rung_price}¢ (dog_bid={current_dog_bid}¢) — too low, stopping')
                bot_log('PHANTOM_REPEAT_SKIP_FLOOR', bot_id, {
                    'first_rung': _first_rung_price, 'lowest_rung': _lowest_rung_price,
                    'dog_bid': current_dog_bid, 'anchor_depth': anchor_depth,
                })
                save_state()
                return
            for rung in bot.get('rungs', []):
                rung_price = max(1, anchor_base - anchor_depth - (len(repeat_specs) * _rung_spacing))
                rung_qty = rung.get('qty', qty)
                repeat_specs.append({'ticker': ticker, 'side': dog_side, 'count': rung_qty, 'price': rung_price})
                repeat_qtys.append(rung_qty)

            new_rungs = []
            if repeat_specs:
                repeat_results = create_orders_batch(repeat_specs, order_group_id=repeat_ph_group)
                for j, result in enumerate(repeat_results):
                    if result is None:
                        print(f'⚠ PHANTOM REPEAT rung {j} failed (batch partial)')
                        continue
                    resp, actual = result
                    new_rungs.append({
                        'price': actual, 'qty': repeat_qtys[j],
                        'order_id': resp['order']['order_id'],
                        'fill_qty': 0, 'filled_at': None,
                    })

            if new_rungs:
                bot['rungs'] = new_rungs
                bot['total_dog_qty'] = sum(r['qty'] for r in new_rungs)
                bot['total_dog_fill_qty'] = 0
                bot['dog_fill_qty'] = 0
                bot['dog_filled_at'] = None
                bot['raw_hedge_ms'] = None
                bot['hedge_latency_ms'] = None
                bot['fav_order_id'] = None
                bot['fav_fill_qty'] = 0
                bot['fav_price'] = None
                bot['yes_fill_qty'] = 0
                bot['no_fill_qty'] = 0
                bot['_hedge_fired'] = False
                bot['_trade_recorded'] = False
                bot['_sweep_timer_started'] = False
                bot['_sellback_attempts'] = 0
                bot['fav_walk_count'] = 0
                bot['fav_last_walk_at'] = None
                bot['avg_fill_price'] = None
                bot['hedge_qty'] = None
                bot['first_fill_at'] = None  # clear stale latency from prior cycle
                bot['status'] = 'ladder_posted'
                bot['posted_at'] = now
                bot['_order_group_id'] = repeat_ph_group
                ws_rp = (ws_manager.get_price(ticker) if ws_manager else None) or {}
                bot['_bid_at_post'] = ws_rp.get(f'{dog_side}_bid', 0)
                bot['_last_repost_at'] = 0
                # Pre-calculate hedge prices + avg prices for new rung prices
                bot['_precalc_hedge_prices'], bot['_precalc_avg_prices'] = _precalc_phantom_ladder_hedges(
                    new_rungs, bot.get('target_width', 5), dog_side
                )
                rung_desc = ', '.join(f'{r["price"]}¢×{r["qty"]}' for r in new_rungs)
                print(f'🔄 PHANTOM LADDER REPEAT: {bot_id} cycle {bot.get("repeats_done",0)}/{bot.get("repeat_count",0)} — {len(new_rungs)} rungs: {rung_desc}')
                bot_log('PHANTOM_LADDER_REPEAT_POSTED', bot_id, {
                    'cycle': bot.get('repeats_done', 0), 'total_cycles': bot.get('repeat_count', 0),
                    'rungs': len(new_rungs), 'first_price': new_rungs[0]['price'] if new_rungs else 0,
                    'rung_desc': rung_desc,
                })
                _audit('LADDER_REANCHOR', bot_id, {'ticker': ticker, 'rungs': len(new_rungs), 'first_price': new_rungs[0]['price'] if new_rungs else 0, 'cycle': bot.get('repeats_done', 0)})
                _audit_position_check(bot_id, ticker, dog_side, 'after_ladder_reanchor')
                save_state()
            else:
                print(f'❌ PHANTOM REPEAT {bot_id}: no rungs placed — waiting')
                bot_log('PHANTOM_LADDER_REPEAT_NO_RUNGS', bot_id, {}, level='WARN')
        except Exception as e:
            print(f'❌ PHANTOM REPEAT {bot_id}: {e}')
            bot_log('PHANTOM_LADDER_REPEAT_ERROR', bot_id, {'error': str(e)[:300]}, level='ERROR')
        return

    # ── STATE: ladder_posted — rungs are live, watching for fills + bounce ──
    if status == 'ladder_posted':
        # Get current dog bid from WS cache or orderbook
        ws_p = (ws_manager.get_price(ticker) if ws_manager else None) or {}
        current_dog_bid = ws_p.get(f'{dog_side}_bid', 0) or 0
        if current_dog_bid <= 0:
            try:
                api_read_limiter.wait()
                ob = kalshi_client.get_market_orderbook(ticker)
                current_dog_bid = _best_bid(ob, dog_side)
            except Exception:
                current_dog_bid = 0

        # Dead market guard: bid at 1¢ OR any rung price at 1¢ = market is dead, cancel all
        _any_rung_at_floor = any(
            r.get('price', 99) <= 1 and r.get('fill_qty', 0) < r.get('qty', 1) and not r.get('cancelled')
            for r in bot.get('rungs', [])
        )
        if (current_dog_bid > 0 and current_dog_bid <= 1) or _any_rung_at_floor:
            _reason = f'rung at 1¢' if _any_rung_at_floor else f'bid at {current_dog_bid}¢'
            print(f'🛑 PHANTOM LADDER DEAD MARKET: {bot_id} {_reason} — cancelling rungs')
            bot_log('PHANTOM_LADDER_DEAD_MARKET', bot_id, {'dog_bid': current_dog_bid, 'reason': _reason})
            for rung in bot.get('rungs', []):
                oid = rung.get('order_id')
                if oid and rung.get('fill_qty', 0) < rung.get('qty', 1):
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(oid)
                        rung['cancelled'] = True
                    except Exception:
                        pass
            # If repeats remain, go to waiting_repeat — repeat handler checks conditions before posting
            _repeats_left = bot.get('repeat_count', 0) - bot.get('repeats_done', 0)
            if _repeats_left > 0:
                bot['status'] = 'waiting_repeat'
                bot['waiting_repeat_since'] = now
                # DON'T increment repeats_done — this wasn't a real run, just a bad pricing cycle
                print(f'   ⏳ Dead market but {_repeats_left} repeats left — waiting for conditions to improve')
            else:
                bot['status'] = 'completed'
                bot['completed_at'] = now
            _audit('PHANTOM_LADDER_DEAD_MARKET', bot_id, {'dog_bid': current_dog_bid, 'repeats_left': _repeats_left})
            save_state()
            return

        # Poll fill counts (backup for WS misses)
        total_fill = 0
        for rung in bot.get('rungs', []):
            if rung.get('fill_qty', 0) >= rung['qty']:
                total_fill += rung['fill_qty']
                continue
            oid = rung.get('order_id')
            if not oid:
                total_fill += rung.get('fill_qty', 0)
                continue
            try:
                api_read_limiter.wait()
                resp = kalshi_client.get_order(oid)
                ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
                filled = _parse_fill_count(ord_data)
                old_fill = rung.get('fill_qty', 0)
                rung['fill_qty'] = max(old_fill, filled)
                if filled > old_fill:
                    print(f'👻 PHANTOM FILL UPDATE: {bot_id} rung@{rung.get("price")}¢ {old_fill}→{filled}/{rung["qty"]}')
                    bot_log('PHANTOM_LADDER_FILL_UPDATE', bot_id, {
                        'rung_price': rung.get('price'), 'old_fill': old_fill,
                        'new_fill': filled, 'rung_qty': rung['qty'],
                        'order_id': oid[:12], 'path': 'monitor',
                    })
                if filled >= rung['qty'] and not rung.get('filled_at'):
                    rung['filled_at'] = now
            except Exception:
                pass
            total_fill += rung.get('fill_qty', 0)

        bot['total_dog_fill_qty'] = total_fill
        if dog_side == 'yes':
            bot['yes_fill_qty'] = total_fill
        else:
            bot['no_fill_qty'] = total_fill

        # Monitor backup: if fills detected but hedge never fired, trigger it now
        if total_fill > 0 and not bot.get('_hedge_fired') and not bot.get('fav_order_id'):
            print(f'👻 PHANTOM MONITOR HEDGE: {bot_id} {total_fill} fills detected, hedge not fired — triggering')
            bot_log('PHANTOM_LADDER_MONITOR_HEDGE_TRIGGER', bot_id, {
                'total_fill': total_fill, 'dog_side': dog_side, 'status': status,
            })
            bot['_hedge_fired'] = True
            bot['dog_filled_at'] = bot.get('dog_filled_at') or now
            _hedge_worker_queue.put((_execute_phantom_ladder_hedge, (bot_id,)))
            save_state()
            return

        # Track lowest dog bid
        if current_dog_bid > 0:
            lowest = bot.get('lowest_dog_bid_seen', 999)
            if current_dog_bid < lowest:
                bot['lowest_dog_bid_seen'] = current_dog_bid
                bot['lowest_dog_bid_at'] = now

        # ── Adaptive gap-based + timer repost for phantom ladder rungs ──
        age_min = (now - bot.get('posted_at', now)) / 60.0
        DOG_REPOST_MINUTES = REPOST_AFTER_MINUTES  # 3 min fallback

        # Gap detection from WS bid (free, no API call)
        gap_thresh, cooldown_s = _phantom_gap_threshold(bot, current_dog_bid) if current_dog_bid > 0 else (3, 15)
        bid_at_post = bot.get('_bid_at_post', 0)
        # Only repost when bid moves AWAY from dog (increases). Bid moving toward dog = good, stay put.
        gap = max(0, current_dog_bid - bid_at_post) if current_dog_bid > 0 and bid_at_post > 0 else 0
        since_last_repost = now - bot.get('_last_repost_at', 0)

        gap_triggered = gap >= gap_thresh and since_last_repost >= cooldown_s and total_fill == 0
        timer_triggered = age_min >= DOG_REPOST_MINUTES and total_fill == 0

        # Above-market check: if bid dropped BELOW first rung, rungs are taker-priced → repost down
        _first_price = bot['rungs'][0]['price'] if bot.get('rungs') else 0
        if total_fill == 0 and current_dog_bid > 0 and _first_price > 0 and _first_price >= current_dog_bid and since_last_repost >= cooldown_s:
            gap_triggered = True
            gap_thresh = 0  # force repost
            print(f'⚠ PHANTOM ABOVE MARKET: {bot_id} first_rung={_first_price}¢ >= bid={current_dog_bid}¢ — forcing repost down')
            bot_log('PHANTOM_LADDER_ABOVE_MARKET', bot_id, {
                'first_rung': _first_price, 'dog_bid': current_dog_bid,
            })

        # Retreat check: if bid crept 2¢+ toward rungs since last post, retreat to restore full depth.
        # No velocity check — real whale dumps blow past rungs in one tick (filled before retreat fires).
        retreat_triggered = False
        if total_fill == 0 and current_dog_bid > 0 and since_last_repost >= cooldown_s:
            _anchor_depth = bot.get('anchor_depth', 5)
            _first_price = bot['rungs'][0]['price'] if bot.get('rungs') else 0
            _depth_gap = current_dog_bid - _first_price if _first_price > 0 else 999
            _retreat_threshold = 2  # retreat if bid crept 2¢+ toward rungs
            if 0 <= _depth_gap and _depth_gap <= (_anchor_depth - _retreat_threshold):
                retreat_triggered = True
        # Track bid for velocity calculation next cycle
        bot['_prev_ws_bid'] = current_dog_bid
        bot['_prev_ws_bid_at'] = now

        if gap_triggered or timer_triggered or retreat_triggered:
            trigger_reason = (f'retreat depth={_depth_gap}¢<{_anchor_depth}¢' if retreat_triggered
                              else f'gap={gap}¢≥{gap_thresh}¢' if gap_triggered
                              else f'timer={age_min:.1f}m')
            anchor_depth = bot.get('anchor_depth', 5)
            try:
                api_read_limiter.wait()
                ob = kalshi_client.get_market_orderbook(ticker)
                rp_dog_bid = _best_bid(ob, dog_side)
                rp_dog_ask = _best_ask(ob, dog_side)
            except Exception:
                rp_dog_bid = 0
                rp_dog_ask = 0

            if rp_dog_bid > 0:
                # Drift guard: no longer underdog
                if rp_dog_bid > 50:
                    _ph_group = bot.get('_order_group_id')
                    if _ph_group:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order_group(_ph_group)
                        except Exception:
                            # Fallback to individual
                            for rung in bot.get('rungs', []):
                                if rung.get('order_id'):
                                    _safe_cancel(rung['order_id'], f'phantom drift {bot_id}')
                    else:
                        for rung in bot.get('rungs', []):
                            if rung.get('order_id'):
                                _safe_cancel(rung['order_id'], f'phantom drift {bot_id}')
                    bot['status'] = 'completed'
                    bot['completed_at'] = now
                    bot_log('PHANTOM_LADDER_DRIFT_CANCEL', bot_id, {
                        'dog_bid': rp_dog_bid, 'dog_side': dog_side,
                    })
                    _audit('PHANTOM_LADDER_DRIFT_CANCEL', bot_id, {'ticker': ticker, 'dog_bid': rp_dog_bid})
                    actions.append({'bot_id': bot_id, 'action': 'phantom_ladder_drift_cancel', 'dog_bid': rp_dog_bid})
                    save_state()
                    return

                # Smart pricing — depth floor anchored to rung 0 (first rung)
                spread = (rp_dog_ask - rp_dog_bid) if rp_dog_ask > 0 else 1
                anchor_base = rp_dog_ask if spread > 2 else rp_dog_bid
                _rung_spacing = bot.get('rung_spacing', 2)
                smart_first = max(1, anchor_base - anchor_depth)

                old_first_price = bot['rungs'][0]['price'] if bot.get('rungs') else 0
                _lad_price_delta = abs(smart_first - old_first_price)
                if retreat_triggered and _lad_price_delta < 2:
                    pass  # retreat jitter filter: don't waste API calls on <2¢ moves
                elif _lad_price_delta > 1 or retreat_triggered:
                    # Cancel old orders via group (1 call) or individual fallback
                    _ph_old_group = bot.get('_order_group_id')
                    if _ph_old_group:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order_group(_ph_old_group)
                        except Exception:
                            for rung in bot.get('rungs', []):
                                if rung.get('order_id') and rung.get('fill_qty', 0) < rung['qty']:
                                    _safe_cancel(rung['order_id'], f'phantom rung repost {bot_id}')
                    else:
                        for rung in bot.get('rungs', []):
                            if rung.get('order_id') and rung.get('fill_qty', 0) < rung['qty']:
                                _safe_cancel(rung['order_id'], f'phantom rung repost {bot_id}')

                    # Check if lowest rung would hit floor — skip repost entirely
                    _last_rung_idx = len(bot.get('rungs', [])) - 1
                    _lowest_new_price = max(1, smart_first - (_last_rung_idx * _rung_spacing)) if _last_rung_idx >= 0 else smart_first
                    if _lowest_new_price <= 3:
                        bot['posted_at'] = now  # reset timer, don't repost
                        bot_log('PHANTOM_LADDER_REPOST_SKIP_FLOOR', bot_id, {
                            'smart_first': smart_first, 'lowest_would_be': _lowest_new_price,
                            'spacing': _rung_spacing,
                        })
                        print(f'⛔ PHANTOM REPOST SKIP: {bot_id} lowest rung would be {_lowest_new_price}¢ — too low')
                        save_state()
                        return

                    # Batch-place new orders for unfilled rungs
                    new_ph_group = _create_order_group()
                    repost_specs = []
                    repost_indices = []
                    # Track old order IDs before overwriting — if group cancel failed, these are orphans
                    _old_rung_oids = []
                    for idx, rung in enumerate(bot.get('rungs', [])):
                        if rung.get('fill_qty', 0) >= rung['qty']:
                            continue  # filled, don't touch
                        if rung.get('order_id'):
                            _old_rung_oids.append(rung['order_id'])
                        new_price = max(1, smart_first - (idx * _rung_spacing))
                        repost_specs.append({'ticker': ticker, 'side': dog_side, 'count': rung['qty'], 'price': new_price})
                        repost_indices.append(idx)

                    if repost_specs:
                        repost_results = create_orders_batch(repost_specs, order_group_id=new_ph_group)
                        for j, ri in enumerate(repost_indices):
                            rung = bot['rungs'][ri]
                            if repost_results[j] is None:
                                rung['order_id'] = None
                                continue
                            resp, actual_price = repost_results[j]
                            rung['order_id'] = resp['order']['order_id']
                            rung['price'] = actual_price
                    # Stash old order IDs so completion/sellback can clean them up
                    _prev_oids = bot.get('_prev_rung_order_ids', [])
                    _prev_oids.extend(_old_rung_oids)
                    bot['_prev_rung_order_ids'] = _prev_oids

                    bot['_order_group_id'] = new_ph_group
                    bot['posted_at'] = now
                    bot['_bid_at_post'] = rp_dog_bid
                    bot['_last_repost_at'] = now
                    bot['dog_repost_count'] = bot.get('dog_repost_count', 0) + 1
                    # Re-precalculate hedge prices + avg prices with updated rung prices
                    bot['_precalc_hedge_prices'], bot['_precalc_avg_prices'] = _precalc_phantom_ladder_hedges(
                        bot['rungs'], bot.get('target_width', 5), dog_side
                    )
                    print(f'🔄 PHANTOM REPOST: {bot_id} {old_first_price}¢→{smart_first}¢ '
                          f'({trigger_reason} bid={rp_dog_bid}¢ ask={rp_dog_ask}¢ #{bot["dog_repost_count"]})')
                    bot_log('PHANTOM_LADDER_REPOST', bot_id, {
                        'trigger': trigger_reason, 'old_first_price': old_first_price,
                        'new_first_price': smart_first, 'dog_bid': rp_dog_bid,
                        'dog_ask': rp_dog_ask, 'spread': (rp_dog_ask - rp_dog_bid) if rp_dog_ask > 0 else 0,
                        'repost_count': bot['dog_repost_count'],
                    })
                    _audit('PHANTOM_LADDER_REPOST', bot_id, {
                        'ticker': ticker, 'old_price': old_first_price,
                        'new_price': smart_first, 'trigger': trigger_reason,
                    })
                    actions.append({'bot_id': bot_id, 'action': 'phantom_rung_repost', 'trigger': trigger_reason})
                    save_state()
                    return
                else:
                    bot['posted_at'] = now  # reset timer

        # All rungs fully filled? → hedge immediately
        if total_fill >= bot['total_dog_qty']:
            print(f'👻 PHANTOM ALL FILLED: {bot_id} {total_fill}/{bot["total_dog_qty"]} — hedging')
            bot_log('PHANTOM_LADDER_ALL_FILLED', bot_id, {
                'total_fill': total_fill, 'total_dog_qty': bot['total_dog_qty'],
                'path': 'monitor',
            })
            _audit('PHANTOM_LADDER_ALL_FILLED', bot_id, {'ticker': ticker, 'total_fill': total_fill})
            bot['dog_filled_at'] = now
            threading.Thread(target=_execute_phantom_ladder_hedge, args=(bot_id,), daemon=True).start()
            return

        # Any fill at all? Hedge instantly (backup for WS miss)
        # WS handler normally catches this first, but monitor is the safety net
        if total_fill > 0 and not bot.get('_sweep_timer_started'):
            print(f'👻 MONITOR PHANTOM FILL: {bot_id} detected {total_fill} fills WS missed — hedging instantly')
            bot_log('PHANTOM_LADDER_MONITOR_FILL_DETECTED', bot_id, {
                'total_fill': total_fill, 'total_dog_qty': bot.get('total_dog_qty'),
                'path': 'monitor_safety_net',
            })
            bot['_sweep_timer_started'] = True
            bot['dog_filled_at'] = now
            threading.Thread(target=_execute_phantom_ladder_hedge, args=(bot_id,), daemon=True).start()
            return

        save_state()
        return

    # ── STATE: ladder_filled_no_fav — retry hedge with timeout ──
    if status == 'ladder_filled_no_fav':
        # Set dog_filled_at if missing (recovery)
        if not bot.get('dog_filled_at'):
            bot['dog_filled_at'] = bot.get('first_fill_at') or now
        dog_filled_at = bot['dog_filled_at']
        hedge_timeout_s = bot.get('hedge_timeout_s', 120)
        wait_s = now - dog_filled_at
        if wait_s >= hedge_timeout_s:
            avg_dog = bot.get('avg_fill_price', 0)
            # Check if market is dead (settled/closed) — don't retry sells on dead markets
            try:
                _mkt_check = kalshi_client.get_market(ticker)
                _mkt_data = _mkt_check.get('market', _mkt_check)
                _mkt_status = _mkt_data.get('status', '')
                if _mkt_status not in ('active', 'open', ''):
                    print(f'⏰ PHANTOM MARKET SETTLED: {bot_id} market={_mkt_status} — waiting for auto-settlement (no sell needed)')
                    bot_log('PHANTOM_LADDER_MARKET_SETTLED_TIMEOUT', bot_id, {
                        'market_status': _mkt_status, 'wait_s': round(wait_s, 1),
                    })
                    bot['status'] = 'completed'
                    bot['completed_at'] = now
                    bot['result'] = 'market_settled_with_position'
                    save_state()
                    actions.append({'bot_id': bot_id, 'action': 'phantom_market_settled'})
                    return
            except Exception:
                pass
            print(f'⏰ PHANTOM NO-FAV TIMEOUT: {bot_id} waited {wait_s:.0f}s for fav bid — selling back')
            bot_log('PHANTOM_LADDER_NO_FAV_TIMEOUT', bot_id, {
                'wait_s': round(wait_s, 1), 'hedge_timeout_s': hedge_timeout_s,
                'avg_dog': avg_dog, 'total_fill_qty': bot.get('total_dog_fill_qty', 0),
            })
            _phantom_ladder_sell_back(bot_id, bot, avg_dog, 0, 999, actions)
            return
        # Ceiling flag: hedge thread found combined >= 98¢ — sell back immediately
        if bot.get('_ceiling_sellback'):
            del bot['_ceiling_sellback']
            avg_dog = bot.get('avg_fill_price', 0)
            print(f'🚫 PHANTOM LADDER CEILING: {bot_id} hedge at ceiling — selling back')
            bot_log('PHANTOM_LADDER_CEILING_NO_HEDGE', bot_id, {
                'avg_dog': avg_dog, 'wait_s': round(wait_s, 1),
            })
            _phantom_ladder_sell_back(bot_id, bot, avg_dog, 0, 999, actions)
            return
        if not bot.get('_hedge_thread_active'):
            bot_log('PHANTOM_LADDER_NO_FAV_RETRY', bot_id, {
                'wait_s': round(wait_s, 1), 'hedge_timeout_s': hedge_timeout_s,
            })
            bot['_hedge_thread_active'] = True
            threading.Thread(target=_execute_phantom_ladder_hedge, args=(bot_id,), daemon=True).start()
        return

    # ── STATE: fav_hedge_posted — waiting for fav fill ──
    if status == 'fav_hedge_posted':
        fav_order_id = bot.get('fav_order_id')
        if not fav_order_id:
            bot_log('PHANTOM_LADDER_NO_FAV_ORDER', bot_id, {'status': status}, level='WARN')
            return
        hedge_qty = bot.get('hedge_qty', bot.get('total_dog_fill_qty', 1))

        api_read_limiter.wait()
        fav_resp = kalshi_client.get_order(fav_order_id)
        fav_ord = fav_resp.get('order', fav_resp) if isinstance(fav_resp, dict) else {}
        fav_filled = _parse_fill_count(fav_ord)
        bot['fav_fill_qty'] = fav_filled
        if fav_side == 'yes':
            bot['yes_fill_qty'] = fav_filled
        else:
            bot['no_fill_qty'] = fav_filled

        # ── Verify actual rung fills before completion (catches WS-missed fills) ──
        if now - bot.get('_last_rung_verify', 0) >= 30:
            bot['_last_rung_verify'] = now
            try:
                verified_total = 0
                for rung in bot.get('rungs', []):
                    oid = rung.get('order_id')
                    if not oid:
                        verified_total += rung.get('fill_qty', 0)
                        continue
                    try:
                        resp_v = kalshi_client.get_order(oid)
                        ord_v = resp_v.get('order', resp_v) if isinstance(resp_v, dict) else {}
                        actual_v = _parse_fill_count(ord_v)
                        if actual_v > rung.get('fill_qty', 0):
                            print(f'⚠ PHANTOM RUNG VERIFY: {bot_id} rung @{rung.get("price")}¢ local={rung.get("fill_qty",0)} Kalshi={actual_v} — updating')
                            bot_log('PHANTOM_LADDER_RUNG_VERIFY_UPDATE', bot_id, {
                                'rung_price': rung.get('price'), 'local_fill': rung.get('fill_qty', 0),
                                'kalshi_fill': actual_v, 'order_id': oid[:12],
                            })
                            rung['fill_qty'] = actual_v
                        verified_total += max(actual_v, rung.get('fill_qty', 0))
                    except Exception:
                        verified_total += rung.get('fill_qty', 0)
                if verified_total > hedge_qty:
                    # More fills than hedged — amend price, sell back stragglers
                    _mon_extra = verified_total - hedge_qty
                    new_avg = round(sum(r['price'] * r.get('fill_qty', 0) for r in bot['rungs'] if r.get('fill_qty', 0) > 0) / verified_total) if verified_total > 0 else bot.get('avg_fill_price', 0)
                    old_avg = bot.get('avg_fill_price', new_avg)
                    bot['avg_fill_price'] = new_avg
                    target_w = bot.get('target_width', 5)
                    amend_p = max(1, 100 - new_avg - target_w)
                    old_tgt = max(1, 100 - old_avg - target_w)
                    w_off = max(0, bot.get('fav_price', amend_p) - old_tgt)
                    amend_p = max(1, amend_p + w_off)
                    try:
                        # Amend price only (Kalshi can't increase count)
                        amend_kw = {f'{fav_side}_price': amend_p}
                        api_rate_limiter.wait()
                        kalshi_client.amend_order(fav_order_id, ticker=hedge_ticker, side=fav_side, count=hedge_qty, **amend_kw)
                        bot['fav_price'] = amend_p
                        # Sell back stragglers — hedge window is closed
                        if _mon_extra > 0:
                            dog_side = bot.get('dog_side', 'yes')
                            print(f'🔙 PHANTOM MONITOR STRAGGLER: {bot_id} {_mon_extra} late fills — selling back')
                            bot_log('PHANTOM_MONITOR_STRAGGLER_SELLBACK', bot_id, {
                                'extra_qty': _mon_extra, 'dog_side': dog_side,
                                'hedge_qty': hedge_qty, 'verified_total': verified_total,
                            })
                            try:
                                _sold, _sell_info = execute_sell(bot.get('ticker',''), dog_side, _mon_extra,
                                                                reason=f'phantom_monitor_straggler_{bot_id}')
                                _sell_p = (_sell_info or {}).get('avg_price', 0) if isinstance(_sell_info, dict) else 0
                                _strag_loss = max(0, new_avg - _sell_p) * _mon_extra if _sell_p else new_avg * _mon_extra
                                session_pnl['gross_loss_cents'] += _strag_loss
                                print(f'🔙 PHANTOM MONITOR STRAGGLER SOLD: {bot_id} {_mon_extra}× @ {_sell_p}¢ loss={_strag_loss}¢')
                            except Exception as _mse:
                                print(f'⚠ PHANTOM MONITOR STRAGGLER FAIL: {bot_id}: {_mse}')
                        print(f'📈 PHANTOM LATE FILL AMEND: {bot_id} hedge_qty={hedge_qty} verified={verified_total} avg={new_avg}¢ hedge@{amend_p}¢ stragglers={_mon_extra}')
                        bot_log('PHANTOM_LADDER_MONITOR_LATE_FILL_AMEND', bot_id, {
                            'verified_total': verified_total, 'new_avg': new_avg,
                            'amend_price': amend_p, 'walk_offset': w_off,
                        })
                    except Exception as ae:
                        print(f'⚠ PHANTOM LATE FILL AMEND FAIL: {bot_id}: {ae}')
                        bot_log('PHANTOM_LADDER_MONITOR_LATE_FILL_AMEND_FAIL', bot_id, {
                            'error': str(ae)[:300], 'verified_total': verified_total,
                        }, level='ERROR')
            except Exception as rv_err:
                print(f'⚠ PHANTOM RUNG VERIFY FAIL: {bot_id}: {rv_err}')
                bot_log('PHANTOM_LADDER_RUNG_VERIFY_ERROR', bot_id, {'error': str(rv_err)[:300]}, level='ERROR')

        if fav_filled >= hedge_qty:
            print(f'👻 PHANTOM COMPLETE: {bot_id} fav filled {fav_filled}/{hedge_qty}')
            bot_log('PHANTOM_LADDER_FAV_FILLED', bot_id, {
                'fav_filled': fav_filled, 'hedge_qty': hedge_qty,
                'fav_order_id': fav_order_id[:12], 'fav_side': fav_side,
            })
            # Guard: if _trade_recorded is already True but status never changed (crash recovery),
            # re-run the completion so the trade actually gets recorded in history
            if bot.get('_trade_recorded') and bot.get('status') != 'completed':
                print(f'🔄 PHANTOM RECOVERY: {bot_id} _trade_recorded=True but status={bot.get("status")} — re-running completion')
                bot_log('PHANTOM_LADDER_RECOVERY_TRADE_RERUN', bot_id, {
                    '_trade_recorded': True, 'status': bot.get('status'),
                })
                bot['_trade_recorded'] = False  # clear so completion path runs fully

            # COMPLETE — calculate P&L
            actual_fav_price = get_actual_fill_price(fav_order_id, fav_side) or bot['fav_price']
            bot['fav_price'] = actual_fav_price
            avg_dog = bot.get('avg_fill_price', 0)
            if fav_side == 'yes':
                yes_p, no_p = actual_fav_price, avg_dog
            else:
                yes_p, no_p = avg_dog, actual_fav_price
            bot['yes_price'] = yes_p
            bot['no_price'] = no_p

            pnl_cents = (100 - yes_p - no_p) * hedge_qty
            fee = sum(
                kalshi_fee_cents(
                    r['price'] if dog_side == 'yes' else actual_fav_price,
                    r['price'] if dog_side == 'no' else actual_fav_price,
                    r.get('fill_qty', 0)
                ) for r in bot['rungs'] if r.get('fill_qty', 0) > 0
            )
            net_pnl = pnl_cents - fee

            filled_rung_count = len([r for r in bot['rungs'] if r.get('fill_qty', 0) > 0])
            filled_rungs_detail = [
                {'price': r['price'], 'qty': r.get('fill_qty', 0)}
                for r in bot['rungs'] if r.get('fill_qty', 0) > 0
            ]
            # Compute hedge speed BEFORE recording trade so it's included
            dog_fill_at = bot.get('dog_filled_at') or bot.get('first_fill_at')
            if dog_fill_at and not bot.get('hedge_fill_latency_ms'):
                bot['hedge_fill_latency_ms'] = round((now - dog_fill_at) * 1000, 1)
            _record_trade({
                'bot_id': bot_id, 'ticker': ticker,
                'yes_price': yes_p, 'no_price': no_p,
                'quantity': hedge_qty,
                'profit_cents': net_pnl if net_pnl >= 0 else 0,
                'loss_cents': abs(net_pnl) if net_pnl < 0 else 0,
                'fee_cents': fee,
                'result': 'completed' if net_pnl >= 0 else 'arb_loss',
                'exit_via': 'anchor_ladder_complete',
                'first_leg': dog_side,
                'dog_side': dog_side,
                'dog_price': avg_dog,
                'fav_price': actual_fav_price,
                'avg_dog_price': avg_dog,
                'hedge_latency_ms': bot.get('hedge_latency_ms'),
                'hedge_fill_latency_ms': bot.get('hedge_fill_latency_ms'),
                'raw_hedge_ms': bot.get('raw_hedge_ms'),
                'rungs_filled': filled_rung_count,
                'rungs_total': len(bot['rungs']),
                'rungs_detail': filled_rungs_detail,
                'bounce_detected': bot.get('bounce_detected_at') is not None,
                'timestamp': now,
                'placed_at': bot.get('created_at', now),
                'arb_width': bot.get('target_width', 0),
                'game_phase': bot.get('game_phase', 'live'),
                'game_context': _get_game_context(ticker),
                'fill_source': 'anchor_ladder',
                'bot_category': 'anchor_ladder',
                'cross_market': bot.get('cross_market', False),
                'hedge_ticker': bot.get('hedge_ticker', ''),
            }, bot)

            # Only update session P&L and mark recorded AFTER successful trade record
            if net_pnl >= 0:
                session_pnl['gross_profit_cents'] += net_pnl
            else:
                session_pnl['gross_loss_cents'] += abs(net_pnl)
            session_pnl['completed_bots'] += 1
            bot['_trade_recorded'] = True
            print(f'👻 PHANTOM P&L: {bot_id} pnl={net_pnl}¢ (yes={yes_p}¢ no={no_p}¢ qty={hedge_qty} fee={fee}¢) hedge_fill={bot.get("hedge_fill_latency_ms", "?")}ms session_profit={session_pnl["gross_profit_cents"]}¢ session_loss={session_pnl["gross_loss_cents"]}¢')
            bot_log('PHANTOM_LADDER_COMPLETE', bot_id, {
                'net_pnl': net_pnl, 'yes_price': yes_p, 'no_price': no_p,
                'hedge_qty': hedge_qty, 'fee': fee, 'avg_dog': avg_dog,
                'actual_fav_price': actual_fav_price,
                'hedge_fill_latency_ms': bot.get('hedge_fill_latency_ms'),
                'raw_hedge_ms': bot.get('raw_hedge_ms'),
                'rungs_filled': filled_rung_count, 'rungs_total': len(bot['rungs']),
            })
            _audit('LADDER_COMPLETE', bot_id, {'ticker': ticker, 'hedge_qty': hedge_qty, 'yes_price': yes_p, 'no_price': no_p, 'pnl': net_pnl})
            _audit_position_check(bot_id, ticker, dog_side, 'after_ladder_complete')

            # Verify no leftover positions from missed WS fills
            _is_cross_market = bot.get('hedge_ticker') and bot.get('hedge_ticker') != ticker
            try:
                api_read_limiter.wait()
                _pos_resp = kalshi_client.get_positions(ticker=ticker)
                _positions = _pos_resp.get('market_positions', _pos_resp.get('positions', []))
                _actual_pos = 0
                for _p in _positions:
                    if _p.get('ticker') == ticker:
                        _actual_pos = abs(_parse_position_qty(_p))
                # Cross-market: anchor position is expected (held until settlement).
                # Only sell contracts ABOVE the hedged qty (true late fills).
                if _is_cross_market:
                    _expected = hedge_qty  # anchor contracts that are part of the arb
                    _leftover = max(0, _actual_pos - _expected)
                else:
                    # Same-ticker: YES+NO net to 0, any position is leftover
                    _leftover = _actual_pos
                if _leftover > 0:
                    _sold, _sell_info = execute_sell(ticker, dog_side, _leftover,
                                                     reason=f'phantom_extra_{bot_id}')
                    _sell_price = _sell_info.get('avg_price', 0) if isinstance(_sell_info, dict) else 0
                    _extra_pnl = (_sell_price - avg_dog) * _leftover
                    bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + _extra_pnl
                    if _extra_pnl >= 0:
                        session_pnl['gross_profit_cents'] += _extra_pnl
                    else:
                        session_pnl['gross_loss_cents'] += abs(_extra_pnl)
                    print(f'👻 PHANTOM EXTRA SELLBACK: {bot_id} {_leftover} leftover contracts sold @{_sell_price}¢ pnl={_extra_pnl}¢')
                    bot_log('PHANTOM_LADDER_EXTRA_SELLBACK', bot_id, {
                        'leftover': _leftover, 'sell_price': _sell_price,
                        'extra_pnl': _extra_pnl, 'combined_pnl': bot.get('net_pnl_cents', 0),
                        'cross_market': _is_cross_market, 'expected_anchor': _expected if _is_cross_market else 0,
                    })
                elif _is_cross_market and _actual_pos == _expected:
                    print(f'✅ PHANTOM CROSS-MARKET: {bot_id} anchor position {_actual_pos} held for settlement (hedge on {bot.get("hedge_ticker")})')
            except Exception as _pe:
                print(f'⚠ PHANTOM EXTRA CHECK FAIL: {bot_id}: {_pe}')
                bot_log('PHANTOM_LADDER_EXTRA_CHECK_FAIL', bot_id, {'error': str(_pe)[:300]}, level='ERROR')

            # Repeat logic — re-anchor if repeats remain
            repeats_done_now = bot.get('repeats_done', 0) + 1
            bot['repeats_done'] = repeats_done_now
            repeat_total = bot.get('repeat_count', 0)
            if repeats_done_now <= repeat_total:
                bot['status'] = 'waiting_repeat'
                bot['waiting_repeat_since'] = time.time() + 3  # 3s linger to show completion
                bot['_just_completed'] = True
                bot['_last_pnl'] = net_pnl
                bot['_last_result'] = 'win' if net_pnl >= 0 else 'loss'
                bot['lifetime_pnl'] = bot.get('lifetime_pnl', 0) + net_pnl
                bot['dog_filled_at'] = None
                bot['raw_hedge_ms'] = None
                bot['hedge_latency_ms'] = None
                bot['fav_order_id'] = None
                bot['fav_fill_qty'] = 0
                bot['total_dog_fill_qty'] = 0
                bot['_hedge_fired'] = False
                bot['_trade_recorded'] = False
                for rung in bot.get('rungs', []):
                    rung['fill_qty'] = 0
                    rung['order_id'] = None
                print(f'👻 PHANTOM REPEAT: {bot_id} cycle {repeats_done_now}/{repeat_total} pnl={net_pnl}¢ — resetting for re-anchor')
                bot_log('PHANTOM_LADDER_ENTER_REPEAT', bot_id, {
                    'cycle': repeats_done_now, 'total': repeat_total, 'net_pnl': net_pnl,
                })
                _audit('LADDER_REPEAT_ENTER', bot_id, {'ticker': ticker, 'cycle': repeats_done_now, 'total': repeat_total})
                _audit_position_check(bot_id, ticker, dog_side, 'entering_ladder_repeat')
            else:
                _is_cross = bot.get('hedge_ticker') and bot.get('hedge_ticker') != ticker
                if _is_cross:
                    bot['status'] = 'awaiting_settlement'
                    bot['awaiting_since'] = now
                    print(f'⏳ PHANTOM AWAITING SETTLEMENT: {bot_id} holding {ticker} + {bot["hedge_ticker"]}')
                    bot_log('PHANTOM_LADDER_AWAITING_SETTLEMENT', bot_id, {
                        'ticker': ticker, 'hedge_ticker': bot['hedge_ticker'],
                        'qty': hedge_qty, 'pnl': net_pnl,
                    })
                else:
                    bot['status'] = 'completed'
                    bot['completed_at'] = now
                    bot['_just_completed'] = True
                    bot['_last_pnl'] = net_pnl
                    bot['lifetime_pnl'] = bot.get('lifetime_pnl', 0) + net_pnl
                    print(f'👻 PHANTOM COMPLETED: {bot_id} — all cycles done pnl={net_pnl}¢')
            save_state()
            actions.append({'bot_id': bot_id, 'action': 'ladder_complete', 'profit_cents': net_pnl})
            return

        # ── Fav Walk-Up (same system as anchor_dog) ──
        hedge_timeout_s = bot.get('hedge_timeout_s', 120)
        fav_posted_at = bot.get('fav_posted_at') or bot.get('dog_filled_at') or now
        wait_s = now - fav_posted_at
        avg_dog = bot.get('avg_fill_price', 0)

        # Halftime pause
        if _is_halftime(ticker):
            bot['fav_posted_at'] = now
            bot['fav_last_walk_at'] = now
            actions.append({'bot_id': bot_id, 'action': 'ladder_fav_halftime_pause'})
            return

        # Absolute timeout — only if hedge is at/near bid (let snap catch up first)
        _lad_fav = bot.get('fav_price', 0)
        _lad_bid = bot.get(f'live_{fav_side}_bid', 0)
        _lad_at_bid = _lad_fav >= _lad_bid - 1 if _lad_bid > 0 and _lad_fav > 0 else True
        if wait_s >= hedge_timeout_s and _lad_at_bid:
            # Check for partial fav fills before selling back
            _partial_fav = bot.get('fav_fill_qty', 0)
            if _partial_fav > 0 and _partial_fav < hedge_qty:
                # Partial hedge filled — record profit for completed portion, sell back rest
                print(f'⏰ PHANTOM TIMEOUT: {bot_id} partial fav fill {_partial_fav}/{hedge_qty} — completing partial, selling back rest')
                fav_price = bot.get('fav_price', 0)
                _partial_profit_per = 100 - avg_dog - fav_price
                _partial_fee = kalshi_fee_cents(
                    avg_dog if dog_side == 'yes' else fav_price,
                    avg_dog if dog_side == 'no' else fav_price,
                    _partial_fav
                )
                _partial_net = max(0, _partial_profit_per * _partial_fav - _partial_fee)
                session_pnl['gross_profit_cents'] += _partial_net
                bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + _partial_net
                _record_trade({
                    'bot_id': bot_id, 'ticker': ticker,
                    'yes_price': avg_dog if dog_side == 'yes' else fav_price,
                    'no_price': avg_dog if dog_side == 'no' else fav_price,
                    'quantity': _partial_fav, 'profit_cents': _partial_net, 'loss_cents': 0,
                    'fee_cents': _partial_fee, 'result': 'partial_arb',
                    'exit_via': 'ladder_partial_timeout',
                    'timestamp': now, 'placed_at': bot.get('created_at', now),
                    'arb_width': bot.get('target_width', 0),
                    'fill_source': 'anchor_ladder', 'bot_category': 'anchor_ladder',
                }, bot)
                bot_log('PHANTOM_LADDER_FAV_TIMEOUT_PARTIAL', bot_id, {
                    'wait_s': round(wait_s, 1), 'fav_filled': _partial_fav,
                    'hedge_qty': hedge_qty, 'unhedged': hedge_qty - _partial_fav,
                    'partial_net': _partial_net,
                })
                # Adjust hedge_qty so sell-back only sells the unhedged portion
                bot['hedge_qty'] = hedge_qty - _partial_fav
                bot['_partial_fav_completed'] = _partial_fav
            else:
                print(f'⏰ PHANTOM TIMEOUT: {bot_id} waited {wait_s:.0f}s — selling back')
            bot_log('PHANTOM_LADDER_FAV_TIMEOUT', bot_id, {
                'wait_s': round(wait_s, 1), 'hedge_timeout_s': hedge_timeout_s,
                'avg_dog': avg_dog, 'fav_price': bot.get('fav_price', 0),
                'fav_filled': fav_filled, 'hedge_qty': bot.get('hedge_qty', hedge_qty),
            })
            try:
                api_rate_limiter.wait()
                kalshi_client.cancel_order(fav_order_id)
            except Exception:
                pass
            _phantom_ladder_sell_back(bot_id, bot, avg_dog, bot.get('fav_price', 0), 999, actions)
            return

        # ── Phantom Ladder Bid-Follow System ──
        WALK_CEILING = bot.get('fav_walk_ceiling', HARD_CEILING_CENTS)
        current_fav_price = bot.get('fav_price', 0)
        if current_fav_price <= 0:
            return

        try:
            api_read_limiter.wait()
            ob = kalshi_client.get_market_orderbook(hedge_ticker)
            current_fav_bid = _best_bid(ob, fav_side)
            current_fav_ask = _best_ask(ob, fav_side)
        except Exception:
            current_fav_bid = 0
            current_fav_ask = 0

        if current_fav_bid <= 0:
            return

        bot['_no_fav_bid_count'] = 0

        # Walk target: always bid, capped at ceiling
        max_fav = WALK_CEILING - avg_dog
        walk_target = min(current_fav_bid, max_fav)

        if walk_target <= 0:
            return

        # ── Ceiling exit: bid above max and we're already at max ──
        if current_fav_bid > max_fav and current_fav_price >= max_fav:
            try:
                api_rate_limiter.wait()
                kalshi_client.cancel_order(fav_order_id)
            except Exception:
                pass
            _over = avg_dog + current_fav_bid
            print(f'🚫 PHANTOM LADDER CEILING EXIT: {bot_id} bid={current_fav_bid}¢ > max={max_fav}¢ combined_at_bid={_over}¢ — selling back')
            bot_log('PHANTOM_LADDER_CEILING_EXIT', bot_id, {
                'avg_dog': avg_dog, 'fav_bid': current_fav_bid,
                'fav_price': current_fav_price, 'max_fav': max_fav,
                'combined_at_bid': _over, 'ceiling': WALK_CEILING,
            })
            _phantom_ladder_sell_back(bot_id, bot, avg_dog, current_fav_price, 999, actions)
            return

        # ── Bid-follow: snap to bid every cycle ──
        new_fav_price = walk_target
        if new_fav_price == current_fav_price:
            return

        walk_type = 'snap_to_bid'
        combined = avg_dog + new_fav_price
        if combined > WALK_CEILING:
            return

        try:
            _phantom_drop_lock.acquire()
            try:
                fav_order_id = bot.get('fav_order_id', fav_order_id)
                amend_kwargs = {'yes_price': new_fav_price} if fav_side == 'yes' else {'no_price': new_fav_price}
                api_rate_limiter.wait()
                kalshi_client.amend_order(fav_order_id, ticker=hedge_ticker, side=fav_side, count=hedge_qty, **amend_kwargs)
            finally:
                _phantom_drop_lock.release()
            walk_count = bot.get('fav_walk_count', 0) + 1
            direction = '↓' if new_fav_price < current_fav_price else '↑'
            print(f'📈 PHANTOM {walk_type.upper()}: {bot_id} fav {current_fav_price}¢{direction}{new_fav_price}¢ '
                  f'(bid={current_fav_bid}¢ combined={combined}¢ ceiling={WALK_CEILING}¢ step #{walk_count})')
            bot_log('PHANTOM_LADDER_WALK_SUCCESS', bot_id, {
                'walk_type': walk_type, 'old_price': current_fav_price,
                'new_price': new_fav_price, 'fav_bid': current_fav_bid,
                'avg_dog': avg_dog, 'combined': combined,
                'ceiling': WALK_CEILING, 'walk_count': walk_count,
                'wait_s': round(wait_s, 1),
            })
            bot['fav_price'] = new_fav_price
            bot['fav_walk_count'] = walk_count
            bot['fav_last_walk_at'] = now
            if fav_side == 'yes':
                bot['yes_price'] = new_fav_price
            else:
                bot['no_price'] = new_fav_price
            save_state()
        except Exception as e:
            err_str = str(e)
            print(f'❌ PHANTOM {bot_id}: fav {walk_type} failed: {e}')
            bot_log('PHANTOM_LADDER_WALK_ERROR', bot_id, {
                'walk_type': walk_type, 'error': err_str[:300],
                'old_price': current_fav_price, 'target_price': new_fav_price,
                'fav_order_id': fav_order_id[:12],
            }, level='ERROR')
            bot['fav_last_walk_at'] = now
            # 404 = fav order no longer exists on Kalshi — check if it was filled
            if '404' in err_str:
                try:
                    api_read_limiter.wait()
                    _fav_resp = kalshi_client.get_order(fav_order_id)
                    _fav_data = _fav_resp.get('order', _fav_resp) if isinstance(_fav_resp, dict) else {}
                    _fav_fills = _parse_fill_count(_fav_data)
                    _fav_status = _fav_data.get('status', '')
                    print(f'   🔍 PHANTOM LADDER FAV ORDER CHECK: {bot_id} status={_fav_status} fills={_fav_fills}/{hedge_qty}')
                    bot_log('PHANTOM_LADDER_FAV_404_CHECK', bot_id, {
                        'fav_order_id': fav_order_id[:12], 'kalshi_status': _fav_status,
                        'kalshi_fills': _fav_fills, 'expected_qty': hedge_qty,
                    })
                    if _fav_fills >= hedge_qty:
                        print(f'   ✅ PHANTOM LADDER FAV FILLED (404 recovery): {bot_id} {_fav_fills}/{hedge_qty}')
                        bot[f'{fav_side}_fill_qty'] = _fav_fills
                        bot['fav_fill_qty'] = _fav_fills
                    elif _fav_fills > 0:
                        print(f'   ⚠ PHANTOM LADDER FAV PARTIAL (404 recovery): {bot_id} {_fav_fills}/{hedge_qty}')
                        bot[f'{fav_side}_fill_qty'] = _fav_fills
                        bot['fav_fill_qty'] = _fav_fills
                    else:
                        print(f'   🔙 PHANTOM LADDER FAV GONE (404 recovery): {bot_id} — triggering sellback')
                        bot['fav_order_id'] = None
                        bot['status'] = 'ladder_filled_no_fav'
                except Exception as _check_err:
                    if '404' in str(_check_err):
                        print(f'   🔙 PHANTOM LADDER FAV GONE 404 (recovery): {bot_id} — triggering sellback')
                        bot['fav_order_id'] = None
                        bot['status'] = 'ladder_filled_no_fav'
        return


def _handle_apex(bot_id, bot, actions):
    """Handle all states for a ladder-arb bot in the monitor loop."""
    now = time.time()
    ticker = bot['ticker']
    status = bot['status']
    qty_per = bot.get('quantity', 1)
    phase = bot.get('game_phase', 'pregame')

    # ── State validation: recover from half-updated state after prior exceptions ──
    if bot.get('_consolidated') and not bot.get('hedge_order_id') and status in ('ladder_arb_yes_filled', 'ladder_arb_no_filled'):
        # Consolidation flagged but hedge never posted — reset so we retry
        print(f'🔧 APEX RECOVERY: {bot_id} _consolidated but no hedge_order_id — resetting')
        bot['_consolidated'] = False

    # Update live bid/ask from WS cache
    try:
        ws_p = ws_manager.get_price(ticker) if ws_manager else None
        if ws_p:
            bot['live_yes_bid'] = ws_p.get('yes_bid', 0)
            bot['live_no_bid'] = ws_p.get('no_bid', 0)
            bot['live_yes_ask'] = ws_p.get('yes_ask', 0)
            bot['live_no_ask'] = ws_p.get('no_ask', 0)
            _record_price_for_velocity(ticker, ws_p.get('yes_bid', 0), ws_p.get('no_bid', 0))
    except Exception:
        pass

    yes_bid = bot.get('live_yes_bid', 0)
    no_bid = bot.get('live_no_bid', 0)
    total_expected = sum(r.get('quantity', qty_per) for r in bot.get('rungs', []))

    # ── Settlement guard: if market is closed/settled, cancel everything (every 30s) ──
    if now - bot.get('_last_settle_check', 0) >= 30:
        bot['_last_settle_check'] = now
        try:
            api_read_limiter.wait()
            mkt_la = kalshi_client.get_market(ticker)
            mkt_la_data = mkt_la.get('market', mkt_la) if isinstance(mkt_la, dict) else {}
            mkt_la_status = mkt_la_data.get('status', 'active')
            mkt_la_result = mkt_la_data.get('result', '')
            if mkt_la_status not in ('active', 'open') or mkt_la_result:
                for rung in bot.get('rungs', []):
                    for side in ('yes', 'no'):
                        oid = rung.get(f'{side}_order_id')
                        if oid:
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(oid)
                            except Exception:
                                pass
                # Also cancel hedge orders (bot-level + history)
                settle_cancel_ids = set()
                if bot.get('hedge_order_id'):
                    settle_cancel_ids.add(bot['hedge_order_id'])
                for oid in bot.get('_all_hedge_order_ids', []):
                    settle_cancel_ids.add(oid)
                for hg in bot.get('hedge_history', []):
                    if hg.get('order_id'):
                        settle_cancel_ids.add(hg['order_id'])
                    for oid in hg.get('order_ids', []):
                        settle_cancel_ids.add(oid)
                for oid in settle_cancel_ids:
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(oid)
                    except Exception:
                        pass
                bot['status'] = 'completed'
                bot['completed_at'] = now
                actions.append({'bot_id': bot_id, 'action': 'ladder_arb_settled', 'result': mkt_la_result})
                print(f'🏁 APEX SETTLED: {bot_id} market={mkt_la_status} result={mkt_la_result}')
                _audit('APEX_SETTLED', bot_id, {'ticker': ticker, 'market_status': mkt_la_status, 'result': mkt_la_result})
                save_state()
                return
        except Exception as e:
            print(f'⚠ ladder_arb settlement check {bot_id}: {e}')

    # ── STATE: apex_selling_back — maker sell order posted, walk price down toward bid ──
    if status == 'apex_selling_back':
        # ── GUARD: Check if hedge actually filled while we were selling back ──
        # If all hedges filled, the arb completed — cancel sell-back and complete
        # Check multiple fill sources since _hedge_fill_count may be stale in sell-back state
        _filled_side = bot.get('first_fill_side', 'yes')
        _hedge_side = 'no' if _filled_side == 'yes' else 'yes'
        _hedge_fill_count = max(
            bot.get('_hedge_fill_count', 0),
            bot.get(f'filled_{_hedge_side}_qty', 0),
            sum(r.get(f'{_hedge_side}_fill_qty', 0) for r in bot.get('rungs', []))
        )
        _hedge_qty = bot.get('hedge_qty', 1)
        if _hedge_fill_count >= _hedge_qty:
            print(f'✅ APEX SELLBACK ABORT: {bot_id} hedge fully filled ({_hedge_fill_count}/{_hedge_qty}) — completing arb instead')
            bot_log('APEX_SELLBACK_ABORT_HEDGE_FILLED', bot_id, {
                'hedge_fill_count': _hedge_fill_count, 'hedge_qty': _hedge_qty,
            })
            # Cancel the sell-back order
            _sb_oid = bot.get('_sellback_order_id')
            if _sb_oid:
                try:
                    api_rate_limiter.wait()
                    kalshi_client.cancel_order(_sb_oid)
                except Exception:
                    pass
            bot['_sellback_order_id'] = None
            bot['status'] = bot.get('_pre_sellback_status', 'ladder_arb_yes_filled')
            threading.Thread(target=_execute_apex_completion, args=(bot_id,), daemon=True).start()
            return

        sell_oid = bot.get('_sellback_order_id')
        sell_price = bot.get('_sellback_price', 0)
        sell_qty = bot.get('_sellback_qty', 1)
        sell_started = bot.get('_sellback_started_at', now)
        anchor_side = bot.get('first_fill_side', 'yes')
        sell_wait_s = now - sell_started

        # Check if sell order filled or cancelled
        if sell_oid:
            try:
                api_read_limiter.wait()
                sell_resp = kalshi_client.get_order(sell_oid)
                sell_ord = sell_resp.get('order', sell_resp) if isinstance(sell_resp, dict) else {}
                sell_filled = _parse_fill_count(sell_ord)
                sell_status = sell_ord.get('status', '')
                bot['_sellback_fill_qty'] = sell_filled
                if sell_filled >= sell_qty:
                    # Fully filled — record completion
                    actual_sell_price = sell_ord.get(f'{anchor_side}_price', sell_price)
                    print(f'🔙 APEX SELLBACK FILLED: {bot_id} {sell_filled}/{sell_qty} @{actual_sell_price}¢')
                    _apex_sellback_complete(bot_id, bot, actual_sell_price, actions)
                    return
                if sell_status in ('canceled', 'cancelled'):
                    # Order was cancelled (by restart, Kalshi, etc.)
                    _remaining = max(1, sell_qty - sell_filled)
                    # Check if market is dead before trying to cross
                    _mkt_dead = False
                    try:
                        api_read_limiter.wait()
                        _mkt_resp = kalshi_client.get_market(ticker)
                        _mkt_data = _mkt_resp.get('market', _mkt_resp) if isinstance(_mkt_resp, dict) else {}
                        _mkt_status = _mkt_data.get('status', 'active')
                        _mkt_result = _mkt_data.get('result', '')
                        if _mkt_status not in ('active', 'open') or _mkt_result:
                            _mkt_dead = True
                    except Exception:
                        pass
                    # Also treat as dead if anchor bid is <= 1¢ (no liquidity, can't sell)
                    # Check WS price first, fallback to orderbook
                    _anchor_bid = bot.get(f'live_{anchor_side}_bid', 0)
                    if _anchor_bid <= 0:
                        try:
                            api_read_limiter.wait()
                            _ob = kalshi_client.get_market_orderbook(ticker)
                            _anchor_bid = _best_bid(_ob, anchor_side)
                        except Exception:
                            _anchor_bid = 0
                    if not _mkt_dead and _anchor_bid <= 1:
                        _mkt_dead = True
                        _mkt_status = f'dead_liquidity_bid{_anchor_bid}'
                    if _mkt_dead:
                        # Market is done — transition to awaiting_settlement, let it settle naturally
                        print(f'⚠ APEX SELLBACK: order cancelled + market dead ({_mkt_status}) — awaiting settlement')
                        bot_log('APEX_SELLBACK_AWAITING_SETTLEMENT', bot_id, {
                            'filled': sell_filled, 'remaining': _remaining,
                            'market_status': _mkt_status, 'result': _mkt_result,
                        })
                        bot['status'] = 'awaiting_settlement'
                        bot['_sellback_order_id'] = None
                        save_state()
                        return
                    # Market still active — cross remaining as taker
                    print(f'⚠ APEX SELLBACK: order cancelled with {sell_filled}/{sell_qty} filled — crossing {_remaining} as taker')
                    bot_log('APEX_SELLBACK_ORDER_CANCELLED', bot_id, {
                        'filled': sell_filled, 'remaining': _remaining, 'sell_price': sell_price,
                    })
                    sold, sell_info = execute_sell(ticker, anchor_side, _remaining, reason=f'apex_sellback_cancelled_{bot_id}')
                    _cross_price = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price') or sell_price
                    _apex_sellback_complete(bot_id, bot, _cross_price, actions)
                    return
            except Exception as e:
                if '404' in str(e):
                    # Order gone — might have been cancelled or filled
                    print(f'⚠ APEX SELLBACK: order 404 — checking if position cleared')
                    bot['_sellback_fill_qty'] = sell_qty  # assume filled
                    _apex_sellback_complete(bot_id, bot, sell_price, actions)
                    return

        # Emergency taker exit: if game is ending, cross to bid
        _sb_urgency = _get_game_urgency(ticker)
        if _sb_urgency == 'critical' and sell_wait_s >= 30:
            # Re-verify fill count before crossing
            _em_verified = bot.get('_sellback_fill_qty', 0)
            if sell_oid:
                try:
                    api_read_limiter.wait()
                    _em_resp = kalshi_client.get_order(sell_oid)
                    _em_ord = _em_resp.get('order', _em_resp) if isinstance(_em_resp, dict) else {}
                    _em_verified = _parse_fill_count(_em_ord)
                    bot['_sellback_fill_qty'] = _em_verified
                    if _em_verified >= sell_qty:
                        print(f'🔙 APEX SELLBACK: fully filled on re-verify before emergency cross')
                        _apex_sellback_complete(bot_id, bot, _em_ord.get(f'{anchor_side}_price', sell_price), actions)
                        return
                except Exception:
                    pass
            _remaining_emergency = max(1, sell_qty - _em_verified)
            print(f'🚨 APEX SELLBACK EMERGENCY: {bot_id} game ending — crossing {_remaining_emergency}/{sell_qty} to bid')
            bot_log('APEX_SELLBACK_EMERGENCY_CROSS', bot_id, {
                'sell_wait_s': round(sell_wait_s), 'urgency': _sb_urgency,
                'verified_fill': _em_verified, 'remaining': _remaining_emergency,
            })
            # Cancel maker order, execute taker sell
            if sell_oid:
                try:
                    api_rate_limiter.wait()
                    kalshi_client.cancel_order(sell_oid)
                except Exception:
                    pass
            sold, sell_info = execute_sell(ticker, anchor_side, _remaining_emergency, reason=f'apex_sellback_emergency_{bot_id}')
            emergency_price = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price') or sell_price
            _apex_sellback_complete(bot_id, bot, emergency_price, actions)
            return

        # Walk sell price down toward bid (same adaptive system as hedge walk)
        try:
            api_read_limiter.wait()
            ob = kalshi_client.get_market_orderbook(ticker)
            anchor_bid = _best_bid(ob, anchor_side)
            anchor_ask = _best_ask(ob, anchor_side)
        except Exception:
            anchor_bid = 0
            anchor_ask = 0

        if anchor_bid > 0 and sell_price > 0:
            # Walk target: ask-1 if gapped, bid+1 if tight, but never below bid
            spread = (anchor_ask - anchor_bid) if anchor_ask > 0 else 0
            if spread >= 2 and anchor_ask > anchor_bid:
                walk_target = max(anchor_bid, anchor_ask - 1)
            else:
                walk_target = max(anchor_bid, anchor_bid + 1) if anchor_bid < sell_price else anchor_bid
            walk_target = max(1, walk_target)

            # Adaptive walk interval (same as hedge walk)
            combined = bot.get('_sellback_avg_anchor', 0) + sell_price
            _sb_walk_interval = _calc_walk_interval(combined, _sb_urgency, False, False, sell_price > walk_target)
            if _sb_walk_interval == 0:
                _sb_walk_interval = 5  # minimum 5s for sell-back walks (don't spam)
            bot['_walk_interval'] = _sb_walk_interval
            bot['_game_urgency'] = _sb_urgency
            bot['_sellback_bid'] = anchor_bid
            bot['_sellback_ask'] = anchor_ask
            bot['_sellback_walk_target'] = walk_target

            last_walk = bot.get('_sellback_last_walk_at', sell_started)
            since_walk = now - last_walk

            if since_walk >= _sb_walk_interval and sell_price > walk_target:
                # Walk down: reduce sell price by 1¢ toward bid
                new_sell_price = max(walk_target, sell_price - 1)
                if new_sell_price != sell_price:
                    try:
                        amend_kwargs = {f'{anchor_side}_price': new_sell_price}
                        api_rate_limiter.wait()
                        kalshi_client.amend_order(sell_oid, ticker=ticker, side=anchor_side,
                                                 count=sell_qty, action='sell', **amend_kwargs)
                        walk_count = bot.get('_sellback_walk_count', 0) + 1
                        bot['_sellback_price'] = new_sell_price
                        bot['_sellback_last_walk_at'] = now
                        bot['_sellback_walk_count'] = walk_count
                        bot_log('APEX_SELLBACK_WALK', bot_id, {
                            'old_price': sell_price, 'new_price': new_sell_price,
                            'bid': anchor_bid, 'ask': anchor_ask,
                            'walk_count': walk_count, 'urgency': _sb_urgency,
                            'walk_interval': _sb_walk_interval,
                        })
                        print(f'🔙 APEX SELLBACK WALK: {bot_id} {sell_price}→{new_sell_price}¢ '
                              f'(bid={anchor_bid}¢ step #{walk_count})')
                    except Exception as e:
                        if '404' in str(e):
                            # Order gone during amend — assume filled
                            _apex_sellback_complete(bot_id, bot, sell_price, actions)
                            return
                        print(f'⚠ APEX SELLBACK WALK ERROR: {e}')

            # Timeout: if selling for >5 minutes, cross to bid as taker (last resort)
            if sell_wait_s >= 300:
                # Re-verify fill count before crossing (don't double-sell partial fills)
                _verified_fill = bot.get('_sellback_fill_qty', 0)
                if sell_oid:
                    try:
                        api_read_limiter.wait()
                        _vresp = kalshi_client.get_order(sell_oid)
                        _vord = _vresp.get('order', _vresp) if isinstance(_vresp, dict) else {}
                        _verified_fill = _parse_fill_count(_vord)
                        bot['_sellback_fill_qty'] = _verified_fill
                        if _verified_fill >= sell_qty:
                            print(f'🔙 APEX SELLBACK: fully filled on re-verify before timeout cross')
                            actual_sell_price = _vord.get(f'{anchor_side}_price', sell_price)
                            _apex_sellback_complete(bot_id, bot, actual_sell_price, actions)
                            return
                    except Exception:
                        pass
                _remaining_timeout = max(1, sell_qty - _verified_fill)
                print(f'⏰ APEX SELLBACK TIMEOUT: {bot_id} waited {sell_wait_s:.0f}s — crossing {_remaining_timeout}/{sell_qty} to bid')
                bot_log('APEX_SELLBACK_TIMEOUT_CROSS', bot_id, {
                    'sell_wait_s': round(sell_wait_s), 'verified_fill': _verified_fill,
                    'remaining': _remaining_timeout, 'total_qty': sell_qty,
                })
                if sell_oid:
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(sell_oid)
                    except Exception:
                        pass
                sold, sell_info = execute_sell(ticker, anchor_side, _remaining_timeout, reason=f'apex_sellback_timeout_{bot_id}')
                timeout_price = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price') or sell_price
                _apex_sellback_complete(bot_id, bot, timeout_price, actions)
                return

        save_state()
        return

    # ── STATE: waiting_repeat — repost the ladder arb ──
    if status == 'waiting_repeat':
        wait_since = bot.get('waiting_repeat_since', now)
        # Safety: if no repeats left, cancel orphaned orders and complete
        if bot.get('repeat_count', 0) <= 0 or bot.get('repeats_done', 0) > bot.get('repeat_count', 0):
            for rung in bot.get('rungs', []):
                for side in ('yes', 'no'):
                    oid = rung.get(f'{side}_order_id')
                    if oid:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(oid)
                        except Exception:
                            pass
            # Also cancel hedge orders
            repeat_cancel_ids = set()
            if bot.get('hedge_order_id'):
                repeat_cancel_ids.add(bot['hedge_order_id'])
            for oid in bot.get('_all_hedge_order_ids', []):
                repeat_cancel_ids.add(oid)
            for hg in bot.get('hedge_history', []):
                if hg.get('order_id'):
                    repeat_cancel_ids.add(hg['order_id'])
                for oid in hg.get('order_ids', []):
                    repeat_cancel_ids.add(oid)
            for oid in repeat_cancel_ids:
                try:
                    api_rate_limiter.wait()
                    kalshi_client.cancel_order(oid)
                except Exception:
                    pass
            bot['status'] = 'completed'
            bot['completed_at'] = now
            print(f'🏁 APEX REPEAT DONE: {bot_id} repeats_done={bot.get("repeats_done",0)}/{bot.get("repeat_count",0)} — completing')
            save_state()
            return
        if now - wait_since < 10:  # 10s cooldown
            return
        # Fetch fresh orderbook and repost
        try:
            api_read_limiter.wait()
            ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
            ob = ob_data.get('orderbook', ob_data)
            yes_levels = sorted(ob.get('yes', []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
            no_levels  = sorted(ob.get('no',  []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
            fresh_yes_bid = (yes_levels[0][0] if isinstance(yes_levels[0], list) else yes_levels[0].get('price', 0)) if yes_levels else 0
            fresh_no_bid  = (no_levels[0][0]  if isinstance(no_levels[0], list)  else no_levels[0].get('price', 0))  if no_levels  else 0
            fresh_yes_ask = 100 - fresh_no_bid if fresh_no_bid > 0 else 99
            fresh_no_ask  = 100 - fresh_yes_bid if fresh_yes_bid > 0 else 99
            if fresh_yes_bid <= 0 or fresh_no_bid <= 0 or fresh_yes_bid + fresh_no_bid >= 100:
                return  # No market — wait
            # Drift guard: don't repost if game has drifted into blowout
            price_lean = abs(fresh_yes_bid - fresh_no_bid)
            if price_lean > 30:
                bot_log('APEX_REPEAT_DRIFT_SKIP', bot_id, {
                    'yes_bid': fresh_yes_bid, 'no_bid': fresh_no_bid,
                    'price_lean': price_lean, 'reason': 'blowout_drift',
                })
                # Don't kill repeats — game can swing back. Just wait.
                print(f'⏳ APEX DRIFT WAIT: {bot_id} lean={price_lean} — waiting for market to balance')
                return
            use_scaling = bot.get('width_scaling', False)
            valid_specs = []
            for rung in bot.get('rungs', []):
                w = rung['width']
                ty, tn = _calculate_arb_prices_server(fresh_yes_bid, fresh_no_bid, fresh_yes_ask, fresh_no_ask, w)
                profit = 100 - ty - tn
                if profit <= 0:
                    continue
                rung_qty = _scale_qty_for_width(qty_per, w) if use_scaling else qty_per
                valid_specs.append({'width': w, 'yes_price': ty, 'no_price': tn, 'rung_qty': rung_qty})
            repeat_group_id = _create_order_group()
            if valid_specs:
                yes_specs = [{'ticker': ticker, 'side': 'yes', 'count': s['rung_qty'], 'price': s['yes_price']} for s in valid_specs]
                no_specs  = [{'ticker': ticker, 'side': 'no',  'count': s['rung_qty'], 'price': s['no_price']}  for s in valid_specs]
                yes_results = create_orders_batch(yes_specs, order_group_id=repeat_group_id)
                no_results  = create_orders_batch(no_specs, order_group_id=repeat_group_id)
                new_rungs = []
                for idx, spec in enumerate(valid_specs):
                    try:
                        if yes_results[idx] is None or no_results[idx] is None:
                            continue
                        yr, ya = yes_results[idx]
                        nr, na = no_results[idx]
                        new_rungs.append({
                            'width': spec['width'], 'yes_price': ya, 'no_price': na,
                            'yes_order_id': yr['order']['order_id'],
                            'no_order_id': nr['order']['order_id'],
                            'yes_fill_qty': 0, 'no_fill_qty': 0,
                            'yes_filled_at': None, 'no_filled_at': None,
                            'quantity': spec['rung_qty'],
                        })
                    except Exception:
                        pass
            else:
                new_rungs = []
            if new_rungs:
                # Collect all order IDs from new rungs for verification
                _repeat_oids = []
                for _nr in new_rungs:
                    if _nr.get('yes_order_id'): _repeat_oids.append(_nr['yes_order_id'])
                    if _nr.get('no_order_id'): _repeat_oids.append(_nr['no_order_id'])
                bot['_all_placed_order_ids'] = _repeat_oids

                bot['rungs'] = new_rungs
                bot['total_rungs'] = len(new_rungs)
                bot['posted_at'] = now
                bot['status'] = 'ladder_arb_posted'
                bot['filled_yes_qty'] = 0
                bot['filled_no_qty'] = 0
                bot['avg_yes_price'] = None
                bot['avg_no_price'] = None
                bot['first_fill_at'] = None
                bot['first_fill_side'] = None
                bot['walk_count'] = 0
                bot['_consolidated'] = False
                bot['_trade_recorded'] = False
                bot['_ws_fill_handling'] = False
                bot['_bot_completed'] = False
                bot['_completion_repeat_processed'] = False
                bot['hedge_order_id'] = None
                bot['repost_count'] = bot.get('repost_count', 0) + 1
                bot['live_yes_bid'] = fresh_yes_bid
                bot['live_no_bid'] = fresh_no_bid
                bot['yes_price'] = new_rungs[0]['yes_price']
                bot['no_price'] = new_rungs[0]['no_price']
                bot['_order_group_id'] = repeat_group_id
                actions.append({'bot_id': bot_id, 'action': 'ladder_arb_repeat_repost'})
                print(f'🔄 APEX REPEAT: {bot_id} cycle {bot.get("repeats_done",0)}/{bot.get("repeat_count",0)} — {len(new_rungs)} rungs reposted (group={repeat_group_id[:8]})')
                _audit('APEX_REPEAT_ENTER', bot_id, {'ticker': ticker, 'cycle': bot.get('repeats_done', 0), 'total': bot.get('repeat_count', 0), 'rungs': len(new_rungs)})
            else:
                return  # No profitable rungs — wait
        except Exception as e:
            print(f'❌ APEX REPEAT {bot_id}: {e}')
            return
        save_state()
        return

    # ── STATE: ladder_arb_posted — all rungs live, both sides ──
    if status == 'ladder_arb_posted':
        # Guard: don't process if completion thread is running
        if bot.get('_bot_completed'):
            bot['status'] = 'completed'
            return

        # Poll fill counts (backup for WS misses) — skip if WS is healthy
        ws_healthy = ws_manager and ws_manager.connected and (time.time() - ws_manager.ticker_cache.get(ticker, {}).get('_local_ts', 0)) < 30
        if not ws_healthy:
            for rung in bot.get('rungs', []):
                for side in ('yes', 'no'):
                    fk = f'{side}_fill_qty'
                    if rung.get(fk, 0) >= rung.get('quantity', qty_per):
                        continue
                    oid = rung.get(f'{side}_order_id')
                    if not oid:
                        continue
                    try:
                        api_read_limiter.wait()
                        resp = kalshi_client.get_order(oid)
                        ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
                        filled = _parse_fill_count(ord_data)
                        old_fk_posted = rung.get(fk, 0)
                        rung[fk] = max(old_fk_posted, filled)
                        if filled >= rung.get('quantity', qty_per) and not rung.get(f'{side}_filled_at'):
                            rung[f'{side}_filled_at'] = now
                        # Update bot-level hedge fill count from API poll
                        if oid in bot.get('_all_hedge_order_ids', []):
                            bot['_hedge_fill_count'] = max(bot.get('_hedge_fill_count', 0), filled)
                        if filled > old_fk_posted:
                            bot_log('LADDER_ARB_REST_FILL_POSTED', bot_id, {
                                'rung_idx': bot.get('rungs', []).index(rung) if rung in bot.get('rungs', []) else None,
                                'side': side, 'old_fill': old_fk_posted, 'new_fill': filled,
                                'price': rung.get(f'{side}_price', 0),
                                'is_hedge_order': oid in bot.get('_all_hedge_order_ids', []),
                            })
                    except Exception:
                        pass

        _recompute_apex_fills(bot)
        total_yes = bot['filled_yes_qty']
        total_no = bot['filled_no_qty']

        # Record any newly completed rungs + check if bot fully done
        all_resolved = _check_apex_rung_completions(bot_id, bot)
        if all_resolved and bot.get('completed_rungs_count', 0) > 0:
            bot_log('APEX_MONITOR_COMPLETION_TRIGGER', bot_id, {
                'trigger': 'monitor_posted_all_resolved',
                'completed_rungs_count': bot.get('completed_rungs_count', 0),
                'hedge_qty': bot.get('hedge_qty', 0),
                '_hedge_fill_count': bot.get('_hedge_fill_count', 0),
                'filled_yes_qty': bot.get('filled_yes_qty', 0),
                'filled_no_qty': bot.get('filled_no_qty', 0),
                '_consolidated': bot.get('_consolidated', False),
                'hedge_order_id': bot.get('hedge_order_id'),
            })
            threading.Thread(target=_execute_apex_completion, args=(bot_id,), daemon=True).start()
            return

        # One side has fills — transition state
        uncompleted_yes = sum(min(r.get('yes_fill_qty', 0), r.get('quantity', qty_per))
                              for r in bot.get('rungs', []))
        uncompleted_no = sum(min(r.get('no_fill_qty', 0), r.get('quantity', qty_per))
                             for r in bot.get('rungs', []))
        if uncompleted_yes > 0 or uncompleted_no > 0:
            if uncompleted_yes > 0 and uncompleted_no == 0:
                bot['status'] = 'ladder_arb_yes_filled'
                filled_side = 'yes'
            elif uncompleted_no > 0 and uncompleted_yes == 0:
                bot['status'] = 'ladder_arb_no_filled'
                filled_side = 'no'
            else:
                filled_side = 'yes' if uncompleted_yes >= uncompleted_no else 'no'
                bot['status'] = f'ladder_arb_{filled_side}_filled'
            unfilled_side = 'no' if filled_side == 'yes' else 'yes'

            if not bot.get('first_fill_at'):
                bot['first_fill_at'] = now
                bot['first_fill_side'] = filled_side
                bot['walk_count'] = 0
                bot['last_walk_at'] = now
                # Record the initial hedge price for walk-up progress display
                unfilled_bid_init = yes_bid if unfilled_side == 'yes' else no_bid
                bot['walk_start_price'] = unfilled_bid_init or 0

                # ── 1s SWEEP: first fill detected ──
                bot['_sweep_at'] = now
                # Immediately cancel opposite-side orders (don't let them fill during window)
                cancelled_opp = 0
                for _rung in bot.get('rungs', []):
                    _oid = _rung.get(f'{unfilled_side}_order_id')
                    if _oid:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(_oid)
                        except Exception:
                            pass
                        _rung[f'{unfilled_side}_order_id'] = None
                        cancelled_opp += 1
                print(f'⚡ SWEEP START: {bot_id} {filled_side.upper()} fill — cancelled {cancelled_opp} {unfilled_side.upper()} orders, 1s anchor window')
                save_state()
                return

            # Sweep + cancel + consolidation now handled in the yes_filled/no_filled block
            save_state()
            return

        # Repost stale orders (60s — apex needs fresh prices since both sides are at market)
        REPOST_AFTER_MIN = 1
        age_min = (now - bot.get('posted_at', now)) / 60.0
        if phase == 'live' and age_min >= REPOST_AFTER_MIN and bot.get('filled_yes_qty', 0) == 0 and bot.get('filled_no_qty', 0) == 0:
            # Cancel all via order group (1 API call) or fall back to individual
            old_group_id = bot.get('_order_group_id')
            if old_group_id:
                try:
                    api_rate_limiter.wait()
                    kalshi_client.cancel_order_group(old_group_id)
                except Exception as cg_err:
                    # Group cancel failed — fall back to individual cancels
                    print(f'  ⚠ Group cancel failed ({old_group_id[:8]}): {cg_err} — individual fallback')
                    for rung in bot.get('rungs', []):
                        for side in ('yes', 'no'):
                            oid = rung.get(f'{side}_order_id')
                            if oid:
                                try:
                                    api_rate_limiter.wait()
                                    kalshi_client.cancel_order(oid)
                                except Exception:
                                    pass
            else:
                # Legacy bot without order group — cancel individually
                for rung in bot.get('rungs', []):
                    for side in ('yes', 'no'):
                        oid = rung.get(f'{side}_order_id')
                        if oid:
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(oid)
                            except Exception:
                                pass

            # Fetch fresh orderbook
            try:
                new_group_id = _create_order_group()
                api_read_limiter.wait()
                ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
                ob = ob_data.get('orderbook', ob_data)
                yes_levels = sorted(ob.get('yes', []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                no_levels  = sorted(ob.get('no',  []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                fresh_yes_bid = (yes_levels[0][0] if isinstance(yes_levels[0], list) else yes_levels[0].get('price', 0)) if yes_levels else 0
                fresh_no_bid  = (no_levels[0][0]  if isinstance(no_levels[0], list)  else no_levels[0].get('price', 0))  if no_levels  else 0
                fresh_yes_ask = 100 - fresh_no_bid if fresh_no_bid > 0 else 99
                fresh_no_ask  = 100 - fresh_yes_bid if fresh_yes_bid > 0 else 99

                if fresh_yes_bid <= 0 or fresh_no_bid <= 0 or fresh_yes_bid + fresh_no_bid >= 100:
                    # Market gone — kill bot
                    bot['status'] = 'drift_cancelled'
                    bot['completed_at'] = now
                    actions.append({'bot_id': bot_id, 'action': 'repost_market_dead'})
                    save_state()
                    return

                valid_specs = []
                for rung in bot.get('rungs', []):
                    w = rung['width']
                    ty, tn = _calculate_arb_prices_server(fresh_yes_bid, fresh_no_bid, fresh_yes_ask, fresh_no_ask, w)
                    profit = 100 - ty - tn
                    if profit <= 0:
                        continue
                    valid_specs.append({'width': w, 'yes_price': ty, 'no_price': tn})
                new_rungs = []
                if valid_specs:
                    yes_specs = [{'ticker': ticker, 'side': 'yes', 'count': qty_per, 'price': s['yes_price']} for s in valid_specs]
                    no_specs  = [{'ticker': ticker, 'side': 'no',  'count': qty_per, 'price': s['no_price']}  for s in valid_specs]
                    yes_results = create_orders_batch(yes_specs, order_group_id=new_group_id)
                    no_results  = create_orders_batch(no_specs, order_group_id=new_group_id)
                    for idx, spec in enumerate(valid_specs):
                        try:
                            if yes_results[idx] is None or no_results[idx] is None:
                                continue
                            yr, ya = yes_results[idx]
                            nr, na = no_results[idx]
                            new_rungs.append({
                                'width': spec['width'], 'yes_price': ya, 'no_price': na,
                                'yes_order_id': yr['order']['order_id'],
                                'no_order_id': nr['order']['order_id'],
                                'yes_fill_qty': 0, 'no_fill_qty': 0,
                                'yes_filled_at': None, 'no_filled_at': None,
                                'quantity': qty_per,
                            })
                        except Exception:
                            pass

                if new_rungs:
                    bot['rungs'] = new_rungs
                    bot['total_rungs'] = len(new_rungs)
                    bot['posted_at'] = now
                    bot['repost_count'] = bot.get('repost_count', 0) + 1
                    bot['live_yes_bid'] = fresh_yes_bid
                    bot['live_no_bid'] = fresh_no_bid
                    bot['yes_price'] = new_rungs[0]['yes_price']
                    bot['no_price'] = new_rungs[0]['no_price']
                    bot['_order_group_id'] = new_group_id
                    actions.append({'bot_id': bot_id, 'action': 'ladder_arb_reposted', 'repost_count': bot['repost_count']})
                    print(f'🔄 APEX REPOST: {bot_id} #{bot["repost_count"]} — {len(new_rungs)} rungs refreshed (group={new_group_id[:8]})')
                else:
                    bot['status'] = 'drift_cancelled'
                    bot['completed_at'] = now
            except Exception as e:
                print(f'❌ APEX REPOST {bot_id}: {e}')

        save_state()
        return

    # ── STATE: ladder_arb_yes_filled or ladder_arb_no_filled — walk unfilled side ──
    if status in ('ladder_arb_yes_filled', 'ladder_arb_no_filled'):
        # Guard: don't process if completion thread is running
        if bot.get('_bot_completed'):
            bot['status'] = 'completed'
            return

        # Sweep thread handles cancel + hedge — don't interfere
        if bot.get('_sweep_thread_running'):
            save_state()
            return

        filled_side = 'yes' if status == 'ladder_arb_yes_filled' else 'no'
        unfilled_side = 'no' if filled_side == 'yes' else 'yes'

        # Backfill first_fill_side if cleared by previous hedge gen completion
        if not bot.get('first_fill_side'):
            bot['first_fill_side'] = filled_side
        if not bot.get('first_fill_at'):
            bot['first_fill_at'] = now

        # ── Consolidate: cancel unfilled-side rung orders, place ONE hedge ──
        # Skip if sweep thread is still running (it will do the cancel+hedge)
        if bot.get('_sweep_thread_running'):
            save_state()
            return

        if not bot.get('_consolidated'):
            total_filled_qty = sum(
                min(r.get(f'{filled_side}_fill_qty', 0), r.get('quantity', qty_per))
                for r in bot.get('rungs', [])
                if r.get(f'{filled_side}_fill_qty', 0) > 0
            )
            if total_filled_qty > 0:
                _recompute_apex_fills(bot)
                # Recompute total after recompute
                total_filled_qty = sum(
                    min(r.get(f'{filled_side}_fill_qty', 0), r.get('quantity', qty_per))
                    for r in bot.get('rungs', [])
                    if r.get(f'{filled_side}_fill_qty', 0) > 0
                )
                if total_filled_qty <= 0:
                    save_state()
                    return

                # Use WS cache for hedge pricing (saves ~30ms + rate limit wait)
                ws_data = ws_manager.get_price(ticker, max_age_s=5) if ws_manager else None
                if ws_data:
                    fresh_yes_bid = ws_data.get('yes_bid', 0)
                    fresh_no_bid = ws_data.get('no_bid', 0)
                else:
                    # WS cache miss — fall back to REST
                    try:
                        api_read_limiter.wait()
                        ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
                        ob = ob_data.get('orderbook', ob_data)
                        yes_lvl = sorted(ob.get('yes', []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                        no_lvl  = sorted(ob.get('no',  []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                        fresh_yes_bid = (yes_lvl[0][0] if isinstance(yes_lvl[0], list) else yes_lvl[0].get('price', 0)) if yes_lvl else 0
                        fresh_no_bid  = (no_lvl[0][0]  if isinstance(no_lvl[0], list)  else no_lvl[0].get('price', 0))  if no_lvl  else 0
                    except Exception:
                        fresh_yes_bid = bot.get('live_yes_bid', 0)
                        fresh_no_bid = bot.get('live_no_bid', 0)
                unfilled_bid = fresh_yes_bid if unfilled_side == 'yes' else fresh_no_bid

                # Place ONE consolidated hedge at WEIGHTED-AVG-WIDTH target price
                avg_filled_price = bot.get(f'avg_{filled_side}_price', 0)
                total_width_x_qty = sum(
                    r.get('width', 0) * min(r.get(f'{filled_side}_fill_qty', 0), r.get('quantity', qty_per))
                    for r in bot.get('rungs', [])
                    if r.get(f'{filled_side}_fill_qty', 0) > 0
                )
                weighted_avg_width = total_width_x_qty / total_filled_qty if total_filled_qty > 0 else 0
                target_hedge = round(100 - avg_filled_price - weighted_avg_width)
                unfilled_ask = (100 - fresh_no_bid) if unfilled_side == 'yes' and fresh_no_bid > 0 else ((100 - fresh_yes_bid) if unfilled_side == 'no' and fresh_yes_bid > 0 else 0)
                hedge_price = max(1, target_hedge)  # Use calculated price, not bid
                bot['_target_hedge_price'] = target_hedge
                bot['_avg_width'] = weighted_avg_width

                # Safety: cap at 98¢ combined
                max_safe = HARD_CEILING_CENTS - avg_filled_price
                if hedge_price > max_safe:
                    print(f'⚠ APEX CEILING: {bot_id} target_hedge={target_hedge}¢ capped to {max_safe}¢ (avg_anchor={avg_filled_price}¢)')
                    hedge_price = max(max_safe, 1)

                print(f'📊 APEX HEDGE CALC: {bot_id} avg_anchor={avg_filled_price}¢ weighted_width={weighted_avg_width:.1f}¢ target={target_hedge}¢ bid={unfilled_bid}¢ ask={unfilled_ask}¢ placing@{hedge_price}¢')

                # ── HEDGE FIRST — gets priority burst token before cancels ──
                _pre_cancel_oids = []
                if hedge_price > 0:
                    try:
                        hedge_resp, actual_hedge = create_order_maker(
                            ticker=ticker, side=unfilled_side, action='buy',
                            count=total_filled_qty, price=hedge_price,
                        )
                        hedge_oid = hedge_resp['order']['order_id']
                        bot['hedge_order_id'] = hedge_oid
                        bot['hedge_price'] = actual_hedge
                        bot['hedge_qty'] = total_filled_qty
                        bot['_hedge_fill_count'] = 0
                        all_ids = bot.get('_all_hedge_order_ids', [])
                        all_ids.append(hedge_oid)
                        bot['_all_hedge_order_ids'] = all_ids
                        # Collect unfilled-side order IDs BEFORE clearing them
                        _pre_cancel_oids = []
                        for r in bot['rungs']:
                            _oid = r.get(f'{unfilled_side}_order_id')
                            if _oid and _oid != hedge_oid:
                                _pre_cancel_oids.append((_oid, r))
                        # Now safe to update rung references
                        bot['rungs'][0][f'{unfilled_side}_order_id'] = hedge_oid
                        for r in bot['rungs'][1:]:
                            r[f'{unfilled_side}_order_id'] = None
                        bot['_consolidated'] = True
                        print(f'🎯 APEX CONSOLIDATE: {bot_id} {filled_side.upper()} filled (avg={avg_filled_price}¢) → single {unfilled_side.upper()} hedge @{actual_hedge}¢ × {total_filled_qty}')
                        _audit('APEX_HEDGE_POSTED', bot_id, {'ticker': ticker, 'filled_side': filled_side, 'hedge_side': unfilled_side, 'hedge_price': actual_hedge, 'hedge_qty': total_filled_qty, 'hedge_order_id': hedge_oid})
                        # Track fill-to-hedge latency
                        fill_at = bot.get('first_fill_at')
                        if fill_at:
                            f2h_ms = (time.time() - fill_at) * 1000
                            if not bot.get('hedge_latency_ms'):
                                bot['hedge_latency_ms'] = round(f2h_ms, 1)
                            _record_latency('fill_to_hedge_apex', f2h_ms, {'bot_id': bot_id, 'type': 'apex_monitor', 'hedge_price': actual_hedge, 'avg_anchor': avg_filled_price})
                            print(f'   ⏱ Hedge placed latency: {f2h_ms:.0f}ms')
                    except Exception as e:
                        print(f'❌ APEX CONSOLIDATE {bot_id}: hedge placement failed: {e}')

                # ── THEN cancel remaining UNFILLED-SIDE orders (collected before clearing) ──
                # NEVER cancel anchor (filled_side) orders — they stay alive for late fills
                cancel_oids = _pre_cancel_oids
                if not cancel_oids:
                    # Fallback: collect from rungs (for non-consolidation path)
                    for _rung in bot.get('rungs', []):
                        _oid = _rung.get(f'{unfilled_side}_order_id')
                        if _oid and _oid != bot.get('hedge_order_id'):
                            cancel_oids.append((_oid, _rung))
                if cancel_oids:
                    cancel_ok = 0
                    for _oid, _rung in cancel_oids:
                        if _cancel_with_retry(_oid):
                            cancel_ok += 1
                        else:
                            print(f'⚠ APEX MON CANCEL FAILED: {_oid}')
                        _rung[f'{unfilled_side}_order_id'] = None
                    print(f'🔄 APEX MON: cancelled {cancel_ok}/{len(cancel_oids)} {unfilled_side} orders (anchors preserved)')

                save_state()
                return

        # Re-poll fills (backup) — ONLY if WS is unhealthy (saves ~1s of REST calls per cycle)
        ws_healthy_la = ws_manager and ws_manager.connected and (time.time() - ws_manager.ticker_cache.get(ticker, {}).get('_local_ts', 0)) < 30
        if not ws_healthy_la:
            # 1) Poll per-rung anchor orders
            for rung in bot.get('rungs', []):
                fk = f'{filled_side}_fill_qty'
                if rung.get(fk, 0) >= rung.get('quantity', qty_per):
                    continue
                oid = rung.get(f'{filled_side}_order_id')
                if not oid:
                    continue
                try:
                    api_read_limiter.wait()
                    resp = kalshi_client.get_order(oid)
                    ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
                    filled = _parse_fill_count(ord_data)
                    old_fk = rung.get(fk, 0)
                    rung[fk] = max(old_fk, filled)
                    if filled >= rung.get('quantity', qty_per) and not rung.get(f'{filled_side}_filled_at'):
                        rung[f'{filled_side}_filled_at'] = now
                    if filled > old_fk:
                        bot_log('LADDER_ARB_REST_ANCHOR_FILL', bot_id, {
                            'rung_idx': bot.get('rungs', []).index(rung) if rung in bot.get('rungs', []) else None,
                            'side': filled_side, 'old_fill': old_fk, 'new_fill': filled,
                            'rung_qty': rung.get('quantity', qty_per),
                            'price': rung.get(f'{filled_side}_price', 0),
                        })
                except Exception:
                    pass

            # 2) Poll ALL hedge orders for fill tracking
            total_hedge_polled = 0
            orders_polled_ok = 0
            _per_order_fills = {}
            for hedge_oid in bot.get('_all_hedge_order_ids', []):
                try:
                    api_read_limiter.wait()
                    resp = kalshi_client.get_order(hedge_oid)
                    ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
                    filled = _parse_fill_count(ord_data)
                    _ord_status = ord_data.get('status', '')
                    _ord_count = ord_data.get('count', ord_data.get('count_fp', ''))
                    total_hedge_polled += filled
                    orders_polled_ok += 1
                    _per_order_fills[hedge_oid[:12]] = {'fills': filled, 'status': _ord_status, 'count': _ord_count}
                except Exception as poll_err:
                    if '404' in str(poll_err):
                        print(f'⚠ APEX hedge order {hedge_oid[:8]}... 404 — checking portfolio positions')
                        _per_order_fills[hedge_oid[:12]] = {'fills': 0, 'status': '404'}
                    pass
            if total_hedge_polled > bot.get('_hedge_fill_count', 0):
                old_hfc = bot.get('_hedge_fill_count', 0)
                bot['_hedge_fill_count'] = total_hedge_polled
                print(f'📊 APEX {bot_id} hedge fills updated: {total_hedge_polled} (from {orders_polled_ok} orders)')
                bot_log('LADDER_ARB_HEDGE_FILL_UPDATE', bot_id, {
                    'old_hedge_fill_count': old_hfc, 'new_hedge_fill_count': total_hedge_polled,
                    'orders_polled': orders_polled_ok, 'hedge_price': bot.get('hedge_price', 0),
                    'hedge_qty': bot.get('hedge_qty', 0),
                    'per_order': _per_order_fills,
                    'filled_yes_qty': bot.get('filled_yes_qty', 0),
                    'filled_no_qty': bot.get('filled_no_qty', 0),
                })

            # 3) If hedge orders are 404ing but we have positions, reconcile from portfolio
            if orders_polled_ok == 0 and len(bot.get('_all_hedge_order_ids', [])) > 0:
                try:
                    api_read_limiter.wait()
                    positions = kalshi_client.get_positions(ticker=ticker)
                    pos_list = positions.get('market_positions', positions.get('positions', []))
                    if isinstance(pos_list, list):
                        for pos in pos_list:
                            side_pos = pos.get(f'{unfilled_side}_contracts', 0) or pos.get('position', 0)
                            if side_pos > bot.get('_hedge_fill_count', 0):
                                bot['_hedge_fill_count'] = side_pos
                                print(f'📊 APEX {bot_id} hedge fills from positions: {side_pos}')
                except Exception:
                    pass

        _recompute_apex_fills(bot)
        total_yes = bot['filled_yes_qty']
        total_no = bot['filled_no_qty']

        # Safety: cancel stale UNFILLED-SIDE orders on consolidated bots (e.g. cancel API failed during sweep)
        # NEVER cancel anchor (filled_side) orders — they stay alive for late fills
        if bot.get('_consolidated'):
            hedge_oid = bot.get('hedge_order_id')
            for _rung in bot.get('rungs', []):
                _oid = _rung.get(f'{unfilled_side}_order_id')
                if _oid and _oid != hedge_oid:
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(_oid)
                        print(f'🧹 STALE ORDER CLEANUP: {bot_id} cancelled {unfilled_side} {_oid[:8]}...')
                    except Exception:
                        pass
                    _rung[f'{unfilled_side}_order_id'] = None

        # Record any newly completed rungs + check if bot fully done
        all_resolved = _check_apex_rung_completions(bot_id, bot)
        # Also trigger completion when hedge is fully filled even if it doesn't cover all anchors
        # The completion handler will detect unhedged anchors and place extra hedges
        _hfc = bot.get('_hedge_fill_count', 0)
        _hq = bot.get('hedge_qty', 0)
        _hedge_done_trigger = (bot.get('_consolidated') and _hfc >= _hq and _hq > 0
                               and bot.get('_hedge_verified'))
        if (all_resolved and bot.get('completed_rungs_count', 0) > 0) or _hedge_done_trigger:
            _trigger = 'monitor_filled_all_resolved' if all_resolved else 'hedge_fully_filled'
            bot_log('APEX_MONITOR_COMPLETION_TRIGGER', bot_id, {
                'trigger': _trigger,
                'completed_rungs_count': bot.get('completed_rungs_count', 0),
                'hedge_qty': _hq,
                '_hedge_fill_count': _hfc,
                'filled_yes_qty': bot.get('filled_yes_qty', 0),
                'filled_no_qty': bot.get('filled_no_qty', 0),
                '_consolidated': bot.get('_consolidated', False),
                'hedge_order_id': bot.get('hedge_order_id'),
                '_all_hedge_order_ids': bot.get('_all_hedge_order_ids', []),
            })
            bot['_completion_repeat_processed'] = False
            threading.Thread(target=_execute_apex_completion, args=(bot_id,), daemon=True).start()
            return

        # ── Walk-up is the only way to complete the hedge from here ──
        # Additional hedge placement is handled ONLY by the posted-state consolidation block.
        # This handler only walks the existing hedge order toward the bid.

        avg_filled = bot.get(f'avg_{filled_side}_price', 0)
        first_fill_at = bot.get('first_fill_at', now)
        wait_min = (now - first_fill_at) / 60.0

        # Backfill walk_start_price for bots created before this field existed
        if not bot.get('walk_start_price') and bot.get('hedge_price'):
            bot['walk_start_price'] = bot['hedge_price']

        # ── Bidirectional walk + snap system ──
        unfilled_bid = yes_bid if unfilled_side == 'yes' else no_bid
        unfilled_ask = bot.get(f'live_{unfilled_side}_ask', 0)
        wide_spread = unfilled_ask > 0 and (unfilled_ask - unfilled_bid) >= 2
        current_price_for_snap = bot.get('hedge_price', 0)
        anchor_for_snap = bot.get(f'avg_{filled_side}_price', 0)
        rq_for_snap = bot.get('hedge_qty', 1)
        _apex_urgency = _get_game_urgency(ticker)
        _apex_snap_ceiling = URGENCY_PARAMS.get(_apex_urgency, {}).get('snap_ceiling', SNAP_CEILING_CENTS)
        # Snap ready: combined ≤ snap ceiling → profit locked in, snap to bid
        snap_ready = (unfilled_bid and unfilled_bid > 0 and current_price_for_snap > 0
                      and anchor_for_snap > 0
                      and _apex_snap_check(anchor_for_snap, unfilled_bid, rq_for_snap, snap_ceiling=_apex_snap_ceiling))
        at_ceiling = (current_price_for_snap > 0 and anchor_for_snap > 0
                      and anchor_for_snap + current_price_for_snap >= HARD_CEILING_CENTS)
        # Target price: bid+1 in gapped, bid in tight
        bid_target = (min(unfilled_bid + 1, unfilled_ask - 1) if wide_spread and unfilled_ask > unfilled_bid
                      else unfilled_bid) if unfilled_bid and unfilled_bid > 0 else 0
        needs_drop = current_price_for_snap > 0 and bid_target > 0 and current_price_for_snap > bid_target
        # Queue position: track bid stability to avoid unnecessary walks
        _prev_bid = bot.get('_last_bid_seen', 0)
        if unfilled_bid != _prev_bid:
            bot['_bid_stable_since'] = now
            bot['_last_bid_seen'] = unfilled_bid
        _bid_stable_s = now - bot.get('_bid_stable_since', now)
        _at_bid = current_price_for_snap > 0 and current_price_for_snap == unfilled_bid
        _queue_grace = _at_bid and _bid_stable_s >= 10 and not snap_ready and not needs_drop and not at_ceiling
        # Interval: adaptive based on ceiling proximity + game urgency
        _apex_combined = anchor_for_snap + current_price_for_snap if (anchor_for_snap and current_price_for_snap) else 0
        walk_interval = _calc_walk_interval(_apex_combined, _apex_urgency, snap_ready, at_ceiling, needs_drop)
        if _queue_grace:
            walk_interval = max(walk_interval, 30)  # extend to 30s when at stable bid
        bot['_walk_interval'] = walk_interval  # expose to frontend
        bot['_game_urgency'] = _apex_urgency
        bot['_snap_ready'] = snap_ready
        bot['_at_ceiling'] = at_ceiling
        last_walk = bot.get('last_walk_at') or first_fill_at or now
        since_walk = now - last_walk
        if since_walk >= walk_interval:
            if not bot.get('_trade_recorded'):
                if unfilled_bid and unfilled_bid > 0:
                    walked_any = False
                    if bot.get('_consolidated') and bot.get('hedge_order_id'):
                        # Consolidated: walk the single hedge order
                        oid = bot['hedge_order_id']
                        current_price = bot.get('hedge_price', 0)
                        rq = bot.get('hedge_qty', 1)
                        anchor_price_for_ceiling = avg_filled if avg_filled > 0 else max(
                            (r.get(f'{filled_side}_price', 0)
                             for r in bot.get('rungs', [])
                             if r.get(f'{filled_side}_fill_qty', 0) > 0),
                            default=0
                        )
                        if current_price > 0 and oid:
                            combined = anchor_price_for_ceiling + current_price
                            # Market-based combined: in gapped markets, ask is the real price
                            _cur_ask_for_combined = unfilled_ask if unfilled_ask > 0 else unfilled_bid + 1
                            _spread_for_combined = _cur_ask_for_combined - unfilled_bid if unfilled_bid > 0 else 1
                            _market_price = _cur_ask_for_combined if _spread_for_combined > 2 else unfilled_bid
                            _market_combined = anchor_price_for_ceiling + _market_price
                            bot['_market_combined'] = _market_combined
                            bot['_market_price_ref'] = _market_price
                            # Hard ceiling: per-bot configurable (96-98¢)
                            _bot_ceiling = bot.get('hard_ceiling', HARD_CEILING_CENTS)
                            max_hedge = _bot_ceiling - anchor_price_for_ceiling
                            bot['_max_hedge'] = max_hedge
                            bot['_profitable_cap'] = anchor_price_for_ceiling + min(max_hedge, _bot_ceiling - anchor_price_for_ceiling)

                            # ── Bid-drift emergency exit (late/critical only) ──
                            _cur_ask_drift = unfilled_ask if unfilled_ask > 0 else unfilled_bid + 1
                            _drift_spread = _cur_ask_drift - unfilled_bid if unfilled_bid > 0 else 1
                            _drift_is_gapped = _drift_spread > 2
                            _gap_above = (current_price - _cur_ask_drift if _drift_is_gapped else current_price - unfilled_bid) if unfilled_bid > 0 else 0
                            _gap_below = unfilled_bid - current_price if unfilled_bid > 0 else 0
                            _bid_gap = max(_gap_above, _gap_below)
                            bot['_bid_gap'] = _bid_gap
                            _bid_drift_threshold = 5 if _apex_urgency == 'critical' else 10 if _apex_urgency == 'late' else 0
                            if (_bid_drift_threshold > 0 and _bid_gap >= _bid_drift_threshold
                                    and unfilled_bid > 0 and not bot.get('_trade_recorded')
                                    and not bot.get('_apex_sellback_attempted')):
                                print(f'🚨 APEX BID-DRIFT EXIT: {bot_id} hedge@{current_price}¢ bid@{unfilled_bid}¢ '
                                      f'gap={_bid_gap}¢ threshold={_bid_drift_threshold}¢ urgency={_apex_urgency}')
                                bot_log('APEX_BID_DRIFT_EXIT', bot_id, {
                                    'hedge_price': current_price, 'bid': unfilled_bid,
                                    'gap': _bid_gap, 'threshold': _bid_drift_threshold,
                                    'urgency': _apex_urgency, 'combined': combined,
                                })
                                bot['_apex_sellback_attempted'] = True
                                _apex_sell_back(bot_id, bot, anchor_price_for_ceiling, unfilled_bid, actions)
                                return

                            # ── Sell-back escape (time-gated by urgency) ──
                            _sellback_grace = {'normal': 600, 'halftime': 9999, 'late': 60, 'critical': 10}.get(_apex_urgency, 600)
                            _fill_at = bot.get('first_fill_at') or now
                            _hedge_age_s = now - _fill_at
                            bot['_sellback_grace_s'] = _sellback_grace
                            bot['_sellback_time_left'] = max(0, _sellback_grace - _hedge_age_s)
                            _above_snap = combined > _apex_snap_ceiling or _market_combined > _apex_snap_ceiling
                            if (_above_snap and _hedge_age_s >= _sellback_grace
                                    and not bot.get('_trade_recorded')):
                                if _apex_sellback_check(bot_id, bot, anchor_price_for_ceiling, unfilled_bid, rq):
                                    # Selling back is cheaper — do it
                                    bot['_apex_sellback_attempted'] = True
                                    bot['_sellback_decision'] = 'selling_back'
                                    _apex_sell_back(bot_id, bot, anchor_price_for_ceiling, unfilled_bid, actions)
                                    return
                                else:
                                    # Complete is cheaper — cross to bid to actually fill
                                    # Re-evaluated EVERY cycle: if bid moves and selling becomes cheaper, we'll sell next cycle
                                    bot['_sellback_decision'] = 'crossing_to_bid'
                                    # Bypass ceiling when exiting — ceiling is for entries, not exits
                                    _cross_target = unfilled_bid + 1 if unfilled_ask > unfilled_bid + 1 else unfilled_bid
                                    if unfilled_bid > 0 and (_cross_target > current_price or current_price <= 0):
                                        print(f'💀 APEX LOSS-EXIT: {bot_id} crossing to {_cross_target}¢ (bid={unfilled_bid}) — cheaper than sell-back')
                                        bot_log('APEX_LOSS_EXIT_CROSS', bot_id, {
                                            'old_price': current_price, 'cross_target': _cross_target,
                                            'unfilled_bid': unfilled_bid, 'anchor': anchor_price_for_ceiling,
                                            'combined_at_cross': anchor_price_for_ceiling + _cross_target,
                                        })
                                        _late_anchor_amend_lock.acquire()
                                        try:
                                            hedge_oid = bot.get('hedge_order_id', hedge_oid)  # re-read after lock
                                            api_rate_limiter.wait()
                                            _amend_ticker = bot.get('ticker', '')
                                            _amend_side = unfilled_side
                                            _amend_count = rq
                                            _amend_kwargs = {'yes_price': _cross_target} if _amend_side == 'yes' else {'no_price': _cross_target}
                                            kalshi_client.amend_order(hedge_oid, _amend_ticker, _amend_side, _amend_count, **_amend_kwargs)
                                            bot['hedge_price'] = _cross_target
                                            if unfilled_side == 'yes':
                                                bot['yes_price'] = _cross_target
                                            else:
                                                bot['no_price'] = _cross_target
                                            bot['walk_count'] = bot.get('walk_count', 0) + 1
                                            bot['last_walk_at'] = now
                                            save_state()
                                        except Exception as _ce:
                                            print(f'⚠ APEX LOSS-EXIT amend failed: {_ce} — placing new order')
                                            # Amend failed (404 = order dead) — place fresh order at cross target
                                            try:
                                                _cr_resp, _cr_actual = create_order_maker(
                                                    ticker=bot.get('ticker', ''), side=unfilled_side, action='buy',
                                                    count=rq, price=_cross_target, priority=True,
                                                )
                                                _cr_oid = _cr_resp['order']['order_id']
                                                bot['hedge_order_id'] = _cr_oid
                                                bot['hedge_price'] = _cr_actual
                                                _all = bot.get('_all_hedge_order_ids', [])
                                                _all.append(_cr_oid)
                                                bot['_all_hedge_order_ids'] = _all
                                                bot['walk_count'] = bot.get('walk_count', 0) + 1
                                                bot['last_walk_at'] = now
                                                print(f'   ✅ LOSS-EXIT new order: {unfilled_side} {rq}× @{_cr_actual}¢ | {_cr_oid[:12]}')
                                                save_state()
                                            except Exception as _cr_err:
                                                print(f'   ⚠ LOSS-EXIT new order failed: {_cr_err}')
                                                bot['_apex_sellback_attempted'] = True  # stop retrying
                                        finally:
                                            _late_anchor_amend_lock.release()
                                        return

                            # ══════════════════════════════════════════════
                            # 3-ZONE WALK SYSTEM
                            # ≤96¢: SNAP to bid (profit locked in, speed > price improvement)
                            # 97¢:  WALK +1¢ (marginal profit, slow approach, no cap)
                            # ≥98¢: STOP (breakeven, sit at bid, wait for fill or sell-back)
                            # ══════════════════════════════════════════════

                            # Walk cap: hard ceiling only (no profitable cap — let it reach bid)
                            walk_cap = max(1, max_hedge)

                            # ── DROP: price above bid → follow bid down (always instant) ──
                            if current_price > bid_target and bid_target > 0:
                                new_price = min(bid_target, walk_cap) if walk_cap > 0 else bid_target
                                walk_type = 'drop_to_bid'

                            # ── SNAP: combined ≤ snap ceiling → snap to bid instantly ──
                            # Profit is locked in. No reason to wait.
                            elif snap_ready and bid_target > current_price:
                                new_price = min(bid_target, walk_cap)
                                walk_type = 'snap_to_profit'
                                print(f'⚡ APEX SNAP: {bot_id} {unfilled_side.upper()} {current_price}→{new_price}¢ '
                                      f'(combined={anchor_price_for_ceiling + new_price}¢ ≤ {_apex_snap_ceiling}¢)')

                            # ── WALK: bid above us, combined would be > snap ceiling ──
                            # Walk +1¢ per interval toward bid. No cap — can walk to 98.
                            elif bid_target > current_price:
                                new_price = min(current_price + 1, min(bid_target, walk_cap))
                                walk_type = 'normal_walk'

                            else:
                                new_price = current_price  # At bid or no bid — hold
                            if new_price != current_price and new_price > 0:
                                print(f'📈 APEX WALK ATTEMPT: {bot_id} {unfilled_side.upper()} {current_price}¢ → {new_price}¢ (bid={unfilled_bid}¢ max_hedge={max_hedge}¢ avg_anchor={anchor_price_for_ceiling}¢)')
                                bot_log('APEX_WALK_ATTEMPT', bot_id, {
                                    'walk_type': walk_type, 'consolidated': True,
                                    'old_price': current_price, 'new_price': new_price,
                                    'unfilled_bid': unfilled_bid, 'max_hedge': max_hedge,
                                    'anchor_price': anchor_price_for_ceiling, 'combined': anchor_price_for_ceiling + new_price,
                                    'hedge_qty': rq, 'hedge_fill_count': bot.get('_hedge_fill_count', 0),
                                    'walk_interval': walk_interval, 'snap_ready': snap_ready,
                                    'walk_count': bot.get('walk_count', 0),
                                    'since_walk_s': round(since_walk, 1),
                                })
                                _late_anchor_amend_lock.acquire()
                                try:
                                    oid = bot.get('hedge_order_id', oid)  # re-read after lock
                                    # Pre-amend diagnostic: check order status before attempting
                                    try:
                                        api_read_limiter.wait()
                                        _pre_check = kalshi_client.get_order(oid)
                                        _pre_data = _pre_check.get('order', _pre_check) if isinstance(_pre_check, dict) else {}
                                        _pre_status = _pre_data.get('status', 'unknown')
                                        _pre_fills = _parse_fill_count(_pre_data)
                                        _pre_remaining = _pre_data.get('remaining_count_fp', _pre_data.get('remaining_count', '?'))
                                        if _pre_status != 'resting':
                                            print(f'⚠ APEX WALK PRE-CHECK: {bot_id} hedge {oid[:12]} status={_pre_status} fills={_pre_fills} remaining={_pre_remaining} — NOT RESTING')
                                            bot_log('APEX_WALK_PRE_CHECK_NOT_RESTING', bot_id, {
                                                'hedge_oid': oid[:12], 'status': _pre_status,
                                                'fills': _pre_fills, 'remaining': str(_pre_remaining),
                                            }, level='WARN')
                                            if _pre_fills > bot.get('_hedge_fill_count', 0):
                                                bot['_hedge_fill_count'] = _pre_fills
                                            if _pre_status == 'executed':
                                                bot['_hedge_verified'] = True
                                                _late_anchor_amend_lock.release()
                                                return
                                            # Canceled with no/partial fills — repost at walk target
                                            if _pre_status in ('canceled', 'cancelled'):
                                                _repost_qty = max(1, rq - bot.get('_hedge_fill_count', 0))
                                                if _repost_qty > 0:
                                                    try:
                                                        _rp_resp, _rp_actual = create_order_maker(
                                                            ticker=ticker, side=unfilled_side, action='buy',
                                                            count=_repost_qty, price=new_price,
                                                        )
                                                        _rp_oid = _rp_resp['order']['order_id']
                                                        bot['hedge_order_id'] = _rp_oid
                                                        bot['hedge_price'] = _rp_actual
                                                        bot['hedge_qty'] = _repost_qty
                                                        _all_ids = bot.get('_all_hedge_order_ids', [])
                                                        _all_ids.append(_rp_oid)
                                                        bot['_all_hedge_order_ids'] = _all_ids
                                                        bot['walk_count'] = 0
                                                        print(f'🔄 APEX WALK REPOST (pre-check): {bot_id} {unfilled_side} {_repost_qty}× @ {_rp_actual}¢ (old was {_pre_status})')
                                                        bot_log('APEX_WALK_REPOST_PRECHECK', bot_id, {
                                                            'new_oid': _rp_oid[:12], 'qty': _repost_qty,
                                                            'price': _rp_actual, 'old_status': _pre_status,
                                                        })
                                                        save_state()
                                                    except Exception as _rp_err:
                                                        print(f'⚠ APEX WALK REPOST FAIL: {bot_id}: {_rp_err}')
                                            _late_anchor_amend_lock.release()
                                            return
                                    except Exception as _pc_err:
                                        print(f'⚠ APEX WALK PRE-CHECK failed: {bot_id}: {_pc_err}')
                                    api_rate_limiter.wait()
                                    # Use remaining qty (hedge_qty - fills already counted) to avoid over-buying
                                    _amend_count = max(1, rq - bot.get('_hedge_fill_count', 0))
                                    kalshi_client.amend_order(oid, ticker=ticker, side=unfilled_side,
                                                              count=_amend_count, **{f'{unfilled_side}_price': new_price})
                                    bot['hedge_price'] = new_price
                                    walked_any = True
                                    bot_log('APEX_WALK_SUCCESS', bot_id, {
                                        'walk_type': walk_type, 'old_price': current_price, 'new_price': new_price,
                                        'walk_interval': walk_interval, 'urgency': _apex_urgency,
                                    })
                                except Exception as e:
                                    bot_log('APEX_WALK_ERROR', bot_id, {
                                        'walk_type': walk_type, 'error': str(e)[:200],
                                        'old_price': current_price, 'target_price': new_price,
                                    })
                                    if '404' in str(e):
                                        # Order gone — verify fills on Kalshi, let completion handle the rest
                                        try:
                                            api_read_limiter.wait()
                                            _404_resp = kalshi_client.get_order(oid)
                                            _404_data = _404_resp.get('order', _404_resp) if isinstance(_404_resp, dict) else {}
                                            _404_fills = _parse_fill_count(_404_data)
                                            _404_status = _404_data.get('status', '')
                                            if _404_fills > bot.get('_hedge_fill_count', 0):
                                                bot['_hedge_fill_count'] = _404_fills
                                            if _404_status == 'executed':
                                                bot['_hedge_verified'] = True
                                            print(f'🔍 APEX WALK 404: {bot_id} hedge status={_404_status} fills={_404_fills}')
                                            bot_log('APEX_WALK_404_VERIFY', bot_id, {
                                                'hedge_status': _404_status, 'hedge_fills': _404_fills,
                                                'hedge_qty': bot.get('hedge_qty', 0),
                                            })
                                            # Executed + fully filled = trigger completion (handles unhedged anchors)
                                            if _404_status == 'executed' and _404_fills >= bot.get('hedge_qty', 0) and bot.get('hedge_qty', 0) > 0:
                                                print(f'✅ APEX HEDGE DONE (404 verify): {bot_id} fills={_404_fills} qty={bot.get("hedge_qty")} — triggering completion')
                                                # Force-clear stale flags — previous completion thread may be dead
                                                bot['_completion_in_progress'] = False
                                                bot['_completion_repeat_processed'] = False
                                                bot['_ws_fill_handling'] = False
                                                bot['_bot_completed'] = False
                                                bot['_completion_in_progress'] = True
                                                threading.Thread(target=_execute_apex_completion, args=(bot_id,), daemon=True).start()
                                                return
                                            # Canceled (with or without partial fills) = repost REMAINING qty at current price
                                            if _404_status in ('canceled', 'cancelled') and unfilled_bid > 0:
                                                # Update fill count from Kalshi truth
                                                if _404_fills > 0:
                                                    bot['_hedge_fill_count'] = max(bot.get('_hedge_fill_count', 0), _404_fills)
                                                # Repost for ALL unhedged anchors (not stale bot.hedge_qty)
                                                # Recalculate from actual anchor fills
                                                _filled_side = bot.get('first_fill_side', 'no')
                                                _qty_per = bot.get('quantity', 1)
                                                _total_anchor = sum(min(r.get(f'{_filled_side}_fill_qty', 0), r.get('quantity', _qty_per)) for r in bot.get('rungs', []))
                                                _completed_h = sum(h.get('fill_qty', h.get('qty', 0)) for h in bot.get('hedge_history', []))
                                                _remaining = max(_total_anchor - _completed_h - bot.get('_hedge_fill_count', 0), bot.get('hedge_qty', 0) - bot.get('_hedge_fill_count', 0))
                                                if _remaining <= 0:
                                                    # Fully filled despite cancelled status — trigger completion
                                                    bot['_hedge_verified'] = True
                                                    bot['_completion_repeat_processed'] = False
                                                    threading.Thread(target=_execute_apex_completion, args=(bot_id,), daemon=True).start()
                                                    return
                                                _repost_qty = _remaining
                                                # Repost at where the order WAS (or bid) — capped at hard_ceiling
                                                _repost_price = max(current_price, unfilled_bid) if current_price > 0 else unfilled_bid
                                                _repost_price = min(_repost_price, walk_cap) if walk_cap > 0 else _repost_price
                                                try:
                                                    _rp_resp, _rp_actual = create_order_maker(
                                                        ticker=ticker, side=unfilled_side, action='buy',
                                                        count=_repost_qty, price=_repost_price
                                                    )
                                                    _rp_oid = _rp_resp['order']['order_id']
                                                    bot['hedge_order_id'] = _rp_oid
                                                    bot['hedge_price'] = _rp_actual
                                                    bot['hedge_qty'] = _repost_qty
                                                    _all_ids = bot.get('_all_hedge_order_ids', [])
                                                    _all_ids.append(_rp_oid)
                                                    bot['_all_hedge_order_ids'] = _all_ids
                                                    bot['walk_count'] = 0
                                                    bot['last_walk_at'] = now
                                                    print(f'🔄 APEX HEDGE REPOST: {bot_id} new {unfilled_side} {_repost_qty}× @ {_rp_actual}¢ (old was canceled)')
                                                    bot_log('APEX_HEDGE_REPOST_404', bot_id, {
                                                        'new_oid': _rp_oid[:12], 'qty': _repost_qty,
                                                        'price': _rp_actual, 'hedge_qty_source': 'bot.hedge_qty' if bot.get('hedge_qty', 0) > 0 else 'anchor_sum',
                                                    })
                                                    save_state()
                                                    return  # Fresh order — next cycle uses new ID
                                                except Exception as _rp_err:
                                                    print(f'⚠ APEX HEDGE REPOST FAIL: {bot_id}: {_rp_err}')
                                        except Exception:
                                            pass
                                        return  # Don't continue walk with stale order ID
                                    elif '409' in str(e):
                                        # 409 Conflict = order may be filled or market closed
                                        # Re-poll fills to check
                                        try:
                                            api_read_limiter.wait()
                                            resp = kalshi_client.get_order(oid)
                                            ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
                                            filled = _parse_fill_count(ord_data)
                                            if filled > bot.get('_hedge_fill_count', 0):
                                                bot['_hedge_fill_count'] = filled
                                                print(f'📊 APEX WALK 409 → hedge already filled: {filled} contracts')
                                        except Exception:
                                            pass
                                        # Force immediate settlement check on next cycle
                                        bot['_last_settle_check'] = 0
                                        print(f'⚠ APEX WALK {bot_id} 409 conflict — order may be filled, forcing settlement check')
                                    else:
                                        print(f'❌ APEX WALK {bot_id} hedge: {e}')
                                finally:
                                    _late_anchor_amend_lock.release()
                    else:
                        # Non-consolidated: walk individual rung orders (same bidirectional logic)
                        for rung in bot.get('rungs', []):
                            uf = rung.get(f'{unfilled_side}_fill_qty', 0)
                            rq = rung.get('quantity', qty_per)
                            oid = rung.get(f'{unfilled_side}_order_id')
                            if uf >= rq or not oid:
                                continue
                            current_price = rung.get(f'{unfilled_side}_price', 0)
                            if current_price <= 0:
                                continue
                            rung_anchor = rung.get(f'{filled_side}_price', avg_filled)
                            _rung_ceiling = bot.get('hard_ceiling', HARD_CEILING_CENTS)
                            combined = rung_anchor + current_price
                            max_hedge = _rung_ceiling - rung_anchor
                            past_ceiling = current_price >= max_hedge
                            rung_at_ceiling = rung_anchor + current_price >= _rung_ceiling
                            rung_snap_ready = _apex_snap_check(rung_anchor, unfilled_bid, rq, snap_ceiling=_apex_snap_ceiling) if unfilled_bid > 0 else False

                            # Same priority system as consolidated walk
                            if current_price > bid_target and bid_target > 0:
                                if rung_at_ceiling:
                                    new_price = bid_target
                                    rung_walk_type = 'ceiling_snap_down'
                                else:
                                    new_price = bid_target
                                    rung_walk_type = 'drop_to_bid'
                            elif rung_at_ceiling and bid_target > current_price:
                                new_price = bid_target
                                rung_walk_type = 'ceiling_snap'
                            elif rung_snap_ready and bid_target > current_price:
                                new_price = min(bid_target, max_hedge)
                                rung_walk_type = 'profit_snap'
                            elif bid_target > current_price:
                                walk_cap = min(bid_target, max_hedge)
                                new_price = min(current_price + 1, walk_cap)
                                rung_walk_type = 'normal_walk'
                            else:
                                new_price = current_price

                            if new_price == current_price or new_price <= 0:
                                continue
                            rung_idx = bot.get('rungs', []).index(rung) if rung in bot.get('rungs', []) else None
                            bot_log('APEX_WALK_ATTEMPT', bot_id, {
                                'walk_type': rung_walk_type, 'consolidated': False, 'rung_idx': rung_idx,
                                'old_price': current_price, 'new_price': new_price,
                                'unfilled_bid': unfilled_bid, 'max_hedge': max_hedge,
                                'anchor_price': rung_anchor, 'combined': rung_anchor + new_price,
                                'walk_interval': walk_interval, 'snap_ready': snap_ready,
                            })
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.amend_order(oid, ticker=ticker, side=unfilled_side,
                                                          count=rq, **{f'{unfilled_side}_price': new_price})
                                rung[f'{unfilled_side}_price'] = new_price
                                walked_any = True
                                bot_log('APEX_WALK_SUCCESS', bot_id, {
                                    'walk_type': rung_walk_type, 'rung_idx': rung_idx,
                                    'old_price': current_price, 'new_price': new_price,
                                })
                            except Exception as e:
                                bot_log('APEX_WALK_ERROR', bot_id, {
                                    'walk_type': rung_walk_type, 'rung_idx': rung_idx,
                                    'error': str(e)[:200],
                                })
                                print(f'❌ APEX WALK {bot_id} rung: {e}')

                    if walked_any:
                        walk_count = bot.get('walk_count', 0) + 1
                        bot['walk_count'] = walk_count
                        # Update compat fields with new average
                        _recompute_apex_fills(bot)
                        print(f'📈 APEX WALK: {bot_id} {unfilled_side.upper()} stepped (walk #{walk_count}) avg_{filled_side}={avg_filled}¢')

                bot['last_walk_at'] = now
                save_state()

        actions.append({
            'bot_id': bot_id, 'action': f'walking_{status}',
            'wait_min': round(wait_min, 1), 'walk_count': bot.get('walk_count', 0),
        })
        return


def _phantom_sell_back(bot_id, bot, dog_price, fav_bid, total_cost, actions):
    """Sell the filled dog leg back to recover capital when arb is dead."""
    now = time.time()
    ticker = bot['ticker']
    dog_side = bot['dog_side']
    qty = bot.get('quantity', 1)
    bot_log('PHANTOM_SELLBACK_START', bot_id, {
        'dog_price': dog_price, 'fav_bid': fav_bid, 'total_cost': total_cost,
        'qty': qty, 'dog_side': dog_side, 'ticker': ticker,
        'sellback_attempts': bot.get('_sellback_attempts', 0),
    })

    # Verify actual fill by checking the dog order on Kalshi (not positions —
    # positions are aggregate across all bots on the same ticker)
    dog_oid = bot.get('dog_order_id')
    _order_actual_fills = None
    if dog_oid:
        try:
            api_read_limiter.wait()
            resp = kalshi_client.get_order(dog_oid)
            ord_data = resp.get('order', resp) if isinstance(resp, dict) else {}
            _order_actual_fills = _parse_fill_count(ord_data)
            if _order_actual_fills == 0:
                # Dog order was cancelled/never filled (e.g. self-trade prevention) —
                # nothing to sell back, complete the bot with 0 cost
                print(f'✅ PHANTOM SELLBACK SKIP: {bot_id} dog order {dog_oid} has 0 fills on Kalshi — '
                      f'order was cancelled, no position to sell')
                bot_log('PHANTOM_SELLBACK_NO_FILLS', bot_id, {
                    'dog_order_id': dog_oid, 'order_status': ord_data.get('status', '?'),
                    'kalshi_status': ord_data.get('kalshi_status', '?'),
                }, level='WARN')
                # Record as 0-cost completion — no position was ever held
                _record_trade(bot_id, {
                    'result': 'anchor_sellback',
                    'ticker': ticker, 'dog_side': dog_side, 'fav_side': bot.get('fav_side', ''),
                    'dog_price': 0, 'fav_price': 0, 'profit_cents': 0, 'net_pnl_cents': 0,
                    'quantity': 0, 'sell_price': 0, 'loss_cents': 0, 'fees_cents': 0,
                    'timestamp': now, 'fill_source': 'anchor_sellback_no_fills',
                    'bot_category': 'anchor_dog',
                    'cross_market': bot.get('cross_market', False),
                    'hedge_ticker': bot.get('hedge_ticker', ''),
                }, bot)
                bot['status'] = 'completed'
                bot['completed_at'] = now
                save_state()
                actions.append({'bot_id': bot_id, 'action': 'sellback_no_fills'})
                return
            if _order_actual_fills != qty:
                print(f'⚠ PHANTOM SELLBACK ORDER CHECK: {bot_id} local={qty} Kalshi={_order_actual_fills} — using Kalshi')
                qty = _order_actual_fills
        except Exception as vf_err:
            print(f'⚠ PHANTOM SELLBACK order check failed: {bot_id}: {vf_err} — using local qty')

    sold_back, sell_info = execute_sell(ticker, dog_side, qty, reason=f'anchor_sellback_{bot_id}')

    if not sold_back:
        _attempts = bot.get('_sellback_attempts', 0) + 1
        bot['_sellback_attempts'] = _attempts
        # CRITICAL: clear hedge state so monitor doesn't deadlock at the
        # "if _hedge_fired and fav_order_id: return" guard
        bot['_hedge_fired'] = False
        bot['fav_order_id'] = None

        # If position_not_found and we verified the order DID fill, another bot
        # or emergency exit already cleared this position — record as 0-cost
        _sell_err = (sell_info or {}).get('error', '') if isinstance(sell_info, dict) else ''
        _pos_empty = (sell_info or {}).get('position_check_empty', False) if isinstance(sell_info, dict) else False
        if _pos_empty and _order_actual_fills is not None and _order_actual_fills > 0:
            print(f'✅ PHANTOM SELLBACK CLEARED: {bot_id} position gone but order had {_order_actual_fills} fills — '
                  f'another bot or emergency exit already sold. Recording 0-cost.')
            bot_log('PHANTOM_SELLBACK_ALREADY_CLEARED', bot_id, {
                'dog_price': dog_price, 'qty': qty, 'order_fills': _order_actual_fills,
            }, level='WARN')
            _record_trade(bot_id, {
                'result': 'anchor_sellback',
                'ticker': ticker, 'dog_side': dog_side, 'fav_side': bot.get('fav_side', ''),
                'dog_price': dog_price, 'fav_price': 0, 'profit_cents': 0, 'net_pnl_cents': 0,
                'quantity': qty, 'sell_price': dog_price, 'loss_cents': 0, 'fees_cents': 0,
                'timestamp': now, 'fill_source': 'anchor_sellback_position_cleared',
                'bot_category': 'anchor_dog',
                'cross_market': bot.get('cross_market', False),
                'hedge_ticker': bot.get('hedge_ticker', ''),
            }, bot)
            bot['status'] = 'completed'
            bot['completed_at'] = now
            save_state()
            actions.append({'bot_id': bot_id, 'action': 'sellback_position_cleared'})
            return

        # Max retry limit — don't retry forever
        if _attempts >= 5:
            print(f'⚠ PHANTOM SELLBACK MAX RETRIES: {bot_id} failed {_attempts} times — giving up')
            bot_log('PHANTOM_SELLBACK_MAX_RETRIES', bot_id, {
                'dog_price': dog_price, 'qty': qty, 'attempts': _attempts,
            }, level='ERROR')
            bot['status'] = 'stopped'
            bot['stopped_at'] = now
            save_state()
            actions.append({'bot_id': bot_id, 'action': 'sellback_max_retries'})
            return

        # Normal retry — keep alive for next monitor cycle
        print(f'⚠ PHANTOM SELLBACK FAILED: {bot_id} attempt {_attempts}/5 — retrying next cycle')
        bot['status'] = 'dog_filled'  # go back to dog_filled so monitor retries
        bot_log('PHANTOM_SELLBACK_FAILED', bot_id, {
            'dog_price': dog_price, 'qty': qty, 'dog_side': dog_side,
            'attempt': _attempts,
            'sell_info': str(sell_info)[:200] if sell_info else 'none',
        }, level='ERROR')
        _audit('PHANTOM_SELLBACK_FAIL', bot_id, {'ticker': ticker, 'dog_side': dog_side, 'attempt': _attempts})
        actions.append({'bot_id': bot_id, 'action': 'sellback_retry', 'attempt': _attempts})
        return

    already_cleared = (sell_info or {}).get('already_cleared', False)
    sell_price = sell_info.get('actual_fill_price') or sell_info.get('sell_price') or 0

    if already_cleared and not sell_price:
        print(f'🔙 PHANTOM SELLBACK: {bot_id} | position already cleared on Kalshi — recording 0 loss')
        loss_cents = 0
        sell_price = dog_price  # assume break-even
    else:
        loss_cents = (dog_price - sell_price) * qty if sell_price else dog_price * qty

    # Calculate fees: maker fee on original buy (post_only) + taker fee on sell (crosses spread)
    buy_fee = _kalshi_side_fee_cents(dog_price, qty)
    sell_fee = _kalshi_taker_side_fee_cents(sell_price, qty) if sell_price else 0
    total_fees = buy_fee + sell_fee
    loss_cents += total_fees

    # Handle profitable sellbacks (sell_price > dog_price minus fees)
    if loss_cents < 0:
        profit_cents = abs(loss_cents)
        loss_cents = 0
        session_pnl['gross_profit_cents'] = session_pnl.get('gross_profit_cents', 0) + profit_cents
        bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + profit_cents
    else:
        profit_cents = 0
        session_pnl['gross_loss_cents'] += loss_cents
        bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) - loss_cents

    session_pnl['stopped_bots'] += 1
    bot['_trade_recorded'] = True

    yes_p = dog_price if dog_side == 'yes' else (sell_price or fav_bid)
    no_p = dog_price if dog_side == 'no' else (sell_price or fav_bid)

    _record_trade({
        'bot_id': bot_id, 'ticker': ticker,
        'yes_price': yes_p, 'no_price': no_p,
        'quantity': qty,
        'profit_cents': profit_cents,
        'loss_cents': loss_cents,
        'fee_cents': total_fees,
        'result': 'anchor_sellback',
        'exit_via': f'sell_back_{dog_side}',
        'first_leg': dog_side,
        'dog_side': dog_side,
        'dog_price': dog_price,
        'fav_price': fav_bid,
        'sell_back_price': sell_price,
        'hard_ceiling_total': total_cost,
        'hedge_latency_ms': bot.get('hedge_latency_ms'),
        'raw_hedge_ms': bot.get('raw_hedge_ms'),
        'timestamp': now,
        'placed_at': bot.get('created_at', now),
        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
        'arb_width': bot.get('target_width', 0),
        'game_phase': bot.get('game_phase', 'live'),
        'game_context': _get_game_context(ticker),
        'fill_source': 'anchor_sellback',
        'bot_category': 'anchor_dog',
        'cross_market': bot.get('cross_market', False),
        'hedge_ticker': bot.get('hedge_ticker', ''),
    }, bot)
    bot_log('ANCHOR_SELLBACK', bot_id, {
        'dog_price': dog_price, 'sell_price': sell_price,
        'loss_cents': loss_cents, 'fav_bid': fav_bid,
    })
    print(f'🔙 PHANTOM SELLBACK: {bot_id} sold {dog_side}@{sell_price}¢ (bought@{dog_price}¢) loss={loss_cents}¢')
    _audit('PHANTOM_SELLBACK', bot_id, {'ticker': ticker, 'dog_side': dog_side, 'sell_price': sell_price, 'qty': qty, 'sold': True})
    _audit_position_check(bot_id, ticker, dog_side, 'after_sellback')

    # Verify no leftover positions from race condition fills
    try:
        api_read_limiter.wait()
        _pos_resp = kalshi_client.get_positions(ticker=ticker)
        _positions = _pos_resp.get('market_positions', _pos_resp.get('positions', []))
        _leftover = 0
        for _p in _positions:
            if _p.get('ticker') == ticker:
                # Only count positions on the dog side this bot was trading
                _pqty = _parse_position_qty(_p)
                if (dog_side == 'yes' and _pqty > 0) or (dog_side == 'no' and _pqty < 0):
                    _leftover = abs(_pqty)
        # Cap at this bot's qty — never sell more than we could own
        _leftover = min(_leftover, qty)
        if _leftover > 0:
            _sold, _sell_info = execute_sell(ticker, dog_side, _leftover,
                                             reason=f'phantom_sellback_leftover_{bot_id}')
            print(f'🔙 PHANTOM SELLBACK LEFTOVER: {bot_id} {_leftover} extra contracts cleared')
            bot_log('PHANTOM_SELLBACK_LEFTOVER', bot_id, {'leftover': _leftover})
    except Exception as _pe:
        print(f'⚠ PHANTOM SELLBACK LEFTOVER CHECK FAIL: {bot_id}: {_pe}')

    # Repeat logic — sellback counts as a cycle, re-anchor if repeats remain
    repeats_done_now = bot.get('repeats_done', 0) + 1
    bot['repeats_done'] = repeats_done_now
    repeat_total = bot.get('repeat_count', 0)
    if repeats_done_now <= repeat_total:
        bot['status'] = 'waiting_repeat'
        bot['waiting_repeat_since'] = now
        bot['dog_filled_at'] = None
        bot['raw_hedge_ms'] = None
        bot['hedge_latency_ms'] = None
        bot['fav_order_id'] = None
        bot['fav_fill_qty'] = 0
        bot['dog_fill_qty'] = 0
        bot['yes_fill_qty'] = 0
        bot['no_fill_qty'] = 0
        bot['_hedge_fired'] = False
        bot['_trade_recorded'] = False
        bot['_sellback_attempts'] = 0
        bot['_all_dog_order_ids'] = []  # clear so verify doesn't double-count prior repeats
        bot['_bid_at_post'] = bot.get(f'live_{dog_side}_bid', 0)
        bot['_last_repost_at'] = 0
        print(f'🔄 PHANTOM SELLBACK REPEAT: {bot_id} cycle {repeats_done_now}/{repeat_total} — re-anchoring')
    else:
        bot['status'] = 'stopped'
        bot['stopped_at'] = now

    save_state()
    actions.append({'bot_id': bot_id, 'action': 'anchor_sellback', 'loss_cents': loss_cents})


def _run_monitor():
    """Internal monitor logic — must only be called while holding monitor_lock."""
    try:
        # Auto-reset P&L if the date has changed
        auto_reset_daily_pnl()

        # ── Purge stale completed/stopped bots from active_bots ──
        # Keep them for 60s so the frontend sees the final state, then remove.
        _purge_cutoff = time.time() - 60
        _purge_ids = [bid for bid, b in active_bots.items()
                      if b.get('status') in ('completed', 'stopped', 'cancelled')
                      and b.get('completed_at', b.get('stopped_at', b.get('cancelled_at', 0))) < _purge_cutoff
                      and not b.get('repeat_count', 0) >= b.get('repeats_done', 0)]  # keep if repeats pending
        if _purge_ids:
            for _pid in _purge_ids:
                del active_bots[_pid]
            if len(_purge_ids) <= 5:
                print(f'🧹 Purged {len(_purge_ids)} stale bots: {[p[:25] for p in _purge_ids]}')
            else:
                print(f'🧹 Purged {len(_purge_ids)} stale bots')
            save_state()

        # ── Drift-cancelled smart wait: re-enter waiting_repeat if prices recover ──
        _now = time.time()
        for _bot_id, _bot in list(active_bots.items()):
            if _bot.get('status') == 'drift_cancelled':
                _tk = _bot.get('ticker', '')
                _ws = (ws_manager.get_price(_tk) if ws_manager else None) or {}
                _fy = _ws.get('yes_bid', 0) or 0
                _fn = _ws.get('no_bid', 0) or 0
                if _fy > 0 and _fn > 0 and max(_fy, _fn) < 80:
                    # Market came back — only re-enter if repeats remain
                    _repeats_done = _bot.get('repeats_done', 0)
                    _repeat_total = _bot.get('repeat_count', 0)
                    if _repeats_done < _repeat_total:
                        _bot['status'] = 'waiting_repeat'
                        _bot['waiting_repeat_since'] = _now
                        _bot.pop('drift_cancelled_at', None)
                        print(f'🔄 DRIFT RECOVERY: {_bot_id} Y={_fy}¢ N={_fn}¢ back < 80¢ — re-entering waiting_repeat')
                    else:
                        _bot['status'] = 'completed'
                        _bot['completed_at'] = _now
                        print(f'🏁 DRIFT RECOVERY SKIP: {_bot_id} no repeats left — marking completed')
                elif _now - _bot.get('drift_cancelled_at', _now) >= 300:
                    # Still drifted after 5 min — give up
                    _bot['status'] = 'completed'

        # Drain any WS-queued actions (completions, repeats) so the frontend sees them
        with _pending_ws_actions_lock:
            actions = list(_pending_ws_actions)
            _pending_ws_actions.clear()
        active_statuses = ('fav_posted', 'both_posted', 'pending_fills', 'yes_filled', 'no_filled', 'amending_no', 'amending_yes', 'watching', 'waiting_repeat', 'waiting', 'one_filled', 'both_filled', 'one_leg_timeout', 'dog_anchor_posted', 'dog_filled', 'fav_hedge_posted', 'ladder_posted', 'ladder_filled_no_fav', 'ladder_arb_posted', 'ladder_arb_yes_filled', 'ladder_arb_no_filled', 'apex_selling_back', 'awaiting_settlement')

        # ── Auto-phase: switch pregame → live when game is in progress ──
        for bot_id, bot in list(active_bots.items()):
            if bot.get('game_phase') == 'pregame' and bot['status'] in active_statuses:
                if bot.get('type') == 'watch':
                    continue
                try:
                    if _is_game_live(bot['ticker']):
                        bot['game_phase'] = 'live'
                        bot['posted_at'] = time.time()  # restart timeout counters
                        actions.append({'bot_id': bot_id, 'action': 'auto_phase_live'})
                        bot_log('AUTO_PHASE_LIVE', bot_id, {'reason': 'Kalshi expected_expiration within window'})
                        print(f'🏟 AUTO-PHASE: {bot_id} switched to LIVE (game in progress)')
                except Exception:
                    pass

        for bot_id, bot in list(active_bots.items()):
            if bot['status'] not in active_statuses:
                continue
            # Middle bots are handled separately below — skip them here
            if bot.get('type') == 'middle':
                continue

            # ── ANCHOR-DOG BOT HANDLING ──────────────────────────────
            if bot.get('bot_category') == 'anchor_dog':
                try:
                    _handle_phantom(bot_id, bot, actions)
                except Exception as ad_err:
                    print(f'❌ anchor_dog monitor {bot_id}: {ad_err}')
                continue

            # ── ANCHOR-LADDER BOT HANDLING ─────────────────────────────
            if bot.get('bot_category') == 'anchor_ladder':
                try:
                    _handle_phantom_ladder(bot_id, bot, actions)
                except Exception as al_err:
                    print(f'❌ anchor_ladder monitor {bot_id}: {al_err}')
                continue

            # ── LADDER-ARB BOT HANDLING ──────────────────────────────
            if bot.get('bot_category') == 'ladder_arb':
                try:
                    _handle_apex(bot_id, bot, actions)
                except Exception as la_err:
                    import traceback
                    print(f'❌ ladder_arb monitor {bot_id}: {la_err}\n{traceback.format_exc()}')
                continue

            try:
                ticker  = bot['ticker']
                qty     = bot.get('quantity', bot.get('qty', 1))  # arb bots use 'quantity'
                stop    = max(1, bot.get('stop_loss_cents', 5))  # enforce min 1¢
                now     = time.time()
                age_min = (now - bot.get('posted_at', now)) / 60.0
                phase   = bot.get('game_phase', 'pregame')

                # ── Settlement guard: skip if market is closed/settled ──
                if bot.get('type') != 'watch':  # arb bots only
                    try:
                        api_read_limiter.wait()
                        mkt_check = kalshi_client.get_market(ticker)
                        mkt_data = mkt_check.get('market', mkt_check)
                        mkt_status = mkt_data.get('status', 'active')
                        mkt_result = mkt_data.get('result', '')  # 'yes' or 'no' when settled
                        if mkt_status not in ('active', 'open'):
                            # Check fill status of each leg
                            try:
                                # Handle fav_posted bots where one order ID may be None
                                yes_f = 0
                                no_f = 0
                                if bot.get('yes_order_id'):
                                    api_read_limiter.wait()
                                    yes_resp_s = kalshi_client.get_order(bot['yes_order_id'])
                                    yes_ord_s = yes_resp_s.get('order', yes_resp_s) if isinstance(yes_resp_s, dict) else {}
                                    yes_f = _parse_fill_count(yes_ord_s)
                                if bot.get('no_order_id'):
                                    api_read_limiter.wait()
                                    no_resp_s = kalshi_client.get_order(bot['no_order_id'])
                                    no_ord_s = no_resp_s.get('order', no_resp_s) if isinstance(no_resp_s, dict) else {}
                                    no_f = _parse_fill_count(no_ord_s)
                            except Exception:
                                yes_f = bot.get('yes_fill_qty', 0)
                                no_f  = bot.get('no_fill_qty', 0)

                            if yes_f >= qty and no_f >= qty:
                                # Both legs filled — true completion, profit locked
                                if bot.get('_trade_recorded'):
                                    bot['status'] = 'completed'
                                    print(f'⚡ SETTLEMENT SKIP: {bot_id} — trade already recorded')
                                else:
                                    actual_yes = get_actual_fill_price(bot['yes_order_id'], 'yes')
                                    actual_no  = get_actual_fill_price(bot['no_order_id'], 'no')
                                    real_yes = actual_yes if actual_yes else bot['yes_price']
                                    real_no  = actual_no  if actual_no  else bot['no_price']
                                    _settle_fee = kalshi_fee_cents(real_yes, real_no, qty)
                                    profit_cents = (100 - real_yes - real_no) * qty - _settle_fee
                                    bot['status'] = 'completed'
                                    bot['completed_at'] = now
                                    orig_repeat_count = bot.get('repeat_count', 0)
                                    bot['repeat_count'] = 0
                                    session_pnl['gross_profit_cents'] += profit_cents
                                    session_pnl['completed_bots'] += 1
                                    bot['_trade_recorded'] = True
                                    _record_trade({
                                        'bot_id': bot_id, 'ticker': ticker,
                                        'yes_price': real_yes, 'no_price': real_no,
                                        'quantity': qty, 'profit_cents': profit_cents,
                                        'result': 'completed', 'timestamp': now,
                                        'note': f'market {mkt_status} — both legs filled',
                                        'game_phase': bot.get('game_phase', ''),
                                        'repeats_done': bot.get('repeats_done', 0),
                                        'repeat_count': orig_repeat_count,
                                    }, bot)
                                    bot_log('SETTLEMENT_COMPLETE', bot_id, {'profit_cents': profit_cents, 'real_yes': real_yes, 'real_no': real_no, 'market_status': mkt_status})
                                    print(f'🏁 SETTLED COMPLETE: {bot_id} — both legs filled, +{profit_cents}¢')
                            elif yes_f >= qty and no_f < qty:
                                # YES filled, NO never filled — check settlement result
                                if bot.get('no_order_id'):
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.cancel_order(bot['no_order_id'])
                                    except Exception:
                                        pass
                                orig_repeat_count = bot.get('repeat_count', 0)
                                bot['repeat_count'] = 0
                                if mkt_result == 'yes':
                                    # YES won — our YES position pays out 100¢ each
                                    _sfee = _kalshi_side_fee_cents(bot['yes_price'], yes_f)
                                    profit = (100 - bot['yes_price']) * yes_f - _sfee
                                    bot['status'] = 'completed'
                                    bot['completed_at'] = now
                                    session_pnl['gross_profit_cents'] += profit
                                    session_pnl['completed_bots'] += 1
                                    _record_trade({
                                        'bot_id': bot_id, 'ticker': ticker,
                                        'yes_price': bot['yes_price'], 'no_price': bot['no_price'],
                                        'quantity': yes_f, 'profit_cents': profit,
                                        'result': 'settled_win_yes', 'timestamp': now,
                                        'note': f'market settled YES — YES leg won, +{profit}¢',
                                        'game_phase': bot.get('game_phase', ''),
                                        'arb_width': bot.get('arb_width', 0),
                                        'first_leg': bot.get('first_leg', ''),
                                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                                        'repeats_done': bot.get('repeats_done', 0),
                                        'repeat_count': orig_repeat_count,
                                    }, bot)
                                    bot_log('SETTLEMENT_WIN', bot_id, {'leg': 'yes', 'filled_qty': yes_f, 'price': bot['yes_price'], 'profit_cents': profit, 'market_result': mkt_result})
                                    print(f'🏆 SETTLED WIN: {bot_id} — YES filled ({yes_f}×{bot["yes_price"]}¢), market settled YES, +{profit}¢')
                                else:
                                    # YES lost — we lose the cost
                                    bot['status'] = 'stopped'
                                    bot['stopped_at'] = now
                                    _sfee = _kalshi_side_fee_cents(bot['yes_price'], yes_f)
                                    loss = bot['yes_price'] * yes_f + _sfee
                                    session_pnl['gross_loss_cents'] += loss
                                    session_pnl['stopped_bots'] += 1
                                    _record_trade({
                                        'bot_id': bot_id, 'ticker': ticker,
                                        'yes_price': bot['yes_price'], 'no_price': bot['no_price'],
                                        'quantity': yes_f, 'loss_cents': loss,
                                        'result': 'settled_loss_yes', 'timestamp': now,
                                        'note': f'market settled {mkt_result or "NO"} — YES leg lost, -{loss}¢',
                                        'game_phase': bot.get('game_phase', ''),
                                        'arb_width': bot.get('arb_width', 0),
                                        'first_leg': bot.get('first_leg', ''),
                                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                                        'repeats_done': bot.get('repeats_done', 0),
                                        'repeat_count': orig_repeat_count,
                                    }, bot)
                                    bot_log('SETTLEMENT_LOSS', bot_id, {'leg': 'yes', 'filled_qty': yes_f, 'price': bot['yes_price'], 'loss_cents': loss, 'market_result': mkt_result})
                                    print(f'⚠ SETTLED LOSS: {bot_id} — YES filled ({yes_f}×{bot["yes_price"]}¢), market settled {mkt_result or "NO"}, -{loss}¢')
                            elif no_f >= qty and yes_f < qty:
                                # NO filled, YES never filled — check settlement result
                                if bot.get('yes_order_id'):
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.cancel_order(bot['yes_order_id'])
                                    except Exception:
                                        pass
                                orig_repeat_count = bot.get('repeat_count', 0)
                                bot['repeat_count'] = 0
                                if mkt_result == 'no':
                                    # NO won — our NO position pays out 100¢ each
                                    _sfee = _kalshi_side_fee_cents(bot['no_price'], no_f)
                                    profit = (100 - bot['no_price']) * no_f - _sfee
                                    bot['status'] = 'completed'
                                    bot['completed_at'] = now
                                    session_pnl['gross_profit_cents'] += profit
                                    session_pnl['completed_bots'] += 1
                                    _record_trade({
                                        'bot_id': bot_id, 'ticker': ticker,
                                        'yes_price': bot['yes_price'], 'no_price': bot['no_price'],
                                        'quantity': no_f, 'profit_cents': profit,
                                        'result': 'settled_win_no', 'timestamp': now,
                                        'note': f'market settled NO — NO leg won, +{profit}¢',
                                        'game_phase': bot.get('game_phase', ''),
                                        'arb_width': bot.get('arb_width', 0),
                                        'first_leg': bot.get('first_leg', ''),
                                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                                        'repeats_done': bot.get('repeats_done', 0),
                                        'repeat_count': orig_repeat_count,
                                    }, bot)
                                    bot_log('SETTLEMENT_WIN', bot_id, {'leg': 'no', 'filled_qty': no_f, 'price': bot['no_price'], 'profit_cents': profit, 'market_result': mkt_result})
                                    print(f'🏆 SETTLED WIN: {bot_id} — NO filled ({no_f}×{bot["no_price"]}¢), market settled NO, +{profit}¢')
                                else:
                                    # NO lost — we lose the cost
                                    bot['status'] = 'stopped'
                                    bot['stopped_at'] = now
                                    _sfee = _kalshi_side_fee_cents(bot['no_price'], no_f)
                                    loss = bot['no_price'] * no_f + _sfee
                                    session_pnl['gross_loss_cents'] += loss
                                    session_pnl['stopped_bots'] += 1
                                    _record_trade({
                                        'bot_id': bot_id, 'ticker': ticker,
                                        'yes_price': bot['yes_price'], 'no_price': bot['no_price'],
                                        'quantity': no_f, 'loss_cents': loss,
                                        'result': 'settled_loss_no', 'timestamp': now,
                                        'note': f'market settled {mkt_result or "YES"} — NO leg lost, -{loss}¢',
                                        'game_phase': bot.get('game_phase', ''),
                                        'arb_width': bot.get('arb_width', 0),
                                        'first_leg': bot.get('first_leg', ''),
                                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                                        'repeats_done': bot.get('repeats_done', 0),
                                        'repeat_count': orig_repeat_count,
                                    }, bot)
                                    bot_log('SETTLEMENT_LOSS', bot_id, {'leg': 'no', 'filled_qty': no_f, 'price': bot['no_price'], 'loss_cents': loss, 'market_result': mkt_result})
                                    print(f'⚠ SETTLED LOSS: {bot_id} — NO filled ({no_f}×{bot["no_price"]}¢), market settled {mkt_result or "YES"}, -{loss}¢')
                            else:
                                # Neither leg filled — no cost, just clean up
                                bot['status'] = 'completed'
                                bot['completed_at'] = now
                                bot_log('SETTLEMENT_CLEAN', bot_id, {'market_status': mkt_status})
                                print(f'🏁 MARKET SETTLED: {bot_id} — no fills, clean exit')
                            actions.append({'bot_id': bot_id, 'action': 'market_settled', 'market_status': mkt_status})
                            save_state()
                            continue
                    except Exception:
                        pass  # If API fails, proceed with normal monitoring

                # ── BOTH_POSTED: both orders are live simultaneously ─────────
                if bot.get('status') == 'both_posted':
                    # Update live prices from WebSocket then fall through to
                    # the normal fill-check / repost / timeout logic below.
                    try:
                        ws_p = ws_manager.get_price(ticker)
                        if ws_p:
                            _bp_yb = ws_p.get('yes_bid', 0)
                            _bp_nb = ws_p.get('no_bid', 0)
                            bot['live_yes_bid'] = _bp_yb
                            bot['live_no_bid']  = _bp_nb
                            bot['live_yes_ask'] = ws_p.get('yes_ask', 0) or (100 - _bp_nb if _bp_nb > 0 else 0)
                            bot['live_no_ask']  = ws_p.get('no_ask',  0) or (100 - _bp_yb if _bp_yb > 0 else 0)
                            bot['last_price_update'] = now
                    except Exception:
                        pass
                    # Don't continue — fall through to fill-check code below

                # ── FAV-FIRST: favorite order posted, waiting for fill ────
                if bot.get('status') == 'fav_posted':
                    # Skip if WS fill handler is already processing this bot
                    if bot.get('_ws_fill_handling'):
                        print(f'⚡ SKIPPING monitor fav check for {bot_id} — WS real-time already handling')
                        continue
                    fav_side = bot.get('fav_side', 'yes')
                    fav_order_id = bot.get('fav_order_id')
                    if not fav_order_id:
                        # Legacy bot without fav_posted data — skip
                        bot['status'] = 'pending_fills'
                        continue

                    # Check fill status of favorite order
                    try:
                        api_read_limiter.wait()
                        fav_resp = kalshi_client.get_order(fav_order_id)
                        fav_ord = fav_resp.get('order', fav_resp) if isinstance(fav_resp, dict) else {}
                        fav_filled = _parse_fill_count(fav_ord)
                    except Exception as fav_err:
                        print(f'⚠ Fav order check failed for {bot_id}: {fav_err}')
                        continue

                    if fav_filled >= qty:
                        # ── Favorite filled! Now post the underdog ──
                        dog_side = bot.get('dog_side', 'no' if fav_side == 'yes' else 'yes')
                        dog_price = bot.get('dog_price', bot['no_price'] if dog_side == 'no' else bot['yes_price'])

                        # Fetch fresh orderbook to verify arb is still viable
                        try:
                            api_read_limiter.wait()
                            ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
                            ob = ob_data.get('orderbook', ob_data)
                            if dog_side == 'no':
                                dog_levels = sorted(ob.get('no', []),
                                    key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                                live_dog_bid = (dog_levels[0][0] if isinstance(dog_levels[0], list) else dog_levels[0].get('price', 0)) if dog_levels else 0
                            else:
                                dog_levels = sorted(ob.get('yes', []),
                                    key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                                live_dog_bid = (dog_levels[0][0] if isinstance(dog_levels[0], list) else dog_levels[0].get('price', 0)) if dog_levels else 0

                            # NEVER post above the current bid
                            if dog_price > live_dog_bid and live_dog_bid > 0:
                                dog_price = live_dog_bid
                                print(f'📉 Adjusted {dog_side.upper()} price to bid {live_dog_bid}¢ (was {bot.get("dog_price")}¢)')
                        except Exception as ob_err:
                            print(f'⚠ Orderbook check for underdog failed: {ob_err} — using planned price')

                        # Verify arb width still makes sense
                        fav_price = bot.get('fav_price', bot['yes_price'] if fav_side == 'yes' else bot['no_price'])
                        actual_profit = 100 - fav_price - dog_price
                        min_width = max(1, bot.get('arb_width', bot.get('profit_per', 3)) // 2)  # accept half the target width
                        if actual_profit < min_width:
                            print(f'⚠ FAV-FIRST arb no longer viable: {fav_side}@{fav_price} + {dog_side}@{dog_price} = {fav_price+dog_price}¢ '
                                  f'(profit {actual_profit}¢ < min {min_width}¢) — will SL the favorite')
                            # Arb collapsed — don't post underdog, let SL handle the filled favorite
                            if fav_side == 'yes':
                                bot['status'] = 'yes_filled'
                                bot['yes_fill_qty'] = fav_filled
                            else:
                                bot['status'] = 'no_filled'
                                bot['no_fill_qty'] = fav_filled
                            bot['first_fill_at'] = now
                            bot['first_leg'] = fav_side
                            bot['posted_at'] = now
                            continue

                        # Post the underdog order
                        try:
                            api_rate_limiter.wait()
                            if dog_side == 'no':
                                dog_order = kalshi_client.create_order(
                                    ticker=ticker, side='no', action='buy',
                                    count=qty, no_price=dog_price, post_only=True)
                                dog_oid = _extract_order_id(dog_order, f'monitor phantom dog post {bot_id}')
                                if not dog_oid:
                                    continue
                                bot['no_order_id'] = dog_oid
                                bot['no_price'] = dog_price
                                bot['yes_fill_qty'] = fav_filled
                                bot['status'] = 'yes_filled'
                            else:
                                dog_order = kalshi_client.create_order(
                                    ticker=ticker, side='yes', action='buy',
                                    count=qty, yes_price=dog_price, post_only=True)
                                dog_oid = _extract_order_id(dog_order, f'monitor phantom dog post {bot_id}')
                                if not dog_oid:
                                    continue
                                bot['yes_order_id'] = dog_oid
                                bot['yes_price'] = dog_price
                                bot['no_fill_qty'] = fav_filled
                                bot['status'] = 'no_filled'

                            bot['first_fill_at'] = now
                            bot['first_leg'] = fav_side
                            bot['posted_at'] = now
                            bot['profit_per'] = 100 - bot['yes_price'] - bot['no_price']

                            bot_log('FAV_FILLED_DOG_POSTED', bot_id, {'fav_side': fav_side, 'fav_price': fav_price, 'dog_side': dog_side, 'dog_price': dog_price, 'profit_per': bot['profit_per']})
                            print(f'🎯 FAV-FIRST FILL: {bot_id} {fav_side.upper()} filled at {fav_price}¢ → '
                                  f'posted {dog_side.upper()} at {dog_price}¢ '
                                  f'(profit target: {bot["profit_per"]}¢)')
                            actions.append({'bot_id': bot_id, 'action': 'fav_filled_dog_posted',
                                           'fav_side': fav_side, 'fav_price': fav_price,
                                           'dog_side': dog_side, 'dog_price': dog_price,
                                           'profit_per': bot['profit_per']})
                            save_state()
                        except Exception as dog_err:
                            print(f'⚠ Underdog order failed for {bot_id}: {dog_err} — will retry next cycle')
                    else:
                        # Favorite not yet filled — check for repost if stale
                        if phase == 'live' and age_min >= REPOST_AFTER_MINUTES:
                            # Repost favorite at current bid (never above)
                            try:
                                ws_price = ws_manager.get_price(ticker)
                                if ws_price:
                                    cur_fav_bid = ws_price.get(f'{fav_side}_bid', 0)
                                else:
                                    api_read_limiter.wait()
                                    mkt = kalshi_client.get_market(ticker)
                                    m = mkt.get('market', mkt)
                                    d = m.get(f'{fav_side}_bid_dollars')
                                    cur_fav_bid = round(float(d) * 100) if d else m.get(f'{fav_side}_bid', 0)

                                # If bid is AT or BELOW our order price, market is moving toward us
                                # (or already there) — the order will fill naturally. Don't repost.
                                # If bid is ABOVE our order price, the market has moved on and our
                                # order is stale/buried — repost at the new level to stay competitive.
                                if cur_fav_bid <= bot['fav_price']:
                                    print(f'⏳ FAV REPOST SKIPPED: {bot_id} bid {cur_fav_bid}¢ <= order {bot["fav_price"]}¢ — market closing toward us, leaving alone')
                                    bot['posted_at'] = now  # reset timer so we re-check in another 3 min
                                    save_state()
                                    continue

                                # Width-aware cap: use the CURRENT live dog-side bid, not the
                                # stale stored price from deployment. Market may have moved
                                # (e.g. YES 79→99, NO 12→1) so we must re-check live.
                                # fav_cap = 100 - live_dog_bid - min_width
                                dog_side_rp  = 'no' if fav_side == 'yes' else 'yes'
                                min_width_rp = bot.get('arb_width', bot.get('profit_per', 3))
                                # Get current dog bid from ws_price (already fetched above) or market
                                if ws_price:
                                    cur_dog_bid = ws_price.get(f'{dog_side_rp}_bid', 0)
                                else:
                                    cur_dog_bid = 0
                                    try:
                                        _m2 = kalshi_client.get_market(ticker)
                                        _mk2 = _m2.get('market', _m2)
                                        _d2 = _mk2.get(f'{dog_side_rp}_bid_dollars')
                                        cur_dog_bid = round(float(_d2) * 100) if _d2 else _mk2.get(f'{dog_side_rp}_bid', 0)
                                    except Exception:
                                        pass
                                # If dog bid is 0, the game is over — no hedge possible.
                                # Cancel the fav and exit instead of reposting into a dead market.
                                if cur_dog_bid == 0:
                                    print(f'🏁 FAV REPOST ABORTED: {bot_id} {dog_side_rp.upper()} bid=0¢ — game likely over, cancelling')
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.cancel_order(fav_order_id)
                                    except Exception:
                                        pass
                                    bot['status'] = 'completed'
                                    bot['completed_at'] = now
                                    bot_log('FAV_NO_HEDGE_MARKET', bot_id, {'fav_side': fav_side, 'dog_side': dog_side_rp, 'fav_bid': cur_fav_bid})
                                    actions.append({'bot_id': bot_id, 'action': 'fav_no_hedge_cancelled'})
                                    save_state()
                                    continue
                                max_fav_for_width = 100 - cur_dog_bid - min_width_rp
                                new_fav_price = min(cur_fav_bid, 98, max_fav_for_width) if cur_fav_bid > 0 else bot['fav_price']
                                new_fav_price = max(1, new_fav_price)
                                # Falling knife guard: don't repost fav below MIN_FAV_ENTRY_CENTS
                                if new_fav_price < MIN_FAV_ENTRY_CENTS:
                                    print(f'🔪 FAV REPOST BLOCKED: {bot_id} {fav_side.upper()} bid={new_fav_price}¢ < {MIN_FAV_ENTRY_CENTS}¢ — falling knife, cancelling')
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.cancel_order(fav_order_id)
                                    except Exception:
                                        pass
                                    bot['status'] = 'completed'
                                    bot['completed_at'] = now
                                    bot_log('FAV_FALLING_KNIFE', bot_id, {'fav_side': fav_side, 'bid': new_fav_price, 'min': MIN_FAV_ENTRY_CENTS})
                                    actions.append({'bot_id': bot_id, 'action': 'fav_falling_knife_cancelled'})
                                    save_state()
                                    continue
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(fav_order_id)
                                api_rate_limiter.wait()
                                if fav_side == 'yes':
                                    new_fav = kalshi_client.create_order(
                                        ticker=ticker, side='yes', action='buy',
                                        count=qty, yes_price=new_fav_price, post_only=True)
                                else:
                                    new_fav = kalshi_client.create_order(
                                        ticker=ticker, side='no', action='buy',
                                        count=qty, no_price=new_fav_price, post_only=True)
                                new_fav_id = _extract_order_id(new_fav, f'fav repost {bot_id}')
                                if not new_fav_id:
                                    continue
                                bot['fav_order_id'] = new_fav_id
                                if fav_side == 'yes':
                                    bot['yes_order_id'] = new_fav_id
                                    bot['yes_price'] = new_fav_price
                                    bot['fav_price'] = new_fav_price
                                else:
                                    bot['no_order_id'] = new_fav_id
                                    bot['no_price'] = new_fav_price
                                    bot['fav_price'] = new_fav_price
                                bot['posted_at'] = now
                                bot['repost_count'] = bot.get('repost_count', 0) + 1
                                bot_log('FAV_REPOSTED', bot_id, {'fav_side': fav_side, 'new_price': new_fav_price, 'repost_count': bot['repost_count']})
                                print(f'🔄 FAV REPOST: {bot_id} {fav_side.upper()} at {new_fav_price}¢ '
                                      f'(repost #{bot["repost_count"]})')
                                actions.append({'bot_id': bot_id, 'action': 'fav_reposted',
                                               'fav_side': fav_side, 'new_price': new_fav_price})
                            except Exception as rp_err:
                                print(f'⚠ Fav repost failed for {bot_id}: {rp_err}')

                        # Game ending: cancel unfilled bot immediately
                        elif phase == 'live' and _is_game_ending(ticker):
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(fav_order_id)
                            except Exception:
                                pass
                            bot['status'] = 'completed'
                            bot['completed_at'] = now
                            bot_log('GAME_ENDING_CANCEL', bot_id, {'fav_side': fav_side})
                            print(f'🏁 GAME ENDING: {bot_id} unfilled — cancelled')
                            actions.append({'bot_id': bot_id, 'action': 'game_ending_cancel'})

                        # Cancel unfilled favorite after STALE_CANCEL_MINUTES if live
                        elif phase == 'live' and age_min >= STALE_CANCEL_MINUTES:
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(fav_order_id)
                            except Exception:
                                pass
                            bot['status'] = 'completed'
                            bot['completed_at'] = now
                            bot_log('FAV_STALE_CANCELLED', bot_id, {'fav_side': fav_side, 'age_min': round(age_min, 1)})
                            print(f'⏰ FAV STALE: {bot_id} favorite {fav_side.upper()} unfilled after {age_min:.1f}m — cancelled')
                            actions.append({'bot_id': bot_id, 'action': 'fav_stale_cancelled'})

                        # Store live prices for frontend display even while waiting
                        try:
                            ws_p = ws_manager.get_price(ticker)
                            if ws_p:
                                _fp_yb = ws_p.get('yes_bid', 0)
                                _fp_nb = ws_p.get('no_bid', 0)
                                bot['live_yes_bid'] = _fp_yb
                                bot['live_no_bid']  = _fp_nb
                                bot['live_yes_ask'] = ws_p.get('yes_ask', 0) or (100 - _fp_nb if _fp_nb > 0 else 0)
                                bot['live_no_ask']  = ws_p.get('no_ask',  0) or (100 - _fp_yb if _fp_yb > 0 else 0)
                            else:
                                api_read_limiter.wait()
                                _m = kalshi_client.get_market(ticker)
                                _mk = _m.get('market', _m)
                                def _tc(f):
                                    d = _mk.get(f + '_dollars')
                                    if d: return round(float(d) * 100)
                                    return _mk.get(f, 0)
                                bot['live_yes_bid'] = _tc('yes_bid')
                                bot['live_no_bid']  = _tc('no_bid')
                                _rest_yb = _tc('yes_bid')
                                _rest_nb = _tc('no_bid')
                                bot['live_yes_ask'] = _tc('yes_ask') or (100 - _rest_nb if _rest_nb > 0 else 0)
                                bot['live_no_ask']  = _tc('no_ask')  or (100 - _rest_yb if _rest_yb > 0 else 0)
                            bot['last_price_update'] = now
                        except Exception:
                            pass
                    continue

                # ── Watch Bots: monitor existing positions ───────────
                if bot.get('type') == 'watch':
                    watch_side = bot.get('side', 'yes')
                    entry = bot.get('entry_price', 50)
                    sl = bot.get('stop_loss_cents', 5)
                    tp = bot.get('take_profit_cents', 0)
                    has_sl_tp = bot.get('has_sl_tp', sl > 0 or tp > 0)

                    # ── Settlement guard for watch bots ──────────────
                    try:
                        api_read_limiter.wait()
                        mkt_check_w = kalshi_client.get_market(ticker)
                        mkt_status_w = mkt_check_w.get('market', mkt_check_w).get('status', 'active')
                        if mkt_status_w not in ('active', 'open'):
                            if not bot.get('order_filled', False):
                                # Order never filled on a settled market — cancel & clean up
                                if bot.get('order_id'):
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.cancel_order(bot['order_id'])
                                    except Exception:
                                        pass
                                bot['status'] = 'stopped'
                                bot['stopped_at'] = now
                                bot_log('WATCH_SETTLED_UNFILLED', bot_id, {'market_status': mkt_status_w})
                                print(f'🏁 WATCH SETTLED (unfilled): {bot_id} — market {mkt_status_w}, order never filled')
                                actions.append({'bot_id': bot_id, 'action': 'watch_settled_unfilled'})
                                save_state()
                                continue
                            else:
                                # Position was filled — market settled, Kalshi auto-settles it
                                mkt_data_w  = mkt_check_w.get('market', mkt_check_w)
                                mkt_result_w = mkt_data_w.get('result', '').lower()  # 'yes' or 'no'
                                watch_side  = bot.get('side', 'yes')
                                entry       = bot.get('entry_price', 50)
                                qty         = bot.get('quantity', 1)
                                won = (mkt_result_w == watch_side) if mkt_result_w else None
                                if won is True:
                                    profit_cents = (100 - entry) * qty
                                    loss_cents   = 0
                                    res_label    = 'take_profit_watch'
                                    session_pnl['gross_profit_cents'] += profit_cents
                                    session_pnl['completed_bots']     += 1
                                elif won is False:
                                    profit_cents = 0
                                    loss_cents   = entry * qty
                                    res_label    = 'stop_loss_watch'
                                    session_pnl['gross_loss_cents'] += loss_cents
                                    session_pnl['stopped_bots']     += 1
                                else:
                                    # Result unknown yet — don't complete, retry next cycle
                                    print(f'⏳ WATCH SETTLED (no result yet): {bot_id} market={mkt_status_w} — waiting for result')
                                    continue
                                if mkt_result_w:  # only record if we have a result
                                    _record_trade({
                                        'bot_id': bot_id, 'ticker': ticker,
                                        'side': watch_side, 'entry_price': entry,
                                        'quantity': qty,
                                        'profit_cents': profit_cents,
                                        'loss_cents': loss_cents,
                                        'result': res_label,
                                        'timestamp': now,
                                        'placed_at': bot.get('created_at', now),
                                        'type': 'watch',
                                    }, bot)
                                bot['status'] = 'completed'
                                bot['completed_at'] = now
                                bot_log('WATCH_SETTLED_FILLED', bot_id, {'market_status': mkt_status_w, 'result': mkt_result_w, 'won': won})
                                print(f'🏁 WATCH SETTLED (filled): {bot_id} — {mkt_result_w} won, {"profit" if won else "loss"} recorded')
                                actions.append({'bot_id': bot_id, 'action': 'watch_settled_filled'})
                                save_state()
                                continue
                    except Exception as ws_err:
                        pass  # If API fails, proceed with normal monitoring

                    # ── Manual watch bots (no order_id) are pre-filled positions ──
                    if not bot.get('order_id'):
                        if not bot.get('order_filled'):
                            bot['order_filled'] = True
                            bot['filled_at'] = now
                            bot['has_sl_tp'] = True
                            has_sl_tp = True
                            save_state()
                            print(f'👁 Watch {bot_id}: manual position — marking as filled')

                    # ── Step 1: Check if the limit order has filled ──
                    if not bot.get('order_filled', False) and bot.get('order_id'):
                        try:
                            api_read_limiter.wait()
                            order_check = kalshi_client.get_order(bot['order_id'])
                            order_obj = order_check.get('order', order_check)
                            filled_qty = _parse_fill_count(order_obj)
                            bot['fill_qty'] = filled_qty
                            order_status = order_obj.get('status', '')

                            if filled_qty >= qty:
                                bot['order_filled'] = True
                                bot['filled_at'] = now
                                # Sync quantity to actual Kalshi position (user may have
                                # had fewer contracts than they ordered)
                                try:
                                    api_read_limiter.wait()
                                    pos_resp = kalshi_client.get_positions(ticker=ticker)
                                    positions = pos_resp.get('market_positions', [])
                                    actual_pos = 0
                                    for p in positions:
                                        if watch_side == 'yes':
                                            actual_pos = max(actual_pos, p.get('yes_contracts', 0) + p.get('total_traded', 0) if p.get('yes_contracts', 0) > 0 else p.get('yes_contracts', 0))
                                        else:
                                            actual_pos = max(actual_pos, p.get('no_contracts', 0))
                                    if watch_side == 'yes':
                                        actual_pos = max(0, sum(p.get('yes_contracts', 0) for p in positions))
                                    else:
                                        actual_pos = max(0, sum(p.get('no_contracts', 0) for p in positions))
                                    if actual_pos > 0 and actual_pos != qty:
                                        print(f'🔄 Watch {bot_id}: syncing qty {qty}→{actual_pos} (actual position)')
                                        bot['quantity'] = actual_pos
                                except Exception as pos_err:
                                    print(f'⚠ Position sync for {bot_id}: {pos_err}')
                                actions.append({
                                    'bot_id': bot_id, 'action': 'straight_bet_filled',
                                    'ticker': ticker, 'side': watch_side,
                                    'price': entry, 'quantity': qty
                                })
                                bot_log('WATCH_ORDER_FILLED', bot_id, {'side': watch_side, 'qty': qty, 'entry': entry})
                                print(f'💰 STRAIGHT BET FILLED: {bot_id} — {watch_side.upper()} {qty}× at {entry}¢')
                                save_state()
                            elif order_status in ('canceled', 'cancelled', 'expired', 'declined'):
                                # Order was cancelled/expired — remove tracker
                                bot['status'] = 'stopped'
                                bot['stopped_at'] = now
                                actions.append({
                                    'bot_id': bot_id, 'action': 'straight_bet_cancelled',
                                    'ticker': ticker, 'side': watch_side
                                })
                                bot_log('WATCH_ORDER_CANCELLED', bot_id, {'order_status': order_status})
                                print(f'❌ STRAIGHT BET CANCELLED: {bot_id} — {order_status}')
                                save_state()
                                continue
                        except Exception as fill_err:
                            print(f'⚠ Fill check error for {bot_id}: {fill_err}')

                    # ── Step 2: Always fetch live bid (even pre-fill) so UI shows it ──
                    try:
                        ws_price_pre = ws_manager.get_price(ticker)
                        if ws_price_pre:
                            bot['live_bid'] = ws_price_pre.get(f'{watch_side}_bid', 0)
                        else:
                            api_read_limiter.wait()
                            mkt_pre = kalshi_client.get_market(ticker)
                            mkt_pre_data = mkt_pre.get('market', mkt_pre)
                            d_pre = mkt_pre_data.get(f'{watch_side}_bid_dollars')
                            if d_pre:
                                bot['live_bid'] = round(float(d_pre) * 100)
                            else:
                                bot['live_bid'] = mkt_pre_data.get(f'{watch_side}_bid', 0)
                        bot['last_price_update'] = now
                    except Exception as bid_err:
                        print(f'⚠ Watch live_bid fetch for {bot_id}: {bid_err}')

                    # If order hasn't filled yet, skip SL/TP monitoring
                    if not bot.get('order_filled', False):
                        continue

                    # ── Step 3: If no SL/TP configured, just keep watching (track until settlement) ──
                    if not has_sl_tp:
                        continue

                    # Use the live_bid we already fetched above
                    cur_bid = bot.get('live_bid', 0)

                    # Stop-loss: sell at 1¢ (gets price improvement to actual bid)
                    if cur_bid <= entry - sl:
                        # ── REST VERIFY: double-check bid via REST API before firing ──
                        # WS can send stale/incorrect bids (e.g. Clowney 15+ showed 21¢
                        # when real bid was 60¢). One REST call prevents false SL fires.
                        try:
                            api_read_limiter.wait()
                            mkt_verify = kalshi_client.get_market(ticker)
                            mkt_v_data = mkt_verify.get('market', mkt_verify)
                            d_verify = mkt_v_data.get(f'{watch_side}_bid_dollars')
                            if d_verify:
                                rest_bid = round(float(d_verify) * 100)
                            else:
                                rest_bid = mkt_v_data.get(f'{watch_side}_bid', 0)
                            if rest_bid > entry - sl:
                                # REST says bid is actually fine — WS was stale
                                bot_log('SL_BLOCKED_STALE_WS', bot_id, {'ws_bid': cur_bid, 'rest_bid': rest_bid, 'trigger': entry - sl}, level='WARN')
                                print(f'🛡 WATCH SL BLOCKED: {bot_id} WS bid {cur_bid}¢ but REST bid {rest_bid}¢ > trigger {entry - sl}¢ — WS was stale')
                                bot['live_bid'] = rest_bid  # correct the cached bid
                                cur_bid = rest_bid
                                actions.append({'bot_id': bot_id, 'action': 'watch_sl_blocked_stale_ws',
                                               'ws_bid': bot.get('live_bid', 0), 'rest_bid': rest_bid})
                                # Skip this SL — bid is not actually breached
                            else:
                                # REST confirms SL breach — update cur_bid to REST value
                                bot_log('SL_CONFIRMED_REST', bot_id, {'rest_bid': rest_bid, 'trigger': entry - sl, 'ws_bid': cur_bid})
                                print(f'✅ WATCH SL CONFIRMED: {bot_id} REST bid {rest_bid}¢ ≤ trigger {entry - sl}¢ (WS was {cur_bid}¢)')
                                cur_bid = rest_bid
                                bot['live_bid'] = rest_bid
                        except Exception as rest_err:
                            print(f'⚠ Watch SL REST verify failed for {bot_id}: {rest_err} — proceeding with WS bid')

                        # Re-check after REST verify — bid may have been corrected
                        if cur_bid > entry - sl:
                            continue

                        # SAFETY: re-check bot hasn't already been stopped
                        if bot['status'] in ('stopped', 'completed'):
                            print(f'⛔ SKIPPING duplicate watch SL for {bot_id} — already {bot["status"]}')
                            continue
                        sold, sell_info = execute_sell(ticker, watch_side, qty, reason=f'watch_SL_{bot_id}')
                        if sold:
                            actual_sell = sell_info.get('actual_fill_price') or sell_info.get('sell_price', cur_bid)
                            loss = (entry - actual_sell) * qty
                            bot['status'] = 'stopped'
                            bot['stopped_at'] = now
                            session_pnl['gross_loss_cents'] += loss
                            session_pnl['stopped_bots'] += 1
                            _record_trade({
                        'bot_id': bot_id, 'ticker': ticker, 'type': 'watch',
                        'side': watch_side, 'entry_price': entry,
                        'exit_bid': actual_sell, 'quantity': qty,
                        'loss_cents': loss, 'result': 'stop_loss_watch',
                        'timestamp': now,
                        'placed_at': bot.get('created_at', now),
                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                        'stop_loss_cents': sl,
                        'game_context': _get_game_context(ticker),
                    }, bot)
                            actions.append({'bot_id': bot_id, 'action': 'stop_loss_watch',
                                           'loss_cents': loss})
                            bot_log('WATCH_SL_FIRED', bot_id, {'entry': entry, 'exit': actual_sell, 'loss_cents': loss, 'sl_trigger': entry - sl, 'live_bid': cur_bid})
                        else:
                            bot_log('WATCH_SL_FAILED', bot_id, {'sell_info': str(sell_info)}, level='ERROR')
                            print(f'⚠ Watch SL sell FAILED for {bot_id} — will retry next cycle')
                            actions.append({'bot_id': bot_id, 'action': 'stop_loss_watch_FAILED',
                                           'info': str(sell_info)})
                    # Take-profit
                    elif tp > 0 and cur_bid >= entry + tp:
                        # SAFETY: re-check bot hasn't already been stopped
                        if bot['status'] in ('stopped', 'completed'):
                            print(f'⛔ SKIPPING duplicate watch TP for {bot_id} — already {bot["status"]}')
                            continue
                        sold, sell_info = execute_sell(ticker, watch_side, qty, reason=f'watch_TP_{bot_id}')
                        if sold:
                            actual_sell = sell_info.get('actual_fill_price') or sell_info.get('sell_price', cur_bid)
                            profit = (actual_sell - entry) * qty
                            bot['status'] = 'completed'
                            bot['completed_at'] = now
                            session_pnl['gross_profit_cents'] += profit
                            session_pnl['completed_bots'] += 1
                            _record_trade({
                        'bot_id': bot_id, 'ticker': ticker, 'type': 'watch',
                        'side': watch_side, 'entry_price': entry,
                        'exit_bid': actual_sell, 'quantity': qty,
                        'profit_cents': profit, 'result': 'take_profit_watch',
                        'timestamp': now,
                        'placed_at': bot.get('created_at', now),
                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                        'stop_loss_cents': sl,
                        'take_profit_cents': tp,
                        'game_context': _get_game_context(ticker),
                    }, bot)
                            actions.append({'bot_id': bot_id, 'action': 'take_profit_watch',
                                           'profit_cents': profit})
                            bot_log('WATCH_TP_FIRED', bot_id, {'entry': entry, 'exit': actual_sell, 'profit_cents': profit, 'tp_trigger': entry + tp, 'live_bid': cur_bid})
                        else:
                            bot_log('WATCH_TP_FAILED', bot_id, {'sell_info': str(sell_info)}, level='ERROR')
                            print(f'⚠ Watch TP sell FAILED for {bot_id} — will retry next cycle')
                            actions.append({'bot_id': bot_id, 'action': 'take_profit_watch_FAILED',
                                           'info': str(sell_info)})
                    continue

                # ── WAITING REPEAT: keep checking for spread to reopen ─────
                if bot['status'] == 'waiting_repeat':
                    target_width = bot.get('arb_width', bot.get('profit_per', 5))
                    wait_age_min = (now - bot.get('waiting_repeat_since', now)) / 60.0

                    # Pause the wait timer during halftime — spread won't reopen until play resumes
                    if _is_halftime(ticker):
                        bot['waiting_repeat_since'] = now  # reset so we wait a full window post-halftime
                        actions.append({'bot_id': bot_id, 'action': 'repeat_halftime_pause'})
                        continue

                    # Give up after 20 minutes of waiting (was 5 — too short, halftime is ~15 min)
                    if wait_age_min > 20:
                        bot['status'] = 'completed'
                        print(f'⏰ REPEAT TIMEOUT: {bot_id} waited {wait_age_min:.1f}m — giving up on repeat (20 min limit)')
                        actions.append({'bot_id': bot_id, 'action': 'repeat_timeout'})
                        continue

                    # Check current market prices via ORDERBOOK (real-time)
                    fresh_yes_bid = 0
                    fresh_no_bid  = 0
                    try:
                        api_read_limiter.wait()
                        ob_data = _normalize_orderbook(kalshi_client.get_market_orderbook(ticker))
                        ob = ob_data.get('orderbook', ob_data)
                        y_levels = sorted(ob.get('yes', []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                        n_levels = sorted(ob.get('no',  []), key=lambda x: x[0] if isinstance(x, list) else x.get('price', 0), reverse=True)
                        fresh_yes_bid = (y_levels[0][0] if isinstance(y_levels[0], list) else y_levels[0].get('price', 0)) if y_levels else 0
                        fresh_no_bid  = (n_levels[0][0] if isinstance(n_levels[0], list) else n_levels[0].get('price', 0)) if n_levels else 0
                    except Exception as ob_err:
                        print(f'⚠ Orderbook fetch for repeat check failed: {ob_err}')
                        # Fallback to WS cache
                        ws_price = ws_manager.get_price(ticker)
                        if ws_price:
                            fresh_yes_bid = ws_price.get('yes_bid', 0)
                            fresh_no_bid  = ws_price.get('no_bid', 0)

                    # Bail immediately if the game is decided (one side 95+¢)
                    # — spread will never reopen, no point waiting
                    if fresh_yes_bid >= 95 or fresh_no_bid >= 95:
                        bot['status'] = 'completed'
                        print(f'🏁 REPEAT SKIP: {bot_id} game decided (Y={fresh_yes_bid}¢ N={fresh_no_bid}¢) — no spread to exploit')
                        actions.append({'bot_id': bot_id, 'action': 'repeat_game_over'})
                        continue

                    # ── Drift guard: don't repost into a drifted market ──
                    # At 85c+, the partial-fill window shrinks (game may end before
                    # both legs fill). Both legs DO fill in continuous moves but
                    # gap-fills become more likely when a game ends suddenly.
                    drift_side = max(fresh_yes_bid, fresh_no_bid)
                    if drift_side >= 85:
                        bot['status'] = 'drift_cancelled'
                        bot['drift_cancelled_at'] = now
                        bot['drift_yes_bid'] = fresh_yes_bid
                        bot['drift_no_bid'] = fresh_no_bid
                        print(f'🚫 REPEAT DRIFT GUARD: {bot_id} market at Y={fresh_yes_bid}¢ N={fresh_no_bid}¢ — too drifted to repost safely')
                        actions.append({'bot_id': bot_id, 'action': 'repeat_drift_guard', 'yes_bid': fresh_yes_bid, 'no_bid': fresh_no_bid})
                        continue

                    # Also bail if either side has no bids at all
                    if fresh_yes_bid == 0 or fresh_no_bid == 0:
                        # Don't burn API calls — skip this cycle, will timeout naturally
                        actions.append({'bot_id': bot_id, 'action': 'repeat_waiting', 'y_bid': fresh_yes_bid, 'n_bid': fresh_no_bid})
                        continue

                    # Check if bids are high enough to place orders below them
                    # that still achieve the target width.
                    # We need: yes_bid + no_bid >= 100 - target_width
                    # (so we can shave from bids and still have room)
                    # Also skip if late-game window
                    if phase == 'live':
                        late_blocked, late_reason = _is_late_game(ticker)
                        if late_blocked:
                            bot['status'] = 'completed'
                            print(f'🚫 REPEAT BLOCKED (late game): {bot_id} — {late_reason}')
                            actions.append({'bot_id': bot_id, 'action': 'repeat_late_game_block'})
                            continue

                    bid_sum = fresh_yes_bid + fresh_no_bid
                    target_total = 100 - target_width
                    # Derive asks via market identity: YES ask + NO bid = 100
                    fresh_yes_ask = 100 - fresh_no_bid
                    fresh_no_ask  = 100 - fresh_yes_bid
                    ask_sum = fresh_yes_ask + fresh_no_ask  # = 200 - bid_sum

                    # Cancel any orphaned orders left over from previous timeout exits
                    for orphan_id in list(bot.pop('orphaned_order_ids', [])):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(orphan_id)
                            print(f'✓ Late-cancel orphaned order {orphan_id} for {bot_id}')
                        except Exception as _oc:
                            print(f'⚠ Late-cancel still failed ({orphan_id}): {_oc}')

                    # Use ask-side pricing when bids alone can't achieve the target width.
                    # Ask-side: anchor to ask prices and shave down — orders land between bid
                    # and ask, ahead of the top-of-book bid in queue priority.
                    use_ask_side = bid_sum < target_total
                    if (bid_sum >= target_total or (use_ask_side and ask_sum > target_total)) and fresh_yes_bid > 0 and fresh_no_bid > 0:
                        # Spread available — place new orders
                        try:
                            yes_is_fav = fresh_yes_bid >= fresh_no_bid

                            if use_ask_side:
                                # ── Ask-side pricing ──
                                ask_shave = max(0, ask_sum - target_total)
                                fav_ask_shave = ask_shave * 4 // 10
                                dog_ask_shave = ask_shave - fav_ask_shave
                                max_yes_target = max(1, fresh_yes_ask - 1)
                                max_no_target  = max(1, fresh_no_ask  - 1)
                                if yes_is_fav:
                                    new_yes = min(max_yes_target, fresh_yes_ask - fav_ask_shave)
                                    new_no  = min(max_no_target,  fresh_no_ask  - dog_ask_shave)
                                else:
                                    new_yes = min(max_yes_target, fresh_yes_ask - dog_ask_shave)
                                    new_no  = min(max_no_target,  fresh_no_ask  - fav_ask_shave)
                                new_yes = max(1, new_yes)
                                new_no  = max(1, new_no)
                                # Ensure width is still met after capping
                                if 100 - new_yes - new_no < target_width:
                                    if yes_is_fav: new_yes = max(1, 100 - new_no - target_width)
                                    else:          new_no  = max(1, 100 - new_yes - target_width)
                            else:
                                # ── Bid-side pricing ──
                                total_shave = max(0, bid_sum - target_total)
                                fav_shave = total_shave * 4 // 10
                                dog_shave = total_shave - fav_shave
                                dog_bid = fresh_no_bid if yes_is_fav else fresh_yes_bid
                                dog_max_shave = max(0, dog_bid - 1)
                                if dog_shave > dog_max_shave:
                                    overflow = dog_shave - dog_max_shave
                                    dog_shave = dog_max_shave
                                    fav_shave = fav_shave + overflow
                                if yes_is_fav:
                                    new_yes = fresh_yes_bid - fav_shave
                                    new_no  = fresh_no_bid - dog_shave
                                else:
                                    new_yes = fresh_yes_bid - dog_shave
                                    new_no  = fresh_no_bid - fav_shave
                                new_yes = max(1, min(new_yes, fresh_yes_bid))
                                new_no  = max(1, min(new_no, fresh_no_bid))

                            new_profit = 100 - new_yes - new_no

                            if new_profit >= target_width:
                                # Simultaneous dual order placement
                                api_rate_limiter.wait()
                                yes_ord = kalshi_client.create_order(ticker=ticker, side='yes', action='buy', count=qty, yes_price=new_yes, post_only=True)
                                yes_oid = _extract_order_id(yes_ord, f'repeat arb YES {bot_id}')
                                if not yes_oid:
                                    continue
                                api_rate_limiter.wait()
                                no_ord  = kalshi_client.create_order(ticker=ticker, side='no', action='buy', count=qty, no_price=new_no, post_only=True)
                                no_oid = _extract_order_id(no_ord, f'repeat arb NO {bot_id}')
                                if not no_oid:
                                    # YES order succeeded but NO failed — cancel YES to prevent orphan
                                    print(f'⚠ repeat arb {bot_id}: NO order failed, cancelling YES order {yes_oid}')
                                    _safe_cancel(yes_oid, f'repeat arb cleanup {bot_id}')
                                    continue

                                bot['yes_price']    = new_yes
                                bot['no_price']     = new_no
                                bot['profit_per']   = new_profit
                                bot['yes_order_id'] = yes_oid
                                bot['no_order_id']  = no_oid
                                bot['yes_fill_qty'] = 0
                                bot['no_fill_qty']  = 0
                                bot['status']       = 'both_posted'
                                bot['posted_at']    = time.time()
                                bot['repost_count'] = 0
                                bot['first_fill_at'] = None
                                bot.pop('_trade_recorded', None)
                                if 'completed_at' in bot:
                                    del bot['completed_at']

                                cycle = bot.get('repeats_done', 0)
                                total = bot.get('repeat_count', 0)
                                pricing_mode = 'ask-side' if use_ask_side else 'bid-side'
                                print(f'🔄 REPEAT ARB cycle {cycle + 1}/{total + 1}: '
                                      f'{bot_id} YES {new_yes}¢ + NO {new_no}¢ posted ({pricing_mode}) → {new_profit}¢ profit '
                                      f'(waited {wait_age_min:.1f}m)')
                                actions.append({
                                    'bot_id': bot_id, 'action': 'repeat_cycle',
                                    'cycle': cycle + 1, 'total': total + 1,
                                    'yes_price': new_yes, 'no_price': new_no,
                                    'profit_per': new_profit,
                                })
                                save_state()
                        except Exception as rep_err:
                            print(f'⚠ Repeat arb order failed: {rep_err} — will retry next cycle')
                    continue

                # ── Rate-limited fill checks ──────────────────────────────
                # Guard: fav_posted bots are handled above; this is for
                # legacy pending_fills bots with both order IDs set.
                if bot.get('_ws_fill_handling'):
                    # Don't blanket-skip — check if this is a stale flag
                    # (race condition: flag set but completion never triggered)
                    yes_f = bot.get('yes_fill_qty', 0)
                    no_f  = bot.get('no_fill_qty', 0)
                    if yes_f >= qty and no_f >= qty:
                        print(f'⚡ MONITOR FIX: {bot_id} has _ws_fill_handling stuck but both legs filled — completing!')
                        bot.pop('_ws_fill_handling', None)
                        # Fall through to normal completion logic below
                    elif yes_f >= qty or no_f >= qty:
                        # One leg filled via WS — check if the timeout has elapsed.
                        # If so, clear the flag so the normal timeout exit logic can fire.
                        # Without this, the bot is frozen here forever when the dog never fills.
                        _fa = bot.get('first_fill_at')
                        _tout = bot.get('timeout_min', 6.0)
                        if _fa is None:
                            # WS set flag but first_fill_at was never set — fix and fall through
                            print(f'⚠ WS FIX: {bot_id} one leg filled but first_fill_at=None — setting now, clearing _ws_fill_handling')
                            bot['first_fill_at'] = time.time()
                            bot.pop('_ws_fill_handling', None)
                            # Fall through to normal timeout/fill-check logic below
                        elif (now - _fa) / 60.0 >= _tout:
                            print(f'⏰ WS TIMEOUT HANDOFF: {bot_id} one leg filled {(now-_fa)/60:.1f}m ago (>{_tout}m) — clearing _ws_fill_handling for timeout exit')
                            bot.pop('_ws_fill_handling', None)
                            # Fall through to normal timeout/fill-check logic below
                        else:
                            continue  # Still within timeout window — WS is handling
                    else:
                        print(f'⚡ SKIPPING monitor fill check for {bot_id} — WS real-time already handling')
                        continue
                if not bot.get('yes_order_id') or not bot.get('no_order_id'):
                    # Bot has a missing order ID — likely a fav_posted that
                    # slipped through. Reset to fav_posted for proper handling.
                    if bot.get('fav_order_id'):
                        bot['status'] = 'fav_posted'
                    continue

                api_read_limiter.wait()
                yes_resp = kalshi_client.get_order(bot['yes_order_id'])
                api_read_limiter.wait()
                no_resp  = kalshi_client.get_order(bot['no_order_id'])

                # Kalshi API may return {order: {...}} or the order directly
                yes_ord = yes_resp.get('order', yes_resp) if isinstance(yes_resp, dict) else {}
                no_ord  = no_resp.get('order', no_resp)   if isinstance(no_resp, dict) else {}
                yes_filled = _parse_fill_count(yes_ord)
                no_filled  = _parse_fill_count(no_ord)

                # Debug: log fill detection
                if yes_filled > 0 or no_filled > 0:
                    print(f'📊 FILL CHECK {bot_id}: YES={yes_filled}/{qty} NO={no_filled}/{qty} | resp_keys={list(yes_resp.keys()) if isinstance(yes_resp, dict) else "?"}')

                bot['yes_fill_qty'] = max(bot.get('yes_fill_qty', 0), yes_filled)
                bot['no_fill_qty']  = max(bot.get('no_fill_qty', 0), no_filled)

                # ── Both sides fully filled → profit locked at settlement ──
                if yes_filled >= qty and no_filled >= qty:
                    # ── Guard: WS or timeout may have already recorded this trade ──
                    if bot.get('_trade_recorded'):
                        if bot['status'] not in ('stopped', 'completed', 'waiting_repeat'):
                            bot['status'] = 'completed'
                        print(f'⚡ MONITOR SKIP: {bot_id} — trade already recorded')
                        continue
                    # ── REPEAT check runs unconditionally — API failures must NOT prevent it ──
                    repeats_done_now = bot.get('repeats_done', 0) + 1
                    bot['repeats_done'] = repeats_done_now
                    repeat_total = bot.get('repeat_count', 0)
                    will_repeat = repeats_done_now <= repeat_total

                    bot['completed_at'] = now
                    bot['status'] = 'waiting_repeat' if will_repeat else 'completed'
                    if will_repeat:
                        bot['waiting_repeat_since'] = time.time()
                        bot['first_fill_at'] = None
                        bot['first_leg'] = None
                        print(f'🔄 REPEAT: {bot_id} entering waiting_repeat — '
                              f'cycle {repeats_done_now}/{repeat_total}, '
                              f'watching for {bot.get("arb_width", bot.get("profit_per", 0))}¢ spread to reopen')
                        actions.append({
                            'bot_id': bot_id, 'action': 'waiting_repeat',
                            'cycle': repeats_done_now, 'total': repeat_total,
                        })

                    # Record trade + P&L — wrapped separately so failures don't break repeat logic
                    try:
                        actual_yes = get_actual_fill_price(bot['yes_order_id'], 'yes')
                        actual_no  = get_actual_fill_price(bot['no_order_id'], 'no')
                        real_yes = actual_yes if actual_yes else bot['yes_price']
                        real_no  = actual_no  if actual_no  else bot['no_price']
                        fee = kalshi_fee_cents(real_yes, real_no, qty)
                        profit_cents = (100 - real_yes - real_no) * qty - fee

                        session_pnl['gross_profit_cents'] += profit_cents
                        session_pnl['completed_bots']     += 1
                        bot['net_pnl_cents'] = bot.get('net_pnl_cents', 0) + profit_cents

                        _record_trade({
                            'bot_id': bot_id, 'ticker': ticker,
                            'yes_price': real_yes, 'no_price': real_no,
                            'original_yes': bot['yes_price'], 'original_no': bot['no_price'],
                            'quantity': qty, 'profit_cents': profit_cents,
                            'fee_cents': fee,
                            'result': 'completed', 'timestamp': now,
                            'verified_prices': actual_yes is not None and actual_no is not None,
                            'placed_at': bot.get('created_at', now),
                            'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                            'arb_width': bot.get('arb_width', bot.get('profit_per', 0)),
                            'first_leg': bot.get('first_leg', ''),
                            'fill_duration_s': round(now - bot['first_fill_at']) if bot.get('first_fill_at') else None,
                            'game_phase': bot.get('game_phase', ''),
                            'flip_threshold': bot.get('flip_threshold', FLIP_THRESHOLD_CENTS),
                            'stop_loss_cents': bot.get('stop_loss_cents', 0),
                            'game_context': _get_game_context(ticker),
                            'repeats_done': repeats_done_now,
                            'repeat_count': repeat_total,
                            'fill_source': 'monitor_rest',
                        }, bot)
                        bot['_trade_recorded'] = True  # Prevent WS/timeout from double-recording
                        bot_log('ARB_COMPLETED', bot_id, {
                            'real_yes': real_yes, 'real_no': real_no, 'profit_cents': profit_cents,
                            'fill_duration_s': round(now - bot['first_fill_at']) if bot.get('first_fill_at') else None,
                            'will_repeat': will_repeat,
                        })
                        print(f'✅ MONITOR COMPLETED: {bot_id} +{profit_cents}¢ (YES={real_yes}¢ NO={real_no}¢)'
                              + (f' → repeat {repeats_done_now}/{repeat_total}' if will_repeat else ' → done'))
                    except Exception as _rec_err:
                        profit_cents = 0
                        print(f'⚠ Monitor trade record failed for {bot_id}: {_rec_err} — repeat status already set, continuing')
                    # Always fire completed action — even if trade record had an API error
                    actions.append({'bot_id': bot_id, 'action': 'completed', 'profit_cents': profit_cents})

                    continue

                # ── Fetch current market prices (WS cache → REST fallback) ─
                ws_price = ws_manager.get_price(ticker)
                if ws_price and (ws_price.get('yes_bid', 0) > 0 or ws_price.get('no_bid', 0) > 0):
                    yes_bid = ws_price.get('yes_bid', 0)
                    no_bid  = ws_price.get('no_bid', 0)
                    yes_ask = ws_price.get('yes_ask', 0) or (100 - no_bid  if no_bid  > 0 else 0)
                    no_ask  = ws_price.get('no_ask',  0) or (100 - yes_bid if yes_bid > 0 else 0)
                else:
                    api_read_limiter.wait()
                    market_resp = kalshi_client.get_market(ticker)
                    market = market_resp.get('market', market_resp)

                    def to_cents(field):
                        d = market.get(field + '_dollars')
                        if d: return round(float(d) * 100)
                        return market.get(field, 50)

                    yes_bid  = to_cents('yes_bid')
                    no_bid   = to_cents('no_bid')
                    yes_ask  = to_cents('yes_ask')
                    no_ask   = to_cents('no_ask')

                # Store live market data on bot for frontend display
                bot['live_yes_bid'] = yes_bid
                bot['live_no_bid']  = no_bid
                bot['live_yes_ask'] = yes_ask
                bot['live_no_ask']  = no_ask
                bot['last_price_update'] = now

                # ═══════════════════════════════════════════════════════════
                # PREGAME: Patient mode — orders sit, no repost/resize.
                # If one side fills, fall through to the LIVE stop-loss
                # logic (which has grace period + recovery checks).
                # ═══════════════════════════════════════════════════════════
                if phase == 'pregame':
                    # Update status labels for UI display
                    if yes_filled >= qty and no_filled < qty:
                        bot['status'] = 'yes_filled'
                        if not bot.get('first_fill_at'):
                            bot['first_fill_at'] = now
                            bot['first_leg'] = 'yes'
                        # Fill happened — fall through to live SL logic below
                    elif no_filled >= qty and yes_filled < qty:
                        bot['status'] = 'no_filled'
                        if not bot.get('first_fill_at'):
                            bot['first_fill_at'] = now
                            bot['first_leg'] = 'no'
                        # Fill happened — fall through to live SL logic below
                    elif yes_filled >= qty and no_filled >= qty:
                        # Both filled — let the pending_fills handler above deal with it
                        continue
                    else:
                        # No fills yet — just wait (no repost/resize in pregame)
                        continue

                # ═══════════════════════════════════════════════════════════
                # LIVE: Active management — repost, resize, stop-loss
                # ═══════════════════════════════════════════════════════════

                # ── Stale order repost (no fills after REPOST_AFTER_MINUTES) ──
                # NEVER go above the current bid. Repost AT the bid to stay competitive
                # without overpaying. Favorite-anchoring: shave less from the fav side.
                if yes_filled == 0 and no_filled == 0 and age_min >= REPOST_AFTER_MINUTES:
                    # ── Drift guard: don't repost into a drifted market ──
                    if max(yes_bid, no_bid) >= 85:
                        print(f'🚫 REPOST DRIFT GUARD: {bot_id} market at Y={yes_bid}¢ N={no_bid}¢ — too drifted, cancelling')
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['yes_order_id'])
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['no_order_id'])
                        except Exception:
                            pass
                        bot['status'] = 'drift_cancelled'
                        bot['drift_cancelled_at'] = now
                        bot['drift_yes_bid'] = yes_bid
                        bot['drift_no_bid'] = no_bid
                        bot['completed_at'] = now
                        actions.append({'bot_id': bot_id, 'action': 'repost_drift_guard', 'yes_bid': yes_bid, 'no_bid': no_bid})
                        save_state()
                        continue
                    # Width-aware repost: identify fav (higher bid) and dog (lower bid).
                    # Dog posts at its current bid — fav is capped so that
                    # fav + dog = 100 - min_width, preserving target spread.
                    # Example: yes_bid=99, no_bid=1, width=5 → new_no=1, new_yes=94.
                    min_width = bot.get('arb_width', bot.get('profit_per', 3))
                    if yes_bid >= no_bid:   # YES is fav, NO is dog
                        new_no  = max(1, min(no_bid,  98))
                        new_yes = min(yes_bid, 98, 100 - new_no - min_width)
                    else:                   # NO is fav, YES is dog
                        new_yes = max(1, min(yes_bid, 98))
                        new_no  = min(no_bid,  98, 100 - new_yes - min_width)
                    new_yes = max(1, new_yes)
                    new_no  = max(1, new_no)
                    # Falling knife guard: don't repost if fav side has dropped below MIN_FAV_ENTRY_CENTS
                    fav_price = max(new_yes, new_no)
                    if fav_price < MIN_FAV_ENTRY_CENTS:
                        print(f'🔪 REPOST BLOCKED: {bot_id} fav bid={fav_price}¢ < {MIN_FAV_ENTRY_CENTS}¢ — falling knife, cancelling bot')
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['yes_order_id'])
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['no_order_id'])
                        except Exception:
                            pass
                        bot['status'] = 'completed'
                        bot['completed_at'] = now
                        bot_log('REPOST_FALLING_KNIFE', bot_id, {'yes_bid': new_yes, 'no_bid': new_no, 'min': MIN_FAV_ENTRY_CENTS})
                        actions.append({'bot_id': bot_id, 'action': 'repost_falling_knife_cancelled'})
                        save_state()
                        continue
                    new_profit = 100 - new_yes - new_no
                    min_width = bot.get('arb_width', bot.get('profit_per', 3))
                    if new_profit >= min_width:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['yes_order_id'])
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['no_order_id'])
                            batch_r = create_orders_batch([
                                {'ticker': ticker, 'side': 'yes', 'count': qty, 'price': new_yes},
                                {'ticker': ticker, 'side': 'no',  'count': qty, 'price': new_no},
                            ])
                            ny_resp, new_yes = batch_r[0]
                            nn_resp, new_no  = batch_r[1]
                            bot.update({
                                'yes_order_id': ny_resp['order']['order_id'],
                                'no_order_id':  nn_resp['order']['order_id'],
                                'yes_price':    new_yes,
                                'no_price':     new_no,
                                'profit_per':   100 - new_yes - new_no,
                                'posted_at':    now,
                                'repost_count': bot.get('repost_count', 0) + 1,
                            })
                            actions.append({'bot_id': bot_id, 'action': 'reposted',
                                            'new_yes': new_yes, 'new_no': new_no,
                                            'repost_count': bot['repost_count']})
                        except Exception as re_err:
                            print(f"Repost failed for {bot_id}: {re_err}")
                    continue

                # Dog leg is NEVER reposted regardless of which side is fav.
                # Applies to both YES-dog (when NO is fav) and NO-dog (when YES is fav).
                # Chasing the dog away from the original price breaks the arb width.

                # ── YES fully filled, NO still open — smart timeout ──
                # Timeout is shorter when the underdog fills first (riskier situation).
                # Fav fills first → 8 min (fav in, patient wait for underdog)
                # Underdog fills first → 4 min (cheap leg in, fav bid moved on us)
                DUAL_WALK_INTERVAL_S = 20
                if yes_filled >= qty and no_filled < qty:
                    bot['status'] = 'yes_filled'
                    if not bot.get('first_fill_at'):
                        bot['first_fill_at'] = now
                        bot['first_leg'] = 'yes'
                        bot['walk_count'] = 0
                        bot['last_walk_at'] = now
                        bot['walk_start_price'] = bot.get('no_price', 0)
                        bot['last_walk_at'] = now

                    yes_is_fav = (bot.get('yes_price', 50) >= bot.get('no_price', 50))
                    wait_min = (now - bot['first_fill_at']) / 60.0 if bot.get('first_fill_at') else 0

                    # ── Halftime pause: pause walk-up ──
                    if _is_halftime(ticker):
                        bot['last_walk_at'] = now
                        actions.append({'bot_id': bot_id, 'action': 'holding_halftime_yes', 'wait_min': round(wait_min, 1)})
                        continue

                    # ── Game ending: force immediate amend (taker cross as last resort) ──
                    if phase == 'live' and _is_game_ending(ticker) and wait_min >= 0.5:
                        if not (bot.get('_trade_recorded') or bot.get('status') in ('completed', 'stopped', 'waiting_repeat')):
                            old_no_order_id = bot.get('no_order_id')
                            amend_price_no = no_bid if no_bid > 0 else None
                            if old_no_order_id and amend_price_no and amend_price_no >= 1:
                                print(f'🏁 GAME ENDING: {bot_id} YES filled, forcing amend NO→{amend_price_no}¢')
                                arb_w = bot.get('arb_width') or bot.get('profit_per', 0)
                                timeout_min = _late_game_timeout_min(ticker, yes_is_fav, arb_w)
                                bot['status'] = 'amending_no'
                                bot['amend_price'] = amend_price_no
                                save_state()
                                _fire_timeout_amend(bot_id, bot, old_no_order_id, 'no', amend_price_no, qty, ticker, yes_is_fav, timeout_min, actions)
                                continue

                    # ── Pregame fallback: force to live after 10 min stuck in pregame ──
                    PREGAME_MAX_WAIT_MIN = 10.0
                    if phase != 'live' and wait_min >= PREGAME_MAX_WAIT_MIN:
                        print(f'⏰ PREGAME TIMEOUT: {bot_id} YES filled {wait_min:.1f}m in pregame — forcing live')
                        bot['game_phase'] = 'live'

                    # ── Walk-up: every 20s, bump unfilled NO by 1¢ toward bid (maker, no ceiling) ──
                    # When combined cost >= 98¢, snap to bid immediately (still maker/post_only)
                    last_walk = bot.get('last_walk_at') or bot.get('first_fill_at') or now
                    since_walk = now - last_walk
                    if since_walk >= DUAL_WALK_INTERVAL_S:
                        if not (bot.get('_trade_recorded') or bot.get('status') in ('completed', 'stopped', 'waiting_repeat')):
                            old_no_order_id = bot.get('no_order_id')
                            current_no_price = bot.get('no_price', 0)
                            if old_no_order_id and current_no_price > 0 and no_bid > 0:
                                combined_now = bot['yes_price'] + current_no_price
                                # Snap to bid when already close to 100¢ — finish ASAP
                                if combined_now >= 98 and no_bid > current_no_price:
                                    new_no_price = no_bid  # jump straight to bid
                                else:
                                    new_no_price = min(current_no_price + 1, no_bid)
                                if new_no_price > current_no_price:
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.amend_order(old_no_order_id, ticker=ticker, side='no', count=qty, no_price=new_no_price)
                                        walk_count = bot.get('walk_count', 0) + 1
                                        combined = bot['yes_price'] + new_no_price
                                        print(f'📈 DUAL WALK-UP: {bot_id} NO {current_no_price}¢→{new_no_price}¢ (bid={no_bid}¢ combined={combined}¢ step #{walk_count})')
                                        bot['no_price'] = new_no_price
                                        bot['walk_count'] = walk_count
                                        bot['last_walk_at'] = now
                                        save_state()
                                    except Exception as e:
                                        print(f'❌ DUAL WALK-UP {bot_id}: NO amend failed: {e}')
                                        bot['last_walk_at'] = now
                                else:
                                    bot['last_walk_at'] = now  # at bid, wait for next move
                            else:
                                bot['last_walk_at'] = now

                    actions.append({'bot_id': bot_id, 'action': 'walking_yes_filled', 'wait_min': round(wait_min, 1), 'walk_count': bot.get('walk_count', 0)})
                    continue  # ← prevent fall-through to NO check

                # ── NO fully filled, YES still open — walk-up to completion ──
                if no_filled >= qty and yes_filled < qty:
                    bot['status'] = 'no_filled'
                    if not bot.get('first_fill_at'):
                        bot['first_fill_at'] = now
                        bot['first_leg'] = 'no'
                        bot['walk_count'] = 0
                        bot['last_walk_at'] = now
                        bot['walk_start_price'] = bot.get('yes_price', 0)

                    no_is_fav = (bot.get('no_price', 50) >= bot.get('yes_price', 50))
                    wait_min = (now - bot['first_fill_at']) / 60.0 if bot.get('first_fill_at') else 0

                    # ── Halftime pause: pause walk-up ──
                    if _is_halftime(ticker):
                        bot['last_walk_at'] = now
                        actions.append({'bot_id': bot_id, 'action': 'holding_halftime_no', 'wait_min': round(wait_min, 1)})
                        continue

                    # ── Game ending: force immediate amend (taker cross as last resort) ──
                    if phase == 'live' and _is_game_ending(ticker) and wait_min >= 0.5:
                        if not (bot.get('_trade_recorded') or bot.get('status') in ('completed', 'stopped', 'waiting_repeat')):
                            old_yes_order_id = bot.get('yes_order_id')
                            amend_price_yes = yes_bid if yes_bid > 0 else None
                            if old_yes_order_id and amend_price_yes and amend_price_yes >= 1:
                                print(f'🏁 GAME ENDING: {bot_id} NO filled, forcing amend YES→{amend_price_yes}¢')
                                arb_w = bot.get('arb_width') or bot.get('profit_per', 0)
                                timeout_min = _late_game_timeout_min(ticker, no_is_fav, arb_w)
                                bot['status'] = 'amending_yes'
                                bot['amend_price'] = amend_price_yes
                                save_state()
                                _fire_timeout_amend(bot_id, bot, old_yes_order_id, 'yes', amend_price_yes, qty, ticker, no_is_fav, timeout_min, actions)
                                continue

                    # ── Pregame fallback: force to live after 10 min stuck in pregame ──
                    PREGAME_MAX_WAIT_MIN = 10.0
                    if phase != 'live' and wait_min >= PREGAME_MAX_WAIT_MIN:
                        print(f'⏰ PREGAME TIMEOUT: {bot_id} NO filled {wait_min:.1f}m in pregame — forcing live')
                        bot['game_phase'] = 'live'

                    # ── Walk-up: every 20s, bump unfilled YES by 1¢ toward bid (maker, no ceiling) ──
                    # When combined cost >= 98¢, snap to bid immediately (still maker/post_only)
                    last_walk = bot.get('last_walk_at') or bot.get('first_fill_at') or now
                    since_walk = now - last_walk
                    if since_walk >= DUAL_WALK_INTERVAL_S:
                        if not (bot.get('_trade_recorded') or bot.get('status') in ('completed', 'stopped', 'waiting_repeat')):
                            old_yes_order_id = bot.get('yes_order_id')
                            current_yes_price = bot.get('yes_price', 0)
                            if old_yes_order_id and current_yes_price > 0 and yes_bid > 0:
                                combined_now = current_yes_price + bot['no_price']
                                # Snap to bid when already close to 100¢ — finish ASAP
                                if combined_now >= 98 and yes_bid > current_yes_price:
                                    new_yes_price = yes_bid  # jump straight to bid
                                else:
                                    new_yes_price = min(current_yes_price + 1, yes_bid)
                                if new_yes_price > current_yes_price:
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.amend_order(old_yes_order_id, ticker=ticker, side='yes', count=qty, yes_price=new_yes_price)
                                        walk_count = bot.get('walk_count', 0) + 1
                                        combined = new_yes_price + bot['no_price']
                                        print(f'📈 DUAL WALK-UP: {bot_id} YES {current_yes_price}¢→{new_yes_price}¢ (bid={yes_bid}¢ combined={combined}¢ step #{walk_count})')
                                        bot['yes_price'] = new_yes_price
                                        bot['walk_count'] = walk_count
                                        bot['last_walk_at'] = now
                                        save_state()
                                    except Exception as e:
                                        print(f'❌ DUAL WALK-UP {bot_id}: YES amend failed: {e}')
                                        bot['last_walk_at'] = now
                                else:
                                    bot['last_walk_at'] = now  # at bid, wait for next move
                            else:
                                bot['last_walk_at'] = now

                    actions.append({'bot_id': bot_id, 'action': 'walking_no_filled', 'wait_min': round(wait_min, 1), 'walk_count': bot.get('walk_count', 0)})

            except Exception as e:
                print(f"Error monitoring bot {bot_id}: {e}")
                continue

        # ── Middle Bot Rebalancer (last-resort, late-game only) ──────
        def _middle_rebalancer_check(bot, bot_id, now_m, actions, session_pnl):
            """Smart rebalancer for middle bots. Only fires in the final minutes
            of the last period when BOTH market price AND ESPN score confirm a leg
            is dead.  Returns True if an action was taken.

            Supports one_filled (scrape/ride) and both_filled (profit enhancement).
            Default mode is dry_run (log only, no sells).
            """
            if not bot.get('rebalancer_enabled', True):
                return False
            mode = bot.get('rebalancer_mode', 'live')  # 'dry_run' or 'live'

            PROTECT_FLOOR   = bot.get('rebalancer_protect_floor', 80)
            LATE_GAME_SECS  = bot.get('rebalancer_late_game_secs', 180)
            SCRAPE_CEIL     = bot.get('rebalancer_scrape_ceil', 10)
            MARGIN_BUFFER   = bot.get('rebalancer_margin_buffer', 5)
            status = bot['status']

            # ── Determine which legs to check ──
            if status == 'one_filled':
                filled_leg = bot.get('filled_leg', 'a')
                legs_to_check = [filled_leg]
            elif status == 'both_filled':
                legs_to_check = ['a', 'b']
            else:
                return False

            for check_leg in legs_to_check:
                other_leg = 'b' if check_leg == 'a' else 'a'
                check_ticker = bot.get(f'ticker_{check_leg}', '')
                other_ticker = bot.get(f'ticker_{other_leg}', '')
                fill_price = bot.get(f'leg_{check_leg}_fill_price') or bot.get('target_price', 49)
                check_spread = bot.get(f'spread_{check_leg}', 0)
                other_spread = bot.get(f'spread_{other_leg}', 0)
                qty = bot.get('qty', 1)

                if not check_ticker:
                    continue

                # Get live NO bid for this leg
                live_bid = 0
                ws_p = ws_manager.get_price(check_ticker) if ws_manager else None
                if ws_p:
                    live_bid = ws_p.get('no_bid', 0) or 0

                # GUARD: Protect winners — never touch a healthy leg
                if live_bid >= PROTECT_FLOOR:
                    continue

                # GUARD: Late game only — get ESPN score for this leg's team
                score_data = _get_team_margin_for_spread_ticker(check_ticker, check_spread)
                if not score_data:
                    continue  # No ESPN data — don't act on price alone

                period = score_data.get('period', 0)
                secs = score_data.get('secs_remaining')
                margin = score_data.get('margin', 0)
                team_code = score_data.get('team_code', '?')
                covering = score_data.get('covering', False)
                game_status = score_data.get('status', '')

                # Find the late-game rule for this sport
                series = check_ticker.split('-')[0].upper() if check_ticker else ''
                rule = None
                for prefix, r in _LATE_GAME_RULES.items():
                    if series.startswith(prefix):
                        if rule is None or len(prefix) > len(rule[0]):
                            rule = (prefix, r)

                if not rule:
                    continue  # Unknown sport

                final_period = rule[1]['block_period']
                is_late = (game_status == 'post') or \
                          (period >= final_period and secs is not None and secs <= LATE_GAME_SECS)

                if not is_late:
                    continue  # Not late game — too early to act

                # ── CHECK: Dead Leg Scrape ──
                # Price says dead (bid < SCRAPE_CEIL) AND team covering spread by MARGIN_BUFFER+
                buffer_met = (margin >= check_spread + MARGIN_BUFFER)
                if live_bid > 0 and live_bid < SCRAPE_CEIL and covering and buffer_met:
                    log_data = {
                        'leg': check_leg, 'team': team_code, 'margin': margin,
                        'spread': check_spread, 'buffer': MARGIN_BUFFER,
                        'covering': True, 'buffer_met': True,
                        'bid': live_bid, 'fill_price': fill_price,
                        'period': period, 'secs': secs, 'mode': mode,
                    }

                    if mode == 'dry_run':
                        action_str = f'WOULD_SCRAPE at {live_bid}c' if status == 'one_filled' else f'WOULD_ENHANCE sell at {live_bid}c'
                        bot_log('REBALANCER_DRY_RUN', bot_id, {**log_data, 'action': action_str})
                        print(f'🔬 REBALANCER_DRY_RUN: {bot_id} | leg={check_leg.upper()} team={team_code} '
                              f'margin={margin} spread={check_spread} bid={live_bid}c | {action_str}')
                        continue  # Dry run — don't actually do anything

                    # LIVE MODE — execute the scrape
                    event_type = 'REBALANCER_SCRAPE' if status == 'one_filled' else 'REBALANCER_ENHANCE'
                    bot_log(event_type, bot_id, log_data)

                    # For one_filled: cancel unfilled order first
                    if status == 'one_filled':
                        unfilled_order_key = f'order_{other_leg}_id'
                        if bot.get(unfilled_order_key):
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(bot[unfilled_order_key])
                            except Exception as ce:
                                # Check if it filled during cancel (race condition)
                                try:
                                    resp_race = kalshi_client.get_order(bot[unfilled_order_key])
                                    ord_race = resp_race.get('order', resp_race) if isinstance(resp_race, dict) else {}
                                    if _parse_fill_count(ord_race) >= qty:
                                        bot[f'leg_{other_leg}_filled'] = True
                                        bot[f'leg_{other_leg}_fill_price'] = get_actual_fill_price(bot[unfilled_order_key], 'no')
                                        bot['status'] = 'both_filled'
                                        bot['both_filled_at'] = now_m
                                        bot_log('MIDDLE_BOTH_FILLED', bot_id, {'source': 'rebalancer_race'})
                                        save_state()
                                        return True
                                except Exception:
                                    pass

                    # Market-sell the dead leg
                    sold, sell_info = execute_sell(check_ticker, 'no', qty,
                                                   reason=f'rebalancer_{event_type.lower()}_{bot_id}')
                    if not sold:
                        bot_log('REBALANCER_SELL_FAILED', bot_id, {
                            'leg': check_leg, 'bid': live_bid, 'error': str(sell_info),
                        })
                        print(f'⚠ REBALANCER SELL FAILED: {bot_id} leg={check_leg.upper()} — retrying next cycle')
                        return False  # Don't change status, retry next cycle

                    sell_price = (sell_info or {}).get('actual_fill_price') or \
                                 (sell_info or {}).get('sell_price', 0)

                    if status == 'one_filled':
                        buy_fee = _kalshi_side_fee_cents(fill_price, qty)
                        sell_fee = _kalshi_taker_side_fee_cents(sell_price, qty) if sell_price else 0
                        scrape_fees = buy_fee + sell_fee
                        _scrape_net = (fill_price - (sell_price or fill_price)) * qty + scrape_fees
                        _scrape_profit = max(0, -_scrape_net)  # positive when sold higher than bought
                        _scrape_loss = max(0, _scrape_net)     # positive when lost money
                        bot['status'] = 'stopped'
                        bot['stopped_at'] = now_m
                        bot['sl_sell_price'] = sell_price
                        bot['rebalancer_exit_reason'] = 'scrape'
                        if _scrape_loss > 0:
                            session_pnl['gross_loss_cents'] += _scrape_loss
                        elif _scrape_profit > 0:
                            session_pnl['gross_profit_cents'] += _scrape_profit
                        session_pnl['stopped_bots'] += 1
                        _record_trade({
                            'bot_id': bot_id, 'type': 'middle',
                            'ticker_a': bot.get('ticker_a'), 'ticker_b': bot.get('ticker_b'),
                            'team_a_name': bot.get('team_a_name'), 'team_b_name': bot.get('team_b_name'),
                            'spread_a': bot.get('spread_a'), 'spread_b': bot.get('spread_b'),
                            'target_price': bot.get('target_price'), 'qty': qty,
                            'filled_leg': check_leg, 'fill_price': fill_price,
                            'sl_sell_price': sell_price,
                            'profit_cents': _scrape_profit, 'loss_cents': _scrape_loss,
                            'fee_cents': scrape_fees,
                            'result': 'rebalancer_scrape', 'timestamp': now_m,
                            'note': f'rebalancer scrape: {team_code} margin={margin} spread={check_spread} bid={live_bid}c secs={secs}',
                        }, bot)
                        _push_notification('rebalancer',
                            f'Rebalancer scrape: {bot_id} — leg {check_leg.upper()} ({team_code}) '
                            f'sold at {sell_price}c (margin={margin} vs spread={check_spread})',
                            {'bot_id': bot_id, 'reason': 'scrape'})
                    else:
                        # both_filled enhancement — sell dead leg for extra profit
                        recovery_cents = (sell_price or 0) * qty
                        bot['rebalancer_exit_reason'] = 'enhance'
                        bot[f'leg_{check_leg}_sold_early'] = True
                        bot[f'leg_{check_leg}_sell_price'] = sell_price
                        session_pnl['gross_profit_cents'] += recovery_cents
                        _record_trade({
                            'bot_id': bot_id, 'type': 'middle',
                            'ticker_a': bot.get('ticker_a'), 'ticker_b': bot.get('ticker_b'),
                            'team_a_name': bot.get('team_a_name'), 'team_b_name': bot.get('team_b_name'),
                            'spread_a': bot.get('spread_a'), 'spread_b': bot.get('spread_b'),
                            'qty': qty, 'filled_leg': check_leg,
                            'fill_price': fill_price, 'sl_sell_price': sell_price,
                            'recovery_cents': recovery_cents,
                            'profit_cents': recovery_cents, 'loss_cents': 0,
                            'result': 'rebalancer_enhance', 'timestamp': now_m,
                            'note': f'rebalancer enhance: sold dead leg {check_leg.upper()} ({team_code}) '
                                    f'at {sell_price}c (margin={margin} spread={check_spread})',
                        }, bot)
                        _push_notification('rebalancer',
                            f'Rebalancer enhance: {bot_id} — sold dead leg {check_leg.upper()} '
                            f'at {sell_price}c (+{recovery_cents}c recovery)',
                            {'bot_id': bot_id, 'reason': 'enhance'})

                    actions.append({'bot_id': bot_id, 'action': event_type.lower()})
                    save_state()
                    return True

                # ── CHECK: Ride Winner (one_filled only) ──
                # Unfilled leg's team is covering → filled leg is safe → cancel unfilled, ride to settle
                if status == 'one_filled' and live_bid >= 70:
                    other_score = _get_team_margin_for_spread_ticker(other_ticker, other_spread)
                    if other_score and other_score.get('covering') and \
                       other_score.get('margin', 0) >= other_spread + MARGIN_BUFFER:
                        other_team = other_score.get('team_code', '?')
                        log_data = {
                            'filled_leg': check_leg, 'filled_bid': live_bid,
                            'unfilled_leg': other_leg, 'unfilled_team': other_team,
                            'unfilled_margin': other_score['margin'], 'unfilled_spread': other_spread,
                            'period': period, 'secs': secs, 'mode': mode,
                        }

                        if mode == 'dry_run':
                            bot_log('REBALANCER_DRY_RUN', bot_id, {**log_data, 'action': 'WOULD_RIDE (cancel unfilled, ride to settle)'})
                            print(f'🔬 REBALANCER_DRY_RUN: {bot_id} | filled={check_leg.upper()} bid={live_bid}c | '
                                  f'unfilled={other_leg.upper()} {other_team} covering (margin={other_score["margin"]} spread={other_spread}) | WOULD_RIDE')
                            continue

                        # LIVE MODE — cancel unfilled, ride filled to settlement
                        bot_log('REBALANCER_RIDE', bot_id, log_data)
                        unfilled_order_key = f'order_{other_leg}_id'
                        if bot.get(unfilled_order_key):
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(bot[unfilled_order_key])
                            except Exception:
                                pass
                        bot['status'] = 'one_leg_timeout'
                        bot['timeout_at'] = now_m
                        bot['rebalancer_exit_reason'] = 'ride'
                        _push_notification('rebalancer',
                            f'Rebalancer ride: {bot_id} — {other_team} covering, '
                            f'riding leg {check_leg.upper()} (bid={live_bid}c) to settlement',
                            {'bot_id': bot_id, 'reason': 'ride'})
                        actions.append({'bot_id': bot_id, 'action': 'rebalancer_ride'})
                        save_state()
                        return True

                # Log dry-run no-action for visibility
                if mode == 'dry_run' and (live_bid < SCRAPE_CEIL or covering):
                    action_str = 'NONE'
                    reasons = []
                    if live_bid >= SCRAPE_CEIL:
                        reasons.append(f'bid {live_bid}c >= ceil {SCRAPE_CEIL}c')
                    if not covering:
                        reasons.append(f'not covering (margin={margin} < spread={check_spread})')
                    elif not buffer_met:
                        reasons.append(f'buffer not met (margin={margin} < spread+buf={check_spread + MARGIN_BUFFER})')
                    bot_log('REBALANCER_DRY_RUN', bot_id, {
                        'leg': check_leg, 'team': team_code, 'margin': margin,
                        'spread': check_spread, 'bid': live_bid,
                        'covering': covering, 'buffer_met': buffer_met,
                        'action': f'NONE ({"; ".join(reasons)})',
                    })

            return False

        # ── Middle Bots ──────────────────────────────────────────────
        for bot_id, bot in list(active_bots.items()):
            if bot.get('type') != 'middle':
                continue
            if bot['status'] not in ('waiting', 'one_filled'):
                continue
            try:
                now_m = time.time()
                qty_m = bot.get('qty', 1)

                # ── Settlement guard for waiting/one_filled middle bots ──
                if now_m - bot.get('_last_settle_check', 0) >= 30:
                    bot['_last_settle_check'] = now_m
                    try:
                        _tk_a = bot.get('ticker_a', '')
                        _tk_b = bot.get('ticker_b', '')
                        _both_dead = True
                        for _tk in (_tk_a, _tk_b):
                            if _tk:
                                api_read_limiter.wait()
                                _mk = kalshi_client.get_market(_tk)
                                _mkd = _mk.get('market', _mk) if isinstance(_mk, dict) else {}
                                if _mkd.get('status', 'active') in ('active', 'open'):
                                    _both_dead = False
                                    break
                        if _both_dead:
                            # Cancel any open orders
                            for _ok in ('order_a_id', 'order_b_id'):
                                _oid = bot.get(_ok)
                                if _oid:
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.cancel_order(_oid)
                                    except Exception:
                                        pass
                            bot['status'] = 'completed'
                            bot['completed_at'] = now_m
                            bot['result'] = 'market_dead_unfilled'
                            print(f'📐 MIDDLE MARKET DEAD: {bot_id} — markets inactive, cancelling')
                            actions.append({'bot_id': bot_id, 'action': 'middle_market_dead'})
                            save_state()
                            continue
                    except Exception:
                        pass

                # ── Status: waiting — both orders pending ──
                if bot['status'] == 'waiting':
                    # Check order A
                    a_filled = False
                    a_fill_price = None
                    if bot.get('order_a_id'):
                        try:
                            api_read_limiter.wait()
                            resp_a = kalshi_client.get_order(bot['order_a_id'])
                            ord_a = resp_a.get('order', resp_a) if isinstance(resp_a, dict) else {}
                            a_count = _parse_fill_count(ord_a)
                            if a_count >= qty_m:
                                a_filled = True
                                a_fill_price = get_actual_fill_price(bot['order_a_id'], 'no')
                        except Exception as oe:
                            bot_log('ERROR', bot_id, {'step': 'check_order_a', 'error': str(oe)}, level='WARN')

                    # Check order B
                    b_filled = False
                    b_fill_price = None
                    if bot.get('order_b_id'):
                        try:
                            api_read_limiter.wait()
                            resp_b = kalshi_client.get_order(bot['order_b_id'])
                            ord_b = resp_b.get('order', resp_b) if isinstance(resp_b, dict) else {}
                            b_count = _parse_fill_count(ord_b)
                            if b_count >= qty_m:
                                b_filled = True
                                b_fill_price = get_actual_fill_price(bot['order_b_id'], 'no')
                        except Exception as oe:
                            bot_log('ERROR', bot_id, {'step': 'check_order_b', 'error': str(oe)}, level='WARN')

                    if a_filled and b_filled:
                        bot['leg_a_filled'] = True
                        bot['leg_b_filled'] = True
                        bot['leg_a_fill_price'] = a_fill_price or bot['target_price']
                        bot['leg_b_fill_price'] = b_fill_price or bot['target_price']
                        bot['status'] = 'both_filled'
                        bot['both_filled_at'] = now_m
                        bot_log('MIDDLE_BOTH_FILLED', bot_id, {'leg_a_price': bot['leg_a_fill_price'], 'leg_b_price': bot['leg_b_fill_price']})
                        print(f'📐 MIDDLE BOTH FILLED: {bot_id}')
                        actions.append({'bot_id': bot_id, 'action': 'middle_both_filled'})
                        save_state()
                    elif a_filled:
                        bot['leg_a_filled'] = True
                        bot['leg_a_fill_price'] = a_fill_price or bot['target_price']
                        bot['status'] = 'one_filled'
                        bot['filled_leg'] = 'a'
                        bot['one_filled_at'] = now_m
                        bot_log('MIDDLE_LEG_FILLED', bot_id, {'leg': 'a', 'price': bot['leg_a_fill_price']})
                        print(f'📐 MIDDLE LEG A FILLED: {bot_id}')
                        actions.append({'bot_id': bot_id, 'action': 'middle_leg_a_filled'})
                        save_state()
                    elif b_filled:
                        bot['leg_b_filled'] = True
                        bot['leg_b_fill_price'] = b_fill_price or bot['target_price']
                        bot['status'] = 'one_filled'
                        bot['filled_leg'] = 'b'
                        bot['one_filled_at'] = now_m
                        bot_log('MIDDLE_LEG_FILLED', bot_id, {'leg': 'b', 'price': bot['leg_b_fill_price']})
                        print(f'📐 MIDDLE LEG B FILLED: {bot_id}')
                        actions.append({'bot_id': bot_id, 'action': 'middle_leg_b_filled'})
                        save_state()
                    else:
                        # Neither leg filled — coordinated dual-leg repost.
                        # Gets BOTH bids, calculates shave to maintain original combined
                        # cost, splits evenly so orders stay competitive + arb preserved.
                        MIDDLE_GAP_THRESHOLD = 3  # cents total drift before repost
                        MIDDLE_POLL_S = 5
                        last_gap_check = bot.get('_last_gap_check', 0)
                        if now_m - last_gap_check >= MIDDLE_POLL_S:
                            bot['_last_gap_check'] = now_m
                            # Get both NO bids from WS
                            bid_a = 0
                            bid_b = 0
                            ws_a = ws_manager.get_price(bot.get('ticker_a', '')) if ws_manager else None
                            ws_b = ws_manager.get_price(bot.get('ticker_b', '')) if ws_manager else None
                            if ws_a:
                                bid_a = ws_a.get('no_bid', 0) or 0
                            if ws_b:
                                bid_b = ws_b.get('no_bid', 0) or 0

                            if bid_a > 0 and bid_b > 0:
                                cur_price_a = bot.get('target_price_a') or bot.get('target_price', 49)
                                cur_price_b = bot.get('target_price_b') or bot.get('target_price', 49)
                                # Original combined cost the user selected
                                target_cost = bot.get('_original_cost') or (cur_price_a + cur_price_b)

                                total_bid = bid_a + bid_b
                                shave = max(0, total_bid - target_cost)
                                shave_each = shave / 2.0

                                new_a = max(1, round(bid_a - shave_each))
                                new_b = max(1, round(bid_b - shave_each))

                                # Fix rounding so combined never exceeds target
                                while new_a + new_b > target_cost and (new_a > 1 or new_b > 1):
                                    if new_a >= new_b and new_a > 1:
                                        new_a -= 1
                                    elif new_b > 1:
                                        new_b -= 1

                                gap_a = abs(new_a - cur_price_a)
                                gap_b = abs(new_b - cur_price_b)

                                if gap_a + gap_b >= MIDDLE_GAP_THRESHOLD:
                                    reposted = False
                                    for leg, order_key, ticker_key, price_key, new_price, cur_bid in [
                                        ('a', 'order_a_id', 'ticker_a', 'target_price_a', new_a, bid_a),
                                        ('b', 'order_b_id', 'ticker_b', 'target_price_b', new_b, bid_b),
                                    ]:
                                        old_order_id = bot.get(order_key)
                                        ticker_lr = bot.get(ticker_key, '')
                                        cur_target = bot.get(price_key) or bot.get('target_price', 49)
                                        if not ticker_lr or not old_order_id:
                                            continue
                                        if new_price == cur_target:
                                            continue  # no change for this leg
                                        try:
                                            try:
                                                api_rate_limiter.wait()
                                                kalshi_client.cancel_order(old_order_id)
                                            except Exception:
                                                pass
                                            api_rate_limiter.wait()
                                            new_resp = kalshi_client.create_order(
                                                ticker=ticker_lr, side='no', action='buy',
                                                count=qty_m, no_price=new_price, post_only=True
                                            )
                                            new_order_id = _extract_order_id(new_resp, f'middle resize {bot_id} leg {leg}')
                                            if not new_order_id:
                                                continue
                                            bot[order_key] = new_order_id
                                            bot[price_key] = new_price
                                            if leg == 'a':
                                                bot['target_price'] = new_price
                                            reposted = True
                                            bot_log('MIDDLE_RESIZE', bot_id, {
                                                'leg': leg, 'old_target': cur_target,
                                                'new_price': new_price, 'cur_bid': cur_bid,
                                                'total_bid': total_bid, 'target_cost': target_cost,
                                                'shave_each': round(shave_each, 1),
                                                'combined': new_a + new_b,
                                            })
                                            print(f'📐 MIDDLE RESIZE {leg.upper()}: {bot_id} {cur_target}¢→{new_price}¢ '
                                                  f'(bid={cur_bid}¢ shave={shave_each:.0f}¢ combined={new_a+new_b}¢/{target_cost}¢)')
                                        except Exception as rp_err:
                                            bot_log('ERROR', bot_id, {'step': f'middle_resize_{leg}', 'error': str(rp_err)}, level='WARN')
                                    if reposted:
                                        bot['last_repost_at'] = now_m
                                        bot['repost_count'] = bot.get('repost_count', 0) + 1
                                        save_state()

                # ── Status: one_filled — check other leg and stop-loss ──
                elif bot['status'] == 'one_filled':
                    filled_leg = bot.get('filled_leg', 'a')
                    unfilled_leg = 'b' if filled_leg == 'a' else 'a'
                    unfilled_order_key = f'order_{unfilled_leg}_id'
                    filled_ticker_key = f'ticker_{filled_leg}'
                    filled_price_key = f'leg_{filled_leg}_fill_price'
                    stop_loss = bot.get('stop_loss_cents', 0)  # default OFF — middle markets are too volatile for a floor
                    fill_price = bot.get(filled_price_key) or bot['target_price']

                    # Check if unfilled leg has filled
                    other_filled = False
                    other_fill_price = None
                    if bot.get(unfilled_order_key):
                        try:
                            api_read_limiter.wait()
                            resp_uf = kalshi_client.get_order(bot[unfilled_order_key])
                            ord_uf = resp_uf.get('order', resp_uf) if isinstance(resp_uf, dict) else {}
                            uf_count = _parse_fill_count(ord_uf)
                            if uf_count >= qty_m:
                                other_filled = True
                                other_fill_price = get_actual_fill_price(bot[unfilled_order_key], 'no')
                        except Exception as oe:
                            bot_log('ERROR', bot_id, {'step': 'check_unfilled_leg', 'error': str(oe)}, level='WARN')

                    if other_filled:
                        bot[f'leg_{unfilled_leg}_filled'] = True
                        bot[f'leg_{unfilled_leg}_fill_price'] = other_fill_price or bot['target_price']
                        bot['status'] = 'both_filled'
                        bot['both_filled_at'] = now_m
                        bot_log('MIDDLE_BOTH_FILLED', bot_id, {
                            'leg_a_price': bot.get('leg_a_fill_price'),
                            'leg_b_price': bot.get('leg_b_fill_price'),
                        })
                        print(f'📐 MIDDLE BOTH FILLED (2nd leg): {bot_id}')
                        actions.append({'bot_id': bot_id, 'action': 'middle_both_filled'})
                        save_state()
                    else:
                        # ── Smart Rebalancer (last-resort, late-game only) ──
                        if _middle_rebalancer_check(bot, bot_id, now_m, actions, session_pnl):
                            continue  # Rebalancer acted — skip legacy checks

                        # Check stop-loss: get live bid of the filled leg
                        filled_ticker = bot.get(filled_ticker_key, '')
                        try:
                            live_bid = 0
                            ws_p = ws_manager.get_price(filled_ticker) if ws_manager else None
                            if ws_p:
                                live_bid = ws_p.get('no_bid', 0) or 0
                            if not live_bid and filled_ticker:
                                api_read_limiter.wait()
                                mkt_sl = kalshi_client.get_market(filled_ticker)
                                mkt_sl_data = mkt_sl.get('market', mkt_sl)
                                no_bid_d = mkt_sl_data.get('no_bid_dollars')
                                live_bid = round(float(no_bid_d) * 100) if no_bid_d else mkt_sl_data.get('no_bid', 0)
                            # Store live bid for frontend
                            bot[f'live_no_bid_{filled_leg}'] = live_bid
                            # Trigger stop-loss: raw price floor (not relative to entry)
                            # stop_loss_cents here is the absolute floor price, default 15
                            sl_trigger = stop_loss  # e.g. 15 = exit if bid drops below 15¢
                            if sl_trigger > 0 and live_bid > 0 and live_bid < sl_trigger:
                                bot_log('MIDDLE_SL_TRIGGERED', bot_id, {
                                    'filled_leg': filled_leg, 'fill_price': fill_price,
                                    'live_bid': live_bid, 'sl_trigger': sl_trigger,
                                })
                                print(f'🛑 MIDDLE STOP-LOSS: {bot_id} — {filled_leg} bid={live_bid}¢ < trigger={sl_trigger}¢')
                                # Cancel the unfilled order
                                if bot.get(unfilled_order_key):
                                    try:
                                        api_rate_limiter.wait()
                                        kalshi_client.cancel_order(bot[unfilled_order_key])
                                        bot_log('ORDER_CANCELLED', bot_id, {'order_id': bot[unfilled_order_key], 'reason': 'middle_sl'})
                                    except Exception as ce:
                                        bot_log('ERROR', bot_id, {'step': 'cancel_unfilled', 'error': str(ce)}, level='WARN')
                                # Market-sell the filled leg
                                sold_sl, sell_info_sl = execute_sell(filled_ticker, 'no', qty_m, reason=f'middle_sl_{bot_id}')
                                sell_price_sl = (sell_info_sl or {}).get('actual_fill_price') or (sell_info_sl or {}).get('sell_price', 0)
                                sl_buy_fee = _kalshi_side_fee_cents(fill_price, qty_m)
                                sl_sell_fee = _kalshi_taker_side_fee_cents(sell_price_sl, qty_m) if sell_price_sl else 0
                                sl_fees = sl_buy_fee + sl_sell_fee
                                loss_cents = (fill_price - (sell_price_sl or fill_price)) * qty_m + sl_fees
                                bot['status'] = 'stopped'
                                bot['stopped_at'] = now_m
                                bot['sl_sell_price'] = sell_price_sl
                                session_pnl['gross_loss_cents'] += max(0, loss_cents)
                                session_pnl['stopped_bots'] += 1
                                _record_trade({
                                    'bot_id': bot_id, 'type': 'middle',
                                    'ticker_a': bot.get('ticker_a'), 'ticker_b': bot.get('ticker_b'),
                                    'team_a_name': bot.get('team_a_name'), 'team_b_name': bot.get('team_b_name'),
                                    'spread_a': bot.get('spread_a'), 'spread_b': bot.get('spread_b'),
                                    'target_price': bot.get('target_price'), 'qty': qty_m,
                                    'filled_leg': filled_leg, 'fill_price': fill_price,
                                    'sl_sell_price': sell_price_sl, 'loss_cents': loss_cents,
                                    'fee_cents': sl_fees,
                                    'result': 'stopped_sl', 'timestamp': now_m,
                                    'note': f'stop-loss: {filled_leg} bid={live_bid}¢ < trigger={sl_trigger}¢',
                                }, bot)
                                bot_log('MIDDLE_SL_FIRED', bot_id, {'sold': sold_sl, 'sell_price': sell_price_sl, 'loss_cents': loss_cents})
                                actions.append({'bot_id': bot_id, 'action': 'middle_stop_loss', 'loss_cents': loss_cents})
                                save_state()
                        except Exception as sl_err:
                            bot_log('ERROR', bot_id, {'step': 'sl_check', 'error': str(sl_err)}, level='WARN')

                        # ── One-leg timeout: game over, clean up unfilled order ──
                        # If the unfilled market is dead (bid=0 / closed) OR bot stuck >3 hours,
                        # cancel the unfilled order and wait for the filled leg to settle.
                        try:
                            one_filled_age_min = (now_m - (bot.get('one_filled_at') or now_m)) / 60
                            unfilled_ticker_val = bot.get(f'ticker_{unfilled_leg}', '')
                            if one_filled_age_min > 30 and unfilled_ticker_val and bot['status'] == 'one_filled':
                                uf_dead = False
                                uf_bid_check = 0
                                ws_uf = ws_manager.get_price(unfilled_ticker_val) if ws_manager else None
                                if ws_uf:
                                    uf_bid_check = ws_uf.get('no_bid', 0) or 0
                                if uf_bid_check == 0:
                                    api_read_limiter.wait()
                                    mkt_uf = kalshi_client.get_market(unfilled_ticker_val)
                                    mkt_uf_data = mkt_uf.get('market', mkt_uf)
                                    _uf_nb_d = mkt_uf_data.get('no_bid_dollars')
                                    uf_bid_check = round(float(_uf_nb_d) * 100) if _uf_nb_d else (mkt_uf_data.get('no_bid', 0) or 0)
                                    if mkt_uf_data.get('status', '') not in ('active', 'open', '') or uf_bid_check == 0:
                                        uf_dead = True
                                if uf_dead or one_filled_age_min > 180:
                                    # Cancel unfilled order
                                    if bot.get(unfilled_order_key):
                                        try:
                                            api_rate_limiter.wait()
                                            kalshi_client.cancel_order(bot[unfilled_order_key])
                                            bot_log('ORDER_CANCELLED', bot_id, {'order_id': bot[unfilled_order_key], 'reason': 'middle_one_leg_timeout'})
                                        except Exception:
                                            pass
                                    bot['status'] = 'one_leg_timeout'
                                    bot['timeout_at'] = now_m
                                    bot_log('MIDDLE_ONE_LEG_TIMEOUT', bot_id, {
                                        'filled_leg': filled_leg,
                                        'age_min': round(one_filled_age_min, 1),
                                        'reason': 'market_dead' if uf_dead else 'time_limit',
                                    })
                                    print(f'⌛ MIDDLE ONE-LEG TIMEOUT: {bot_id} — {filled_leg} filled, {unfilled_leg} expired after {round(one_filled_age_min, 1)} min')
                                    actions.append({'bot_id': bot_id, 'action': 'middle_one_leg_timeout'})
                                    save_state()
                        except Exception as to_err:
                            bot_log('ERROR', bot_id, {'step': 'one_leg_timeout_check', 'error': str(to_err)}, level='WARN')

            except Exception as mid_err:
                print(f'Error monitoring middle bot {bot_id}: {mid_err}')
                continue

        # ── Settle both_filled middle bots when markets close ────────
        for bot_id, bot in list(active_bots.items()):
            if bot.get('type') != 'middle' or bot['status'] != 'both_filled':
                continue
            try:
                now_s = time.time()

                # ── Rebalancer: sell dead leg to enhance arb profit ──
                if _middle_rebalancer_check(bot, bot_id, now_s, actions, session_pnl):
                    continue  # Rebalancer sold a leg — settlement will handle the rest

                ticker_a = bot.get('ticker_a', '')
                ticker_b = bot.get('ticker_b', '')
                # Check if both markets are settled
                settled_a = False
                settled_b = False
                result_a = ''
                result_b = ''
                try:
                    api_read_limiter.wait()
                    mkt_a = kalshi_client.get_market(ticker_a)
                    mkt_a_data = mkt_a.get('market', mkt_a)
                    if mkt_a_data.get('status', '') not in ('active', 'open', ''):
                        settled_a = True
                        result_a = mkt_a_data.get('result', '').lower()
                except Exception:
                    pass
                try:
                    api_read_limiter.wait()
                    mkt_b = kalshi_client.get_market(ticker_b)
                    mkt_b_data = mkt_b.get('market', mkt_b)
                    if mkt_b_data.get('status', '') not in ('active', 'open', ''):
                        settled_b = True
                        result_b = mkt_b_data.get('result', '').lower()
                except Exception:
                    pass

                if settled_a and settled_b:
                    # Guard: require actual result values before settling
                    # Kalshi may return market as closed before result is populated
                    if result_a not in ('yes', 'no') or result_b not in ('yes', 'no'):
                        bot['_last_settle_check'] = now_s
                        continue
                    qty_s = bot.get('qty', 1)
                    fill_a = bot.get('leg_a_fill_price', bot.get('target_price', 49))
                    fill_b = bot.get('leg_b_fill_price', bot.get('target_price', 49))
                    # NO wins when market result is 'no'
                    leg_a_win = (result_a == 'no')
                    leg_b_win = (result_b == 'no')
                    middle_hit = leg_a_win and leg_b_win
                    profit_a = (100 - fill_a) * qty_s if leg_a_win else (-fill_a * qty_s)
                    profit_b = (100 - fill_b) * qty_s if leg_b_win else (-fill_b * qty_s)
                    # Maker fees on both NO legs (each is a posted limit order)
                    fee_a = _kalshi_side_fee_cents(fill_a, qty_s)
                    fee_b = _kalshi_side_fee_cents(fill_b, qty_s)
                    total_fee = fee_a + fee_b
                    total_profit = profit_a + profit_b - total_fee
                    bot['status'] = 'completed'
                    bot['completed_at'] = now_s
                    bot['leg_a_result'] = 'win' if leg_a_win else 'loss'
                    bot['leg_b_result'] = 'win' if leg_b_win else 'loss'
                    bot['middle_hit'] = middle_hit
                    if total_profit > 0:
                        session_pnl['gross_profit_cents'] += total_profit
                        session_pnl['completed_bots'] += 1
                    else:
                        session_pnl['gross_loss_cents'] += abs(total_profit)
                        session_pnl['stopped_bots'] += 1
                    _record_trade({
                        'bot_id': bot_id, 'type': 'middle',
                        'ticker_a': ticker_a, 'ticker_b': ticker_b,
                        'team_a_name': bot.get('team_a_name'), 'team_b_name': bot.get('team_b_name'),
                        'spread_a': bot.get('spread_a'), 'spread_b': bot.get('spread_b'),
                        'target_price': bot.get('target_price'), 'qty': qty_s,
                        'leg_a_fill_price': fill_a, 'leg_b_fill_price': fill_b,
                        'leg_a_result': bot['leg_a_result'], 'leg_b_result': bot['leg_b_result'],
                        'middle_hit': middle_hit,
                        'profit_cents': max(0, total_profit),
                        'loss_cents': max(0, -total_profit),
                        'fee_cents': total_fee,
                        'result': 'middle_hit' if middle_hit else ('arb_win' if (leg_a_win or leg_b_win) else 'loss'),
                        'timestamp': now_s,
                        'note': f'{"MIDDLE HIT" if middle_hit else ("partial win" if (leg_a_win or leg_b_win) else "both lost")} — A:{result_a} B:{result_b}',
                    }, bot)
                    bot_log('MIDDLE_SETTLED', bot_id, {
                        'middle_hit': middle_hit, 'profit_cents': total_profit,
                        'leg_a_result': result_a, 'leg_b_result': result_b,
                    })
                    print(f'📐 MIDDLE SETTLED: {bot_id} | middle_hit={middle_hit} | profit={total_profit}¢')
                    actions.append({'bot_id': bot_id, 'action': 'middle_settled', 'profit_cents': total_profit, 'middle_hit': middle_hit})
                    save_state()
            except Exception as ms_err:
                print(f'Error settling middle bot {bot_id}: {ms_err}')
                continue

        # ── Settle one_leg_timeout: wait for the filled leg's market to close ──
        for bot_id, bot in list(active_bots.items()):
            if bot.get('type') != 'middle' or bot['status'] != 'one_leg_timeout':
                continue
            try:
                now_s = time.time()
                filled_leg = bot.get('filled_leg', 'a')
                unfilled_leg = 'b' if filled_leg == 'a' else 'a'
                filled_ticker = bot.get(f'ticker_{filled_leg}', '')
                if not filled_ticker:
                    continue
                api_read_limiter.wait()
                mkt_f = kalshi_client.get_market(filled_ticker)
                mkt_f_data = mkt_f.get('market', mkt_f)
                if mkt_f_data.get('status', '') not in ('active', 'open', ''):
                    result_f = mkt_f_data.get('result', '').lower()
                    filled_leg_win = (result_f == 'no')
                    qty_s = bot.get('qty', 1)
                    fill_price = bot.get(f'leg_{filled_leg}_fill_price') or bot.get('target_price', 49)
                    one_leg_fee = _kalshi_side_fee_cents(fill_price, qty_s)
                    profit = ((100 - fill_price) * qty_s if filled_leg_win else (-fill_price * qty_s)) - one_leg_fee
                    bot['status'] = 'completed'
                    bot['completed_at'] = now_s
                    bot[f'leg_{filled_leg}_result'] = 'win' if filled_leg_win else 'loss'
                    bot[f'leg_{unfilled_leg}_result'] = 'cancelled'
                    if profit > 0:
                        session_pnl['gross_profit_cents'] += profit
                        session_pnl['completed_bots'] += 1
                    else:
                        session_pnl['gross_loss_cents'] += abs(profit)
                        session_pnl['stopped_bots'] += 1
                    _record_trade({
                        'bot_id': bot_id, 'type': 'middle',
                        'ticker_a': bot.get('ticker_a'), 'ticker_b': bot.get('ticker_b'),
                        'team_a_name': bot.get('team_a_name'), 'team_b_name': bot.get('team_b_name'),
                        'spread_a': bot.get('spread_a'), 'spread_b': bot.get('spread_b'),
                        'target_price': bot.get('target_price'), 'qty': qty_s,
                        'leg_a_fill_price': bot.get('leg_a_fill_price'), 'leg_b_fill_price': bot.get('leg_b_fill_price'),
                        'leg_a_result': bot.get('leg_a_result') or ('win' if filled_leg == 'a' and filled_leg_win else ('loss' if filled_leg == 'a' else 'cancelled')),
                        'leg_b_result': bot.get('leg_b_result') or ('win' if filled_leg == 'b' and filled_leg_win else ('loss' if filled_leg == 'b' else 'cancelled')),
                        'middle_hit': False,
                        'profit_cents': max(0, profit),
                        'loss_cents': max(0, -profit),
                        'fee_cents': one_leg_fee,
                        'result': 'arb_win' if profit > 0 else 'loss',
                        'timestamp': now_s,
                        'note': f'one-leg settle: {filled_leg} {"win" if filled_leg_win else "loss"}, {unfilled_leg} cancelled/unfilled',
                    }, bot)
                    bot_log('MIDDLE_ONE_LEG_SETTLED', bot_id, {'filled_leg': filled_leg, 'profit_cents': profit})
                    print(f'📐 MIDDLE ONE-LEG SETTLED: {bot_id} | {filled_leg} {"win" if filled_leg_win else "loss"} | profit={profit}¢')
                    actions.append({'bot_id': bot_id, 'action': 'middle_one_leg_settled', 'profit_cents': profit})
                    save_state()
            except Exception as ol_err:
                print(f'Error settling one_leg_timeout bot {bot_id}: {ol_err}')
                continue

        # ── Stale bot cleanup: auto-complete dead bots that have no positions to track ──
        _cleanup_now = time.time()
        for _cid, _cb in list(active_bots.items()):
            _cs = _cb.get('status', '')
            # Skip already terminal or genuinely active bots
            if _cs in ('completed', 'cancelled', 'error'):
                continue
            if _cs in active_statuses and _cs != 'stopped':
                # Active bot — only clean up when the market itself has closed/settled
                _ticker = _cb.get('ticker', '')
                if not _ticker:
                    continue
                # Check market status on Kalshi (only check once per bot per cycle, throttled)
                _last_mkt_check = _cb.get('_last_stale_market_check', 0)
                if _cleanup_now - _last_mkt_check < 300:  # check at most every 5 min
                    continue
                _cb['_last_stale_market_check'] = _cleanup_now
                try:
                    api_read_limiter.wait()
                    _mkt_resp = kalshi_client.get_market(_ticker)
                    _mkt_data = _mkt_resp.get('market', _mkt_resp) if isinstance(_mkt_resp, dict) else {}
                    _mkt_status = _mkt_data.get('status', 'active')
                    _mkt_result = _mkt_data.get('result', '')
                except Exception:
                    continue  # API error — skip this cycle, don't reap
                if _mkt_status in ('active', 'open') and not _mkt_result:
                    continue  # market still open — bot is doing its job, leave it alone
                # Market closed/settled — check for fills
                _has_fills = False
                for _rung in _cb.get('rungs', []):
                    if (_rung.get('yes_fill_qty', 0) or 0) > 0 or (_rung.get('no_fill_qty', 0) or 0) > 0:
                        _has_fills = True
                        break
                if not _has_fills:
                    _has_fills = ((_cb.get('dog_fill_qty', 0) or 0) > 0 or
                                 (_cb.get('fav_fill_qty', 0) or 0) > 0 or
                                 (_cb.get('yes_fill_qty', 0) or 0) > 0 or
                                 (_cb.get('no_fill_qty', 0) or 0) > 0 or
                                 (_cb.get('fill_qty', 0) or 0) > 0)
                if _has_fills:
                    continue  # has positions — keep for settlement tracking
                # No fills + old → cancel resting orders on Kalshi, then auto-complete
                _cancelled_orders = []
                for _okey in ('dog_order_id', 'fav_order_id', 'hedge_order_id', 'order_a_id', 'order_b_id', 'yes_order_id', 'no_order_id'):
                    _oid = _cb.get(_okey)
                    if _oid:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(_oid)
                            _cancelled_orders.append(_oid[:12])
                        except Exception:
                            pass
                # Cancel rung orders (ladders)
                _ac_group = _cb.get('_order_group_id')
                if _ac_group:
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order_group(_ac_group)
                    except Exception:
                        _ac_group = None
                if not _ac_group:
                    for _rung in _cb.get('rungs', []):
                        for _side in ('yes', 'no'):
                            _oid = _rung.get(f'{_side}_order_id')
                            if _oid and not _rung.get('cancelled'):
                                try:
                                    api_rate_limiter.wait()
                                    kalshi_client.cancel_order(_oid)
                                    _cancelled_orders.append(_oid[:12])
                                except Exception:
                                    pass
                # Also cancel any tracked dog order IDs
                for _oid in _cb.get('_all_dog_order_ids', []):
                    if _oid:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(_oid)
                            _cancelled_orders.append(_oid[:12])
                        except Exception:
                            pass
                _cb['status'] = 'completed'
                _cb['completed_at'] = _cleanup_now
                _cb['_auto_cleaned'] = True
                print(f'🧹 AUTO-CLEAN: {_cid} ({_cs}) — market {_mkt_status}/{_mkt_result}, no fills, cancelled {len(_cancelled_orders)} orders, marking completed')
                bot_log('AUTO_CLEAN_STALE', _cid, {'market_status': _mkt_status, 'market_result': _mkt_result, 'cancelled_orders': _cancelled_orders})
                actions.append({'bot_id': _cid, 'action': 'auto_clean_stale'})
            elif _cs == 'stopped':
                # Stopped bots: clean up after 1 hour if no fills to track
                _stopped_age = (_cleanup_now - (_cb.get('stopped_at', _cb.get('created_at', _cleanup_now)))) / 3600
                if _stopped_age < 1:
                    continue
                _has_fills = ((_cb.get('dog_fill_qty', 0) or 0) > 0 or
                              (_cb.get('fav_fill_qty', 0) or 0) > 0 or
                              (_cb.get('yes_fill_qty', 0) or 0) > 0 or
                              (_cb.get('no_fill_qty', 0) or 0) > 0 or
                              (_cb.get('fill_qty', 0) or 0) > 0)
                for _rung in _cb.get('rungs', []):
                    if (_rung.get('yes_fill_qty', 0) or 0) > 0 or (_rung.get('no_fill_qty', 0) or 0) > 0 or (_rung.get('fill_qty', 0) or 0) > 0:
                        _has_fills = True
                        break
                if _has_fills:
                    continue  # holding position for settlement
                _cb['status'] = 'completed'
                _cb['completed_at'] = _cleanup_now
                _cb['_auto_cleaned'] = True
                print(f'🧹 AUTO-CLEAN: {_cid} (stopped) — {_stopped_age:.1f}h stopped, no fills, marking completed')
                actions.append({'bot_id': _cid, 'action': 'auto_clean_stopped'})

        # Only persist when something actually changed — saves ~50ms per idle cycle
        if actions:
            save_state()
        active_count = len([b for b in active_bots.values() if b['status'] in active_statuses])
        if actions:
            bot_log('MONITOR_CYCLE', '', {'active_bots': active_count, 'actions_count': len(actions), 'actions_summary': [a.get('action', '?') for a in actions]})
        return jsonify({
            'success':     True,
            'actions':     actions,
            'active_bots': active_count,
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/middle/bot/create', methods=['POST'])
def create_middle_bot():
    """
    Middle Bot: places limit BUY NO orders on two opposing spread markets at target_price.
    Both orders rest in the book waiting for game volatility to push prices down to target.
    When both fill, profit is locked. Stop-loss sells the filled leg if the other stalls.
    """
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        data = request.json or {}
        ticker_a        = data.get('ticker_a', '').strip()
        ticker_b        = data.get('ticker_b', '').strip()
        # Per-leg prices (new); fall back to legacy target_price if not provided
        _legacy_price   = int(data.get('target_price', 49))
        target_price_a  = int(data.get('target_price_a', _legacy_price))
        target_price_b  = int(data.get('target_price_b', _legacy_price))
        qty             = int(data.get('qty', 1))
        stop_loss_cents = int(data.get('stop_loss_cents', 0))
        team_a_name     = data.get('team_a_name', '')
        team_b_name     = data.get('team_b_name', '')
        spread_a        = data.get('spread_a', 0)
        spread_b        = data.get('spread_b', 0)
        no_a_bid        = data.get('no_a_bid', 0)
        no_b_bid        = data.get('no_b_bid', 0)
        game_id         = data.get('game_id', '')
        # Rebalancer config
        rebalancer_enabled    = data.get('rebalancer_enabled', True)
        rebalancer_mode       = data.get('rebalancer_mode', 'live')  # 'dry_run' or 'live'
        rebalancer_protect    = int(data.get('rebalancer_protect_floor', 80))
        rebalancer_late_secs  = int(data.get('rebalancer_late_game_secs', 180))
        rebalancer_scrape     = int(data.get('rebalancer_scrape_ceil', 10))
        rebalancer_buffer     = int(data.get('rebalancer_margin_buffer', 5))

        if not ticker_a or not ticker_b:
            return jsonify({'error': 'Missing required fields: ticker_a, ticker_b'}), 400
        if not (1 <= target_price_a <= 99) or not (1 <= target_price_b <= 99):
            return jsonify({'error': f'Prices out of range (1-99): A={target_price_a} B={target_price_b}'}), 400
        if qty < 1:
            return jsonify({'error': 'qty must be at least 1'}), 400

        # Place NO limit orders on both legs (each at their own price)
        api_rate_limiter.wait()
        order_a_resp = kalshi_client.create_order(
            ticker=ticker_a, side='no', action='buy',
            count=qty, no_price=target_price_a, post_only=True
        )
        order_a_id = _extract_order_id(order_a_resp, f'middle dual leg A {ticker_a}')
        if not order_a_id:
            return jsonify({'error': 'Leg A order placed but no order_id returned — check Kalshi positions'}), 500

        try:
            api_rate_limiter.wait()
            order_b_resp = kalshi_client.create_order(
                ticker=ticker_b, side='no', action='buy',
                count=qty, no_price=target_price_b, post_only=True
            )
            order_b_id = _extract_order_id(order_b_resp, f'middle dual leg B {ticker_b}')
            if not order_b_id:
                # Leg A succeeded but leg B failed — cancel A to prevent orphan
                _safe_cancel(order_a_id, f'middle dual leg B failed, cancelling A {ticker_a}')
                return jsonify({'error': 'Leg B order failed — cancelled leg A to prevent orphan'}), 500
        except Exception as e:
            _safe_cancel(order_a_id, f'middle dual leg B exception, cancelling A {ticker_a}')
            return jsonify({'error': f'Leg B failed: {e} — cancelled leg A'}), 500

        bot_id = f"mid_bot_{int(time.time() * 1000)}"
        active_bots[bot_id] = {
            'id':               bot_id,
            'type':             'middle',
            'status':           'waiting',
            'ticker_a':         ticker_a,
            'ticker_b':         ticker_b,
            'ticker':           ticker_a,  # used by grouping/display logic
            'target_price':     target_price_a,   # legacy single-price field (leg A)
            'target_price_a':   target_price_a,
            'target_price_b':   target_price_b,
            'qty':              qty,
            'stop_loss_cents':  stop_loss_cents,
            'team_a_name':      team_a_name,
            'team_b_name':      team_b_name,
            'spread_a':         spread_a,
            'spread_b':         spread_b,
            'no_a_bid':         no_a_bid,
            'no_b_bid':         no_b_bid,
            'game_id':          game_id,
            'order_a_id':       order_a_id,
            'order_b_id':       order_b_id,
            'leg_a_filled':     False,
            'leg_b_filled':     False,
            'leg_a_fill_price': None,
            'leg_b_fill_price': None,
            'filled_leg':       None,
            'created_at':       time.time(),
            'placed_at':        time.time(),
            '_original_cost':   target_price_a + target_price_b,
            # Rebalancer (last-resort, late-game smart exit)
            'rebalancer_enabled':        rebalancer_enabled,
            'rebalancer_mode':           rebalancer_mode,
            'rebalancer_protect_floor':  rebalancer_protect,
            'rebalancer_late_game_secs': rebalancer_late_secs,
            'rebalancer_scrape_ceil':    rebalancer_scrape,
            'rebalancer_margin_buffer':  rebalancer_buffer,
        }
        save_state()

        # Subscribe WS to both tickers for real-time price updates
        if ws_manager.connected:
            ws_manager.add_ticker(ticker_a)
            ws_manager.add_ticker(ticker_b)

        guaranteed    = 100 - target_price_a - target_price_b
        middle_profit = 200 - target_price_a - target_price_b
        price_str = f'{target_price_a}¢/{target_price_b}¢' if target_price_a != target_price_b else f'{target_price_a}¢'

        bot_log('MIDDLE_BOT_CREATED', bot_id, {
            'ticker_a': ticker_a, 'ticker_b': ticker_b,
            'target_price_a': target_price_a, 'target_price_b': target_price_b,
            'qty': qty, 'stop_loss_cents': stop_loss_cents,
            'order_a_id': order_a_id, 'order_b_id': order_b_id,
            'guaranteed': guaranteed, 'middle_profit': middle_profit,
        })
        print(f'📐 MIDDLE BOT CREATED: {bot_id} | NO {ticker_a} @ {target_price_a}¢ + NO {ticker_b} @ {target_price_b}¢ × {qty}')

        return jsonify({
            'success':          True,
            'bot_id':           bot_id,
            'order_a_id':       order_a_id,
            'order_b_id':       order_b_id,
            'target_price_a':   target_price_a,
            'target_price_b':   target_price_b,
            'guaranteed':       guaranteed,
            'middle_profit':    middle_profit,
            'message':          f'Middle bot deployed: NO {ticker_a} @ {target_price_a}¢ + NO {ticker_b} @ {target_price_b}¢ × {qty} — '
                                f'guaranteed {guaranteed:+}¢, middle profit +{middle_profit}¢',
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/bot/list', methods=['GET'])
def list_bots():
    """Get all bots with live market data"""
    # Enrich bots with live WS prices
    for bid, bot in list(active_bots.items()):
        st = bot.get('status', '')
        if st in ('completed', 'stopped'):
            continue

        # Clear stale live prices so we always fetch fresh from WS
        for k in ('live_yes_bid', 'live_no_bid', 'live_yes_ask', 'live_no_ask',
                   'live_no_a_bid', 'live_no_a_ask', 'live_no_b_bid', 'live_no_b_ask'):
            bot.pop(k, None)

        # Standard arb/dog bots — single ticker
        if bot.get('ticker'):
            if ws_manager and ws_manager.connected:
                ws_manager.add_ticker(bot['ticker'])
            ws_p = ws_manager.get_price(bot['ticker']) if ws_manager else None
            if ws_p:
                _bl_yb = ws_p.get('yes_bid', 0)
                _bl_nb = ws_p.get('no_bid', 0)
                bot['live_yes_bid'] = _bl_yb
                bot['live_no_bid']  = _bl_nb
                bot['live_yes_ask'] = ws_p.get('yes_ask', 0) or (100 - _bl_nb if _bl_nb > 0 else 0)
                bot['live_no_ask']  = ws_p.get('no_ask',  0) or (100 - _bl_yb if _bl_yb > 0 else 0)
                bot['_price_source'] = 'ws'
                bot['_price_age_s'] = round(time.time() - ws_p.get('_local_ts', 0))
            elif kalshi_client:
                # REST fallback for display — only if WS has no data
                _rest_ticker = bot['ticker']
                if _rest_ticker not in _rest_price_cache or (time.time() - _rest_price_cache[_rest_ticker].get('_ts', 0)) > 10:
                    try:
                        api_read_limiter.wait()
                        _ob = kalshi_client.get_market_orderbook(_rest_ticker)
                        _yb = _best_bid(_ob, 'yes')
                        _nb = _best_bid(_ob, 'no')
                        _rest_price_cache[_rest_ticker] = {
                            'yes_bid': _yb, 'no_bid': _nb,
                            'yes_ask': (100 - _nb) if _nb > 0 else 0,
                            'no_ask': (100 - _yb) if _yb > 0 else 0,
                            '_ts': time.time(),
                        }
                    except Exception as _re:
                        print(f'⚠ REST price fetch failed for {_rest_ticker}: {_re}')
                _rp = _rest_price_cache.get(_rest_ticker, {})
                _rp_age = round(time.time() - _rp.get('_ts', 0)) if _rp else 999
                if _rp.get('yes_bid', 0) > 0 or _rp.get('no_bid', 0) > 0:
                    # If REST cache is very stale (>60s), don't show it — it's misleading
                    if _rp_age > 60:
                        bot['_price_source'] = 'stale'
                        bot['_price_age_s'] = _rp_age
                    else:
                        bot['live_yes_bid'] = _rp.get('yes_bid', 0)
                        bot['live_no_bid']  = _rp.get('no_bid', 0)
                        bot['live_yes_ask'] = _rp.get('yes_ask', 0)
                        bot['live_no_ask']  = _rp.get('no_ask', 0)
                        bot['_price_source'] = 'rest'
                        bot['_price_age_s'] = _rp_age

        # Middle bots — dual tickers (ticker_a / ticker_b)
        if bot.get('type') == 'middle':
            for leg in ('a', 'b'):
                tk = bot.get(f'ticker_{leg}', '')
                if tk:
                    if ws_manager and ws_manager.connected:
                        ws_manager.add_ticker(tk)
                    ws_p = ws_manager.get_price(tk) if ws_manager else None
                    if ws_p:
                        bot[f'live_no_{leg}_bid'] = ws_p.get('no_bid', 0)
                        bot[f'live_no_{leg}_ask'] = ws_p.get('no_ask', 0) or (100 - ws_p.get('yes_bid', 0) if ws_p.get('yes_bid', 0) else 0)
                    elif kalshi_client:
                        # REST fallback for middle bot legs
                        if tk not in _rest_price_cache or (time.time() - _rest_price_cache[tk].get('_ts', 0)) > 10:
                            try:
                                api_read_limiter.wait()
                                _ob = kalshi_client.get_market_orderbook(tk)
                                _nb = _best_bid(_ob, 'no')
                                _yb = _best_bid(_ob, 'yes')
                                _rest_price_cache[tk] = {
                                    'no_bid': _nb, 'no_ask': (100 - _yb) if _yb > 0 else 0,
                                    'yes_bid': _yb, '_ts': time.time(),
                                }
                            except Exception:
                                pass
                        _rp = _rest_price_cache.get(tk, {})
                        if _rp.get('no_bid', 0) > 0:
                            bot[f'live_no_{leg}_bid'] = _rp.get('no_bid', 0)
                            bot[f'live_no_{leg}_ask'] = _rp.get('no_ask', 0)

    # Gather live scores per game-key for frontend display
    game_scores = {}
    for bid, bot in list(active_bots.items()):
        if bot.get('status') in ('completed', 'stopped'):
            continue
        ticker = bot.get('ticker', '')
        parts = ticker.split('-')
        gk = parts[1] if len(parts) >= 2 else parts[0]
        if gk not in game_scores:
            score_info = _get_game_score_for_ticker(ticker)
            if score_info:
                game_scores[gk] = score_info
    return jsonify({'bots': active_bots, 'game_scores': game_scores})


@app.route('/api/bot/history', methods=['GET'])
def bot_history():
    """Get completed/stopped trade history"""
    limit = int(request.args.get('limit', 50))
    date_filter = request.args.get('date', '').strip()
    dates_filter = request.args.get('dates', '').strip()  # comma-separated multi-day
    category_filter = request.args.get('category', '').strip()
    if dates_filter:
        date_set = set(d.strip() for d in dates_filter.split(',') if d.strip())
        filtered = [t for t in trade_history if _trade_day_key(t) in date_set]
    elif date_filter:
        filtered = [t for t in trade_history if _trade_day_key(t) == date_filter]
    else:
        filtered = trade_history
    if category_filter:
        cats = category_filter.split(',')
        filtered = [t for t in filtered if t.get('bot_category') in cats or t.get('fill_source') in cats or t.get('type') in cats]
    return jsonify({'trades': filtered[:limit], 'total': len(filtered)})


@app.route('/api/logs', methods=['GET'])
def get_activity_logs():
    """Get the activity log for debugging. Supports ?lines=N (default 200) and ?event=X filter."""
    try:
        lines = int(request.args.get('lines', 200))
        event_filter = request.args.get('event', '').strip()
        bot_filter = request.args.get('bot_id', '').strip()
        level_filter = request.args.get('level', '').strip().upper()

        if not os.path.exists(LOG_FILE):
            return jsonify({'logs': [], 'total': 0})

        with open(LOG_FILE, 'r') as f:
            all_lines = f.readlines()

        # Parse from newest to oldest
        entries = []
        for line in reversed(all_lines):
            line = line.strip()
            if not line:
                continue
            try:
                entry = json.loads(line)
            except json.JSONDecodeError:
                continue
            if event_filter and entry.get('event', '') != event_filter:
                continue
            if bot_filter and bot_filter not in entry.get('bot_id', ''):
                continue
            if level_filter and entry.get('level', '') != level_filter:
                continue
            entries.append(entry)
            if len(entries) >= lines:
                break

        return jsonify({'logs': entries, 'total': len(all_lines)})
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/logs/clear', methods=['POST'])
def clear_activity_logs():
    """Clear the activity log file."""
    try:
        with open(LOG_FILE, 'w') as f:
            f.write('')
        return jsonify({'success': True, 'message': 'Activity log cleared'})
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/bot/history/clear', methods=['POST'])
def clear_history():
    """Clear all trade history and reset P&L counters"""
    global trade_history, session_pnl
    trade_history = []
    session_pnl['gross_profit_cents'] = 0
    session_pnl['gross_loss_cents'] = 0
    session_pnl['completed_bots'] = 0
    session_pnl['stopped_bots'] = 0
    save_state()
    return jsonify({'success': True, 'message': 'History cleared, P&L reset'})


def _compute_completed_stats(arb_wins):
    """Detailed breakdown of completed (profitable) arb trades."""
    if not arb_wins:
        return {'total': 0}
    profits = [t.get('profit_cents', 0) for t in arb_wins]
    total_profit = sum(profits)
    avg_profit = round(total_profit / len(profits)) if profits else 0
    max_profit = max(profits) if profits else 0
    min_profit = min(profits) if profits else 0
    quantities = [t.get('quantity', 1) for t in arb_wins]
    avg_qty = round(sum(quantities) / len(quantities), 1)
    total_contracts = sum(quantities)
    # Per-contract profit
    per_contract_profits = []
    for t in arb_wins:
        q = t.get('quantity', 1)
        p = t.get('profit_cents', 0)
        if q > 0:
            per_contract_profits.append(round(p / q))
    avg_per_contract = round(sum(per_contract_profits) / len(per_contract_profits)) if per_contract_profits else 0
    # Best/worst width for completed
    width_profits = {}
    for t in arb_wins:
        w = t.get('arb_width', 0)
        if w > 0:
            if w not in width_profits:
                width_profits[w] = {'count': 0, 'total': 0}
            width_profits[w]['count'] += 1
            width_profits[w]['total'] += t.get('profit_cents', 0)
    best_width = max(width_profits.items(), key=lambda x: x[1]['total'])[0] if width_profits else 0
    best_width_profit = width_profits[best_width]['total'] if best_width else 0
    return {
        'total': len(arb_wins),
        'total_profit_cents': total_profit,
        'avg_profit_cents': avg_profit,
        'max_profit_cents': max_profit,
        'min_profit_cents': min_profit,
        'avg_quantity': avg_qty,
        'total_contracts': total_contracts,
        'avg_per_contract': avg_per_contract,
        'best_width': best_width,
        'best_width_profit': best_width_profit,
    }


def _compute_amended_stats(arb_trades):
    """Breakdown of timeout-amended arb trades into profitable vs losing."""
    amended = [t for t in arb_trades if t.get('exit_via') == 'timeout_amend']
    if not amended:
        return {'total': 0}
    profitable = []
    losing = []
    for t in amended:
        p = t.get('profit_cents', 0) or 0
        l = t.get('loss_cents', 0) or 0
        net = p - l
        if net >= 0:
            profitable.append(t)
        else:
            losing.append(t)
    gross_profit = sum((t.get('profit_cents', 0) or 0) for t in amended)
    gross_loss = sum((t.get('loss_cents', 0) or 0) for t in amended)
    return {
        'total': len(amended),
        'profitable_n': len(profitable),
        'losing_n': len(losing),
        'gross_profit_cents': gross_profit,
        'gross_loss_cents': gross_loss,
        'net_cents': gross_profit - gross_loss,
        'avg_profit_cents': round(sum((t.get('profit_cents', 0) or 0) - (t.get('loss_cents', 0) or 0) for t in profitable) / len(profitable)) if profitable else 0,
        'avg_loss_cents': round(sum((t.get('loss_cents', 0) or 0) - (t.get('profit_cents', 0) or 0) for t in losing) / len(losing)) if losing else 0,
        'yes_first_n': sum(1 for t in amended if t.get('first_leg') == 'yes'),
        'no_first_n': sum(1 for t in amended if t.get('first_leg') == 'no'),
    }


@app.route('/api/bot/history/stats', methods=['GET'])
def history_stats():
    """Compute analytics from trade history for the optimization dashboard."""
    date_filter = request.args.get('date', '').strip()
    dates_filter = request.args.get('dates', '').strip()  # comma-separated multi-day
    if dates_filter:
        date_set = set(d.strip() for d in dates_filter.split(',') if d.strip())
        source = []
        for t in trade_history:
            day = _trade_day_key(t)
            if day not in date_set:
                continue
            day_reset = _pnl_reset_for_day(day)
            if day_reset > 0 and (t.get('timestamp') or 0) < day_reset:
                continue
            source.append(t)
    elif date_filter:
        source = [t for t in trade_history if _trade_day_key(t) == date_filter]
        # Apply per-day reset for the filtered day
        day_reset = _pnl_reset_for_day(date_filter)
        if day_reset > 0:
            source = [t for t in source if (t.get('timestamp') or 0) >= day_reset]
    else:
        # Lifetime: apply per-day resets so stats match the calendar/pnl endpoints
        source = []
        for t in trade_history:
            day = _trade_day_key(t)
            day_reset = _pnl_reset_for_day(day)
            if day_reset > 0 and (t.get('timestamp') or 0) < day_reset:
                continue
            source.append(t)
    arb_trades = [t for t in source if t.get('type') not in ('watch', 'middle')
                  and t.get('bot_category') not in ('anchor_dog', 'anchor_ladder')
                  and t.get('result') not in ('anchor_sellback', 'ladder_sellback')]
    # Width stats use only current Apex system (ladder_arb), not old arb system
    apex_trades = [t for t in arb_trades if t.get('bot_category') == 'ladder_arb']
    watch_trades = [t for t in source if t.get('type') == 'watch']

    WIN_RESULTS = ('completed', 'settled_win_yes', 'settled_win_no', 'manual_exit_completed')
    LOSS_RESULTS = (
        'stop_loss_yes', 'stop_loss_no', 'flip_yes', 'flip_no',
        'force_exit_yes', 'force_exit_no', 'settled_loss_yes', 'settled_loss_no',
        'amended', 'arb_loss',
    )

    def _is_win(t):
        """Amended arbs that lost money are losses, not wins."""
        r = t.get('result', '')
        if r not in WIN_RESULTS:
            return False
        if t.get('exit_via') == 'timeout_amend':
            return (t.get('profit_cents', 0) or 0) >= (t.get('loss_cents', 0) or 0)
        return True

    arb_wins = [t for t in arb_trades if _is_win(t)]
    arb_losses = [t for t in arb_trades if t.get('result', '') in LOSS_RESULTS
                  or (t.get('result', '') in WIN_RESULTS and not _is_win(t))]

    # ── Result type breakdown ──────────────────────────────────────
    result_counts = {}
    for t in arb_trades:
        r = t.get('result', 'unknown')
        result_counts[r] = result_counts.get(r, 0) + 1

    # ── Timeout exit aggregates (legacy timeout_exit_* + new completed with exit_via) ──
    timeout_trades = [t for t in arb_trades if t.get('result', '') in ('timeout_exit_yes', 'timeout_exit_no')
                      or t.get('exit_via') == 'timeout_amend']
    timeout_total_profit = sum(t.get('profit_cents', 0) for t in timeout_trades)
    timeout_total_loss   = sum(t.get('loss_cents',   0) for t in timeout_trades)
    timeout_yes_n  = sum(1 for t in timeout_trades if t.get('result') == 'timeout_exit_yes'
                        or (t.get('exit_via') == 'timeout_amend' and t.get('first_leg') == 'yes'))
    timeout_no_n   = sum(1 for t in timeout_trades if t.get('result') == 'timeout_exit_no'
                        or (t.get('exit_via') == 'timeout_amend' and t.get('first_leg') == 'no'))

    # ── Flip analysis ──────────────────────────────────────────────
    flip_trades = [t for t in arb_trades if t.get('result', '').startswith('flip_')]
    flip_total = len(flip_trades)
    flip_total_loss = sum(t.get('loss_cents', 0) for t in flip_trades)
    flip_avg_loss = round(flip_total_loss / flip_total) if flip_total > 0 else 0
    # What were the entry prices when flips happened?
    flip_entries = []
    for t in flip_trades:
        if t['result'] == 'flip_yes':
            flip_entries.append(t.get('yes_price', 0))
        elif t['result'] == 'flip_no':
            flip_entries.append(t.get('no_price', 0))
    flip_avg_entry = round(sum(flip_entries) / len(flip_entries)) if flip_entries else 0
    # flip_threshold in trade records is the FLOOR; effective_trigger may be stored too.
    # For any trade, we can compute effective_trigger = max(entry - 15, floor).
    flip_effective_triggers = []
    flip_thresholds_used = []
    for t, entry in zip(flip_trades, flip_entries):
        floor = t.get('flip_threshold', FLIP_THRESHOLD_CENTS)
        eff = t.get('effective_trigger') or max(entry - FLIP_ENTRY_MARGIN, floor)
        flip_effective_triggers.append(eff)
        flip_thresholds_used.append(floor)
    flip_avg_floor = round(sum(flip_thresholds_used) / len(flip_thresholds_used)) if flip_thresholds_used else 0
    flip_avg_effective_trigger = round(sum(flip_effective_triggers) / len(flip_effective_triggers)) if flip_effective_triggers else 0
    # Entry bucket breakdown: classify flips by entry price range
    entry_buckets = {'65-69': {'count': 0, 'loss': 0, 'expected_loss': None},
                     '70-79': {'count': 0, 'loss': 0, 'expected_loss': 15},
                     '80-89': {'count': 0, 'loss': 0, 'expected_loss': 15},
                     '90-99': {'count': 0, 'loss': 0, 'expected_loss': 15}}
    for entry, eff, t in zip(flip_entries, flip_effective_triggers, flip_trades):
        loss_c = t.get('loss_cents', 0)
        if 65 <= entry < 70:
            bucket = '65-69'
        elif 70 <= entry < 80:
            bucket = '70-79'
        elif 80 <= entry < 90:
            bucket = '80-89'
        elif entry >= 90:
            bucket = '90-99'
        else:
            continue
        entry_buckets[bucket]['count'] += 1
        entry_buckets[bucket]['loss'] += loss_c
    entry_bucket_breakdown = []
    for label, b in entry_buckets.items():
        if b['count'] == 0:
            continue
        lo, hi = [int(x) for x in label.split('-')]
        # Expected trigger = max(mid - 15, 55); expected loss from entry = entry - trigger
        mid = (lo + hi) // 2
        exp_trigger = max(mid - FLIP_ENTRY_MARGIN, FLIP_THRESHOLD_CENTS)
        exp_loss = mid - exp_trigger
        entry_bucket_breakdown.append({
            'range': f'{label}¢',
            'count': b['count'],
            'avg_actual_loss': round(b['loss'] / b['count']) if b['count'] else 0,
            'expected_loss': exp_loss,
        })

    # ── Fill rate by width (with real breakeven %) ─────────────────
    # Count all current-system results (wins + all exit types).
    # Excludes old stop_loss_yes/no which used a different risk model.
    current_system_results = WIN_RESULTS + (
        'timeout_exit_yes', 'timeout_exit_no',
        'manual_exit_yes', 'manual_exit_no',
        'flip_yes', 'flip_no',          # legacy — kept for historical data
        'force_exit_yes', 'force_exit_no',
        'settled_loss_yes', 'settled_loss_no',
        'amended',  # timeout amend losses (migration 004 relabeled these)
        'arb_loss',  # rung completions where fees > spread (Apex/Phantom)
    )
    flip_system_results = current_system_results  # alias kept for below code
    width_stats = {}
    for t in apex_trades:
        if t.get('result', '') not in flip_system_results:
            continue
        w = t.get('arb_width', 0)
        if w < 5:  # ignore non-preset widths (2/3/4¢ are bad reconstructed data)
            continue
        if w not in width_stats:
            width_stats[w] = {'wins': 0, 'losses': 0, 'total_profit': 0,
                              'total_loss': 0, 'fill_durations': [],
                              'flips': 0, 'settled_losses': 0, 'amended_losses': 0}
        if _is_win(t):
            width_stats[w]['wins'] += 1
            width_stats[w]['total_profit'] += t.get('profit_cents', 0)
        else:
            width_stats[w]['losses'] += 1
            width_stats[w]['total_loss'] += t.get('loss_cents', 0)
            if t.get('exit_via') == 'timeout_amend' or t.get('result') == 'amended':
                width_stats[w]['amended_losses'] += 1
            elif t['result'].startswith('flip_'):
                width_stats[w]['flips'] += 1
            elif t['result'].startswith('settled_loss'):
                width_stats[w]['settled_losses'] += 1
        if t.get('fill_duration_s') is not None:
            width_stats[w]['fill_durations'].append(t['fill_duration_s'])

    width_breakdown = []
    for w, s in sorted(width_stats.items()):
        total = s['wins'] + s['losses']
        fill_rate = round(s['wins'] / total * 100, 1) if total > 0 else 0
        avg_fill_dur = round(sum(s['fill_durations']) / len(s['fill_durations'])) if s['fill_durations'] else None
        avg_profit = round(s['total_profit'] / s['wins']) if s['wins'] > 0 else w
        avg_loss = round(s['total_loss'] / s['losses']) if s['losses'] > 0 else 0
        # Real breakeven: avg_loss / (avg_loss + avg_profit)
        breakeven_pct = round(avg_loss / (avg_loss + avg_profit) * 100, 1) if (avg_loss + avg_profit) > 0 else 0
        edge = round(fill_rate - breakeven_pct, 1)
        ratio = f'{max(1, round(avg_loss / avg_profit))}:1' if avg_profit > 0 and avg_loss > 0 else '-'
        # System theoretical BE%: assumes avg flip loss = 15¢ (entry-15 formula, width W)
        system_be_pct = round(15 / (15 + w) * 100, 1) if w > 0 else 0
        width_breakdown.append({
            'width': w, 'wins': s['wins'], 'losses': s['losses'],
            'fill_rate': fill_rate, 'net_cents': s['total_profit'] - s['total_loss'],
            'avg_profit_cents': avg_profit, 'avg_loss_cents': avg_loss,
            'avg_fill_duration_s': avg_fill_dur,
            'breakeven_pct': breakeven_pct,
            'system_be_pct': system_be_pct,
            'edge': edge,
            'ratio': ratio,
            'flips': s['flips'], 'settled_losses': s['settled_losses'],
            'amended_losses': s['amended_losses'],
        })

    # Phase breakdown
    phase_stats = {'pregame': {'wins': 0, 'losses': 0}, 'live': {'wins': 0, 'losses': 0}}
    for t in arb_trades:
        p = t.get('game_phase', 'live')
        if p not in phase_stats:
            phase_stats[p] = {'wins': 0, 'losses': 0}
        if _is_win(t):
            phase_stats[p]['wins'] += 1
        else:
            phase_stats[p]['losses'] += 1

    # Quarter/period breakdown
    quarter_stats = {}
    for t in arb_trades:
        gc = t.get('game_context', {})
        period = gc.get('period', 0)
        if period <= 0:
            continue
        q_key = f'Q{period}' if period <= 4 else 'OT'
        if q_key not in quarter_stats:
            quarter_stats[q_key] = {'wins': 0, 'losses': 0}
        if _is_win(t):
            quarter_stats[q_key]['wins'] += 1
        else:
            quarter_stats[q_key]['losses'] += 1

    # Score differential breakdown
    margin_stats = {'close_0_5': {'wins': 0, 'losses': 0}, 'mid_6_15': {'wins': 0, 'losses': 0}, 'blowout_16plus': {'wins': 0, 'losses': 0}}
    for t in arb_trades:
        gc = t.get('game_context', {})
        diff = gc.get('score_diff', -1)
        if diff < 0:
            continue
        if diff <= 5:
            bucket = 'close_0_5'
        elif diff <= 15:
            bucket = 'mid_6_15'
        else:
            bucket = 'blowout_16plus'
        if _is_win(t):
            margin_stats[bucket]['wins'] += 1
        else:
            margin_stats[bucket]['losses'] += 1

    # First leg analysis
    first_leg_stats = {'yes': {'wins': 0, 'losses': 0}, 'no': {'wins': 0, 'losses': 0}}
    for t in arb_trades:
        fl = t.get('first_leg', '')
        if fl in first_leg_stats:
            if _is_win(t):
                first_leg_stats[fl]['wins'] += 1
            else:
                first_leg_stats[fl]['losses'] += 1

    # Average fill duration
    all_durations = [t['fill_duration_s'] for t in arb_trades if t.get('fill_duration_s') is not None]
    win_durations = [t['fill_duration_s'] for t in arb_wins if t.get('fill_duration_s') is not None]
    loss_durations = [t['fill_duration_s'] for t in arb_losses if t.get('fill_duration_s') is not None]

    total_arb = len(arb_wins) + len(arb_losses)
    # Use same PNL_WIN_RESULTS / PNL_LOSS_RESULTS logic as /api/pnl endpoint
    # so Lifetime P&L card and Daily P&L card always show the same number
    pnl_bucket = _compute_pnl_bucket(arb_trades, 'arb')
    total_profit = pnl_bucket['gross_profit_cents']
    total_loss   = pnl_bucket['gross_loss_cents']
    # avg profit/loss still based on wins/loss buckets for meaningful averages
    avg_profit_for_display = sum(t.get('profit_cents', 0) for t in arb_wins)
    avg_loss_for_display   = sum(t.get('loss_cents',   0) for t in arb_losses)

    return jsonify({
        'arb_total': total_arb,
        'arb_wins': len(arb_wins),
        'arb_losses': len(arb_losses),
        'arb_fill_rate': round(len(arb_wins) / total_arb * 100, 1) if total_arb > 0 else 0,
        'arb_net_cents': total_profit - total_loss,
        'arb_avg_profit': round(avg_profit_for_display / len(arb_wins)) if arb_wins else 0,
        'arb_avg_loss': round(avg_loss_for_display / len(arb_losses)) if arb_losses else 0,
        'avg_fill_duration_s': round(sum(all_durations) / len(all_durations)) if all_durations else None,
        'avg_win_duration_s': round(sum(win_durations) / len(win_durations)) if win_durations else None,
        'avg_loss_duration_s': round(sum(loss_durations) / len(loss_durations)) if loss_durations else None,
        'width_breakdown': width_breakdown,
        'result_breakdown': result_counts,
        'timeout_stats': {
            'total': len(timeout_trades),
            'yes_n': timeout_yes_n,
            'no_n':  timeout_no_n,
            'total_profit_cents': timeout_total_profit,
            'total_loss_cents':   timeout_total_loss,
            'net_cents': timeout_total_profit - timeout_total_loss,
        },
        'flip_stats': {
            'total': flip_total,
            'total_loss_cents': flip_total_loss,
            'avg_loss_cents': flip_avg_loss,
            'avg_entry_price': flip_avg_entry,
            'avg_floor': flip_avg_floor,
            'avg_effective_trigger': flip_avg_effective_trigger,
            'entry_bucket_breakdown': entry_bucket_breakdown,
        },
        'completed_stats': _compute_completed_stats([t for t in arb_wins if t.get('exit_via') != 'timeout_amend']),
        'amended_stats': _compute_amended_stats(arb_trades),
        'phase_stats': phase_stats,
        'quarter_stats': quarter_stats,
        'margin_stats': margin_stats,
        'first_leg_stats': first_leg_stats,
        'watch_total': len(watch_trades),
        'watch_wins': len([t for t in watch_trades if t.get('result') == 'take_profit_watch']),
        'watch_losses': len([t for t in watch_trades if t.get('result') == 'stop_loss_watch']),
    })


# ── Middle tracking ──────────────────────────────────────────────────────────

@app.route('/api/middle/log', methods=['POST'])
def log_middle():
    """Record a middle opportunity (two legs, side by side)."""
    data = request.json or {}
    leg1 = data.get('leg1', {})
    leg2 = data.get('leg2', {})
    qty  = int(data.get('qty', leg1.get('qty', 1)))
    p1   = float(leg1.get('price', 0))
    p2   = float(leg2.get('price', 0))
    arb_width    = round(100 - p1 - p2, 2)   # positive = free arb window
    combined_cost = round((p1 + p2 - 100) * qty, 2)  # positive = costs this, negative = guaranteed profit
    max_profit    = round((100 - p1 + 100 - p2) * qty, 2)

    trade = {
        'id': f"mid_{int(time.time() * 1000)}",
        'type': 'middle',
        'timestamp': time.time(),
        'status': 'pending',
        'leg1': {
            'ticker': leg1.get('ticker', ''),
            'title':  leg1.get('title', ''),
            'side':   leg1.get('side', 'yes'),
            'price':  p1,
            'qty':    qty,
            'result': None,
        },
        'leg2': {
            'ticker': leg2.get('ticker', ''),
            'title':  leg2.get('title', ''),
            'side':   leg2.get('side', 'yes'),
            'price':  p2,
            'qty':    qty,
            'result': None,
        },
        'arb_width':     arb_width,
        'combined_cost': combined_cost,
        'max_profit':    max_profit,
        'middle_hit':    None,
        'profit_cents':  0,
        'loss_cents':    0,
        'result':        'pending',
        'notes':         data.get('notes', ''),
        'placed_at':     time.time(),
    }
    trade_history.append(trade)
    save_state()
    bot_log('MIDDLE_LOGGED', trade['id'], {'leg1': trade['leg1'], 'leg2': trade['leg2'],
                                           'arb_width': arb_width, 'combined_cost': combined_cost})
    return jsonify({'ok': True, 'trade': trade})


@app.route('/api/middle/<trade_id>/settle', methods=['POST'])
def settle_middle(trade_id):
    """Settle both legs of a middle — leg1_result and leg2_result: 'win' or 'loss'."""
    data = request.json or {}
    r1 = data.get('leg1_result', '').lower()
    r2 = data.get('leg2_result', '').lower()
    if r1 not in ('win', 'loss') or r2 not in ('win', 'loss'):
        return jsonify({'error': 'leg1_result and leg2_result must be win or loss'}), 400

    for trade in trade_history:
        if trade.get('id') == trade_id and trade.get('type') == 'middle':
            trade['leg1']['result'] = r1
            trade['leg2']['result'] = r2
            p1  = trade['leg1']['price']
            p2  = trade['leg2']['price']
            qty = trade['leg1']['qty']
            middle_hit = (r1 == 'win' and r2 == 'win')
            trade['middle_hit'] = middle_hit
            trade['status'] = 'settled'

            # Fees: maker fee on each NO leg
            fee = _kalshi_side_fee_cents(p1, qty) + _kalshi_side_fee_cents(p2, qty)
            if middle_hit:
                profit = round(((100 - p1) + (100 - p2)) * qty - fee)
                trade['profit_cents'] = profit
                trade['loss_cents']   = 0
                trade['result']       = 'middle_hit'
            elif r1 == 'win':
                net = round((100 - p1) * qty - p2 * qty - fee)
                trade['profit_cents'] = max(0, net)
                trade['loss_cents']   = max(0, -net)
                trade['result']       = 'arb_win' if net >= 0 else 'loss'
            elif r2 == 'win':
                net = round((100 - p2) * qty - p1 * qty - fee)
                trade['profit_cents'] = max(0, net)
                trade['loss_cents']   = max(0, -net)
                trade['result']       = 'arb_win' if net >= 0 else 'loss'
            else:
                trade['profit_cents'] = 0
                trade['loss_cents']   = round((p1 + p2) * qty + fee)
                trade['result']       = 'loss'

            save_state()
            bot_log('MIDDLE_SETTLED', trade_id, {'result': trade['result'],
                                                 'middle_hit': middle_hit,
                                                 'profit_cents': trade['profit_cents'],
                                                 'loss_cents': trade['loss_cents']})
            return jsonify({'ok': True, 'trade': trade})

    return jsonify({'error': 'Middle trade not found'}), 404


@app.route('/api/middle/<trade_id>/delete', methods=['DELETE', 'POST'])
def delete_middle(trade_id):
    """Permanently remove a middle history entry."""
    global trade_history
    before = len(trade_history)
    trade_history = [t for t in trade_history if not (t.get('id') == trade_id and t.get('type') == 'middle')]
    if len(trade_history) == before:
        return jsonify({'error': 'Middle trade not found'}), 404
    save_state()
    return jsonify({'ok': True, 'deleted': trade_id})


# ── Insta Arb log (scanner-placed immediate both-sides arb) ─────────────────

@app.route('/api/instarb/log', methods=['POST'])
def log_instarb():
    """Record an insta-arb (scanner opportunity placed immediately, no bot)."""
    data = request.json or {}
    yes_price = float(data.get('yes_price', 0))
    no_price  = float(data.get('no_price', 0))
    qty       = int(data.get('qty', 1))
    arb_width = round(100 - yes_price - no_price, 2)
    profit    = round(arb_width * qty)

    trade = {
        'id':          f"ia_{int(time.time() * 1000)}",
        'type':        'insta_arb',
        'timestamp':   time.time(),
        'placed_at':   time.time(),
        'status':      'completed',
        'yes_ticker':  data.get('yes_ticker', ''),
        'no_ticker':   data.get('no_ticker', ''),
        'ticker':      data.get('yes_ticker', ''),
        'market_title': data.get('market_title', ''),
        'yes_price':   yes_price,
        'no_price':    no_price,
        'quantity':    qty,
        'arb_width':   arb_width,
        'profit_cents': profit,
        'loss_cents':  0,
        'result':      'completed',
        'sport':       data.get('sport', ''),
        'notes':       data.get('notes', ''),
    }
    trade_history.append(trade)
    save_state()
    bot_log('INSTA_ARB_PLACED', trade['id'], {'yes_price': yes_price, 'no_price': no_price,
                                              'arb_width': arb_width, 'profit_cents': profit})
    return jsonify({'ok': True, 'trade': trade})


@app.route('/api/bot/set_phase/<bot_id>', methods=['POST'])
def set_bot_phase(bot_id):
    """Switch a bot between 'pregame' and 'live' phases.
    When a game goes live, flip the phase so the monitor starts
    doing repost / stop-loss management."""
    if bot_id not in active_bots:
        return jsonify({'error': 'Bot not found'}), 404
    data = request.json or {}
    new_phase = data.get('phase', 'live')
    if new_phase not in ('pregame', 'live'):
        return jsonify({'error': 'phase must be pregame or live'}), 400
    active_bots[bot_id]['game_phase'] = new_phase
    # Reset posted_at so timeout counters restart from now
    active_bots[bot_id]['posted_at'] = time.time()
    save_state()
    return jsonify({'success': True, 'bot_id': bot_id, 'phase': new_phase})


@app.route('/api/bot/cancel/<bot_id>', methods=['DELETE'])
def cancel_bot(bot_id):
    """Cancel a bot and its outstanding limit orders.
    SAFETY: If one side has filled contracts, sell them first to avoid orphaned positions.
    Acquires monitor_lock to prevent races with the monitor loop.
    """
    if bot_id not in active_bots:
        return jsonify({'error': 'Bot not found'}), 404

    # Acquire monitor lock to prevent race with monitor loop
    lock_acquired = monitor_lock.acquire(blocking=True, timeout=30)
    if not lock_acquired:
        return jsonify({'error': 'Server busy — monitor cycle in progress. Try again in a few seconds.'}), 503

    try:
        # Re-check after acquiring lock (bot may have been removed by monitor)
        if bot_id not in active_bots:
            return jsonify({'error': 'Bot was already removed'}), 404

        bot = active_bots[bot_id]
        cancelled = []
        sold_positions = []
        warnings = []
        sell_prices = {}  # Track actual sell prices: {'yes': price_cents, 'no': price_cents}
        already_cleared_sides = set()  # Sides already manually sold on Kalshi before bot cancel
        ticker = bot.get('ticker', '')

        if kalshi_client:
            yes_filled = bot.get('yes_fill_qty', 0)
            no_filled = bot.get('no_fill_qty', 0)
            qty = bot.get('quantity', 1)
            bot_type = bot.get('type', 'arb')

            # ── Handle middle bots ──
            if bot_type == 'middle':
                mid_qty = bot.get('qty', 1)
                # Cancel any unfilled orders
                for order_key in ('order_a_id', 'order_b_id'):
                    if bot.get(order_key):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot[order_key])
                            cancelled.append(order_key)
                        except Exception as me:
                            print(f'⚠ cancel_bot({bot_id}): cancel {order_key} failed: {me}')
                # Sell any filled legs
                for leg, ticker_key in (('a', 'ticker_a'), ('b', 'ticker_b')):
                    if bot.get(f'leg_{leg}_filled'):
                        leg_ticker = bot.get(ticker_key, '')
                        if leg_ticker:
                            sold, sell_info = execute_sell(leg_ticker, 'no', mid_qty, reason=f'cancel_middle_{leg}_{bot_id}')
                            if sold:
                                sold_positions.append(f'LEG_{leg.upper()}_NO {mid_qty}x')
                                sp = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price', 0)
                                sell_prices[f'leg_{leg}'] = sp
                            else:
                                warnings.append(f'FAILED to sell LEG_{leg.upper()} NO {mid_qty}x — position may still be open on Kalshi!')

            # ── Handle watch bots ──
            elif bot_type == 'watch':
                watch_side = bot.get('side', 'yes')
                if bot.get('order_filled', False):
                    watch_qty = bot.get('fill_qty', bot.get('quantity', 1))
                    sold, sell_info = execute_sell(ticker, watch_side, watch_qty, reason=f'cancel_watch_{bot_id}')
                    if sold:
                        sold_positions.append(f'{watch_side.upper()} {watch_qty}x')
                        sp = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price', 0)
                        sell_prices[watch_side] = sp
                    else:
                        warnings.append(f'FAILED to sell {watch_side.upper()} {watch_qty}x — position may still be open on Kalshi!')
                elif bot.get('order_id'):
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(bot['order_id'])
                        cancelled.append(watch_side.upper())
                    except Exception as e:
                        print(f'⚠ cancel_bot({bot_id}): cancel watch order failed: {e}')
                        warnings.append(f'Could not cancel {watch_side.upper()} order: {e}')

            # ── Handle anchor-dog bots ──
            elif bot.get('bot_category') == 'anchor_dog':
                dog_side = bot.get('dog_side', 'no')
                fav_side = bot.get('fav_side', 'yes')
                dog_fill = bot.get('dog_fill_qty', 0)
                fav_fill = bot.get('fav_fill_qty', 0)
                # Cancel unfilled dog order
                if dog_fill < qty and bot.get('dog_order_id'):
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(bot['dog_order_id'])
                        cancelled.append(f'DOG_{dog_side.upper()}')
                    except Exception as e:
                        print(f'⚠ cancel_bot({bot_id}): cancel dog order failed: {e}')
                # Cancel all historically tracked dog orders (from reposts)
                for oid in bot.get('_all_dog_order_ids', []):
                    if oid and oid != bot.get('dog_order_id'):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(oid)
                        except Exception:
                            pass
                # Cancel unfilled fav order
                if bot.get('fav_order_id') and fav_fill < qty:
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(bot['fav_order_id'])
                        cancelled.append(f'FAV_{fav_side.upper()}')
                    except Exception as e:
                        print(f'⚠ cancel_bot({bot_id}): cancel fav order failed: {e}')
                # Sell back filled dog leg if fav isn't filled
                if dog_fill > 0 and fav_fill < qty:
                    sold, sell_info = execute_sell(ticker, dog_side, dog_fill,
                                                   reason=f'cancel_anchor_dog_{bot_id}')
                    if sold:
                        sold_positions.append(f'{dog_side.upper()} {dog_fill}x (dog)')
                        sp = (sell_info or {}).get('actual_fill_price', 0)
                        sell_prices[dog_side] = sp
                    else:
                        warnings.append(f'FAILED to sell {dog_side.upper()} {dog_fill}x — position may still be open!')
                # If both legs filled, it's a completed arb (auto-netted)
                elif dog_fill >= qty and fav_fill >= qty:
                    already_cleared_sides.add('yes')
                    already_cleared_sides.add('no')
                    sold_positions.append(f'ARB_ALREADY_NETTED {qty}x')

            # ── Handle ladder-arb bots ──
            elif bot.get('bot_category') == 'ladder_arb':
                # Cancel rung orders via order group (1 API call) or fall back to individual
                _larb_group_id = bot.get('_order_group_id')
                if _larb_group_id:
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order_group(_larb_group_id)
                        cancelled.append(f'GROUP_{_larb_group_id[:8]}')
                    except Exception as e:
                        print(f'⚠ cancel_bot({bot_id}): group cancel failed: {e} — falling back to individual')
                        _larb_group_id = None  # trigger individual fallback below
                if not _larb_group_id:
                    for rung in bot.get('rungs', []):
                        for side in ('yes', 'no'):
                            oid = rung.get(f'{side}_order_id')
                            fq = rung.get(f'{side}_fill_qty', 0)
                            rq = rung.get('quantity', bot.get('quantity', 1))
                            if oid and fq < rq:
                                try:
                                    api_rate_limiter.wait()
                                    kalshi_client.cancel_order(oid)
                                    cancelled.append(f'{side.upper()}@{rung.get(f"{side}_price", "?")}c')
                                except Exception as e:
                                    print(f'⚠ cancel_bot({bot_id}): cancel {side} rung failed: {e}')
                # Cancel all historically tracked hedge/placed orders
                rung_oids = set()
                for rung in bot.get('rungs', []):
                    for sk in ('yes_order_id', 'no_order_id'):
                        if rung.get(sk):
                            rung_oids.add(rung[sk])
                for oid in bot.get('_all_hedge_order_ids', []):
                    if oid and oid not in rung_oids:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(oid)
                            cancelled.append(f'HEDGE_{oid[:8]}')
                        except Exception:
                            pass
                for oid in bot.get('_all_placed_order_ids', []):
                    if oid and oid not in rung_oids:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(oid)
                        except Exception:
                            pass
                # Cancel orders from hedge_history (walk-up replacements)
                for hg in bot.get('hedge_history', []):
                    for hg_oid in [hg.get('order_id')] + hg.get('order_ids', []):
                        if hg_oid and hg_oid not in rung_oids:
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(hg_oid)
                            except Exception:
                                pass
                # Sell back any filled positions on either side
                for side in ('yes', 'no'):
                    total_fill = sum(r.get(f'{side}_fill_qty', 0) for r in bot.get('rungs', []))
                    if total_fill > 0 and side not in already_cleared_sides:
                        sold, sell_info = execute_sell(ticker, side, total_fill,
                                                       reason=f'cancel_larb_{side}_{bot_id}')
                        if sold:
                            sold_positions.append(f'{side.upper()} {total_fill}x')
                            sp = (sell_info or {}).get('actual_fill_price', 0)
                            sell_prices[side] = sp
                            if (sell_info or {}).get('order_id') == 'already_cleared':
                                already_cleared_sides.add(side)
                        else:
                            warnings.append(f'FAILED to sell {side.upper()} {total_fill}x')

            # ── Handle anchor-ladder bots ──
            elif bot.get('bot_category') == 'anchor_ladder':
                dog_side = bot.get('dog_side', 'no')
                # Cancel all unfilled rung orders
                for rung in bot.get('rungs', []):
                    if rung.get('order_id') and rung.get('fill_qty', 0) < rung.get('qty', 1):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(rung['order_id'])
                            cancelled.append(f'rung@{rung["price"]}c')
                        except Exception as e:
                            print(f'⚠ cancel_bot({bot_id}): cancel rung failed: {e}')
                # Cancel fav order if posted
                if bot.get('fav_order_id'):
                    try:
                        api_rate_limiter.wait()
                        kalshi_client.cancel_order(bot['fav_order_id'])
                        cancelled.append('FAV')
                    except Exception as e:
                        print(f'⚠ cancel_bot({bot_id}): cancel fav failed: {e}')
                # Sell back any filled dog contracts
                total_fill = sum(r.get('fill_qty', 0) for r in bot.get('rungs', []))
                if total_fill > 0:
                    sold, sell_info = execute_sell(ticker, dog_side, total_fill,
                                                   reason=f'cancel_ladder_{bot_id}')
                    if sold:
                        sold_positions.append(f'{dog_side.upper()} {total_fill}x')
                        sp = (sell_info or {}).get('actual_fill_price', 0)
                        sell_prices[dog_side] = sp
                    else:
                        warnings.append(f'FAILED to sell {dog_side.upper()} {total_fill}x')

            # ── Handle arb bots ──
            else:
                # ── Scenario: YES fully filled, NO still resting → amend NO to complete arb ──
                if yes_filled >= qty and no_filled < qty:
                    no_order_id = bot.get('no_order_id')
                    yes_bid_now = bot.get('live_yes_bid', 0)
                    amend_price = (100 - yes_bid_now) if yes_bid_now > 0 else 2
                    amend_ok = False
                    if no_order_id:
                        amend_ok, amend_info = execute_net_via_amend(
                            no_order_id, 'no', amend_price, qty,
                            ticker=ticker, reason=f'cancel_complete_yes_{bot_id}'
                        )
                    if amend_ok:
                        no_fill = amend_info.get('actual_fill_price') or amend_price
                        sold_positions.append(f'ARB_COMPLETED YES+NO {qty}x')
                        sell_prices['yes'] = bot.get('yes_price', 0)
                        sell_prices['no'] = no_fill
                    else:
                        # Amend failed — fall back to selling YES position
                        sold, sell_info = execute_sell(ticker, 'yes', yes_filled, reason=f'cancel_sell_yes_{bot_id}')
                        if sold:
                            sold_positions.append(f'YES {yes_filled}x')
                            sp = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price', 0)
                            sell_prices['yes'] = sp
                            if (sell_info or {}).get('order_id') == 'already_cleared':
                                already_cleared_sides.add('yes')
                        else:
                            warnings.append(f'FAILED to exit YES {yes_filled}x — position may still be open on Kalshi!')
                        # Also cancel the pending NO order
                        if no_order_id:
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(no_order_id)
                                cancelled.append('NO')
                            except Exception as e:
                                print(f'⚠ cancel_bot({bot_id}): cancel NO order failed: {e}')

                # ── Scenario: NO fully filled, YES still resting → amend YES to complete arb ──
                elif no_filled >= qty and yes_filled < qty:
                    yes_order_id = bot.get('yes_order_id')
                    no_bid_now = bot.get('live_no_bid', 0)
                    amend_price = (100 - no_bid_now) if no_bid_now > 0 else 2
                    amend_ok = False
                    if yes_order_id:
                        amend_ok, amend_info = execute_net_via_amend(
                            yes_order_id, 'yes', amend_price, qty,
                            ticker=ticker, reason=f'cancel_complete_no_{bot_id}'
                        )
                    if amend_ok:
                        yes_fill = amend_info.get('actual_fill_price') or amend_price
                        sold_positions.append(f'ARB_COMPLETED YES+NO {qty}x')
                        sell_prices['yes'] = yes_fill
                        sell_prices['no'] = bot.get('no_price', 0)
                    else:
                        # Amend failed — fall back to selling NO position
                        sold, sell_info = execute_sell(ticker, 'no', no_filled, reason=f'cancel_sell_no_{bot_id}')
                        if sold:
                            sold_positions.append(f'NO {no_filled}x')
                            sp = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price', 0)
                            sell_prices['no'] = sp
                            if (sell_info or {}).get('order_id') == 'already_cleared':
                                already_cleared_sides.add('no')
                        else:
                            warnings.append(f'FAILED to exit NO {no_filled}x — position may still be open on Kalshi!')
                        # Also cancel the pending YES order
                        if yes_order_id:
                            try:
                                api_rate_limiter.wait()
                                kalshi_client.cancel_order(yes_order_id)
                                cancelled.append('YES')
                            except Exception as e:
                                print(f'⚠ cancel_bot({bot_id}): cancel YES order failed: {e}')

                # ── Scenario: both legs filled → already auto-netted ──
                elif yes_filled >= qty and no_filled >= qty:
                    already_cleared_sides.add('yes')
                    already_cleared_sides.add('no')
                    sold_positions.append(f'ARB_ALREADY_NETTED {qty}x')

                # ── Scenario: YES partial fill ──
                elif yes_filled > 0:
                    # Cancel resting YES order first
                    if bot.get('yes_order_id'):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['yes_order_id'])
                            cancelled.append('YES order')
                        except Exception as e:
                            print(f'⚠ cancel_bot({bot_id}): cancel partial YES order failed: {e}')
                    # Also cancel NO order
                    if bot.get('no_order_id'):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['no_order_id'])
                            cancelled.append('NO order')
                        except Exception as e:
                            print(f'⚠ cancel_bot({bot_id}): cancel partial NO order failed: {e}')
                    # Sell the partial position
                    sold, sell_info = execute_sell(ticker, 'yes', yes_filled, reason=f'cancel_sell_partial_yes_{bot_id}')
                    if sold:
                        sold_positions.append(f'YES {yes_filled}x (partial)')
                        sp = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price', 0)
                        sell_prices['yes'] = sp
                        if (sell_info or {}).get('order_id') == 'already_cleared':
                            already_cleared_sides.add('yes')
                    else:
                        warnings.append(f'FAILED to sell YES {yes_filled}x (partial) — position may still be open on Kalshi!')

                # ── Scenario: NO partial fill ──
                elif no_filled > 0:
                    # Cancel resting orders
                    if bot.get('yes_order_id'):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['yes_order_id'])
                            cancelled.append('YES order')
                        except Exception as e:
                            print(f'⚠ cancel_bot({bot_id}): cancel YES order failed: {e}')
                    if bot.get('no_order_id'):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['no_order_id'])
                            cancelled.append('NO order')
                        except Exception as e:
                            print(f'⚠ cancel_bot({bot_id}): cancel partial NO order failed: {e}')
                    sold, sell_info = execute_sell(ticker, 'no', no_filled, reason=f'cancel_sell_partial_no_{bot_id}')
                    if sold:
                        sold_positions.append(f'NO {no_filled}x (partial)')
                        sp = (sell_info or {}).get('actual_fill_price') or (sell_info or {}).get('sell_price', 0)
                        sell_prices['no'] = sp
                        if (sell_info or {}).get('order_id') == 'already_cleared':
                            already_cleared_sides.add('no')
                    else:
                        warnings.append(f'FAILED to sell NO {no_filled}x (partial) — position may still be open on Kalshi!')

                # ── Scenario: nothing filled → cancel both orders cleanly ──
                else:
                    if bot.get('yes_order_id'):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['yes_order_id'])
                            cancelled.append('YES')
                        except Exception as e:
                            print(f'⚠ cancel_bot({bot_id}): cancel YES order failed: {e}')
                            warnings.append(f'Could not cancel YES order: {e}')
                    if bot.get('no_order_id'):
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(bot['no_order_id'])
                            cancelled.append('NO')
                        except Exception as e:
                            print(f'⚠ cancel_bot({bot_id}): cancel NO order failed: {e}')
                            warnings.append(f'Could not cancel NO order: {e}')

        # ── Awaiting Settlement check ─────────────────────────────────────────────
        # If sells FAILED (market may be expired/awaiting settlement), check Kalshi
        # positions. If contracts still held, keep bot alive as 'awaiting_settlement'.
        if kalshi_client and warnings and any('FAILED to sell' in w for w in warnings):
            try:
                api_read_limiter.wait()
                pos_resp = kalshi_client.get_positions(ticker=ticker)
                positions = pos_resp.get('market_positions', pos_resp.get('positions', []))
                held_yes = 0
                held_no = 0
                for p in positions:
                    if p.get('ticker') == ticker:
                        qty_p = _parse_position_qty(p)
                        if qty_p > 0:   held_yes = qty_p
                        elif qty_p < 0: held_no = abs(qty_p)
                if held_yes > 0 or held_no > 0:
                    bot['status'] = 'awaiting_settlement'
                    bot['awaiting_qty_yes'] = held_yes
                    bot['awaiting_qty_no'] = held_no
                    bot['awaiting_since'] = time.time()
                    save_state()
                    bot_log('AWAITING_SETTLEMENT', bot_id, {'held_yes': held_yes, 'held_no': held_no, 'warnings': warnings})
                    return jsonify({
                        'success': True, 'awaiting_settlement': True,
                        'cancelled_orders': cancelled, 'sold_positions': sold_positions,
                        'sell_prices': sell_prices, 'warnings': warnings,
                        'held_yes': held_yes, 'held_no': held_no
                    })
            except Exception as ase:
                print(f'⚠ awaiting_settlement position check failed: {ase}')

        # Record in trade history so manual deletes are tracked
        if sold_positions:
            # At least one position was sold — record the exit
            yes_sold_qty = 0
            no_sold_qty = 0
            arb_completed_via_amend = False
            for sp in sold_positions:
                if sp.startswith('ARB_COMPLETED YES+NO'):
                    # Amend-based arb completion: both legs filled cleanly
                    yes_sold_qty = bot.get('yes_fill_qty', bot.get('quantity', 1))
                    no_sold_qty  = yes_sold_qty
                    arb_completed_via_amend = True
                elif sp.startswith('ARB_ALREADY_NETTED'):
                    # Both legs already netted by Kalshi — already recorded by WS handler
                    already_cleared_sides.add('yes')
                    already_cleared_sides.add('no')
                elif sp.startswith('YES'):
                    yes_sold_qty = bot.get('yes_fill_qty', 0) or bot.get('fill_qty', 0)
                elif sp.startswith('NO'):
                    no_sold_qty = bot.get('no_fill_qty', 0) or bot.get('fill_qty', 0)
            # Don't record fake exits for sides already manually cleared on Kalshi
            if 'yes' in already_cleared_sides: yes_sold_qty = 0
            if 'no'  in already_cleared_sides: no_sold_qty  = 0

            entry_yes = bot.get('yes_price', 0) or bot.get('entry_price', 0)
            entry_no = bot.get('no_price', 0)
            qty = bot.get('quantity', 1)
            bot_type = bot.get('type', 'arb')

            if bot_type == 'watch':
                # Watch bot — single side exit
                watch_side = bot.get('side', 'yes')
                watch_entry = bot.get('entry_price', 0) or (entry_yes if watch_side == 'yes' else entry_no)
                watch_sell = sell_prices.get(watch_side, 0)
                watch_qty = bot.get('fill_qty', bot.get('quantity', 1))
                buy_fee = _kalshi_side_fee_cents(watch_entry, watch_qty)
                sell_fee = _kalshi_taker_side_fee_cents(watch_sell, watch_qty) if watch_sell else 0
                profit = (watch_sell - watch_entry) * watch_qty - buy_fee - sell_fee
                _record_trade({
                    'bot_id': bot_id, 'ticker': ticker,
                    'yes_price': watch_entry if watch_side == 'yes' else 0,
                    'no_price': watch_entry if watch_side == 'no' else 0,
                    'quantity': watch_qty, 'profit_cents': profit,
                    'sell_price': watch_sell,
                    'result': 'manual_exit_completed',
                    'timestamp': time.time(),
                    'note': f'Manual exit — {watch_side.upper()} {watch_qty}x sold at {watch_sell}¢ (entry {watch_entry}¢)',
                    'game_phase': bot.get('game_phase', ''),
                    'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                }, bot)
                if profit >= 0:
                    session_pnl['gross_profit_cents'] += profit
                else:
                    session_pnl['gross_loss_cents'] += abs(profit)
                session_pnl['completed_bots'] += 1

            elif bot_type != 'watch':
                # Apex/ladder_arb bots: rung completions already recorded P&L — skip re-recording
                _apex_already_tracked = (bot.get('bot_category') == 'ladder_arb'
                                         and bot.get('completed_rungs_count', 0) > 0)
                if _apex_already_tracked and not arb_completed_via_amend:
                    # P&L already recorded by _record_rung_completion — just log the manual exit
                    _apex_cum_pnl = bot.get('cumulative_pnl', 0)
                    _record_trade({
                        'bot_id': bot_id, 'ticker': ticker,
                        'yes_price': entry_yes, 'no_price': entry_no,
                        'quantity': max(yes_sold_qty, no_sold_qty),
                        'profit_cents': 0, 'loss_cents': 0,
                        'result': 'manual_exit_apex',
                        'exit_via': 'cancel_sell',
                        'timestamp': time.time(),
                        'note': f'Manual exit — P&L already tracked via rung completions ({_apex_cum_pnl}¢)',
                        'game_phase': bot.get('game_phase', ''),
                        'bot_category': 'ladder_arb',
                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                    }, bot)
                    session_pnl['completed_bots'] += 1
                elif yes_sold_qty > 0 and no_sold_qty > 0:
                    # Both legs exited — either amend-completed arb or both sold at market
                    actual_yes_fill = sell_prices.get('yes', entry_yes)
                    actual_no_fill  = sell_prices.get('no', entry_no)
                    exit_qty = min(yes_sold_qty, no_sold_qty)
                    fee = kalshi_fee_cents(actual_yes_fill, actual_no_fill, exit_qty)
                    profit = (100 - actual_yes_fill - actual_no_fill) * exit_qty - fee
                    trade_result = ('amended' if profit < 0 else 'completed') if arb_completed_via_amend else 'manual_exit_completed'
                    _record_trade({
                        'bot_id': bot_id, 'ticker': ticker,
                        'yes_price': actual_yes_fill, 'no_price': actual_no_fill,
                        'original_yes': entry_yes, 'original_no': entry_no,
                        'quantity': min(yes_sold_qty, no_sold_qty), 'profit_cents': profit,
                        'result': trade_result,
                        'exit_via': 'cancel_amend' if arb_completed_via_amend else 'cancel_sell',
                        'timestamp': time.time(),
                        'note': f'{"Amend-completed arb" if arb_completed_via_amend else "Manual exit"} — YES {actual_yes_fill}¢, NO {actual_no_fill}¢',
                        'game_phase': bot.get('game_phase', ''),
                        'arb_width': bot.get('arb_width', 0),
                        'first_leg': bot.get('first_leg', ''),
                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                        'repeats_done': bot.get('repeats_done', 0),
                        'repeat_count': bot.get('repeat_count', 0),
                    }, bot)
                    if profit >= 0:
                        session_pnl['gross_profit_cents'] += profit
                    else:
                        session_pnl['gross_loss_cents'] += abs(profit)
                    session_pnl['completed_bots'] += 1
                elif yes_sold_qty > 0:
                    # Only YES was filled and sold at market
                    yes_sell = sell_prices.get('yes', 0)
                    buy_fee = _kalshi_side_fee_cents(entry_yes, yes_sold_qty)
                    sell_fee = _kalshi_taker_side_fee_cents(yes_sell, yes_sold_qty) if yes_sell else 0
                    profit = (yes_sell - entry_yes) * yes_sold_qty - buy_fee - sell_fee
                    _record_trade({
                        'bot_id': bot_id, 'ticker': ticker,
                        'yes_price': entry_yes, 'no_price': entry_no,
                        'quantity': yes_sold_qty, 'profit_cents': profit,
                        'sell_price': yes_sell,
                        'result': 'manual_exit_yes',
                        'timestamp': time.time(),
                        'note': f'Manual exit — YES {yes_sold_qty}x sold at {yes_sell}¢ (entry {entry_yes}¢, P&L {profit:+d}¢)',
                        'game_phase': bot.get('game_phase', ''),
                        'arb_width': bot.get('arb_width', 0),
                        'first_leg': bot.get('first_leg', ''),
                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                        'repeats_done': bot.get('repeats_done', 0),
                        'repeat_count': bot.get('repeat_count', 0),
                    }, bot)
                    if profit >= 0:
                        session_pnl['gross_profit_cents'] += profit
                    else:
                        session_pnl['gross_loss_cents'] += abs(profit)
                    session_pnl['completed_bots'] += 1
                elif no_sold_qty > 0:
                    # Only NO was filled and sold at market
                    no_sell = sell_prices.get('no', 0)
                    buy_fee = _kalshi_side_fee_cents(entry_no, no_sold_qty)
                    sell_fee = _kalshi_taker_side_fee_cents(no_sell, no_sold_qty) if no_sell else 0
                    profit = (no_sell - entry_no) * no_sold_qty - buy_fee - sell_fee
                    _record_trade({
                        'bot_id': bot_id, 'ticker': ticker,
                        'yes_price': entry_yes, 'no_price': entry_no,
                        'quantity': no_sold_qty, 'profit_cents': profit,
                        'sell_price': no_sell,
                        'result': 'manual_exit_no',
                        'timestamp': time.time(),
                        'note': f'Manual exit — NO {no_sold_qty}x sold at {no_sell}¢ (entry {entry_no}¢, P&L {profit:+d}¢)',
                        'game_phase': bot.get('game_phase', ''),
                        'arb_width': bot.get('arb_width', 0),
                        'first_leg': bot.get('first_leg', ''),
                        'team_label': ticker.split('-')[-1] if '-' in ticker else '',
                        'repeats_done': bot.get('repeats_done', 0),
                        'repeat_count': bot.get('repeat_count', 0),
                    }, bot)
                    if profit >= 0:
                        session_pnl['gross_profit_cents'] += profit
                    else:
                        session_pnl['gross_loss_cents'] += abs(profit)
                    session_pnl['completed_bots'] += 1
                bot_log('MANUAL_DELETE', bot_id, {'sold': sold_positions, 'cancelled': cancelled, 'sell_prices': sell_prices})

        del active_bots[bot_id]
        save_state()

        result = {'success': True, 'cancelled_orders': cancelled, 'sold_positions': sold_positions, 'sell_prices': sell_prices}
        if warnings:
            result['warnings'] = warnings
        return jsonify(result)
    finally:
        monitor_lock.release()


@app.route('/api/bot/cancel-bulk', methods=['POST'])
def cancel_bulk():
    """Cancel multiple bots in one request — calls cancel_bot sequentially.
    Each cancel_bot call acquires its own lock, but since we're sequential
    there's no contention between them (only with monitor loop).
    Expects JSON body: {"bot_ids": ["id1", "id2", ...]}"""
    data = request.get_json(force=True, silent=True) or {}
    bot_ids = data.get('bot_ids', [])
    if not bot_ids or not isinstance(bot_ids, list):
        return jsonify({'error': 'bot_ids array required'}), 400

    results = []
    for bot_id in bot_ids:
        try:
            resp = cancel_bot(bot_id)
            # cancel_bot returns jsonify(result) or (jsonify(error), status_code)
            if isinstance(resp, tuple):
                resp_data = resp[0].get_json()
                results.append({'bot_id': bot_id, 'success': resp_data.get('success', False), **resp_data})
            else:
                resp_data = resp.get_json()
                results.append({'bot_id': bot_id, 'success': resp_data.get('success', False), **resp_data})
        except Exception as e:
            results.append({'bot_id': bot_id, 'success': False, 'error': str(e)})

    ok = sum(1 for r in results if r.get('success'))
    fail = len(results) - ok

    # Auto-sweep orphaned orders after bulk cancel
    orphan_result = _sweep_orphaned_orders()

    resp = {'success': True, 'results': results, 'ok': ok, 'fail': fail}
    if orphan_result.get('cancelled_count', 0) > 0:
        resp['orphan_sweep'] = orphan_result
    return jsonify(resp)


def _sweep_orphaned_orders():
    """Query Kalshi for all resting orders and cancel any not owned by an active bot."""
    if not kalshi_client:
        return {'error': 'not authenticated'}

    # Collect all order IDs that belong to active bots
    known_ids = set()
    for bot in active_bots.values():
        for key in ('yes_order_id', 'no_order_id', 'dog_order_id', 'fav_order_id',
                    'order_id', 'order_a_id', 'order_b_id', 'hedge_order_id'):
            oid = bot.get(key)
            if oid:
                known_ids.add(oid)
        # Ladder rungs
        for rung in bot.get('rungs', []):
            for key in ('yes_order_id', 'no_order_id', 'order_id'):
                oid = rung.get(key)
                if oid:
                    known_ids.add(oid)
        # All hedge order IDs
        for oid in bot.get('_all_hedge_order_ids', []):
            if oid:
                known_ids.add(oid)
        # All placed order IDs (master list)
        for oid in bot.get('_all_placed_order_ids', []):
            if oid:
                known_ids.add(oid)
        # All dog order IDs (anchor-dog reposts)
        for oid in bot.get('_all_dog_order_ids', []):
            if oid:
                known_ids.add(oid)

    try:
        resp = kalshi_client.get_orders(status='resting')
        resting = resp.get('orders', [])
    except Exception as e:
        print(f'⚠️ Orphan sweep: failed to fetch resting orders: {e}')
        return {'error': str(e)}

    orphans = [o for o in resting if o.get('order_id') not in known_ids]
    cancelled = []
    failed = []
    for o in orphans:
        oid = o.get('order_id', '')
        ticker = o.get('ticker', '?')
        side = o.get('side', '?')
        try:
            api_rate_limiter.wait()
            kalshi_client.cancel_order(oid)
            cancelled.append({'order_id': oid, 'ticker': ticker, 'side': side})
            print(f'🧹 Orphan sweep: cancelled {side} order {oid[:8]}... on {ticker}')
        except Exception as e:
            failed.append({'order_id': oid, 'ticker': ticker, 'error': str(e)})
            print(f'⚠️ Orphan sweep: failed to cancel {oid[:8]}... on {ticker}: {e}')

    total = len(orphans)
    if total > 0:
        print(f'🧹 Orphan sweep complete: {len(cancelled)}/{total} cancelled, {len(failed)} failed')

    # ── Also check POSITIONS (filled contracts) not tracked by any bot ──
    orphaned_positions = []
    try:
        def _safe_int_sweep(v):
            if isinstance(v, (list, dict)):
                return 0
            try:
                return int(v or 0)
            except (TypeError, ValueError):
                return 0

        # Build managed qty per (ticker, side) from active bots
        managed_qty = {}
        for b in active_bots.values():
            if b.get('status') in ('completed', 'stopped', 'cancelled'):
                continue
            t = b.get('ticker', '')
            cat = b.get('bot_category', '')
            btype = b.get('type', '')
            if cat in ('anchor_dog', 'anchor_ladder'):
                dog_side = b.get('dog_side', '')
                dog_qty = _safe_int_sweep(b.get('total_dog_fill_qty')) or _safe_int_sweep(b.get('dog_fill_qty')) or _safe_int_sweep(b.get('quantity'))
                fav_side = b.get('fav_side', '')
                fav_qty = _safe_int_sweep(b.get('fav_fill_qty'))
                _hedge_t = b.get('hedge_ticker', t)  # cross-market: fav on different ticker
                if dog_qty > 0 and dog_side:
                    managed_qty[(t, dog_side)] = managed_qty.get((t, dog_side), 0) + dog_qty
                if fav_qty > 0 and fav_side:
                    managed_qty[(_hedge_t, fav_side)] = managed_qty.get((_hedge_t, fav_side), 0) + fav_qty
            elif cat == 'ladder_arb':
                yes_qty = _safe_int_sweep(b.get('filled_yes_qty'))
                no_qty = _safe_int_sweep(b.get('filled_no_qty'))
                if yes_qty > 0:
                    managed_qty[(t, 'yes')] = managed_qty.get((t, 'yes'), 0) + yes_qty
                if no_qty > 0:
                    managed_qty[(t, 'no')] = managed_qty.get((t, 'no'), 0) + no_qty
            elif btype == 'middle':
                # Middle bots hold NO positions on two tickers
                for leg in ('a', 'b'):
                    mt = b.get(f'ticker_{leg}', '')
                    if mt and b.get(f'leg_{leg}_filled'):
                        mq = _safe_int_sweep(b.get('qty', 1))
                        managed_qty[(mt, 'no')] = managed_qty.get((mt, 'no'), 0) + mq

        pos_resp = kalshi_client.get_positions()
        positions = pos_resp.get('market_positions', pos_resp.get('positions', []))
        for pos in positions:
            pticker = pos.get('ticker', '')
            try:
                pos_fp = float(pos.get('position_fp') or 0)
            except (TypeError, ValueError):
                pos_fp = 0
            if not pticker or pos_fp == 0:
                continue
            side = 'yes' if pos_fp > 0 else 'no'
            kalshi_qty = int(abs(pos_fp))
            bot_qty = managed_qty.get((pticker, side), 0)
            orphaned = kalshi_qty - bot_qty
            if orphaned > 0:
                orphaned_positions.append({
                    'ticker': pticker, 'side': side,
                    'orphaned_qty': orphaned, 'kalshi_qty': kalshi_qty,
                    'managed_qty': bot_qty,
                })
                print(f'⚠ ORPHAN POSITION: {pticker} {side.upper()} {orphaned}/{kalshi_qty} (bots track {bot_qty})')
    except Exception as pos_err:
        print(f'⚠ Orphan position check failed: {pos_err}')

    return {'cancelled_count': len(cancelled), 'failed_count': len(failed),
            'cancelled': cancelled, 'failed': failed,
            'orphaned_positions': orphaned_positions}


@app.route('/api/bot/sweep-orphans', methods=['POST'])
def sweep_orphans_endpoint():
    """Manual endpoint to sweep orphaned orders and detect orphaned positions."""
    result = _sweep_orphaned_orders()
    return jsonify({'success': True, **result})


@app.route('/api/bot/scan', methods=['GET'])
def scan_arb_opportunities():
    """
    Smart arb scanner — finds markets with wide bid-bid spreads where
    limit orders can capture profit.  Uses the same series-based fetching
    as the main /markets endpoint so it actually scans real sports markets.

    Strategy: For dual-arb to work you place YES limit buy at yes_bid+1
    and NO limit buy at no_bid+1.  Profit = 100 - yes_price - no_price.
    A market where yes_bid + no_bid is well below 100 means there's room
    for maker orders to capture spread.  The wider the gap, the more profit
    per contract (but also longer fill time / lower liquidity).
    """
    try:
        print(f'🔍 scan_arb START thread={threading.current_thread().name}', flush=True)
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        min_width = max(1, int(request.args.get('min_width', 3)))
        sport_filter = request.args.get('sport', '')
        print(f'🔍 scan_arb sport={sport_filter!r}', flush=True)

        # Use the same series map as /api/markets
        SPORTS_SERIES = {
            'nba': ['KXNBAGAME', 'KXNBASPREAD', 'KXNBATOTAL',
                    'KXNBAPTS', 'KXNBAREB', 'KXNBAAST', 'KXNBA3PT',
                    'KXNBASTL', 'KXNBABLK', 'KXNBAMVP'],
            'nfl': ['KXNFLGAME', 'KXNFLSPREAD', 'KXNFLTOTAL'],
            'nhl': ['KXNHLGAME', 'KXNHLSPREAD', 'KXNHLTOTAL', 'KXNHLGOAL'],
            'mlb': ['KXMLBGAME', 'KXMLBSPREAD', 'KXMLBTOTAL', 'KXMLBSTGAME'],
            'mls': ['KXMLSGAME', 'KXMLSSPREAD', 'KXMLSTOTAL', 'KXMLSBTTS'],
            'ncaab': ['KXNCAAMBGAME', 'KXNCAAMBSPREAD', 'KXNCAAMBTOTAL',
                      'KXNCAAMB1HWINNER', 'KXNCAAMB1HSPREAD', 'KXNCAAMB1HTOTAL',
                      'KXNCAAMBPTS', 'KXNCAAMBREB', 'KXNCAAMBAST',
                      'KXNCAAMB3PT', 'KXNCAAMBSTL', 'KXNCAAMBBLK',
                      'KXMARMAD'],
            'ncaaw': ['KXNCAAWBGAME'],
            'epl': ['KXEPLGAME', 'KXEPLSPREAD', 'KXEPLTOTAL', 'KXEPLGOAL', 'KXEPLBTTS'],
            'ucl': ['KXUCLGAME', 'KXUCLSPREAD', 'KXUCLTOTAL', 'KXUCLGOAL', 'KXUCLBTTS'],
            'tennis': ['KXATPMATCH', 'KXWTAMATCH', 'KXATPCHALLENGERMATCH', 'KXWTACHALLENGERMATCH'],
            'golf': ['KXPGAH2H', 'KXTGLMATCH', 'KXPGATOP10', 'KXPGAMAKECUT',
                     'KXPGAR1LEAD', 'KXPGAR2LEAD', 'KXPGAR3LEAD', 'KXPGATOP5',
                     'KXLIVH2H', 'KXLIVTOP10', 'KXLIVTOP5', 'KXLIVR1LEAD', 'KXLIVTOUR'],
            'nbl': ['KXNBLGAME'],
            'wbc': ['KXWBCGAME'],
            'intl': ['KXVTBGAME', 'KXBSLGAME', 'KXABAGAME', 'KXNBLGAME',
                     'KXKBLGAME', 'KXCBAGAME', 'KXEUROLEAGUEGAME',
                     'KXBBLGAME', 'KXGBLGAME', 'KXACBGAME',
                     'KXJBLEAGUEGAME', 'KXLNBELITEGAME'],
            'soccer': ['KXEPLGAME', 'KXEPLSPREAD', 'KXEPLTOTAL', 'KXEPLGOAL', 'KXEPLBTTS',
                       'KXUCLGAME', 'KXUCLSPREAD', 'KXUCLTOTAL', 'KXUCLGOAL', 'KXUCLBTTS',
                       'KXLALIGAGAME', 'KXLIGAMXGAME', 'KXSERIEAGAME',
                       'KXBUNDESLIGAGAME', 'KXLIGUE1GAME',
                       'KXMLSGAME', 'KXMLSSPREAD', 'KXMLSTOTAL', 'KXMLSBTTS'],
            'ufc': ['KXUFCFIGHT'],
            'f1': ['KXF1RACE'],
            'cricket': ['KXIPL'],
        }

        if sport_filter and sport_filter.lower() not in ('', 'all'):
            series_to_fetch = SPORTS_SERIES.get(sport_filter.lower(), [])
        else:
            # For "All" scans: only fetch game-winner, spread, total, and 1H series.
            # Skip player props (PTS/REB/AST/3PT/STL/BLK) — they rarely have 2-sided
            # arb liquidity and massively inflate fetch time.
            ALL_SCAN_SERIES = [
                'KXNBAGAME','KXNBASPREAD','KXNBATOTAL',
                'KXNFLGAME','KXNFLSPREAD','KXNFLTOTAL',
                'KXNHLGAME','KXNHLSPREAD','KXNHLTOTAL','KXNHLGOAL',
                'KXMLBGAME','KXMLBSPREAD','KXMLBTOTAL',
                'KXMLSGAME','KXMLSSPREAD','KXMLSTOTAL',
                'KXNCAAMBGAME','KXNCAAMBSPREAD','KXNCAAMBTOTAL',
                'KXNCAAMB1HWINNER','KXNCAAMB1HSPREAD','KXNCAAMB1HTOTAL',
                'KXNCAAWBGAME',
                'KXEPLGAME','KXEPLSPREAD','KXEPLTOTAL','KXEPLGOAL',
                'KXUCLGAME','KXUCLSPREAD','KXUCLTOTAL','KXUCLGOAL',
                'KXATPMATCH','KXWTAMATCH',
                'KXWBCGAME',
                # KXVTBGAME, KXBSLGAME, KXABAGAME excluded — near-zero liquidity,
                # bids sum nowhere near 100c, creates false arb signals
            ]
            series_to_fetch = ALL_SCAN_SERIES

        # Fetch all open markets from each series (parallel, same pattern as /api/markets)
        def _fetch_arb_series(series):
            series_markets = []
            cursor = None
            while True:
                try:
                    result = kalshi_client.get_markets_by_series(series, status='open', limit=200, cursor=cursor)
                except Exception:
                    break
                markets = result.get('markets', [])
                if not markets:
                    break
                markets = [m for m in markets if 'mve_selected_legs' not in m
                           and 'KXMVECROSSCATEGORY' not in m.get('ticker', '')]
                series_markets.extend(markets)
                cursor = result.get('cursor')
                if not cursor or len(result.get('markets', [])) < 200:
                    break
            return series, series_markets

        all_markets = []
        with ThreadPoolExecutor(max_workers=20) as executor:
            for _, series_markets in executor.map(_fetch_arb_series, series_to_fetch):
                all_markets.extend(series_markets)
        print(f'🔍 scan_arb: {len(all_markets)} markets fetched', flush=True)

        # Filter stale/postponed markets
        now = datetime.now(timezone.utc)
        def _is_stale(m):
            exp_str = m.get('expected_expiration_time', '')
            if not exp_str: return False
            try:
                exp_time = datetime.fromisoformat(exp_str.replace('Z','+00:00'))
                days_past = (now - exp_time).days
                if days_past > 30: return True
                if days_past > 7 and m.get('volume_24h',0) == 0 and m.get('liquidity',0) == 0: return True
            except: pass
            return False
        all_markets = [m for m in all_markets if not _is_stale(m)]

        def tc(m, field):
            d = m.get(field + '_dollars')
            if d: return round(float(d) * 100)
            return m.get(field, 0)

        opportunities = []
        for m in all_markets:
            yes_bid = tc(m, 'yes_bid')
            no_bid  = tc(m, 'no_bid')
            yes_ask = tc(m, 'yes_ask')
            no_ask  = tc(m, 'no_ask')
            if not yes_bid or not no_bid:
                continue

            # Width = raw profit room (at bid prices)
            width = 100 - yes_bid - no_bid
            if width < min_width:
                continue

            # Default: queue-jump prices (bid+1) to be first in line.
            # This is the only price that makes sense — posting at or below
            # the bid puts you behind everyone already there.
            sug_yes = yes_bid + 1
            sug_no  = no_bid + 1
            posted_profit = 100 - sug_yes - sug_no  # width - 2

            # Skip if queue-jump eats all profit
            if posted_profit <= 0:
                continue

            # ── Spread & Liquidity ─────────────────────────────────
            yes_spread = (yes_ask - yes_bid) if yes_ask and yes_bid else 99
            no_spread  = (no_ask  - no_bid)  if no_ask  and no_bid  else 99
            total_spread = yes_spread + no_spread

            # ── Balance: how close both sides are to 50/50 ─────────
            min_bid_val = min(yes_bid, no_bid)
            max_bid_val = max(yes_bid, no_bid, 1)
            balance = round(min_bid_val / max_bid_val, 2)

            # Skip garbage: extreme-outcome markets that will never
            # fill both sides (e.g. YES 5¢ / NO 92¢)
            if min_bid_val < 5:
                continue

            # Skip extreme width — phantom bids on dead markets
            if width > 50:
                continue

            # ── Liquidity score (0-1): tight spread = high ─────────
            # Perfect spread = 1¢ each side (total 2) → liquidity 1.0
            # 5¢ each side (total 10) → liquidity 0.2
            # No ask data (total 198) → essentially 0
            liquidity = round(min(1.0, 2.0 / max(1, total_spread)), 3)

            # ── Live game detection (use market data we already have) ─
            ticker_str = m.get('ticker', '')
            event_ticker = m.get('event_ticker', '')
            is_live = False
            exp_str = m.get('expected_expiration_time', '')
            if exp_str:
                try:
                    exp_time = datetime.fromisoformat(exp_str.replace('Z', '+00:00'))
                    hours_until_exp = (exp_time - datetime.now(timezone.utc)).total_seconds() / 3600.0
                    is_tennis = ticker_str.startswith('KXATP') or ticker_str.startswith('KXWTA')
                    max_hours = 20.0 if is_tennis else 3.5
                    if -0.5 < hours_until_exp < max_hours:
                        is_live = True
                except Exception:
                    pass

            # ── Game date & time ───────────────────────────────────
            game_date = _parse_game_date(event_ticker)
            game_time = _get_game_time(ticker_str)  # from ESPN cache (fast after first load)

            # ── CATCH SCORE ────────────────────────────────────────
            # How quickly and reliably you'll catch the width as
            # price oscillates during live play.
            #
            # Formula: width × balance × live_multiplier
            #
            # NOTE: Liquidity (1/spread) is intentionally EXCLUDED.
            # On Kalshi's single order book, spread ≈ width, so
            # width × (1/width) = 1 — the terms cancel out and
            # everything scores ~1.  Dropping liquidity lets width
            # and balance differentiate properly.
            #
            # Sweet spot: 3-8¢ width, balanced bids, live game.
            # Extreme odds (5¢/92¢) → low balance → low score.
            live_mult = 3.0 if is_live else 1.0
            catch_score = round(width * balance * live_mult, 1)

            # ── Catch speed label ──────────────────────────────────
            if catch_score >= 15:
                catch_speed = 'prime'    # best opportunities
            elif catch_score >= 8:
                catch_speed = 'fast'     # good fill speed
            elif catch_score >= 3:
                catch_speed = 'moderate' # decent, may take time
            else:
                catch_speed = 'slow'     # wide spread or unbalanced

            opportunities.append({
                'ticker':        ticker_str,
                'title':         m.get('title', ''),
                'event_ticker':  event_ticker,
                'series_ticker': m.get('series_ticker', ''),
                'yes_bid':       yes_bid,
                'no_bid':        no_bid,
                'yes_ask':       yes_ask or 0,
                'no_ask':        no_ask or 0,
                'yes_spread':    yes_spread if yes_spread < 99 else 0,
                'no_spread':     no_spread if no_spread < 99 else 0,
                'width':         width,
                'suggested_yes': sug_yes,
                'suggested_no':  sug_no,
                'profit_posted': posted_profit,
                'catch_score':   catch_score,
                'catch_speed':   catch_speed,
                'liquidity':     liquidity,
                'balance':       balance,
                'min_bid':       min_bid_val,
                'is_live':       is_live,
                'game_date':     game_date,
                'game_time':     game_time,
            })

        opportunities.sort(key=lambda x: x['catch_score'], reverse=True)
        return jsonify({
            'opportunities': opportunities,
            'count': len(opportunities),
            'total_scanned': len(all_markets),
            'min_width': min_width
        })

    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({'error': str(e)}), 500


PNL_LOSS_RESULTS = (
    'stop_loss_yes', 'stop_loss_no', 'flip_yes', 'flip_no',
    'force_exit_yes', 'force_exit_no', 'settled_loss_yes', 'settled_loss_no',
    'stopped_loss', 'flipped', 'manual_stop',
    'manual_exit_yes', 'manual_exit_no',  # manual exits that aren't wins
    'stopped_sl', 'loss',  # middle bot results
    'amended',  # timeout/cancel amends where one leg sold at a loss
    'hard_ceiling_sellback',  # arb dead, sold filled leg back
    'anchor_sellback',  # anchor-dog: sold dog back when fav hedge failed
    'ladder_sellback',  # ladder: sold dog rungs back when fav hedge failed/timed out
    'ladder_arb_sellback',  # ladder arb: sold filled leg back
    'apex_sellback',  # apex: sold anchor back when hedge couldn't fill profitably
    'stop_loss_watch',  # straight bet stop-loss triggered
    'arb_loss',  # anchor-ladder/dog: completed with negative P&L (fees exceeded spread)
    'rebalancer_scrape',  # meridian rebalancer sold a filled leg back
    # timeout_exit_* removed — amend completes the arb, recorded as 'completed' now
)
PNL_WIN_RESULTS = (
    'completed', 'settled_win_yes', 'settled_win_no', 'manual_exit_completed',
    'middle_hit', 'arb_win',  # middle bot results
    'take_profit_watch',  # straight bet take-profit hit
)

def _compute_pnl_bucket(trades, category=None):
    """Compute gross profit/loss/counts from a list of trade_history entries.
    If category given ('arb','bet','middle'), filters to that category only."""
    if category:
        if category == 'arb':
            trades = [t for t in trades if t.get('bot_category', 'arb') in ('arb', 'ladder_arb', 'both_posted')]
        else:
            trades = [t for t in trades if t.get('bot_category', 'arb') == category]
    gross_profit = 0
    gross_loss   = 0
    total_fees   = 0
    completed    = 0
    stopped      = 0
    sport_pnl    = {}
    for t in trades:
        result = t.get('result', '')
        pnl = 0
        fees = t.get('fee_cents', 0) or 0
        if result in PNL_WIN_RESULTS:
            p = t.get('profit_cents', 0) or 0
            l = t.get('loss_cents', 0) or 0
            if p < 0:
                # Negative profit on a "win" result = actually a loss stored wrong
                gross_loss += abs(p)
                pnl = -abs(p)
            else:
                gross_profit += p
                gross_loss += l
                pnl = p - l
            total_fees += fees
            # Amended arbs that lost money count as losses, not wins
            if pnl < 0:
                stopped += 1
            else:
                completed += 1
        elif result in PNL_LOSS_RESULTS:
            p = t.get('profit_cents', 0)  # some exits (e.g. timeout) may be net positive
            l = t.get('loss_cents', 0)
            if p < 0 and l == 0:
                # Loss stored as negative profit_cents — normalize
                l = abs(p)
                p = 0
            gross_profit += p
            gross_loss   += l
            total_fees += fees
            pnl = p - l
            # Mirror win logic: classify by actual P&L, not just result string
            # A sellback that netted positive is still a win
            if pnl >= 0 and p > 0:
                completed += 1
            else:
                stopped += 1
        sport = t.get('sport', 'Other')
        sport_pnl[sport] = sport_pnl.get(sport, 0) + pnl
    net_cents = gross_profit - gross_loss
    return {
        'gross_profit_cents': gross_profit,
        'gross_loss_cents':   gross_loss,
        'total_fee_cents':    total_fees,
        'net_cents':          net_cents,
        'net_dollars':        net_cents / 100,
        'completed_bots':     completed,
        'stopped_bots':       stopped,
        'sport_pnl':          sport_pnl,
    }


def _trade_day_key(t):
    """Return ISO date string for a trade's timestamp (Arizona time)."""
    ts = t.get('timestamp')
    if ts:
        return datetime.fromtimestamp(ts, tz=AZ_TZ).date().isoformat()
    return datetime.now(AZ_TZ).date().isoformat()


@app.route('/api/pnl', methods=['GET'])
def get_pnl():
    """P&L dashboard — daily & lifetime, computed from trade history."""
    today = datetime.now(AZ_TZ).date().isoformat()

    # Split into today vs all-time
    # pnl_resets: per-day reset timestamps — trades before that day's reset are excluded.
    today_reset = _pnl_reset_for_day(today)
    all_today = [t for t in trade_history if _trade_day_key(t) == today]
    if today_reset > 0:
        today_trades = [t for t in all_today if (t.get('timestamp') or 0) >= today_reset]
    else:
        today_trades = all_today

    daily    = _compute_pnl_bucket(today_trades)
    # Lifetime = sum of all calendar day buckets (arb only, per-day resets applied)
    # so that lifetime always equals the sum of each calendar day shown to the user.
    lifetime_trades = []
    for t in trade_history:
        day = _trade_day_key(t)
        day_reset = _pnl_reset_for_day(day)
        if day_reset > 0 and (t.get('timestamp') or 0) < day_reset:
            continue  # skip pre-reset trades for this day
        lifetime_trades.append(t)
    lifetime     = _compute_pnl_bucket(lifetime_trades, 'arb')
    lifetime_bet = _compute_pnl_bucket(lifetime_trades, 'bet')
    lifetime_mid = _compute_pnl_bucket(lifetime_trades, 'middle')
    lifetime_dog_trades = [t for t in lifetime_trades if t.get('bot_category') in ('anchor_dog', 'anchor_ladder')]
    lifetime_dog = _compute_pnl_bucket(lifetime_dog_trades)
    arb_d    = _compute_pnl_bucket(today_trades, 'arb')
    bet_d    = _compute_pnl_bucket(today_trades, 'bet')
    mid_d    = _compute_pnl_bucket(today_trades, 'middle')
    # Dog = anchor_dog + anchor_ladder categories
    dog_today = [t for t in today_trades if t.get('bot_category') in ('anchor_dog', 'anchor_ladder')]
    dog_d    = _compute_pnl_bucket(dog_today)

    # Unrealized P&L from active middle bots
    mid_unrealized_cents = 0
    mid_unrealized_count = 0
    mid_at_risk_cents = 0
    mid_at_risk_count = 0
    for b in active_bots.values():
        if b.get('type') != 'middle':
            continue
        status = b.get('status', '')
        q = b.get('qty', 1)
        if status == 'both_filled':
            # Both legs filled — locked-in minimum profit (one leg MUST win)
            pa = b.get('leg_a_fill_price') or b.get('target_price_a') or 0
            pb = b.get('leg_b_fill_price') or b.get('target_price_b') or 0
            if pa > 0 and pb > 0:
                locked_profit = (100 - pa - pb) * q
                mid_unrealized_cents += locked_profit
                mid_unrealized_count += 1
        elif status in ('one_filled', 'one_leg_timeout'):
            # One leg filled — at risk until settlement
            filled_leg = b.get('filled_leg', 'a')
            fill_price = b.get(f'leg_{filled_leg}_fill_price') or b.get('target_price', 0)
            if fill_price > 0:
                # Max loss = fill_price * qty (if leg loses)
                # Max win = (100 - fill_price) * qty (if leg wins)
                mid_at_risk_cents += fill_price * q
                mid_at_risk_count += 1

    pnl = {
        # Daily (combined — unchanged)
        'gross_profit_cents': daily['gross_profit_cents'],
        'gross_loss_cents':   daily['gross_loss_cents'],
        'net_cents':          daily['net_cents'],
        'net_dollars':        daily['net_dollars'],
        'completed_bots':     daily['completed_bots'],
        'stopped_bots':       daily['stopped_bots'],
        # Lifetime
        'lifetime_gross_profit_cents': lifetime['gross_profit_cents'],
        'lifetime_gross_loss_cents':   lifetime['gross_loss_cents'],
        'lifetime_net_cents':          lifetime['net_cents'],
        'lifetime_net_dollars':        lifetime['net_dollars'],
        'lifetime_completed':          lifetime['completed_bots'],
        'lifetime_stopped':            lifetime['stopped_bots'],
        # Lifetime per-category
        'lifetime_bet_net_cents':  lifetime_bet['net_cents'],
        'lifetime_bet_wins':       lifetime_bet['completed_bots'],
        'lifetime_bet_losses':     lifetime_bet['stopped_bots'],
        'lifetime_mid_net_cents':  lifetime_mid['net_cents'],
        'lifetime_mid_wins':       lifetime_mid['completed_bots'],
        'lifetime_mid_losses':     lifetime_mid['stopped_bots'],
        'lifetime_dog_net_cents':  lifetime_dog['net_cents'],
        'lifetime_dog_wins':       lifetime_dog['completed_bots'],
        'lifetime_dog_losses':     lifetime_dog['stopped_bots'],
        # Category breakdown (today)
        'arb_net_cents':    arb_d['net_cents'],
        'arb_profit_cents': arb_d['gross_profit_cents'],
        'arb_loss_cents':   arb_d['gross_loss_cents'],
        'arb_wins':         arb_d['completed_bots'],
        'arb_losses':       arb_d['stopped_bots'],
        'bet_net_cents':    bet_d['net_cents'],
        'bet_profit_cents': bet_d['gross_profit_cents'],
        'bet_loss_cents':   bet_d['gross_loss_cents'],
        'bet_wins':         bet_d['completed_bots'],
        'bet_losses':       bet_d['stopped_bots'],
        'mid_net_cents':    mid_d['net_cents'],
        'mid_profit_cents': mid_d['gross_profit_cents'],
        'mid_loss_cents':   mid_d['gross_loss_cents'],
        'mid_wins':         mid_d['completed_bots'],
        'mid_losses':       mid_d['stopped_bots'],
        # Dog category breakdown (today)
        'dog_net_cents':    dog_d['net_cents'],
        'dog_profit_cents': dog_d['gross_profit_cents'],
        'dog_loss_cents':   dog_d['gross_loss_cents'],
        'dog_wins':         dog_d['completed_bots'],
        'dog_losses':       dog_d['stopped_bots'],
        # Sport breakdown (today)
        'sport_pnl': {s: round(v/100, 2) for s, v in daily['sport_pnl'].items() if v != 0},
        # Middle bot unrealized (both legs filled, awaiting settlement)
        'mid_unrealized_cents': mid_unrealized_cents,
        'mid_unrealized_count': mid_unrealized_count,
        'mid_at_risk_cents': mid_at_risk_cents,
        'mid_at_risk_count': mid_at_risk_count,
        # Meta
        'active_bots': len([b for b in active_bots.values()
                             if b['status'] in ('pending_fills', 'yes_filled', 'no_filled')]),
        'day_key': today,
        'pnl_reset_since': _pnl_reset_for_day(today),  # trades before this ts excluded from today's view
    }
    return jsonify(pnl)


@app.route('/api/pnl/calendar', methods=['GET'])
def get_pnl_calendar():
    """Return daily P&L for every day that has trades — powers the calendar view.
    Each day respects its own pnl_resets entry (if any).
    ?category=arb|dog|middle|bet — filter by bot type (default: arb)."""
    from collections import defaultdict
    cat = request.args.get('category', 'arb')
    day_buckets = defaultdict(list)
    for t in trade_history:
        # Pre-filter by category to avoid bucketing irrelevant trades
        if cat == 'dog':
            if t.get('bot_category') not in ('anchor_dog', 'anchor_ladder'):
                continue
        elif cat == 'arb':
            if t.get('bot_category', 'arb') not in ('arb', 'ladder_arb', 'both_posted'):
                continue
        elif cat == 'middle':
            if t.get('bot_category') != 'middle':
                continue
        elif cat == 'bet':
            if t.get('bot_category') != 'bet' and t.get('type') != 'watch':
                continue
        day = _trade_day_key(t)
        day_reset = _pnl_reset_for_day(day)
        if day_reset > 0 and (t.get('timestamp') or 0) < day_reset:
            continue
        day_buckets[day].append(t)

    calendar_data = []
    for day in sorted(day_buckets.keys()):
        # Don't re-filter inside _compute_pnl_bucket — already filtered above
        bucket = _compute_pnl_bucket(day_buckets[day])
        calendar_data.append({
            'date':        day,
            'net_cents':   bucket['net_cents'],
            'net_dollars': bucket['net_dollars'],
            'wins':        bucket['completed_bots'],
            'losses':      bucket['stopped_bots'],
            'trades':      bucket['completed_bots'] + bucket['stopped_bots'],
        })
    return jsonify({'days': calendar_data})


@app.route('/api/emergency-sell', methods=['POST'])
def emergency_sell():
    """Sell orphaned contracts — called from positions page."""
    try:
        data = request.get_json(force=True) or {}
        ticker = data.get('ticker', '').strip()
        side = data.get('side', '').strip()
        count = int(data.get('count', 0))
        if not ticker or not side or count <= 0:
            return jsonify({'success': False, 'error': 'Missing ticker, side, or count'}), 400
        success, info = execute_sell(ticker, side, count, reason='emergency_orphan_sell')
        sell_price = (info or {}).get('actual_fill_price') or (info or {}).get('sell_price', 0)
        if success:
            # Cancel any resting orders on this ticker not tracked by active bots
            # (orphan hedge orders from completion that would create naked positions)
            _cancelled_orphan_orders = []
            try:
                _active_oids = set()
                for _b in bots.values():
                    if _b.get('ticker') == ticker and _b.get('status', '') not in ('completed', 'cancelled'):
                        for _key in ('hedge_order_id', '_orphan_hedge_oid'):
                            _oid = _b.get(_key)
                            if _oid:
                                _active_oids.add(_oid)
                        for _oid in _b.get('_all_hedge_order_ids', []):
                            _active_oids.add(_oid)
                api_read_limiter.wait()
                _resting = kalshi_client.get_orders(status='resting', ticker=ticker)
                _resting_orders = _resting.get('orders', []) if isinstance(_resting, dict) else []
                for _ro in _resting_orders:
                    _ro_id = _ro.get('order_id', '')
                    if _ro_id and _ro_id not in _active_oids:
                        try:
                            api_rate_limiter.wait()
                            kalshi_client.cancel_order(_ro_id)
                            _cancelled_orphan_orders.append(_ro_id[:12])
                            print(f'🧹 ORPHAN SELL CLEANUP: cancelled stale order {_ro_id[:12]} on {ticker}')
                        except Exception:
                            pass
                if _cancelled_orphan_orders:
                    bot_log('ORPHAN_SELL_ORDER_CLEANUP', f'orphan_{ticker}', {
                        'ticker': ticker, 'cancelled_orders': _cancelled_orphan_orders,
                        'count': len(_cancelled_orphan_orders),
                    })
            except Exception as _cleanup_err:
                print(f'⚠ Orphan order cleanup failed for {ticker}: {_cleanup_err}')

            bot_log('EMERGENCY_SELL', f'orphan_{ticker}', {
                'ticker': ticker, 'side': side, 'count': count,
                'sell_price': sell_price, 'reason': 'orphan_sell_button',
                'cancelled_stale_orders': len(_cancelled_orphan_orders)})
            return jsonify({'success': True, 'sell_price': sell_price,
                            'cancelled_stale_orders': len(_cancelled_orphan_orders)})
        else:
            return jsonify({'success': False, 'error': (info or {}).get('error', 'Sell failed')})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/latency', methods=['GET'])
def get_latency():
    """Get latency stats for API calls and fill-to-hedge pipeline."""
    # Live ping: hit Kalshi API with a lightweight call
    ping_ms = None
    try:
        t0 = time.time()
        kalshi_client.get_balance()
        ping_ms = round((time.time() - t0) * 1000, 1)
        _record_latency('api_ping', ping_ms)
    except Exception:
        pass
    # Raw ICMP ping to Kalshi API server
    raw_ping_ms = None
    try:
        import subprocess
        result = subprocess.run(
            ['ping', '-c', '1', '-W', '2', 'api.elections.kalshi.com'],
            capture_output=True, text=True, timeout=3
        )
        if result.returncode == 0:
            # Parse "time=1.30 ms" from output
            for part in result.stdout.split():
                if part.startswith('time='):
                    raw_ping_ms = round(float(part.split('=')[1]), 2)
                    break
    except Exception:
        pass
    return jsonify({
        'order_place':   _latency_stats('order_place'),
        'orderbook':     _latency_stats('orderbook'),
        'fill_to_hedge_phantom': _latency_stats('fill_to_hedge_phantom'),
        'fill_to_hedge_apex':    _latency_stats('fill_to_hedge_apex'),
        'raw_hedge_phantom':     _latency_stats('raw_hedge_phantom'),
        'raw_hedge_apex':        _latency_stats('raw_hedge_apex'),
        'api_ping':      _latency_stats('api_ping'),
        'live_ping_ms':  ping_ms,
        'raw_ping_ms':   raw_ping_ms,
    })


@app.route('/api/pnl/reset', methods=['POST'])
def reset_pnl():
    """Reset session P&L counters and set the daily display baseline to now.
    Stores a per-day reset timestamp so the reset persists even on future days."""
    global session_pnl, pnl_resets
    now = time.time()
    today = datetime.now(AZ_TZ).date().isoformat()
    pnl_resets[today] = now  # persist for this day permanently
    session_pnl = {
        'gross_profit_cents': 0, 'gross_loss_cents': 0,
        'completed_bots': 0,     'stopped_bots': 0,
        'session_start': now,
        'day_key': today,
    }
    save_state()
    return jsonify({'success': True, 'reset_since': now})


@app.route('/api/pnl/reset-day', methods=['POST'])
def reset_pnl_day():
    """Admin: set or clear the P&L reset timestamp for a specific past day.
    Body: {"day": "2026-03-12", "timestamp": 1773350487.02}
    Omit timestamp (or set 0) to remove the reset for that day."""
    global pnl_resets
    data = request.get_json(force=True)
    day = data.get('day')
    ts = float(data.get('timestamp', 0))
    if not day:
        return jsonify({'error': 'missing day'}), 400
    if ts > 0:
        pnl_resets[day] = ts
    else:
        pnl_resets.pop(day, None)
    save_state()
    return jsonify({'success': True, 'pnl_resets': pnl_resets})


# ─── Middle Spread Scanner ─────────────────────────────────────────────────────
# A "middle" is when you buy YES on a tight spread (e.g. Team -3.5) and
# NO on a wider spread for the same team (e.g. Team -7.5).
# If the team wins by 4-7 points, BOTH contracts settle YES/NO correctly
# and you win both sides.  Even if only one hits, the combined cost < 100¢
# for each individual contract, so downside is limited.

@app.route('/api/scan/middles', methods=['GET'])
def scan_middles():
    """
    Middle spread scanner — opposing-team NO+NO strategy.

    For a game between Team A and Team B, a "middle" buys:
      - NO on "Team A wins by over X" (wins unless A wins by X+)
      - NO on "Team B wins by over Y" (wins unless B wins by Y+)

    Since only one team can win, AT LEAST ONE NO always wins (100¢ payout).
    If the game margin falls in the "middle" (within X of A or within Y of B),
    BOTH NOs win → 200¢ payout.

    Guaranteed profit if combined NO cost < 100¢.
    Middle bonus if both hit.
    """
    try:
        print(f'🔍 scan_middles START thread={threading.current_thread().name}', flush=True)
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated. Please login first.'}), 401

        sport_filter = request.args.get('sport', '')
        phase_filter = request.args.get('phase', 'all')  # 'all', 'live', 'pregame'
        print(f'🔍 scan_middles sport={sport_filter!r} phase={phase_filter!r}', flush=True)

        # Fetch all spread markets
        SPREAD_SERIES = {
            'nba': ['KXNBASPREAD'],
            'nfl': ['KXNFLSPREAD'],
            'nhl': ['KXNHLSPREAD'],
            'mlb': ['KXMLBSPREAD'],
            'ncaab': ['KXNCAAMBSPREAD'],
            'ncaaw': ['KXNCAAWBSPREAD'],
        }
        if sport_filter and sport_filter.lower() not in ('', 'all'):
            series_to_fetch = SPREAD_SERIES.get(sport_filter.lower(), [])
        else:
            series_to_fetch = []
            for ss in SPREAD_SERIES.values():
                series_to_fetch.extend(ss)

        def _fetch_mid_series(series):
            series_markets = []
            cursor = None
            while True:
                try:
                    api_read_limiter.wait()
                    result = kalshi_client.get_markets_by_series(series, status='open', limit=200, cursor=cursor)
                except Exception:
                    break
                markets = result.get('markets', [])
                if not markets:
                    break
                markets = [m for m in markets if 'mve_selected_legs' not in m]
                series_markets.extend(markets)
                cursor = result.get('cursor')
                if not cursor or len(result.get('markets', [])) < 200:
                    break
            return series_markets

        all_spreads = []
        with ThreadPoolExecutor(max_workers=6) as executor:
            for series_markets in executor.map(_fetch_mid_series, series_to_fetch):
                all_spreads.extend(series_markets)
        print(f'🔍 scan_middles: {len(all_spreads)} spread markets fetched', flush=True)

        def tc(m, field):
            d = m.get(field + '_dollars')
            if d: return round(float(d) * 100)
            return m.get(field, 0)

        # ── Parse each market to extract team + spread number ─────────
        # Title format: "Orlando wins by over 7.5 Points?"
        # or: "TOR -3.5" etc.
        # Ticker format: KXNBASPREAD-26MAR03OKCCHI-OKC24
        #   last segment = {TEAM_CODE}{SPREAD_TIER_DIGITS}
        parsed_markets = []
        for m in all_spreads:
            title = m.get('title', '')
            ticker = m.get('ticker', '')
            et = m.get('event_ticker', '')

            # Extract spread number and team from title
            sp_match = re.search(r'(\w[\w\s\.]+?)\s+wins?\s+by\s+over\s+([\d.]+)', title, re.IGNORECASE)
            if not sp_match:
                sp_match = re.search(r'([A-Z]{2,5})\s+([+-]?[\d.]+)', title)
            if not sp_match:
                continue

            team_name = sp_match.group(1).strip()
            spread_num = float(sp_match.group(2))

            # Use event_ticker as game_id (same for all spread tiers)
            game_id = et

            # Extract team code from the LAST segment of the market ticker
            # e.g. 'KXNHLSPREAD-26MAR05NYILA-NYI2' → last='NYI2' → team='NYI'
            # e.g. 'KXNBASPREAD-26MAR03OKCCHI-OKC24' → last='OKC24' → team='OKC'
            ticker_parts = ticker.split('-')
            team_code = ''
            if len(ticker_parts) >= 3:
                last_seg = ticker_parts[-1]
                # Team code = alphabetic prefix (strip trailing digits)
                code_match = re.match(r'^([A-Z]+)', last_seg)
                team_code = code_match.group(1) if code_match else last_seg

            if not team_code:
                team_code = team_name[:3].upper()

            parsed_markets.append({
                'market': m,
                'game_id': game_id,
                'team_code': team_code,
                'team_name': team_name,
                'spread': spread_num,
                'yes_bid': tc(m, 'yes_bid'),
                'no_bid': tc(m, 'no_bid'),
                'yes_ask': tc(m, 'yes_ask'),
                'no_ask': tc(m, 'no_ask'),
            })

        # ── Group by game ─────────────────────────────────────────────
        games = {}
        for pm in parsed_markets:
            gid = pm['game_id']
            if gid not in games:
                games[gid] = []
            games[gid].append(pm)

        middles = []
        for game_id, markets in games.items():
            if len(markets) < 2:
                continue

            # Separate into teams
            teams = {}
            for pm in markets:
                tc_key = pm['team_code']
                if tc_key not in teams:
                    teams[tc_key] = []
                teams[tc_key].append(pm)

            team_codes = list(teams.keys())
            if len(team_codes) < 2:
                continue

            # ── Build cross-team pairs (opposing NO + NO) ─────────────
            for i in range(len(team_codes)):
                for j in range(i + 1, len(team_codes)):
                    tc_a = team_codes[i]
                    tc_b = team_codes[j]

                    for mkt_a in teams[tc_a]:
                        for mkt_b in teams[tc_b]:
                            no_a = mkt_a['no_bid']
                            no_b = mkt_b['no_bid']
                            if no_a <= 0 or no_b <= 0:
                                continue

                            # Skip phantom bids on extreme spreads
                            # (e.g. 3¢ NO bid on "wins by 29.5+" = dead market)
                            if no_a < 15 or no_b < 15:
                                continue

                            cost = no_a + no_b
                            # Middle zone: game margin between
                            #   "Team A wins by ≤ spread_a" and
                            #   "Team B wins by ≤ spread_b"
                            # Width in points = spread_a + spread_b
                            middle_width = mkt_a['spread'] + mkt_b['spread']

                            # Payoffs
                            guaranteed_profit = 100 - cost   # one NO always wins
                            middle_profit = 200 - cost       # both NOs win

                            # Suggested prices: depends on whether instant arb exists.
                            # Default target = 100¢ (straight middle).
                            target_total = 100
                            if cost <= 100 and (no_a + 1) + (no_b + 1) <= 100:
                                # Instant arb — bid+1 on both to get first in line
                                sug_a = no_a + 1
                                sug_b = no_b + 1
                            elif cost <= 100:
                                # Instant arb but bid+1 pushes over — stay at bid
                                sug_a = no_a
                                sug_b = no_b
                            else:
                                # Over 100¢ — shave evenly to hit target
                                shave = max(0, (cost - target_total + 1) // 2)
                                sug_a = max(1, no_a - shave)
                                sug_b = max(1, no_b - shave)
                                while sug_a + sug_b > target_total and sug_a > 1 and sug_b > 1:
                                    if sug_a >= sug_b:
                                        sug_a -= 1
                                    else:
                                        sug_b -= 1
                            suggested_profit = 100 - sug_a - sug_b

                            # ── Spread & liquidity for each NO leg ────────
                            no_spread_a = (mkt_a['no_ask'] - mkt_a['no_bid']) if mkt_a['no_ask'] and mkt_a['no_bid'] else 99
                            no_spread_b = (mkt_b['no_ask'] - mkt_b['no_bid']) if mkt_b['no_ask'] and mkt_b['no_bid'] else 99
                            total_spread = no_spread_a + no_spread_b
                            liquidity = round(min(1.0, 2.0 / max(1, total_spread)), 3)

                            # ── Balance: how close the two NO bids are ────
                            min_no = min(no_a, no_b)
                            max_no = max(no_a, no_b, 1)
                            balance = round(min_no / max_no, 2)

                            # ── Live game detection (use market data, no extra API calls) ─
                            ticker_a_str = mkt_a['market'].get('ticker', '')
                            event_ticker_a = mkt_a['market'].get('event_ticker', '')
                            is_live = False
                            exp_str_a = mkt_a['market'].get('expected_expiration_time', '')
                            if exp_str_a:
                                try:
                                    exp_t = datetime.fromisoformat(exp_str_a.replace('Z', '+00:00'))
                                    hrs = (exp_t - datetime.now(timezone.utc)).total_seconds() / 3600.0
                                    if -0.5 < hrs < 3.5:
                                        is_live = True
                                except Exception:
                                    pass
                            live_mult = 3.0 if is_live else 1.0

                            # ── Game date & time ─────────────────────────
                            game_date = _parse_game_date(event_ticker_a)
                            game_time = _get_game_time(ticker_a_str)

                            # ── CATCH SCORE for middles ───────────────────
                            # Same philosophy: width × liquidity × balance × live
                            # But width here is middle_width (spread points) and
                            # guaranteed_profit matters too.
                            base = middle_width * 2 + max(0, guaranteed_profit)
                            catch_score = round(base * liquidity * balance * live_mult, 1)

                            # ── Catch speed label ─────────────────────────
                            if catch_score >= 15:
                                catch_speed = 'prime'
                            elif catch_score >= 6:
                                catch_speed = 'fast'
                            elif catch_score >= 2:
                                catch_speed = 'moderate'
                            else:
                                catch_speed = 'slow'

                            middles.append({
                                'game_id': game_id,
                                'team_a': tc_a,
                                'team_b': tc_b,
                                'team_a_name': mkt_a['team_name'],
                                'team_b_name': mkt_b['team_name'],
                                'spread_a': mkt_a['spread'],
                                'spread_b': mkt_b['spread'],
                                'middle_width': middle_width,
                                'no_a_bid': no_a,
                                'no_b_bid': no_b,
                                'no_a_ask': mkt_a['no_ask'] or 0,
                                'no_b_ask': mkt_b['no_ask'] or 0,
                                'no_spread_a': no_spread_a if no_spread_a < 99 else 0,
                                'no_spread_b': no_spread_b if no_spread_b < 99 else 0,
                                'cost': cost,
                                'guaranteed_profit': guaranteed_profit,
                                'middle_profit': middle_profit,
                                'suggested_a': sug_a,
                                'suggested_b': sug_b,
                                'suggested_profit': suggested_profit,
                                'ticker_a': mkt_a['market']['ticker'],
                                'ticker_b': mkt_b['market']['ticker'],
                                'title_a': mkt_a['market']['title'],
                                'title_b': mkt_b['market']['title'],
                                'catch_score': catch_score,
                                'catch_speed': catch_speed,
                                'liquidity': liquidity,
                                'balance': balance,
                                'is_live': is_live,
                                'game_date': game_date,
                                'game_time': game_time,
                            })

        # ── Enrich with live game scores ──────────────────────────────
        _refresh_espn_cache()
        espn_data = _espn_cache.get('data', {})
        for m in middles:
            if m['is_live'] and espn_data:
                # Try to get score from ESPN using team codes
                for code in [m['team_a'], m['team_b']]:
                    espn_code = _KALSHI_TO_ESPN.get(code, code)
                    entry = espn_data.get(code) or espn_data.get(espn_code)
                    if entry and entry.get('status') == 'in':
                        m['score_home'] = entry.get('home_score', 0)
                        m['score_away'] = entry.get('away_score', 0)
                        m['score_diff'] = abs(entry.get('home_score', 0) - entry.get('away_score', 0))
                        m['score_detail'] = entry.get('status_detail', '')
                        m['home_team'] = entry.get('home_team', '')
                        m['away_team'] = entry.get('away_team', '')
                        break

        # ── Phase filter ──────────────────────────────────────────────
        if phase_filter == 'live':
            middles = [m for m in middles if m['is_live']]
            # For live: filter out middles where the score diff is way outside the middle range
            # and where either NO bid is too cheap (one team running away)
            filtered = []
            for m in middles:
                # Both NO legs should be reasonably priced (>= 35c)
                # If one side is < 35c, that team is heavily favored = not a real middle
                if m['no_a_bid'] < 35 or m['no_b_bid'] < 35:
                    continue
                # If we have score data, check score diff vs middle width
                sd = m.get('score_diff')
                if sd is not None:
                    # If score diff already exceeds both spreads, the middle is blown
                    if sd > m['spread_a'] and sd > m['spread_b']:
                        continue
                filtered.append(m)
            middles = filtered
        elif phase_filter == 'pregame':
            middles = [m for m in middles if not m['is_live']]

        # Sort: guaranteed arbs first, then by catch_score
        middles.sort(key=lambda x: (x['guaranteed_profit'] > 0, x['catch_score']), reverse=True)

        return jsonify({
            'middles': middles,
            'count': len(middles),
            'total_spreads': len(all_spreads),
            'games_with_spreads': len(games),
        })

    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({'error': str(e)}), 500


# ─── Active Positions from Kalshi ──────────────────────────────────────────────

@app.route('/api/positions/active', methods=['GET'])
def get_active_positions():
    """Get current Kalshi positions enriched with live market data."""
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        positions = kalshi_client.get_positions(limit=200)
        pos_list = positions.get('market_positions', positions.get('positions', []))

        # Build bot breakdown per (ticker, side) → [{type, qty}]
        def _si(v):
            if isinstance(v, (list, dict)): return 0
            try: return int(v or 0)
            except (TypeError, ValueError): return 0

        _bot_breakdown = {}  # (ticker, side) → {type_label: qty}
        for _bid, b in active_bots.items():
            _bstatus = b.get('status', '')
            # Include completed/stopped bots with fills — their positions are
            # awaiting settlement on Kalshi and shouldn't be flagged as orphans
            if _bstatus in ('completed', 'stopped', 'cancelled'):
                _bcat = b.get('bot_category', '')
                _has_net_fills = False
                if _bcat in ('anchor_dog', 'anchor_ladder'):
                    _yes_f = _si(b.get('yes_fill_qty', 0))
                    _no_f = _si(b.get('no_fill_qty', 0))
                    _has_net_fills = _yes_f != _no_f  # one-sided = position exists on Kalshi
                elif _bcat == 'ladder_arb':
                    _yes_f = _si(b.get('filled_yes_qty', 0))
                    _no_f = _si(b.get('filled_no_qty', 0))
                    _has_net_fills = _yes_f != _no_f
                if not _has_net_fills:
                    continue  # balanced fills → net position is 0, skip
            t = b.get('ticker', '')
            cat = b.get('bot_category', '')
            btype = b.get('type', '')

            def _add(tk, sd, label, q):
                if q > 0 and tk and sd:
                    key = (tk, sd)
                    if key not in _bot_breakdown:
                        _bot_breakdown[key] = {}
                    _bot_breakdown[key][label] = _bot_breakdown[key].get(label, 0) + q

            if cat in ('anchor_dog', 'anchor_ladder'):
                dog_side = b.get('dog_side', '')
                dog_fills = _si(b.get('total_dog_fill_qty')) or _si(b.get('dog_fill_qty'))
                if dog_fills == 0 and b.get('rungs'):
                    dog_fills = sum(_si(r.get('fill_qty', 0)) for r in b.get('rungs', []))
                fav_side = b.get('fav_side', '')
                fav_qty = _si(b.get('fav_fill_qty'))
                # Cross-market: fav position is on hedge_ticker, not ticker
                _fav_ticker = b.get('hedge_ticker', t) or t
                _is_same_market = _fav_ticker == t
                # Same-market: Kalshi settles matching fills instantly - use NET only
                if _is_same_market and dog_side and fav_side and dog_side != fav_side:
                    net_dog = max(0, dog_fills - fav_qty)
                    net_fav = max(0, fav_qty - dog_fills)
                    if net_dog > 0:
                        _add(t, dog_side, 'phantom', net_dog)
                    if net_fav > 0:
                        _add(t, fav_side, 'phantom', net_fav)
                else:
                    # Cross-market: dog on ticker, fav on hedge_ticker (separate positions)
                    if dog_fills > 0:
                        _add(t, dog_side, 'phantom', dog_fills)
                    if fav_qty > 0:
                        _add(_fav_ticker, fav_side, 'phantom', fav_qty)
            elif cat == 'ladder_arb':
                # Kalshi instantly settles matching YES+NO - only NET imbalance is real
                _apex_yes = _si(b.get('filled_yes_qty'))
                _apex_no = _si(b.get('filled_no_qty'))
                if _apex_yes > _apex_no:
                    _add(t, 'yes', 'apex', _apex_yes - _apex_no)
                elif _apex_no > _apex_yes:
                    _add(t, 'no', 'apex', _apex_no - _apex_yes)
            elif btype == 'middle':
                for leg in ('a', 'b'):
                    mt = b.get(f'ticker_{leg}', '')
                    if mt and b.get(f'leg_{leg}_filled'):
                        _add(mt, 'no', 'meridian', _si(b.get('qty', 1)))
            elif btype == 'watch':
                ws = b.get('side', '')
                wq = _si(b.get('quantity', 0))
                _add(t, ws, 'scout', wq)

        def _breakdown_list(tk, sd):
            raw = _bot_breakdown.get((tk, sd), {})
            return [{'type': tp, 'qty': q} for tp, q in raw.items() if q > 0]

        enriched = []
        for pos in pos_list:
            qty = _parse_position_qty(pos)
            if qty == 0:
                continue
            ticker = pos.get('ticker', '')
            side = 'yes' if qty > 0 else 'no'
            abs_qty = abs(qty)

            try:
                api_read_limiter.wait()
                mkt_resp = kalshi_client.get_market(ticker)
                mkt = mkt_resp.get('market', mkt_resp)

                def tc_pos(field):
                    d = mkt.get(field + '_dollars')
                    if d: return round(float(d) * 100)
                    return mkt.get(field, 0)

                # Compute avg entry price from exposure (Kalshi returns dollars as strings)
                exp_dollars = pos.get('market_exposure_dollars', pos.get('market_exposure', 0))
                exposure_cents = round(float(str(exp_dollars)) * 100) if isinstance(exp_dollars, str) else int(exp_dollars)
                avg_entry = round(exposure_cents / abs_qty) if abs_qty > 0 else 0

                rpnl_dollars = pos.get('realized_pnl_dollars', pos.get('realized_pnl', 0))
                realized_pnl_cents = round(float(str(rpnl_dollars)) * 100) if isinstance(rpnl_dollars, str) else int(rpnl_dollars)

                fees_dollars = pos.get('fees_paid_dollars', pos.get('fees_paid', 0))
                fees_cents = round(float(str(fees_dollars)) * 100) if isinstance(fees_dollars, str) else int(fees_dollars)

                # Live orphan detection: compare position qty vs bot-managed qty
                _managed = sum(mb['qty'] for mb in _breakdown_list(ticker, side))
                _orphan_qty = max(0, abs_qty - _managed)
                orphan_info = {'orphaned_qty': _orphan_qty} if _orphan_qty > 0 else {}
                # Parse team matchup from ticker for cleaner display
                _parts = ticker.split('-')
                _kalshi_title = mkt.get('title', '').strip()
                if _kalshi_title and _kalshi_title != ticker:
                    # Use Kalshi's market title (includes spread info like "+13")
                    _display_title = f'{_kalshi_title} — {side.upper()}'
                elif len(_parts) >= 3:
                    # Fallback: parse from ticker
                    _teams_raw = re.sub(r'^\d{2}[A-Z]{3}\d{2}', '', _parts[1])
                    _market_team = re.match(r'^([A-Z]+)', _parts[-1])
                    if _market_team:
                        _mt = _market_team.group(1)
                        _t1, _t2 = _parse_ticker_teams(ticker)
                        if _t1 and _t2:
                            _display_title = f'{_t1} vs {_t2} — {_mt} {side.upper()}'
                        else:
                            _display_title = f'{ticker} — {side.upper()}'
                    else:
                        _display_title = f'{ticker} — {side.upper()}'
                elif len(_parts) >= 2:
                    _t1, _t2 = _parse_ticker_teams(ticker)
                    if _t1 and _t2:
                        _display_title = f'{_t1} vs {_t2} — {side.upper()}'
                    else:
                        _display_title = f'{ticker} — {side.upper()}'

                enriched.append({
                    'ticker':     ticker,
                    'title':      _display_title,
                    'side':       side,
                    'quantity':   abs_qty,
                    'avg_price':  avg_entry,
                    'yes_bid':    tc_pos('yes_bid'),
                    'yes_ask':    tc_pos('yes_ask'),
                    'no_bid':     tc_pos('no_bid'),
                    'no_ask':     tc_pos('no_ask'),
                    'market_exposure': exposure_cents,
                    'realized_pnl':   realized_pnl_cents,
                    'resting_orders': pos.get('resting_orders_count', 0),
                    'fees_paid':      fees_cents,
                    'watched_by': next((bid for bid, b in active_bots.items()
                                        if b.get('ticker') == ticker and b.get('type') == 'watch'
                                        and b['status'] == 'watching'), None),
                    'is_orphaned': bool(orphan_info),
                    'orphaned_qty': orphan_info.get('orphaned_qty', 0),
                    'managing_bots': _breakdown_list(ticker, side),
                })
            except Exception:
                enriched.append({
                    'ticker': ticker, 'title': ticker,
                    'side': side, 'quantity': abs_qty,
                    'yes_bid': 0, 'no_bid': 0, 'yes_ask': 0, 'no_ask': 0,
                    'market_exposure': pos.get('market_exposure', 0),
                    'realized_pnl': pos.get('realized_pnl', 0),
                    'watched_by': None,
                    'managing_bots': _breakdown_list(ticker, side),
                })

        return jsonify({'positions': enriched, 'count': len(enriched)})

    except Exception as e:
        import traceback; traceback.print_exc()
        return jsonify({'error': str(e)}), 500


@app.route('/api/orphaned-positions', methods=['GET'])
def get_orphaned_positions():
    """Check for orphaned positions LIVE (not cached startup data)."""
    try:
        managed_tickers = set()
        for b in active_bots.values():
            # Cross-market bots hold positions on BOTH tickers until settlement,
            # even after completion. Always include both to avoid false orphans.
            _ht = b.get('hedge_ticker')
            if _ht and _ht != b.get('ticker'):
                managed_tickers.add(_ht)
                if b.get('ticker'): managed_tickers.add(b['ticker'])
            if b.get('status') in ('completed', 'stopped', 'cancelled'):
                continue
            if b.get('ticker'): managed_tickers.add(b['ticker'])
            if b.get('ticker_a'): managed_tickers.add(b['ticker_a'])
            if b.get('ticker_b'): managed_tickers.add(b['ticker_b'])
        api_read_limiter.wait()
        pos_resp = kalshi_client.get_positions()
        positions = pos_resp.get('market_positions', pos_resp.get('positions', []))
        orphans = []
        for pos in positions:
            ticker = pos.get('ticker', '')
            pos_fp = float(pos.get('position_fp') or 0)
            if not ticker or pos_fp == 0:
                continue
            if ticker not in managed_tickers:
                side = 'yes' if pos_fp > 0 else 'no'
                qty = int(abs(pos_fp))
                exposure = float(pos.get('market_exposure_dollars') or 0)
                orphans.append({'ticker': ticker, 'side': side, 'orphaned_qty': qty, 'total_qty': qty, 'exposure': exposure})
        return jsonify({'orphaned': orphans, 'count': len(orphans)})
    except Exception as e:
        return jsonify({'orphaned': [], 'count': 0, 'error': str(e)})


@app.route('/api/bot/watch', methods=['POST'])
def watch_position():
    """Attach a watch-bot to an existing Kalshi position for stop-loss / take-profit."""
    try:
        if not kalshi_client:
            return jsonify({'error': 'Not authenticated'}), 401

        data = request.json
        ticker           = data.get('ticker')
        side             = data.get('side', 'yes')
        entry_price      = int(data.get('entry_price', 50))
        quantity         = int(data.get('quantity', 1))
        stop_loss_cents  = int(data.get('stop_loss_cents', 5))
        take_profit_cents = int(data.get('take_profit_cents', 0))

        if not ticker:
            return jsonify({'error': 'ticker required'}), 400

        bot_id = f"watch_{ticker}_{int(time.time())}"
        active_bots[bot_id] = {
            'type':              'watch',
            'ticker':            ticker,
            'side':              side,
            'entry_price':       entry_price,
            'quantity':          quantity,
            'stop_loss_cents':   stop_loss_cents,
            'take_profit_cents': take_profit_cents,
            'has_sl_tp':         True,
            'status':            'watching',
            'order_filled':      True,     # manual position — already placed
            'fill_qty':          quantity,
            'filled_at':         time.time(),
            'game_phase':        'live',
            'created_at':        time.time(),
            'posted_at':         time.time(),
        }
        save_state()

        return jsonify({
            'success': True,
            'bot_id':  bot_id,
            'message': f'Watching {side.upper()} on {ticker} — SL: -{stop_loss_cents}¢'
                       + (f', TP: +{take_profit_cents}¢' if take_profit_cents else ''),
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


_startup_done = False

def _run_startup():
    """Initialize state, auto-login, connect WS — works for both python3 app.py and gunicorn."""
    global kalshi_client, _startup_done
    if _startup_done:
        return
    _startup_done = True

    load_state()
    run_migrations()

    # ── Auto-login at startup if config.json exists ──
    try:
        config_path = os.path.join(os.path.dirname(__file__), 'config.json')
        if os.path.exists(config_path):
            with open(config_path) as f:
                config = json.load(f)
            api_key_id = config.get('api_key_id')
            key_file = config.get('private_key_path', 'kalshi_private_key.pem')
            demo = config.get('demo', False)
            key_path = os.path.join(os.path.dirname(__file__), key_file)
            if api_key_id and os.path.exists(key_path):
                kalshi_client = KalshiAPI(api_key_id, key_path, demo=demo)
                balance = kalshi_client.get_balance()
                bal_usd = balance.get('balance', 0) / 100
                print(f'✅ AUTO-LOGIN at startup: balance=${bal_usd:.2f}')
                _patch_kalshi_orderbook()
                # Start WebSocket
                try:
                    ws_manager.connect(kalshi_client)
                    ws_manager.start_balance_poll(kalshi_client)
                    _ws_tickers = set()
                    for b in active_bots.values():
                        if b.get('status') not in ('completed', 'stopped', 'cancelled', 'dead'):
                            _ws_tickers.add(b['ticker'])
                            if b.get('hedge_ticker') and b['hedge_ticker'] != b['ticker']:
                                _ws_tickers.add(b['hedge_ticker'])
                    active_tickers = list(_ws_tickers)
                    if active_tickers:
                        threading.Timer(2.0, lambda: ws_manager.subscribe(active_tickers)).start()
                except Exception as ws_err:
                    print(f'⚠ WS connect at startup failed (non-fatal): {ws_err}')

                # ── Immediate SL sweep: fire any stop-losses that triggered while offline ──
                active_count = len([b for b in active_bots.values()
                                    if b.get('status') in ('pending_fills', 'yes_filled', 'no_filled', 'watching')])
                if active_count > 0:
                    print(f'🔍 STARTUP SL SWEEP: checking {active_count} active bots for overdue stop-losses...')
                    with app.test_request_context():
                        acquired = monitor_lock.acquire(blocking=True, timeout=10)
                        if acquired:
                            try:
                                result = _run_monitor()
                                print(f'🔍 STARTUP SL SWEEP complete')
                            except Exception as sweep_err:
                                print(f'⚠ Startup SL sweep error: {sweep_err}')
                            finally:
                                monitor_lock.release()
                        else:
                            print(f'⚠ Could not acquire monitor lock for startup sweep')
            else:
                print('⚠ config.json found but missing api_key_id or private key — skipping auto-login')
    except Exception as e:
        print(f'⚠ Auto-login at startup failed (non-fatal): {e}')

    # ── Orphan cleanup: cancel stale orders, detect unmanaged positions ──
    if kalshi_client:
        try:
            # Cancel orphaned limit orders
            sweep_result = _sweep_orphaned_orders()
            cancelled_count = sweep_result.get('cancelled_count', 0)
            if cancelled_count > 0:
                msg = f'🧹 Startup: cancelled {cancelled_count} orphaned order(s)'
                print(msg)
                _push_notification('orphan_sweep', msg, sweep_result)
            else:
                print('🧹 Startup orphan sweep: no orphaned orders')

            # Detect orphaned positions — compare Kalshi qty vs bot-managed qty
            api_read_limiter.wait()
            pos_resp = kalshi_client.get_positions()
            kalshi_positions = pos_resp.get('market_positions', [])

            # Sum managed qty per ticker+side from active bots
            def _safe_int(v):
                """Safely convert bot qty fields to int (some may be lists or None)."""
                if isinstance(v, (list, dict)):
                    return 0
                try:
                    return int(v or 0)
                except (TypeError, ValueError):
                    return 0

            managed_qty = {}  # (ticker, side) -> qty
            for b in active_bots.values():
                _bst = b.get('status', '')
                # Include completed/awaiting bots with one-sided fills (positions await settlement)
                if _bst in ('completed', 'stopped', 'cancelled', 'awaiting_settlement'):
                    _cat = b.get('bot_category', '')
                    if _cat in ('anchor_dog', 'anchor_ladder'):
                        _yf = _safe_int(b.get('yes_fill_qty', 0))
                        _nf = _safe_int(b.get('no_fill_qty', 0))
                        if _yf == _nf:
                            continue  # balanced → no position
                    elif _cat == 'ladder_arb':
                        _yf = _safe_int(b.get('filled_yes_qty', 0))
                        _nf = _safe_int(b.get('filled_no_qty', 0))
                        if _yf == _nf:
                            continue
                    else:
                        continue
                t = b.get('ticker', '')
                if not t:
                    continue
                cat = b.get('bot_category', '')
                if b.get('type') == 'middle':
                    # Meridian bots manage TWO tickers
                    for _leg in ('a', 'b'):
                        _mt = b.get(f'ticker_{_leg}', '')
                        _ms = b.get(f'side_{_leg}', 'no')
                        _mq = _safe_int(b.get(f'fill_qty_{_leg}')) or _safe_int(b.get('quantity', 1))
                        if _mt and _mq > 0:
                            managed_qty[(_mt, _ms)] = managed_qty.get((_mt, _ms), 0) + _mq
                elif cat in ('anchor_dog', 'anchor_ladder'):
                    dog_side = b.get('dog_side', '')
                    # Use total_dog_fill_qty (survives repeats) > dog_fill_qty (reset) > quantity (fallback)
                    dog_qty = _safe_int(b.get('total_dog_fill_qty')) or _safe_int(b.get('dog_fill_qty')) or _safe_int(b.get('quantity'))
                    # For ladder: sum rung fills as backup (most accurate for current cycle)
                    if dog_qty == 0 and b.get('rungs'):
                        dog_qty = sum(_safe_int(r.get('fill_qty', 0)) for r in b.get('rungs', []))
                    fav_side = b.get('fav_side', '')
                    fav_qty = _safe_int(b.get('fav_fill_qty'))
                    _hedge_t = b.get('hedge_ticker', t)  # cross-market: hedge on different ticker
                    if dog_qty > 0 and dog_side:
                        managed_qty[(t, dog_side)] = managed_qty.get((t, dog_side), 0) + dog_qty
                    if fav_qty > 0 and fav_side:
                        managed_qty[(_hedge_t, fav_side)] = managed_qty.get((_hedge_t, fav_side), 0) + fav_qty
                elif cat == 'ladder_arb':
                    yes_qty = _safe_int(b.get('filled_yes_qty'))
                    no_qty = _safe_int(b.get('filled_no_qty'))
                    if yes_qty > 0:
                        managed_qty[(t, 'yes')] = managed_qty.get((t, 'yes'), 0) + yes_qty
                    if no_qty > 0:
                        managed_qty[(t, 'no')] = managed_qty.get((t, 'no'), 0) + no_qty

            # Compare against Kalshi positions
            for pos in kalshi_positions:
                ticker = pos.get('ticker', '')
                try:
                    pos_fp = float(pos.get('position_fp') or 0)
                except (TypeError, ValueError):
                    pos_fp = 0
                try:
                    exposure = float(pos.get('market_exposure_dollars') or 0)
                except (TypeError, ValueError):
                    exposure = 0
                if not ticker or (pos_fp == 0 and exposure == 0):
                    continue
                # position_fp is net: positive = YES held, negative = NO held
                if pos_fp > 0:
                    side = 'yes'
                    kalshi_qty = int(pos_fp)
                elif pos_fp < 0:
                    side = 'no'
                    kalshi_qty = int(abs(pos_fp))
                else:
                    continue
                bot_qty = managed_qty.get((ticker, side), 0)
                orphaned_qty = kalshi_qty - bot_qty
                if orphaned_qty > 0:
                    _orphaned_positions[ticker] = {
                        'side': side,
                        'orphaned_qty': orphaned_qty,
                        'total_qty': kalshi_qty,
                        'managed_qty': bot_qty,
                        'exposure': exposure,
                        'detected_at': time.time(),
                    }
                    print(f'⚠ ORPHANED POSITION: {ticker} {side.upper()} {orphaned_qty}/{kalshi_qty} contracts (${exposure:.2f} exposure)')

            if _orphaned_positions:
                tickers = ', '.join(_orphaned_positions.keys())
                print(f'⚠ {len(_orphaned_positions)} orphaned position(s) on startup: {tickers}')
                # Don't push notification — orphan popup handles this, and data may be stale
            else:
                print('✅ No orphaned positions')
        except Exception as e:
            import traceback
            print(f'⚠ Startup orphan check failed: {e}')
            traceback.print_exc()

    # Start notification monitor thread
    _start_notification_thread()

# Run startup for both gunicorn (import-time) and python3 app.py
_run_startup()

